gameforge.dragon_soul._010_sayTitle = "Ejderha Ta\254\253 Par\231as\253?! "
gameforge.dragon_soul._020_say = "Elinde bir ta\254 par\231as\253 tutuyorsun. I\254\253l \253l\254\253l[ENTER]parl\253yor ve g\252c\252n\252n iliklerine kadar i\254ledi\240ini[ENTER]hissediyorsun.[ENTER]Bu nas\253l bir ta\254 b\246yle? Onu Simyac\253'ya g\246t\252r. O[ENTER]sana yard\253mc\253 olacakt\253r. "
gameforge.dragon_soul._030_npcChat = "Ejderha Ta\254\253 Par\231as\253?! "
gameforge.dragon_soul._040_say = "Bu bir ejderha ta\254\253 par\231as\253, \231ok ender bulunan[ENTER]de\240erli ve tarif edilemeyecek kadar g\252\231l\252 bir[ENTER]kristal. S\246ylenenlere g\246re bu bir ejderhan\253n[ENTER]ruhuymu\254. \221nan\253lmaz g\252zel bir \254ey.[ENTER]\220zerinde ta\254\253d\253\240\253nda g\252c\252n\252n iliklerine kadar[ENTER]i\254ledi\240ini hissediyor musun?[ENTER]Bana toplam on tane ejderha ta\254\253 par\231as\253 getir.[ENTER]Onlar\253 b\252t\252n bir ta\254a d\246n\252\254t\252rebilirim. "
gameforge.dragon_soul._050_npcChat = "Ejderha Ta\254\253 D\246n\252\254t\252rme "
gameforge.dragon_soul._060_say = "O kadar sab\253rs\253zlanma. \222imdilik senin i\231in on[ENTER]par\231ay\253 bir ejderha ta\254\253na d\246n\252\254t\252rebilirim.[ENTER]Aramaya devam et! "
gameforge.dragon_soul._070_say = "Ay s\252per! On tane ejderha ta\254\253 par\231as\253 buldun.[ENTER]Biraz bekle.[ENTER]...[ENTER]Tamamland\253! Ne ilgin\231...d\246n\252\254t\252rme i\254lemi[ENTER]s\253ras\253nda bir Cor Draconis olu\254tu; Bu, ejderha[ENTER]ta\254\253n\253 kaplay\253p koruyan kristalden bir ejderha[ENTER]kalbi.[ENTER]\221\231inde hangi ta\254\253n bulundu\240unu \246\240renmek i\231in onu[ENTER]k\253r\253p a\231. Ta\254 do\240rudan ejderha ta\254\253 simyas\253na ait[ENTER]envantere eklenir.[ENTER]Ard\253ndan da ejderha ta\254lar\253n\253 ar\253nd\253rmaya devam[ENTER]edebilece\240ini biliyor muydun? "
gameforge.dragon_soul._080_say = "Bir Cor Draconis daha m\253 istiyorsun?[ENTER]Malum \231ok gen\231 say\253lmam art\253k, b\246ylesi komplike[ENTER]bir nesneyi yapmak beni bir hayli yoruyor.[ENTER]Yine de senin hat\253r\253na deneyece\240im.[ENTER]Ama g\252nde on taneden fazla yapamam haberin olsun! "
gameforge.dragon_soul._090_say = "Bug\252nl\252k bu kadar yeter. G\252nde on taneden fazla[ENTER]yapamam, elimde de\240il. G\252c\252m t\252kenmi\254 durumda ve[ENTER]\254imdi biraz dinlenmem laz\253m. Yar\253n tekrar gel. "
gameforge.dragon_soul._100_npcChat = "Marketi a\231 "
gameforge.dragon_soul._1010_sendLetter = "Ejderha ta\254\253 par\231as\253n\253n geli\254i "
gameforge.dragon_soul._1020_say = "B\252t\252n krall\253kta minerallerle ilgili en fazla[ENTER]bilgiye sahip olan Simyac\253 seni ar\253yor. Hemen[ENTER]yan\253na git! "
gameforge.dragon_soul._1030_npcChat = "Ejderha Ta\254\253 Par\231as\253?! "
gameforge.dragon_soul._1040_say = "Aa i\254te geldin! \199ok ilgin\231 bir \254ey ke\254fettim: bir[ENTER]ejderha ta\254\253 par\231as\253! Ejderha ta\254\253 \231ok nadir[ENTER]bulunan ve b\252y\252k g\252ce sahip de\240erli bir kristal.[ENTER]\221\231inde bir ejderha ruhu ta\254\253yormu\254 diyorlar.[ENTER]\221nan\253lmaz derecede g\252zel! Par\231alar\253 bulman i\231in[ENTER]sana ejderha g\246z\252 g\252c\252n\252 veriyorum. Bana toplam[ENTER]10 ejderha ta\254\253 par\231as\253 getir. Bunlar\253 b\252t\252n bir[ENTER]ta\254a d\246n\252\254t\252rebilirim. "
gameforge.dragon_soul._1050_sendLetter = "Ejderha ta\254\253 par\231as\253 topla "
gameforge.dragon_soul._1060_say = "Simyac\253ya 10 ejderha ta\254\253 par\231as\253 g\246t\252r. "
gameforge.dragon_soul._1070_say = "Ah, \231ok g\252zel! 10 ejderha ta\254\253 par\231as\253 buldun.[ENTER]L\252tfen bir dakika bekle....[ENTER]\221nan\253lmaz! D\246n\252\254\252m s\253ras\253nda ejderha ta\254\253n\253[ENTER]sarmalayan kristal bir ejderha kalbi olan Cor[ENTER]Draconis olu\254tu.[ENTER]Bunu a\231t\253\240\253nda i\231indeki ejderha ta\254\253 do\240rudan[ENTER]ejderha ta\254\253 simyas\253 envanterine aktar\253l\253r.[ENTER]Ejderha ta\254\253 par\231as\253 bulmak ve d\246n\252\254t\252rmek i\231in[ENTER]ejderha g\246z\252 g\252c\252ne ihtiya\231 duyulur. Sana[ENTER]bunlardan g\252nde bir tane yapabilirim. Bug\252n senin[ENTER]i\231in bir adet olu\254turdum bile, geri kalan %d[ENTER]taneyi de kendin yapabilirsin. "
gameforge.dragon_soul._1080_say = "Hey, zaman kaybetme! Git ve ejderha ta\254\253[ENTER]par\231alar\253 bul! "
gameforge.dragon_soul._1090_sendLetter = "Ejderha G\246z\252 G\252c\252 "
