gameforge.dragon_soul._1130_say = "Selam! Ejderha g\246z\252n\252n g\252c\252n\252 bug\252n zaten ald\253n.[ENTER]\221\254lem beni fazla yoruyor, sana g\252nde sadece bir[ENTER]kez yard\253m edebilirim. Yar\253n yine gel! "
gameforge.dragon_soul._1140_say = "Selam! Bahse girerim ejderha g\246z\252 g\252c\252 nedeniyle[ENTER]buradas\253n. Do\240ru mu? \221yi \246yleyse, al bakal\253m.[ENTER]Sana aramada bol \254anslar! Umar\253m on ejderha[ENTER]ta\254\253na yetecek say\253da par\231a bulabilirsin. "
