gameforge.energy_system = {}
gameforge.energy_system._001_npcChat = "Yeni bir teknik! "
gameforge.energy_system._010_say = "Ba\254ard\253m![ENTER]Nihayet yepyeni bir teknik geli\254tirebildim.[ENTER]E\254yalar\253 tekrar i\254leyerek onlardan saf enerji[ENTER]elde etmenin yolunu buldum. Ne \254ahane! "
gameforge.energy_system._020_say = "E\254ya, benim buldu\240um teknikle tahrip edilir ve[ENTER]enerji par\231alar\253na ayr\253l\253r. Bu par\231alar\253n 30[ENTER]tanesi birle\254tirilince de g\252\231l\252 bir enerji[ENTER]kristali elde edilir! Bir m\252cevher i\231erisinde[ENTER]toplanm\253\254 saf ve filtrelenmemi\254 bir enerji. Bu[ENTER]g\252\231 t\252m te\231hizat\253na i\254ler.[ENTER]\221lgini \231ekiyor mu? "
gameforge.energy_system._030_say = "Avlan\253rken buldu\240un silah, tak\253 ve k\253yafet gibi[ENTER]te\231hizat malzemelerini bana getir. Onlar\253 i\254leyip[ENTER]enerji par\231alar\253na ay\253raca\240\253m.[ENTER]Krall\253\240\253m\253z\253n gelece\240i ve umudu bu tekni\240e ba\240l\253.[ENTER]Yenilmez olaca\240\253z! "
gameforge.energy_system._035_npcChat = "Enerji par\231as\253 elde et "
gameforge.energy_system._040_say = "Yapabildin mi? Enerji par\231as\253 elde edebildin mi?[ENTER]Simya yard\253m\253yla par\231alayabilece\240im daha fazla[ENTER]e\254ya getir bana.[ENTER]Tekni\240im hen\252z m\252kemmelle\254medi.[ENTER]Bu y\252zden ne kadar par\231a elde edilece\240ine dair[ENTER]bir garanti veremeyece\240im. "
gameforge.energy_system._050_say = "Tek bir \254art var: Kendi seviyen ve e\254yan\253n[ENTER]seviyesi en az 35 olmal\253. H\253m, bir g\246z atal\253m[ENTER]bakal\253m... "
gameforge.energy_system._060_say = "Hen\252z yeterince g\252\231l\252 de\240ilsin! En az 35.[ENTER]seviyeye ula\254t\253\240\253nda tekrar gel. "
gameforge.energy_system._070_say = "Ah s\252per! G\252\231l\252 ve tecr\252belisin.[ENTER]\221\254lenecek e\254yay\253 ver bakal\253m. "
gameforge.energy_system._080_say = "Enerji par\231alar\253n\253n i\231erdi\240i g\252ce hakim olacak[ENTER]kadar g\252\231l\252 de\240ilsin.[ENTER]En az 35. seviyeye ula\254t\253\240\253nda tekrar gel. "
gameforge.energy_system._090_say = "Bu e\254ya benim tekni\240im i\231in elveri\254li de\240il. Bana[ENTER]ba\254ka bir \254ey getir. "
gameforge.energy_system._100_say = "Bu e\254ya yeterli enerjiye sahip de\240il.[ENTER]Bana seviyesi en az 35 olan bir tane getirirsen[ENTER]tekni\240imle i\231indeki g\252c\252 \231\253karabilirim. "
gameforge.energy_system._110_say = "Bu e\254yay\253 tahrip edeyim mi? "
gameforge.energy_system._120_select = "Evet "
gameforge.energy_system._130_select = "Hay\253r, \254imdi etme! "
gameforge.energy_system._140_say = "Beceremedim, enerji pa\231as\253 elde edemedim ne yaz\253k[ENTER]ki. Bir dahaki sefer ba\254ar\253l\253 oluruz belki. "
gameforge.energy_system._150_say = "Efsanevi! %d enerji par\231as\253 buldum. \221\254te buyur. "
gameforge.energy_system._160_npcChat = "Enerji kristali \252ret "
gameforge.energy_system._170_say = "G\252c\252n \254imdiden t\252kendi mi yoksa? Kendini o kadar[ENTER]h\253rpalay\253p hayat\253n\253 tehlikeye atmamal\253s\253n.[ENTER]Enerji kristali \252retmek i\231in %d enerji par\231as\253na[ENTER]ihtiyac\253m var. "
gameforge.energy_system._180_say = "Hen\252z yeterli enerji par\231as\253na sahip de\240ilsin.[ENTER]Bunlardan enerji kristali \252retemem.[ENTER]En az %d par\231a toplad\253\240\253nda tekrar gel. "
gameforge.energy_system._190_say = "G\252zel. Laz\253m olan %d enerji par\231as\253n\253 getirdin.[ENTER]Bunlardan bir enerji kristali \252retebilirim. Biraz[ENTER]bekle l\252tfen. Deneyece\240im ama olaca\240\253na dair[ENTER]garanti veremem. "
gameforge.energy_system._200_say = "Her \254ey haz\253r durumda. Par\231alar\253 birle\254tirip[ENTER]enerji kristali \252retebiliriz.[ENTER]Ama ben de bir \254ekilde ekme\240imi kazanmal\253y\253m.[ENTER]Tamir aletleri de g\246kten inmiyor yani. Masraflar\253[ENTER]kar\254\253lamak i\231in %d Yang \246demeni istiyorum.[ENTER]\214demeye haz\253r m\253s\253n? "
gameforge.energy_system._210_select = "Tabii ki. "
gameforge.energy_system._220_select = "Hay\253r, \254imdi de\240il. "
gameforge.energy_system._230_say = "Tamam, karar\253na sayg\253 duyuyorum.[ENTER]Fikrini de\240i\254tirdi\240inde ve enerji kristaline[ENTER]ihtiyac\253n oldu\240unda tekrar gel. "
gameforge.energy_system._240_say = "Kusura bakma ama ilk \246nce paray\253 \246demen laz\253m.[ENTER]Buras\253 yard\253m kurumu de\240il. Paray\253 veren d\252d\252\240\252[ENTER]\231alar - bu i\254ler b\246yle y\252r\252r. "
gameforge.energy_system._250_say = "\221\254te enerji kristalin. Sadece ilk giri\254imde[ENTER]ba\254ar\253l\253 olunur hep. Simya, sa\240\253 solu belli[ENTER]olmayan bir bilim. Ufak tefek farkl\253l\253klar[ENTER]ba\254ar\253s\253zl\253\240a neden olabilir! Yani deneylerde[ENTER]genelde k\252\231\252k de olsa ba\254ar\253s\253zl\253\240a u\240rama riski[ENTER]bulunur. "
gameforge.energy_system._260_say = "Giri\254im ne yaz\253k ki ba\254ar\253s\253zd\253. Enerji kristali[ENTER]\252retemedim. Tekni\240im m\252kemmel ama icras\253[ENTER]risklerle dolu i\254te. Her \254ey planlad\253\240\253n gibi[ENTER]olmuyor. Bir dahaki sefer kesin ba\254ar\253l\253 oluruz! "
gameforge.energy_system._270_say = "Biliyordum! Benim tekni\240imin \252st\252ne yoktur![ENTER]\221\254te enerji kristalin.[ENTER]Tam bir \254ah eser! G\252c\252 hissediyor musun? "
