gameforge.find_squareguard._120_say = "K\253rm\253z\253 iksiri Sat\253c\253 Kad\253ndan alabilirsin. Hemen[ENTER]\254urada. E\240er onu g\246remiyorsan, k\252\231\252k haritada[ENTER]yan\253p s\246nen k\253rm\253z\253 noktaya do\240ru gidebilirsin! "
