gameforge.find_squareguard._131_targetVid = "Sat\253c\253: "
gameforge.find_squareguard._140_say = "Merhaba macerac\253![ENTER]Ah, seni K\246y Gardiyan\253 m\253 g\246nderdi? K\253rm\253z\253 iksir[ENTER]mi istiyor? Sana hemen 5 tane veriyorum.[ENTER]\221\254te burada. Bunlar ya\254am enerjini yeniler ve[ENTER]tatlar\253 da \231ok g\252zeldir. "
gameforge.find_squareguard._150_say = "Sen buralarda yenisin, ama eminim, buraya daha[ENTER]\231ok geleceksin, onun i\231in sana bu kirmizi suyu[ENTER]hediye ediyorum.G\246r\252\254mek \252zere. "
