gameforge.find_squareguard._190_sayReward = "K\246y Gardiyan\253na geri d\246n ve k\253rm\253z\253 iksirleri ver. "
gameforge.find_squareguard._200_say = "Kirmizi iksir almadin mi?[ENTER]Ne yaz\253k! Ama zahmetin i\231in, bozuk para senin[ENTER]olsun.[ENTER]Ve \246gretmenlerin seni ariyor.[ENTER]Onlara gitmen laz\253m. "
gameforge.find_squareguard._20_sayReward = "K\246y meydan\253na git ve K\246y Gardiyan\253 ile konu\254.[ENTER]Sana ilk g\246revini verecek.[ENTER]Onu k\246y meydan\253nda bulabilirsin. "
gameforge.find_squareguard._210_say = "\199ok te\254ekk\252r ederim,bana k\253zm\253z\253 iksiri[ENTER]getirdi\240in i\231in![ENTER]G\252zel,o zaman buray\253 yanliz b\253rakmama gerek yok.[ENTER]G\246revimi \246grenmek mi istiyorsun? Ben yaln\253zca k\246y[ENTER]gardiyan\253 de\240ilim, benden sana yard\253mc\253 olacak[ENTER]bilgiler de alabilirsin. Herkesin duyabilece\240i[ENTER]faydal\253 bilgiler anons ediyorum.[ENTER]Bazen de yard\253m\253ma ve korumaya ihtiyac\253 olan[ENTER]ki\254ilere yard\253m ediyorum. Ama aslinda loncalar[ENTER]benim vazifem. Lonca ile ilgili bir i\254in olursa[ENTER]bana gel. "
gameforge.find_squareguard._220_say = "Ve \246gretmenlerin seni ariyor..[ENTER]Onlara gitmen lazim.[ENTER]Ah,az daha unutuyordum! Sana zahmetin i\231in bozuk[ENTER]paray\253 b\253rakiyorum! G\246r\252\254mek \252zere. "
gameforge.find_squareguard._30_sayTitle = "Gardiyan: "
gameforge.find_squareguard._40_say = "Merhaba macerac\253! Bana yard\253m edebilir misin?[ENTER]Sana 200 Yang versem, bana k\253rm\253z\253 iksir alabilir[ENTER]misin? Ben buradan ayr\253lamam, k\253rm\253z\253 iksiri[ENTER]sat\253c\253dan alabilirsin. "
