gameforge.gamesultan._015_say = "B\252y\252k Metin2 Turnuvas\253'na ho\254 geldin![ENTER]Envanterinde bulmaca kutusunu bulabilirsin. Buna[ENTER]sa\240 fare tu\254uyla t\253klad\253\240\253nda Ate\254 Diyar\253'na[ENTER]\253\254\253nlan\253rs\253n - ve sava\254 ba\254lar! "
gameforge.gamesultan._020_say = "Sadece en iyiler tur atlayabilir! Sen de[ENTER]bunlardan biri misin? E\254ya d\252kkan\253 deponu kontrol[ENTER]et, kutuyu bul ve envanterine \231ek. Sa\240 fare[ENTER]tu\254uyla \252zerine t\253klad\253\240\253n anda sonraki haritaya[ENTER]\253\254\253nlan\253rs\253n. "
gameforge.gamesultan._025_say = "T\252m zorlu m\252cadelelerin \252stesinden geldin.[ENTER]M\252thi\254 kat\253l\253m\253n i\231in \231ok te\254ekk\252rler![ENTER]Final kat\253l\253mc\253lar\253 son a\254amadan sonra[ENTER]belirlenir. E\240er sorular\253n varsa turnuva[ENTER]yard\253mc\253lar\253yla ileti\254ime ge\231. "
gameforge.gamesultan._030_say = "M\252cadele ba\254lamadan \246nce oyun se\231eneklerinde, PvP[ENTER]modunu serbeste \231evirmelisin.[ENTER]Ekran\253n\253n sa\240 alt taraf\253ndaki buttondan veya[ENTER]Esc tu\254uyla a\231, oyun se\231eneklerini se\231 ve PvP[ENTER]modunu serbeste \231evir. "
gameforge.gamesultan._040_say = "Ne yaz\253k ki t\252m yerler doldu. Turnuvaya kat\253lmak[ENTER]i\231in bir sonraki a\254amay\253 bekle. "
gameforge.gamesultan._050_notice_all = "Tur 1: M\252mk\252n oldu\240u kadar \231ok Metin Ta\254\253 yok et. "
gameforge.gamesultan._060_notice_all = "Tur 2: M\252mk\252n oldu\240u kadar \231ok patron yok et! "
gameforge.gamesultan._070_notice_all = "Tur 3: PvP d\252ellosunda m\252mk\252n oldu\240u kadar \231ok[ENTER]rakip yen! "
gameforge.gamesultan._080_notice_all = "10 dakikan kald\253. "
gameforge.gamesultan._090_notice_all = "1 dakikan kald\253. T\252m g\252c\252n\252 kullan! "
