gameforge.ghost_story._010_sayTitle = "Sura Ruhu: "
gameforge.ghost_story._020_npcChat = "Sen bir ruh musun? "
gameforge.ghost_story._030_say = "Yok ninenim...Tabiki bir ruhum! \199ocukken ba\254\253na[ENTER]saks\253 m\253 d\252\254t\252? "
gameforge.ghost_story._040_npcChat = "\221mdat, ruh var! "
gameforge.ghost_story._050_say = "Bak sen \254u i\254e, pek cesur bir sava\254\231\253! Yuh! "
gameforge.ghost_story._060_npcChat = "Sen kimsin? "
gameforge.ghost_story._070_say = "Benim ad\253m Akuma. Bir zamanlar \231ok g\252\231l\252 bir[ENTER]sava\254\231\253yd\253m, o zamanlar\253n en iyi sava\254\231\253s\253. Ben[ENTER]de, evet, en \231ok ben (!) buna inand\253m.[ENTER]Halime bak, ma\240aray\253 bulduktan sonra bak ne hale[ENTER]d\252\254t\252m...ve mahvoldum. "
gameforge.ghost_story._080_npcChat = "Oran\253n hik\226yesini biliyor musun? "
gameforge.ghost_story._090_say = "Ah evet, o zamanlar ne oldu\240unu biliyorum. Asl\253n\253[ENTER]\246\240renip o ma\240ray\253 bulabilmek i\231in hayattayken[ENTER]uzun uzun ara\254t\253rd\253m. \214ld\252kten sonra da d\252\254\252n\252p[ENTER]ta\254\253nmak i\231in epey zaman\253m vard\253. Hadi ne[ENTER]\246\240renmek istedi\240ini s\246yle bana! "
gameforge.ghost_story._100_npcChat = "Bu ne kap\253s\253? "
gameforge.ghost_story._110_say = "Bu ge\231itten, \254ehit d\252\254en Tanr\253 Beran-Setaou olan[ENTER]Karanl\253k Ejderha'n\253n odas\253na gidiliyor. Ge\231it,[ENTER]sadace Beran-Setaous birli\240i liderlerine verilen[ENTER]sihirli bir anahtar ile a\231\253l\253yor.. "
gameforge.ghost_story._120_npcChat = "\220\231 Tanr\253 "
gameforge.ghost_story._130_say = "\220\231 Tanr\253 bir zamanlar k\226inat\253n temellerini[ENTER]yaratt\253.[ENTER]\220\231 karde\254in en k\252\231\252\240\252 ise Yarat\253l\253\254 Tanr\253\231as\253[ENTER]Bahar-Taraji'ydi. Onun g\246revi yeniden yaratmakt\253,[ENTER]nereye gitse \231i\231ekler filizleniyor ve hayat[ENTER]ye\254eriyordu. "
gameforge.ghost_story._140_say = "En b\252y\252k abilerinin ad\253 Beran-Setaou'ydu. Onun[ENTER]g\246revi, son vermek ve \246ld\252rmekti. Ne zaman bir[ENTER]\246m\252r bitse, bedeni ruhunda ay\253r\253p ruhun \246b\252r[ENTER]d\252nyaya gitmesini sa\240lard\253.[ENTER]Var olma ve yok olma temeline dayal\253 bir hayat[ENTER]yarat\253lm\253\254 durumdayd\253. "
gameforge.ghost_story._150_say = "Ortanca abileri ise Baljit-Elvedin'di. Denge[ENTER]Tanr\253s\253 olarak karde\254lerine arabulucuk yap\253p[ENTER]d\252nyada ya\254ayan varl\253klar\253na ebedi bir hayat[ENTER]ak\253\254\253 sa\240lad\253.[ENTER]\214rne\240in mevsimlerin gelip gitmesi onun g\246rev[ENTER]alan\253yd\253. "
gameforge.ghost_story._160_npcChat = "\221htilaf "
gameforge.ghost_story._170_say = "\221nsanlar bu \252\231 tanr\253ya dua ederdi ve s\253k\253nt\253l\253[ENTER]zamanlar\253nda onlardan yalvararak yard\253m isterdi.[ENTER]Dar g\246r\252\254l\252 olduklar\253ndan, yarat\253l\253\254 ile birlikte[ENTER]onun da, aynen ayd\253nl\253k ve g\246lge gibi, olmas\253[ENTER]gerekti\240ini anlamad\253klar\253 i\231in sadece[ENTER]Beran-Setaou'dan hem korkarlard\253 hem nefret[ENTER]ederlerdi. "
gameforge.ghost_story._180_say = "Uzun bir s\252re Tanr\253 bunu g\246rmemezlikten geldi ama[ENTER]y\253llar ge\231tik\231e i\231indeki k\253skan\231l\253k yava\254 yava\254[ENTER]nefrete ve hasete d\246n\252\254t\252. \221nsanlara sava\254 ve[ENTER]hastal\253k vererek ilk \246nce ac\253s\253n\253 onlardan[ENTER]\231\253kard\253. Buna ra\240men ona kar\254\253 olan tepkileri[ENTER]daha da artt\253\240\253 i\231in yeni ye\254eren hayat Tanr\253\231as\253[ENTER]olan Bahar-Taraji'ye daha fazla dua etmeye[ENTER]ba\254lad\253lar. Ortaya \231\253kan bu k\253s\253r d\246ng\252, fel\226kete[ENTER]yol a\231t\253. "
gameforge.ghost_story._190_say = "Tanr\253 o kadar hiddetlendiki kendini daha fazla[ENTER]tutamad\253 ve inan\253lmaz bir\254ey yapt\253: \221nsanlar\253n en[ENTER]\231ok sevdi\240i k\253zkarde\254ini \246ld\252rd\252. Bu su\231u i\254lemek[ENTER]i\231in ne haz\253rl\253k ne de taktik gerekti, \231\252nk\252 o[ENTER]g\252n k\253zkarde\254i onun kar\254\253s\253na b\252t\252n masumiyet ve[ENTER]g\252veni ile \231\253kt\253. Onun o sevecen g\246zlerinin i\231ine[ENTER]baka baka hayat\253na son veren darbeyi indirdi. "
gameforge.ghost_story._200_npcChat = "Sonu\231 "
gameforge.ghost_story._210_say = "Tanr\253lar ve insanlar i\231in Bahar-Taraji'nin \246l\252m\252[ENTER]pahal\253ya mal olacakt\253. Uzun y\253llar s\252ren ac\253mas\253z[ENTER]bir k\253\254 geldi, karada ve suda ya\254ayan bir\231ok[ENTER]mahl\251ku \246ld\252rd\252. D\252nya so\240uktan o kadar donduki[ENTER]ta\254lar \231atlad\253 ve en sa\240lam ve ya\254l\253 a\240a\231lar bile[ENTER]\246ld\252. "
gameforge.ghost_story._220_say = "Hayat\253n\253n bahar\253nda olan insanlar ve hayvanlar[ENTER]\246ld\252. Nihayet s\253cak olmaya ba\254lay\253nca yeni[ENTER]do\240anlar\253n say\253s\253 \246ncekinden \231ok daha d\252\254\252kt\252.[ENTER]Zay\253f d\252\254\252r\252len \252lkede, yeti\254kinleri besleyecek[ENTER]hi\231 bir\254ey kalmam\253\254t\253ki \231ocuk yapmaya d\252\254\252n\252ls\252n.[ENTER]Hayat bitince umutlarda t\252kendi ve yeniden[ENTER]canlanmalar\253 epey zaman ald\253. "
gameforge.ghost_story._230_say = "\221nsanlar\253n saati h\253zl\253 ge\231iyordu ama buna ra\240men,[ENTER]zaman\253 yava\254 ilerleyen Tanr\253lar da ac\253 \231ekiyordu.[ENTER]Ne yapt\253\240\253n\253n fark\253na var\253nca Beran-Setaou[ENTER]inzivaya \231ekilmek istedi. \221\231indeki ac\253 pi\254manl\253k[ENTER]ve derin tatmin duygusuyla sava\254\253rken sonuncusu[ENTER]kazand\253. Kalbi tamamen kat\253la\254t\253 ve \214l\252m[ENTER]Tanr\253s'ndan buz ve so\240ukluk, nefret ve korku[ENTER]veren Tanr\253 oldu. "
gameforge.ghost_story._240_npcChat = "Sava\254 "
gameforge.ghost_story._250_say = "Koruma Tanr\253s\253 Baljit-Elvedin, k\253zkarde\254i i\231in[ENTER]uzun s\252re yas tuttu. \221\231ini \246r\252mcek gibi saran[ENTER]ac\253s\253 biraz hafifleyince erkek karde\254ini aramak[ENTER]i\231in yola \231\253kt\253. Hal\226 ihtiyatl\253 ve ak\253ll\253 olu\254u[ENTER]\252z\252nt\252l\252 halinde bile \254u anki dengesizlikte ya\254am[ENTER]\254ans\253 kalmad\253\240\253n\253 anlamas\253na yard\253mc\253 oldu. "
gameforge.ghost_story._260_say = "Erkek karde\254inin izlerini takip ederek onu y\253llar[ENTER]sonra nihayet ya\254amdan uzak buz, nefret ve[ENTER]yaln\253zl\253kla dolu bir ma\240arada buldu.[ENTER]Baljit-Elvedin, kalbine bir yara daha a\231t\253\240\253[ENTER]halde yapmas\253 gerekeni yapt\253. Karde\254ine sava\254[ENTER]ilan etti. Karde\254i zaten o kadar yoldan[ENTER]\231\253km\253\254t\253ki bir an bile teredd\252t etmedi... "
gameforge.ghost_story._270_say = "\199ok korkun\231 bir sava\254 oldu\240u s\246ylendi, hayal bile[ENTER]edilemeyecek kadar korkun\231. Galip gelen[ENTER]Baljit-Elvedin'di. Ahl\226k\253na sad\253k kalarak[ENTER]karde\254ini \246ld\252rmedi ama elinden b\252t\252n g\252c\252n\252[ENTER]alarak onu o ma\240araya hapsetti. Beran-Setaou,[ENTER]as\253rlar boyunca ya\254ad\253\240\253 ma\240arada yaratt\253\240\253[ENTER]mahl\251katlarla birlikte \246mr\252n\252 ge\231irirdi... "
gameforge.ghost_story._280_npcChat = "Bu anlatt\253klar\253n bana yeter. "
gameforge.ghost_story._290_say = "Senin kaderin benimkine benzemesin. Sana bol[ENTER]\254anslar diliyorum! "
gameforge.ghost_story._300_sayTitle = "Bir sava\254\231\253n\253n ruhu: "
gameforge.ghost_story._310_npcChat = "Sen neden \254effafs\253n? "
gameforge.ghost_story._320_say = "Tahmin et bakal\253m?! Bin y\253ldan beri bu kayaya[ENTER]hapsedilen bir ruhum... "
gameforge.ghost_story._330_say = "\221mdat, ruh var! "
gameforge.ghost_story._340_say = "Evet, ruh. \199abuk ka\231 yoksa yerim seni! "
gameforge.ghost_story._350_npcChat = "Sen kimsin? "
gameforge.ghost_story._360_say = "Bir zamanlar maa\254l\253 bir askerdim, s\253radan bir[ENTER]adamd\253m.[ENTER]Annem ve babam \231ift\231iydi. \214mr\252m boyunca ayn\253[ENTER]tarlay\253 s\252rmek istemedi\240im i\231in askere gittim.[ENTER]\199ok a\240\253r ve kan d\246k\252len bir i\254ti ama fena bir[ENTER]zaman ge\231irmedim. Birg\252n i\254e yaramaz[ENTER]asilzadelerin emirleri alt\253nda olmaktan b\253kt\253m ve[ENTER]askerden ka\231t\253m. Aptalca bir tesad\252f y\252z\252nden[ENTER]\254imdi bu karanl\253k yerdeyim. "
gameforge.ghost_story._370_npcChat = "Ma\240aran\253n hik\226yesini biliyor musun? "
gameforge.ghost_story._380_say = "Hay\253r, hi\231 bir\254ey bilmiyorum. Sadece i\254im ters[ENTER]gitti. Askerden ka\231\253nca da\240larda saklanmak[ENTER]istedim ve bu ma\240aray\253 buldum.[ENTER]Ba\254tan beri hi\231 i\254ime sinmedi ama yer olarak hem[ENTER]uygun hem bombo\254 g\246r\252n\252yordu. Birka\231 g\252n sonra[ENTER]inan\253lmaz bir sava\254a \254ahit oldum ve ma\240dur duruma[ENTER]d\252\254t\252m. \221stersen olay\253 sana anlatabilirim. "
gameforge.ghost_story._390_npcChat = "Sava\254\253n Ba\254lang\253c\253 "
gameforge.ghost_story._400_say = "G\252nlerden birg\252n da\240\253n yama\231lar\253ndan k\246k[ENTER]toplarken habersizce g\246ky\252z\252nden g\252m\252\254 bir[ENTER]ejderha indi. Tamam, benim i\254im bitti diye[ENTER]d\252\254\252nd\252m ama beni g\246rmedi bile. Onun g\246zleri[ENTER]ma\240aran\253n giri\254indeydi. H\253z\253n\253 azaltmadan vadiye[ENTER]d\246nd\252 ve ma\240aran\253n i\231ine dald\253. "
gameforge.ghost_story._410_say = "Bir s\252re ortal\253k sessizdi ve ne yapaca\240\253m\253[ENTER]bilemedim. Z\253rh\253m her\254eyim ma\240aradayd\253, bir[ENTER]ejderha ile de kesinlikle kar\254\253 kar\254\253ya gelmek[ENTER]istemedim! Bu s\253rada yer \231alkaland\253 ve da\240\253n[ENTER]derinliklerinden bo\240uk bir hayk\253rma sesi duyuldu-[ENTER]bu bir de\240il iki tane hayk\253rma sesiydi! Hemen[ENTER]sonra ma\240aradan iki tane ejderha f\253rlad\253, ilk[ENTER]\246nce g\252m\252\254 olan\253, onun arkas\253ndan da mavi olan\253. "
gameforge.ghost_story._420_say = "\221ki ejderha aras\253nda tarif edemeyece\240im bir sava\254[ENTER]ba\254lad\253. Birbirlerinin kanatlar\253n\253 kopard\253lar,[ENTER]\231arp\253\254t\253lar ve her biri uzun di\254lerini birbiri[ENTER]bo\240az\253na ge\231irdi...Kan ya\240\253yordu...Hi\231biri bir an[ENTER]bile durmad\253. "
gameforge.ghost_story._430_npcChat = "Sava\254\253n Sonu "
gameforge.ghost_story._440_say = "\221ki ejderha da\240da f\253rt\253na gibi estiler ve da\240\253n[ENTER]tepesini kopard\253lar. Mavi ejderhan\253n burnunu[ENTER]\254im\254ek yakt\253, g\252m\252\254 ejderhan\253n kanatlar\253n\253 da buz[ENTER]ya\240muru deldi. Y\253llard\253r d\252nyay\253 kaplayan buz[ENTER]kabu\240u bu sald\253r\253 kar\254\253s\253nda eridi ve ard\253ndan[ENTER]\231amur lekeleri kald\253. Ve ben orda bir kayan\253n[ENTER]arkas\253na sinmi\254im, korkudan kaskat\253 olmu\254[ENTER]vaziyetteyim, yine de birt\252rl\252 g\246z\252m\252 alam\253yorum. "
gameforge.ghost_story._450_say = "Saatler sonra ancak g\252\231leri t\252kenmeye ba\254lad\253 ki[ENTER]f\253rsat bu f\253rat deyip, g\246zlerimi g\252\231l\252kle ordan[ENTER]ay\253r\253p ma\240aradan z\253rh\253m\253 almak i\231in vadiye do\240ru[ENTER]ko\254maya ba\254lad\253m. Bu da benim kaderimi \231izdi.[ENTER]Ben geri d\246nerken iki ejderha, da\240dan a\254a\240\253ya[ENTER]u\231maya ba\254lad\253. Mavisi \246ndeydi ve \231ok a\240\253r[ENTER]yaral\253yd\253. "
gameforge.ghost_story._460_say = "Ma\240ar\253n\253n i\231ine ka\231t\253ktan hemen sonra g\252m\252\254[ENTER]ejderha ona yeti\254ti ve \231ok garip bir\254ey oldu:[ENTER]Ortal\253k yan\253p s\246nd\252, \254iddetli bir r\252zgardan sonra[ENTER]bir enerji hortumu olu\254tu. Mavi ejderha bu[ENTER]hortumun i\231inde tutuklu kald\253, a\240r\253dan ve[ENTER]sinirden ba\240\253r\253yordu...Mavi ejderha k\252\231\252ld\252,[ENTER]ba\240\253r\253\254 sesi azald\253, pullar\253 da s\246nmeye ba\254lad\253,[ENTER]matla\254t\253 ve renksizle\254ti... "
gameforge.ghost_story._470_say = "Sonunda g\252m\252\254 ejderha di\240erini ma\240arada serbest[ENTER]b\253rakt\253. Ma\240lup olan ejderha son g\252c\252yle zar zor[ENTER]da\240\253n alt\253ndaki karanl\253\240a s\253\240\253nd\253. G\252m\252\254 ejderha,[ENTER]ma\240aray\253 enerji bariyeri ile kilitleyen ve da\240\253n[ENTER]bir k\253sm\253n\253 \231\246kerten \254iddetli bir b\252y\252 f\253rt\253nas\253[ENTER]kopard\253. Karanl\253k ejderha ile ben orda tutuklu[ENTER]kald\253k. Ac\253 bir \254ekilde a\231l\253ktan \246lmeye mahk\251m... "
gameforge.ghost_story._480_npcChat = "Bu anlatt\253klar\253n bana yeter. "
gameforge.ghost_story._490_say = "Dinledi\240in i\231in te\254ekk\252r ederim. Son bin y\253ld\253r[ENTER]yaln\253zd\253m... "
gameforge.goldbar = {}
gameforge.goldbar._100_say = "Ben Siyah R\252zgar Grubu'ndan ka\231madan \246nce,[ENTER]onlar\253n alt\253nlar\253n\253 gizledikleri yeri buldum. Bir[ENTER]y\253\240\253n k\252l\231e alt\253nlar\253 var! Bu alt\253nlar kaybolursa[ENTER]bulamazlar. Onlar aptal. Anla\254t\253ysak, birlikte[ENTER]\231al\253\254al\253m, Ben gider ve alt\253n k\252l\231elerini al\253r\253m,[ENTER]ama, bir seferde daha fazla alt\253n k\252l\231esi[ENTER]alamam.. "
gameforge.goldbar._104_say = "Zaman "
gameforge.goldbar._108_say = "dakika "
gameforge.goldbar._10_npcChat = "Siyah R\252zgar \199etesinin bir kurban\253 "
gameforge.goldbar._110_say = "Yakla\254\253k olarak %s %s, alt\253n k\252l\231esi ta\254\253nacak. "
gameforge.goldbar._120_say = "\221lgileniyorsan soyle. "
gameforge.goldbar._130_say = "Ger\231ekten mi? Anla\254t\253k m\253?[ENTER]Sadece bana s\246ylemen yeterli, gidip sana bir tane[ENTER]getiririm! "
gameforge.goldbar._140_npcChat = "Bir alt\253n k\252l\231e almak istiyorum. "
gameforge.goldbar._150_say = "Sen neyden bahsediyorsun? D\252\254\252nceni bilmiyorum. "
gameforge.goldbar._160_say = "Ne? Alt\253n k\252l\231elerini sat\253n almak m\253 istiyorsun?[ENTER]Hay\253r, \254imdi de\240il! Siyah R\252zgar Grubu[ENTER]Sava\254\231\253lar\253 g\246z a\231t\253rm\253yorlar. E\240er yeterince[ENTER]dikkatli olmazsam, \231ok tehlikeli... Ortal\253k[ENTER]sakinle\254ince, tekrar deneyece\240im.. "
gameforge.goldbar._170_sayReward = "Hen\252z alt\253n k\252l\231esi sat\253n alamazs\253n. "
gameforge.goldbar._180_say = "Hen\252z alt\253n k\252l\231e alamad\253m. "
gameforge.goldbar._190_say = "%s %s dakika daha beklemeliyiz. "
gameforge.goldbar._200_say = "Yan\253mda bir alt\253n k\252l\231esi getirdim.[ENTER]De\240eri 2,2 milyon Yang. 200.000 Yang benim[ENTER]\252cretim.[ENTER]Ne d\252\254\252n\252yorsun? Onu alacak m\253s\253n? "
gameforge.goldbar._20_sayTitle = "Hain Balso: "
gameforge.goldbar._210_say = "\221\254te alt\253n k\252l\231en! Ak\253ll\253ca bir karar verdin.[ENTER]Yat\253r\253m yapmak her zaman iyi bir fikirdir. "
gameforge.goldbar._220_say = "\220creti 2,2 milyon Yang.[ENTER]Yeterince Yang'\253n\253z yok! "
gameforge.goldbar._230_say = "Madem almayacakt\253n, burada ne i\254in var? Bir s\252r\252[ENTER]vaktimi \231ald\253n. "
gameforge.goldbar._240_npcChat = "GM: Alt\253n K\252l\231esi sat\253\254 s\252resi yeniden ba\254lat\253l\253yor. "
gameforge.goldbar._250_say = "K\252l\231e Alt\253n sat\253\254 s\252resi yeniden ba\254lat\253ld\253. "
gameforge.goldbar._260_npcChat = "Alt\253n k\252l\231e sat "
gameforge.goldbar._270_say = "Sen neyden bahsediyorsun? D\252\254\252nceni bilmiyorum. "
gameforge.goldbar._280_say = "Ne? Bir alt\253n k\252l\231esi mi satmak istiyorsun?[ENTER]Duymad\253n m\253? Siyah R\252zgur Grubu Sava\254\231\253lar\253 \254u[ENTER]ara g\246z a\231t\253rm\253yorlar. E\240er bir alt\253n k\252l\231esi[ENTER]satarsan, fazla uzun ya\254ayamazs\253n.[ENTER]En g\252zeli, ondan uzak durmak. Onu g\252zelce sakla! "
gameforge.goldbar._290_sayReward = "\222u anda alt\253n k\252l\231esi satamazs\253n. "
gameforge.goldbar._300_say = "E\240er alt\253n k\252l\231esini geri getirmek istiyorsan, "
gameforge.goldbar._30_say = "Ne? Siyah R\252zgar Grubu'nun Kurban\253 m\253ym\253\254? Ha,[ENTER]ha, ha! Sen hala \231ocuksun. Bunu nereden duydun?[ENTER]Git ve yabani k\246peklerle oyna! "
gameforge.goldbar._310_say = "%s %s kadar daha beklemelisin. "
