gameforge.guild_building_npc._10_sayTitle = "Silah Ustas\253: "
gameforge.guild_building_npc._20_say = "Ah, benim loncam\253n \252yesisin! E\240er silah\253n\253[ENTER]geli\254tirmek istiyorsan onu bana ver, k\246ydeki[ENTER]acemilere de\240il. Benim ba\254ar\253 \254ans\253m %10 fazlad\253r[ENTER]ve bizim \252yelerimiz fiyatlarda %5 indirimden[ENTER]faydalan\253rlar. \222imdi bana geli\254tirmek istedi\240in[ENTER]silah\253 ver de \231al\253\254maya ba\254layay\253m. "
gameforge.guild_building_npc._30_say = "Benim ad\253m Stanley. Ben silah geli\254tirme[ENTER]sorumlusuyum ve bu i\254i k\246ydeki demirci ustas\253ndan[ENTER]daha iyi yapar\253m! Bana geldi\240in zaman[ENTER]geli\254tirmedeki ba\254ar\253 \254ans\253n %10 daha fazla olur.[ENTER]\222imdi bana geli\254tirmek istedi\240in silah\253 ver. "
gameforge.guild_building_npc._40_sayTitle = "Z\253rh Ustas\253: "
gameforge.guild_building_npc._50_say = "Sen benim loncam\253n \252yesiymi\254sin! Bana geli\254tirmem[ENTER]i\231in z\253rh\253n\253, kalkan\253n\253, ayakkab\253lar\253n\253 ve[ENTER]kask\253n\253 verebilirsin. Ba\254ar\253 \254ans\253m k\246ydeki[ENTER]demirciden %10 daha fazlad\253r. Ayr\253ca bizim[ENTER]\252yelerimiz fiyatlarda %5 indirimden[ENTER]faydalan\253rlar. Geli\254tirmek istedi\240in ekipman\253[ENTER]bana vermen yeterli. "
gameforge.guild_building_npc._60_say = "Ben Stanton. Ben z\253rh geli\254tirme sorumlusuyum.[ENTER]K\246ydeki demirciden daha yetenekliyim: ba\254ar\253[ENTER]\254ans\253m %10 daha fazla. \222imdi bana geli\254tirmek[ENTER]istedi\240in nesneyi ver. "
gameforge.guild_building_npc._70_sayTitle = "Kuyumcu: "
gameforge.guild_building_npc._80_say = "G\246r\252n\252\254e g\246re sen bizim loncadans\253n. Bu sana %10[ENTER]ba\254ar\253 \254ans\253 kazand\253r\253r. Yan\253s\253ra bizim[ENTER]\252yelerimize %5 fiyat indirimimiz olur. Ho\254geldin[ENTER]evlat! Ben bilezikleri, k\252peleri ve ayakkab\253lar\253[ENTER]geli\254tirebilirim. \222imid bana geli\254tirmek[ENTER]istedi\240in aksesuar\253 ver. "
gameforge.guild_building_npc._90_say = "Ad\253m Starbuck. Ben aksesuarlar\253 geli\254tirmekten[ENTER]sorumluyum. \214zel mineral, metal ve t\252ccarlarla[ENTER]\231al\253\254\253yorum, haliyle kaliteli oluyor. K\246ydeki[ENTER]demircilerden bu konuda daha iyiyimdir. E\240er[ENTER]onlar yerine bana gelirsen, ba\254ar\253 \254ans\253n %10[ENTER]artacakt\253r. Ben bilezikleri, k\252peleri ve[ENTER]ayakkab\253lar\253 geli\254tiririm. \222imdi bana geli\254tirmek[ENTER]istedi\240in aksesuar\253 ver. "
