gameforge.locale.bookworm.aranyeo_complete_say = "Aranyo: Ne t\252r bir aptal bu tuhaf kitab\253 benim[ENTER]kocama getirir?[ENTER]B\252t\252n g\252n \254ak\253yor, garip garip \254iirler \246\240reniyor[ENTER]kitaptan. Parma\240\253n\253 bile kald\253rm\253yor art\253k.[ENTER]E\240er onu yakalarsam b\252t\252n kemiklerini tek tek[ENTER]k\253raca\240\253m! "
