gameforge.locale.bookworm.aranyeo_start_say = "Aranyo: Nereye gitti o? O \231ok sinirlerimi[ENTER]bozuyor! B\252t\252n g\252nlerini kitap okuyarak[ENTER]mahvediyor, hi\231 Yang kazanm\253yor! \199ocuklar\253n[ENTER]yan\253nda bari utansa biraz! "
