gameforge.locale.forked_enter = "Kat\253l "
gameforge.locale.forked_kill_boss = "Ahhhh! Sizi ahmaklar! Ben Thor Sarch! Daha[ENTER]ac\253mas\253z olarak geri gelece\240im! Ben Thor Sarch,[ENTER]ve ben \246lmem![ENTER][ENTER]\221mparatorluk sava\254\253n\253 bitirdin. Herkes \254imdi[ENTER]\254ehre transfer edilecek. "
gameforge.locale.forked_man_chat = "\221mparatorluk Sava\254\253na kat\253l "
gameforge.locale.forked_man_say = "Sava\254 y\246neticisi[ENTER]Hm.. Yeni b\246lge ke\254fedildi. Bu b\246lge t\252m[ENTER]krall\253klara ba\240lan\253yor. Canavarlarla kayn\253yor;[ENTER]krall\253k bu hususta senin yard\253m\253na ihtiya\231[ENTER]duymakta. Oraya gidebilir misin? T\252m d\252\254manlar\253[ENTER]yok et ve krall\253\240a huzur getir. "
gameforge.locale.forked_man_say_cant = "Hey! Yeni b\246lge ke\254fedildi. Bu b\246lge t\252m[ENTER]krall\253klara yollar i\231eriyor. Ara\254t\253rma en k\253sa[ENTER]zamanda tamamlanacak, b\246lgeye girebilirsin. "
gameforge.locale.forked_no_enter = "Kat\253lma "
gameforge.locale.forked_open_gate = "\222imdiye kadar kapal\253 olan bu kap\253 art\253k a\231\253ld\253.[ENTER]Hadi kutsal topraklara girelim! Onlar\253[ENTER]ku\254ataca\240\253z![ENTER]K\253sa bir s\252re i\231inde herkes kutsal topraklara[ENTER]transfer edilecek. "
gameforge.locale.forked_rule = "\221mparatorluk sava\254\253na kat\253lma kurallar\253:[ENTER]1. Burada \246len herkes \254ehre tekrar transfer[ENTER]edilir ama Sav\254 Sorumlusu onlar\253 hemen buraya[ENTER]geri g\246nderebilir.[ENTER]2. Bir defa kap\253lar a\231\253ld\253 m\253, bu b\246lge kapat\253l\253r.3. Kutsal topraklara girebilmek i\231in uyumlu[ENTER]anahtar\253n bulunmas\253 gerekir. "
gameforge.locale.forked_rule_sungzi = "Sava\254 kurallar\253:[ENTER]1. Di\240er krall\253klara kar\254\253 en az zafer kazanan[ENTER]kral\253klar \246nce elenir.[ENTER]2. Canavarlar g\246r\252nmeye ba\254layacak. Belli say\253da[ENTER]canavar\253 ilk \246ld\252ren krall\253k kazan\253r.[ENTER]3. Bundan sonra e\240er dokuz kuyruk \246ld\252r\252l\252rse,[ENTER]sava\254 biter.[ENTER]4. Sava\254 s\253ras\253nda hi\231bir e\254ya al\253namaz.[ENTER]5. Kim burada 3 kere \246l\252rse, \254ehrine \253\254\253nlan\253r ve[ENTER]Krall\253k Sava\254\253ndan elenir. "
gameforge.locale.fortune_words_1_body = "Kader senin y\252z\252ne g\252l\252ms\252yor! Enerjinin v\252cuduna[ENTER]ak\253\254\253n\253 hisset! Bug\252n \231ok \254ansl\253 g\252n\252ndesin![ENTER]Bu kadar uyum sayesinde bug\252n \231ok g\252zel \254eyler[ENTER]ya\254anacak! "
gameforge.locale.fortune_words_1_title = "\199ok \254ansl\253! "
gameforge.locale.fortune_words_2_body = "Bu iyi. Ne demi\254ler? Ne ekersen onu bi\231ersin.[ENTER]Bug\252n pek \254ansl\253 g\252n\252ndesin! Senin ad\253na[ENTER]sevindim. Bug\252n biraz \231abayla bile daha fazla[ENTER]\254eyler kazanacaks\253n! "
gameforge.locale.fortune_words_2_title = "Pek \254ansl\253! "
gameforge.locale.fortune_words_3_body = "Bu fena de\240il. Bug\252n biraz \254ansl\253 g\252n\252ndesin.[ENTER]G\252n\252n normalden biraz daha iyi ge\231ecek ama \231ok[ENTER]b\252y\252k \254eyler bekleme! "
gameforge.locale.fortune_words_3_title = "Biraz \254ansl\253. "
gameforge.locale.fortune_words_4_body = "\221yi bir\254ey yok, ancak k\246t\252 bir\254ey de yok! Bug\252n[ENTER]normal \254ansl\253 g\252n\252desin. Bir \254ey kazanaca\240\253n[ENTER]s\246ylenemez ama bu talihsiz olmaktan daha iyidir.[ENTER]Normal g\252nler k\252\231\252msenemez, git ve keyfini \231\253kar! "
gameforge.locale.fortune_words_4_title = "Normal \254ansl\253. "
gameforge.locale.fortune_words_5_body = "Bug\252n \254ansl\253 g\252n\252nde de\240ilsin. Bug\252n her zamanki[ENTER]gibi a\240\253n\253 hesapl\253 bir \254ekilde atsan da \231ok bal\253k[ENTER]tutamayacaks\253n. Di\240er taraftan \231ok da fazla a\231l\253k[ENTER]\231ekmeyeceksin. Bug\252n sadece birazc\253k \254anss\253z[ENTER]g\252n\252ndesin o kadar! Ama haz\253rl\253kl\253 olmanda fayda[ENTER]var. E\240er dilersen sana bir t\253ls\253m satabilirim.[ENTER]Bu senin k\246t\252 \254ans\253n\253 d\246nd\252r\252r. Bir t\253ls\253m ister[ENTER]misin? "
gameforge.locale.fortune_words_5_title = "Birazc\253k \254anss\253z. "
gameforge.locale.fortune_words_6_body = "Bug\252n berbat bir g\252n. Bug\252n elinden gelenin en[ENTER]iyisini bile yapsan hi\231bir \254ey kazanamazs\253n.[ENTER]Bug\252n \254anss\253z g\252n\252ndesin ve nerede olursan ol,[ENTER]ne yaparsan yap, g\246z\252n kula\240\253n a\231\253k olmal\253.[ENTER]\221stersen yard\253mc\253 olmak i\231in sana bir t\253ls\253m[ENTER]satabilirim. T\253ls\253m k\246t\252 \254ans\253n\253 d\246nd\252r\252r. Bir[ENTER]t\253ls\253m ister misin? "
gameforge.locale.fortune_words_6_title = "\222anss\253z. "
gameforge.locale.fortune_words_7_body = "Bug\252n hayat\253ndaki en k\246t\252 g\252nlerden biri.[ENTER]Tanr\253lar sana arkas\253n\253 d\246nm\252\254. Bug\252n hi\231bir i\254in[ENTER]yolunda gitmeyecek. Ate\254 yakmak istesen, ya\240mur[ENTER]ya\240acak. Susasan, g\252ne\254 seni yakacak. Herkesten[ENTER]\231ok daha fazla \231al\253\254acaks\253n ama sana bir\254ey[ENTER]kazand\253rmayacak. Bug\252n inan\253lmaz \254anss\253z[ENTER]g\252n\252ndesin ve \231ekece\240in var! T\253ls\253m kullanmazsan[ENTER]zor bir g\252n ge\231irebilirsin. Sat\253n almak ister[ENTER]misin? "
gameforge.locale.fortune_words_7_title = "\221nan\253lmaz \254anss\253z. "
