gameforge.locale.monster_chat_1040_6 = "Evet! Sava\254, sava\254! (kahkaha) "
gameforge.locale.monster_chat_1041_1 = "Ahahahahahaha "
gameforge.locale.monster_chat_1041_2 = "Yeni bedenler gelmi\254. "
gameforge.locale.monster_chat_1041_3 = "Evet, \254imdi bu yeni bedenleri alma zaman\253. "
gameforge.locale.monster_chat_1041_4 = "Biz yeniden diriliriz. Biz \246l\252ml\252 de\240iliz! "
gameforge.locale.monster_chat_1041_5 = "Bize sald\253r\253labilecek bir yol yok! (kahkaha) "
gameforge.locale.monster_chat_1041_6 = "Ne alacaks\253n: T\252kenip gitmeyi mi yoksa \246lmeyi mi? "
gameforge.locale.monster_chat_1091_1 = "Kim benden daha h\253zl\253 u\231ar ve sald\253r\253 yapar? "
gameforge.locale.monster_chat_1091_2 = "Benim gibi olacaks\253n. "
gameforge.locale.monster_chat_1091_3 = "Benim gibi olmay\253 istemiyor musun? "
gameforge.locale.monster_chat_1091_4 = "Bedenin ve ruhun bana ait! (kahkaha) "
gameforge.locale.monster_chat_1091_5 = "T\252kendin mi? Dizlerin titriyor... "
gameforge.locale.monster_chat_1091_6 = "Daha ne kadar bu \254ekilde devam edebilirsin? (kahkaha) "
gameforge.locale.monster_chat_1093_1 = "Buraya gelenler i\231in \246l\252m daha iyi bir se\231enek de\240il midir? "
gameforge.locale.monster_chat_1093_2 = "Ho\254geldin. "
gameforge.locale.monster_chat_1093_3 = "Av ol. "
gameforge.locale.monster_chat_1093_4 = "Bedenin ve ruhunla ziyafet yapaca\240\253m! "
gameforge.locale.monster_chat_1093_5 = "Daha ne kadar dayanabilirsin? Ha? "
gameforge.locale.monster_chat_1093_6 = "\214l\252m arkandan g\252l\252ms\252yor. (kahkaha) "
gameforge.locale.monster_chat_11000_1 = "Kendi geli\254imleri i\231in endi\254elenen kim varsa dinlesin! "
gameforge.locale.monster_chat_11000_10 = "E\240er do\240an\253n ve \254im\254eklerin g\252c\252n\252 kontrol etmek istiyorsan\253z. \221yile\254tirme e\240itimini tavsiye ederim! "
gameforge.locale.monster_chat_11000_11 = "Her sava\254\231\253 farkl\253 bir yolla sava\254\253r! Bedenini g\252\231lendirmeye odaklan! "
gameforge.locale.monster_chat_11000_12 = "Sura, g\252c\252n\252 b\252y\252den al\253r. Zeka ve h\253z\253n\253 geli\254tir ama beden g\252c\252n\252 ihmal etme! "
gameforge.locale.monster_chat_11000_13 = "Ninjan\253n yeteneklerini kullan! H\253z ve beden g\252c\252ne \231al\253\254! "
gameforge.locale.monster_chat_11000_14 = "\222amanlar yenileme, destekleme ve uzak d\246v\252\254 b\252y\252s\252 kullan\253yor. Zekal\253 olmak laz\253m! "
gameforge.locale.monster_chat_11000_15 = "\199\253rakl\253\240\253n\253 unutma! "
gameforge.locale.monster_chat_11000_16 = "Yeteneklerini geli\254tirmek istiyorsan, bir e\240itim dal\253n\253n \231\253rakl\253\240\253na kat\253l! "
gameforge.locale.monster_chat_11000_17 = "Yetenekler? Yeteneklerinde rastgele olarak 17-21 seviyeler aras\253nda ustala\254abilirsin. "
gameforge.locale.monster_chat_11000_18 = "Grand Master g\252c\252ne eri\254mek ister misin? O zaman, \246zel beceri kitaplar\253na ihtiyac\253n var! "
gameforge.locale.monster_chat_11000_19 = "Beceri kitab\253n\253 bir defa oku\240unda, kitap yok olur! "
gameforge.locale.monster_chat_11000_2 = "5. seviyenin alt\253ndaki t\252m sava\254\231\253lar, beni dinleyin! "
gameforge.locale.monster_chat_11000_20 = "Bir beceri kitab\253 daha okumak ister misin? \214yleyse 1 g\252n bekle. "
gameforge.locale.monster_chat_11000_21 = "Sura yeteneklerini geli\254tirmek i\231in zekan\253 y\252kselt! "
gameforge.locale.monster_chat_11000_22 = "Suran\253n b\252y\252k g\252c\252n\252 sava\254tayken deneyimle! "
gameforge.locale.monster_chat_11000_23 = "Gizli mezhebin tap\253na\240\253 nerede biliyor musun? Seungryong vadisinin tam ortas\253nda! "
gameforge.locale.monster_chat_11000_24 = "\214r\252mcek ma\240aralar\253 tekrar g\246r\252nd\252! Yongbi \231\246l\252n\252n ortas\253ndalar! "
gameforge.locale.monster_chat_11000_25 = "G\246revleri bitir ve \246d\252lleri e\254yalar\253n\253 geli\254tirmek i\231in kullan! "
gameforge.locale.monster_chat_11000_26 = "Bal\253k\231\253l\253k m\253? Kula\240a harika geliyor. Bal\253k\231\253dan zaten bir olta ve kanca almam\253\254 m\253yd\253n? "
gameforge.locale.monster_chat_11000_27 = "Avlayacak daha g\252\231l\252 bir\254eyler mi ar\253yorsun? Kap\253y\253 bul. Oradan da seviyene uygun avlanma b\246lgesine git! "
gameforge.locale.monster_chat_11000_28 = "Di\240er krall\253klardan gelecek d\252\254manlara kar\254\253 haz\253rl\253kl\253 ol. Seni ne vakit arkandan vuracaklar\253n\253 kestiremezsin! "
gameforge.locale.monster_chat_11000_29 = "Yeteneklerini s\253f\253rlamay\253 m\253 d\252\254\252n\252yorsun? Ya\254l\253 kad\253na git. Yan\253nda yeterince Yang g\246t\252rd\252\240\252nden emin ol! "
gameforge.locale.monster_chat_11000_3 = "E\240er sald\253rgan bir sava\254\231\253 olmak istiyorsan, yak\253n d\246v\252\254 \246\240retmenine git ve e\240itim al. "
gameforge.locale.monster_chat_11000_30 = "Hedefin perfect master seviyesi olsun! Ger\231ek bir kahraman olabilmenin ba\254ka yolu yok! "
gameforge.locale.monster_chat_11000_31 = "E\240er ba\254ka bir cephe veya \254ehre gitmek istersen k\253tadaki ya\254l\253 adam\253 bul. "
gameforge.locale.monster_chat_11000_4 = "Sava\254\231\253 yeteneklerinde usta olmak istiyorsan, zihinsel sava\254 e\240itimlerine kat\253l! "
gameforge.locale.monster_chat_11000_5 = "E\240er b\252y\252l\252 k\253l\253\231lar kullanan bir Sura olmak istiyorsan, b\252y\252l\252 silah e\240itimine kat\253l! "
gameforge.locale.monster_chat_11000_6 = "Kara b\252y\252 \246\240renmek ve ustala\254mak istiyorsan, kara b\252y\252 e\240itimlerine kat\253l! "
gameforge.locale.monster_chat_11000_7 = "Uzak d\246v\252\254 e\240itimi seviye 5 ve \252st\252 ninjalarla dolu! "
gameforge.locale.monster_chat_11000_8 = "E\240er gizli bir ninja olacaksan, yak\253n d\246v\252\254 e\240itimlerine kat\253l. "
gameforge.locale.monster_chat_11000_9 = "E\240er sava\254lar\253 kontrol eden bir Ejderha Tanr\253 sava\254\231\253s\253 olacaksan, Ejderha g\252c\252 e\240itimini al! "
