gameforge.locale.monster_chat_11004_9 = "E\240er sava\254lar\253 y\246neten; Ejder Tanr\253n\253n bir sava\254\231\253s\253 olacaksan... Ejderha g\252c\252 e\240itimine kat\253l! "
gameforge.locale.monster_chat_1105_1 = "Donmu\254 hal iyi. "
gameforge.locale.monster_chat_1105_2 = "Sohan Da\240\253 kesinlikle en iyisi. "
gameforge.locale.monster_chat_1105_3 = "Hava ne g\252zel. "
gameforge.locale.monster_chat_1105_4 = "Ayn\253 benim gibi olacaks\253n. "
gameforge.locale.monster_chat_1105_5 = "Sonsuza dek ya\254ayabilirsin, en az\253ndan buzlar eriyene dek. "
gameforge.locale.monster_chat_1105_6 = "Buza d\246n\252\254men ne kadar s\252recek? "
gameforge.locale.monster_chat_1106_1 = "\221nsanlar...burada?! "
gameforge.locale.monster_chat_1106_2 = "Yorgun... ama senin i\231in yeterince uyan\253\240\253m... "
gameforge.locale.monster_chat_1106_3 = "Benim da\240\253mda, birisi mi var?  "
gameforge.locale.monster_chat_1106_4 = "Sen buraya ait de\240ilsin! "
gameforge.locale.monster_chat_1106_5 = "En iyisi geri d\246n! "
gameforge.locale.monster_chat_1106_6 = "Yabanc\253...hemde yaln\253z? "
gameforge.locale.monster_chat_1191_1 = "Bakal\253m yak\253\254\253kl\253 bir adam gelir mi. "
gameforge.locale.monster_chat_1191_2 = "\199ok so\240uk ve yaln\253z. Benim gelecekteki kocam nerede? "
gameforge.locale.monster_chat_1191_3 = "Onlarla biraz \231al\253\254abilir miyim? "
gameforge.locale.monster_chat_1191_4 = {}
gameforge.locale.monster_chat_1191_5 = "Bir\254eyler eksik. Ben soytar\253l\253k yapm\253yorum. "
gameforge.locale.monster_chat_1191_6 = "Hissedece\240in son ac\253y\253 da ben bitirece\240im! "
gameforge.locale.monster_chat_1301_1 = "Bir uzunboyun...! "
gameforge.locale.monster_chat_1301_2 = "Soluk benzin bir dakika i\231inde daha da solacak. "
gameforge.locale.monster_chat_1301_3 = "Bana meydan okumak m\253 istiyorsun? G\252zel! "
gameforge.locale.monster_chat_1301_4 = "Bana sald\253rd\253n! Pweck! Kurtulu\254una m\252saade edilmeyecek! "
gameforge.locale.monster_chat_1301_5 = "Zay\253f, zay\253f insan! "
gameforge.locale.monster_chat_1301_6 = "Hadi, ne kadar dayanabilece\240ini g\246relim! "
gameforge.locale.monster_chat_1302_1 = "Ka\231mak? Akl\253ndan bile ge\231irme. "
gameforge.locale.monster_chat_1302_2 = "Aferin... Yakla\254... Pwiehk! "
gameforge.locale.monster_chat_1302_3 = "Elimdeki k\253l\253\231, titriyor. Pweck! "
gameforge.locale.monster_chat_1302_4 = "Bu m\252cadeleden sa\240 \231\253kamayacaks\253n! "
gameforge.locale.monster_chat_1302_5 = "\221\254te k\253l\253c\253m geliyor! "
gameforge.locale.monster_chat_1302_6 = "Ac\253 verici, de\240il mi? (kahkaha) "
gameforge.locale.monster_chat_1303_1 = "Senin \252zerine bast\253\240\253n ot bile yanl\253\254l\253kla \246lm\252\254t\252r. "
gameforge.locale.monster_chat_1303_2 = "Otlara dikkat et. "
gameforge.locale.monster_chat_1303_3 = "Do\240ru. Yakla\254 bana. (kahkaha) "
gameforge.locale.monster_chat_1303_4 = "Seni korkak! Bana gel ki seni \246ld\252reyim! "
gameforge.locale.monster_chat_1303_5 = "\214l! \214l! "
gameforge.locale.monster_chat_1303_6 = "Geldi\240ine pi\254man m\253s\253n? "
gameforge.locale.monster_chat_1305_1 = "Kim beni yok edebilir? "
gameforge.locale.monster_chat_1305_2 = "Sen mi? Sava\254mak m\253 istiyorsun? "
gameforge.locale.monster_chat_1305_3 = "E\240er istiyorsan buraya gel! "
gameforge.locale.monster_chat_1305_4 = "Gel \254u i\254i do\240ru d\252r\252st yap! Ka\231ma! "
gameforge.locale.monster_chat_1305_5 = "K\253l\253c\253m nas\253l? "
gameforge.locale.monster_chat_1305_6 = "Korktun mu? (kahkaha) "
gameforge.locale.monster_chat_1901_1 = "Bug\252n kimi d\246n\252\254t\252rece\240im? "
gameforge.locale.monster_chat_1901_2 = "Ah, sevdim seni... "
gameforge.locale.monster_chat_1901_3 = "Nas\253ld\253? Benim sevgili e\240lencem... "
gameforge.locale.monster_chat_1901_4 = "Hey! \222u i\254i do\240ru yap ve korkak tavuklar gibi ka\231ma! "
gameforge.locale.monster_chat_1901_5 = "Zaten b\252y\252m\252n etkisindesin? Hmm? "
gameforge.locale.monster_chat_1901_6 = "Biraz \231\253\240l\253k atmak ister misin? (kahkaha) "
gameforge.locale.monster_chat_20001_1 = "Gergin g\246r\252n\252yorsun... Merak etme, hi\231bir\254ey patlamayacak. "
gameforge.locale.monster_chat_20001_2 = "Bazen, ben de gezinmek istiyorum. "
gameforge.locale.monster_chat_20001_3 = "Bu \231ok s\253k\253c\253. Torunlar\253m bile art\253k beni ziyaret etmiyor. "
gameforge.locale.monster_chat_20001_4 = "Ya\254land\253\240\253n zaman, ba\254ka insanlara ihtiya\231 duymaya ba\254l\253yorsun... "
gameforge.locale.monster_chat_20001_5 = "En g\252zel g\252nlerim gitti... "
gameforge.locale.monster_chat_20002_1 = "G\252ne\254 \231ok s\253cak. "
gameforge.locale.monster_chat_20002_2 = "Islak k\253yafetleri kurutmak i\231in harika bir g\252n, de\240il mi? "
gameforge.locale.monster_chat_20002_3 = "Kocam olacak i\254e yaramaz adam nerde? "
gameforge.locale.monster_chat_20002_4 = "Kendine baba diyor ve \231ocuklar\253n \246n\252nde bile k\246t\252 al\253\254kanl\253klar\253ndan utanm\253yor! "
gameforge.locale.monster_chat_20002_5 = "Kitap kitapt\253r. Hi\231 para kazanm\253yor. Sadece kitap okuyor. "
gameforge.locale.monster_chat_20003_1 = "Ooohh, dududu, bebek. \221yi uyudun mu? "
gameforge.locale.monster_chat_20003_2 = "K\252\231\252k bir melek gibi g\252l\252ms\252yorsun. "
gameforge.locale.monster_chat_20003_3 = "Sa\240l\253kl\253 oldu\240unda annen \231ok mutlu oluyor. "
gameforge.locale.monster_chat_20003_4 = "Yine mi ilgi istiyorsun? Karn\253n m\253 ac\253kt\253 bakal\253m? "
gameforge.locale.monster_chat_20003_5 = "\221yi \231ocuk... Uyu, g\252zel \231ocu\240um, uyu... "
gameforge.locale.monster_chat_20004_1 = "Sadece ba\254ka bir g\252n. "
gameforge.locale.monster_chat_20004_2 = "Bug\252n nereden yemek bulaca\240\253m? "
gameforge.locale.monster_chat_20004_3 = "Bu k\253l\253\231 sahipleri \231ok s\253k\253c\253. "
gameforge.locale.monster_chat_20004_4 = "Bakal\253m. Belki de Octavio'nun restorant\253na gitmeliyim. "
gameforge.locale.monster_chat_20004_5 = "Ah, haz\253r s\246ylemi\254ken, sava\254 san\253r\253m art\253k devam etmiyor.. "
gameforge.locale.monster_chat_20005_1 = "Usta \231\246mlek\231inin ruhu parmak u\231lar\253ndan ge\231iyor. "
gameforge.locale.monster_chat_20005_2 = "\220lke kaosa girdi\240inden beri, her yerde sava\254\231\253 bulmak m\252mk\252n. "
gameforge.locale.monster_chat_20005_3 = "Herkes sava\254mak istiyor. "
gameforge.locale.monster_chat_20005_4 = "Mutlu ve huzurlu bir d\252nya i\231in \231ok dua ediyorum. "
gameforge.locale.monster_chat_20005_5 = "Hey, orda m\253s\253n? Birka\231 dakika rahatla ve d\252\254\252n... "
gameforge.locale.monster_chat_20006_1 = "Off.. Ne yapmal\253y\253m? "
gameforge.locale.monster_chat_20006_2 = "Karde\254imden en ufak bir iz yok, ama burada olaca\240\253na s\246z vermi\254ti. "
gameforge.locale.monster_chat_20006_3 = "Ve \254imdi, burada g\246rd\252\240\252m b\252t\252n \254ey silahl\253 sava\254\231\253lar. "
gameforge.locale.monster_chat_20006_4 = "Karde\254imi \246zledim. "
gameforge.locale.monster_chat_20006_5 = "Karde\254imi g\246ren oldu mu? "
gameforge.locale.monster_chat_20007_1 = "Hm, bu ger\231ekten taze et! "
gameforge.locale.monster_chat_20007_2 = "Bu g\252zel, insanlar art\253k daha fazla et yiyebilecek. "
gameforge.locale.monster_chat_20007_3 = "Ticaret iyi i\254liyor, ama et hala nadiren bulunuyor. "
gameforge.locale.monster_chat_20007_4 = "Verdi\240imiz et sipari\254i ne zaman gelir? "
gameforge.locale.monster_chat_20007_5 = "E\240er zaman\253nda gelmezse, avlanmak zorunda kalaca\240\253z. "
gameforge.locale.monster_chat_20008_1 = "Umar\253m havalar g\252zelle\254ti\240inde m\252\254teriler \231o\240al\253r. "
gameforge.locale.monster_chat_20008_2 = "Yaramaz k\246pe\240im birazdan gelir ve yiyecek bir\254eyler ister. "
gameforge.locale.monster_chat_20008_3 = "Ah, ne fakir bir kom\254u! "
gameforge.locale.monster_chat_20008_4 = "O harika bir sava\254\231\253yd\253. "
gameforge.locale.monster_chat_20008_5 = "Neden art\253k sava\254mad\253\240\253n\253 merak ediyorum. "
gameforge.locale.monster_chat_20009_1 = "Gen\231ler... ne kadar canl\253 ve hayat dolular! "
gameforge.locale.monster_chat_20009_2 = "Sava\254\231\253lar, silah ta\254\253rken daha g\252zel g\246r\252n\252yorlar. "
gameforge.locale.monster_chat_20009_3 = "\222u g\252nlerde herkeste katil bir zihniyet mevcut. "
gameforge.locale.monster_chat_20009_4 = "Kalbini kontrol et, d\252\254\252ncelerine odaklan ve ruhunu sakinle\254tir. "
gameforge.locale.monster_chat_20009_5 = "Mutlulu\240un mutlak bir form\252l\252 yoktur ama ba\240l\253 kalman gereken baz\253 basit prensipler var. "
gameforge.locale.monster_chat_20010_1 = "Sana harika bir e\254ya ald\253m. "
gameforge.locale.monster_chat_20010_2 = "Uzak \252lkelerin mallar\253! G\252zel, ola\240an\252st\252 par\231alar! "
gameforge.locale.monster_chat_20010_3 = "Buraya gel! Herkes, buraya gelsin! "
gameforge.locale.monster_chat_20010_4 = "Gelin millet! Sat\253n al\253n! Bir daha \254ans\253n\253z olmayacak! "
gameforge.locale.monster_chat_20010_5 = "Puff! Neden \231ok fazla h\253rs\253z var burada? "
gameforge.locale.monster_chat_20011_1 = "Son g\252nlerde kurakl\253k var... "
gameforge.locale.monster_chat_20011_2 = "Hasat eskisi gibi iyi de\240il. "
gameforge.locale.monster_chat_20011_3 = "Neden art\253k tarlalar verimli de\240il? "
gameforge.locale.monster_chat_20011_4 = "Tah\253l k\253t\253r k\253t\253r ve tad\253 berbat. "
gameforge.locale.monster_chat_20011_5 = "Bu k\246t\252ye i\254aret. Tar\253mc\253l\253k bizim temel ya\254am kayna\240\253m\253z. "
gameforge.locale.monster_chat_20012_1 = "Ya\254 Pasta! \199ok lezzetli ya\254 pasta burada! "
gameforge.locale.monster_chat_20012_2 = "Ben pirin\231 pastas\253 sat\253yorum! "
gameforge.locale.monster_chat_20012_3 = "Evet, ticaret k\246t\252le\254ti \254u g\252nlerde! "
gameforge.locale.monster_chat_20012_4 = "Belki ba\254ka bir \254ehre gitmeliyim. "
gameforge.locale.monster_chat_20012_5 = "Fakat yolda \231ok fazla kaplan var. "
gameforge.locale.monster_chat_20013_1 = "B\246yle g\252nlerde bir sandal\253n i\231inde olmak ba\254a gelebilecek en g\252zel \254ey san\253r\253m. "
gameforge.locale.monster_chat_20013_2 = "Bal\253k tutmak i\231in harika bir hava var. "
gameforge.locale.monster_chat_20013_3 = "Bir d\252\240\252m daha... Tamam! Bu kancadan hi\231 bir bal\253k ka\231amaz! "
gameforge.locale.monster_chat_20013_4 = "Bu pis ay\253 benim oltam\253 k\253rd\253! "
gameforge.locale.monster_chat_20013_5 = "A\240lar\253m\253 tekrar tamir etmeliyim. "
gameforge.locale.monster_chat_20014_1 = "Ha?! "
gameforge.locale.monster_chat_20014_2 = "Benim i\231in endi\254elenme; ben b\246yleyim. "
gameforge.locale.monster_chat_20014_3 = "Haaaaa! "
gameforge.locale.monster_chat_20014_4 = "Ne yapabilirim ki, yani o... \221yi de, ben \254imdi ne dedim ki? "
gameforge.locale.monster_chat_20014_5 = "Art\253k eskisi gibi cesur de\240ilim. "
gameforge.locale.monster_chat_20015_1 = "Bu balta 20 senedir bana \231al\253\254\253r. "
gameforge.locale.monster_chat_20015_2 = "Hala keskin, ama san\253r\253m eskisi kadar iyi de\240il. "
gameforge.locale.monster_chat_20015_3 = "Onu kullanmak ve g\252\231lendirmek istiyorum. "
gameforge.locale.monster_chat_20015_4 = "Ama bunun i\231in tamamen mineralli ta\254lara ihtiyac\253m var. "
gameforge.locale.monster_chat_20015_5 = "Peki bu ta\254lar\253 nereden bulabilirim? "
gameforge.locale.monster_chat_20016_1 = "M\252\254teriler \231ok \231ok geliyorlar. "
gameforge.locale.monster_chat_20016_2 = "Umar\253m her \254eyi zaman\253nda bitirebilirim. "
gameforge.locale.monster_chat_20016_3 = "Darbe \252st\252ne darbe ve hi\231 \254ikayet yok... "
gameforge.locale.monster_chat_20016_4 = "\221\254te bir \231eki\231 b\246yle ses \231\253kartmal\253! "
gameforge.locale.monster_chat_20016_5 = "Buras\253 \231ok s\253cak. "
gameforge.locale.monster_chat_20017_1 = "Bir \231alg\253 \231al\253yormu\254 gibi hissetmiyorum. "
gameforge.locale.monster_chat_20017_2 = "Benim \231alg\253m ger\231ekten k\246t\252 durumda. "
gameforge.locale.monster_chat_20017_3 = "Belki de yeni bir enstr\252man almal\253y\253m? "
gameforge.locale.monster_chat_20017_4 = "Enstr\252man\253m eski ve y\253pranm\253\254... Eski \254eyleri severim! "
gameforge.locale.monster_chat_20017_5 = "Bu kopmu\254 telleri acilen de\240i\254tirmeliyim. "
gameforge.locale.monster_chat_20018_1 = "\199ok me\254gul\252m! "
gameforge.locale.monster_chat_20018_2 = "Her g\252n, yeni bir yaral\253 insan geliyor. "
gameforge.locale.monster_chat_20018_3 = "D\253\254ar\253 \231\253k\253p yeni insanlarla tan\253\254maya vakit yok! "
gameforge.locale.monster_chat_20018_4 = "Ve ila\231s\253z kal\253yoruz. "
gameforge.locale.monster_chat_20018_5 = "Ke\254ke bizim i\231in d\253\254ar\253 gidip ila\231 malzemeleri getirecek biri olsa. "
gameforge.locale.monster_chat_20019_1 = "30 y\253ld\253r, da\240larda yay\253mla avlan\253r\253m. "
gameforge.locale.monster_chat_20019_2 = "Bununla kar\253ma bakt\253m, 3 \231ocuk b\252y\252tt\252m. "
gameforge.locale.monster_chat_20019_3 = "Hayat zor ama buna de\240er. "
gameforge.locale.monster_chat_20019_4 = "Fakat \254imdi yay\253m\253n teli koptu ve art\253k avlanam\253yorum. Bu \254ekilde aileme bakamam. "
gameforge.locale.monster_chat_20019_5 = "E\240er okumu onaramazsam, emekli olaca\240\253m. Aileme art\253k bakam\253yorum. "
gameforge.locale.monster_chat_20020_1 = "Hey, sen neye bak\253yorsun? "
gameforge.locale.monster_chat_20020_2 = "Buradan uzak dur! "
gameforge.locale.monster_chat_20020_3 = "Ah, ne kadar s\252re daha saklamal\253y\253m. "
gameforge.locale.monster_chat_20020_4 = "Bir yerde unutularak \246lecek miyim? "
gameforge.locale.monster_chat_20020_5 = "Ah, umar\253m biri bana yard\253mc\253 olur... "
gameforge.locale.monster_chat_20021_1 = "Bug\252n de di\240er g\252nlerden farks\253z... "
gameforge.locale.monster_chat_20021_2 = "\222imdi ne yapaca\240\253m ha?! "
gameforge.locale.monster_chat_20021_3 = "Bunun b\246yle bitece\240ini hi\231 d\252\254\252nmemi\254tim. "
gameforge.locale.monster_chat_20021_4 = "Hay\253r! Bunu bitirecek tek ki\254i o olamaz! "
gameforge.locale.monster_chat_20021_5 = "Umar\253m intikam\253n\253 al\253r! "
gameforge.locale.monster_chat_20022_1 = "Harika bir ba\254ka g\252n. "
gameforge.locale.monster_chat_20022_2 = "Ariyoung'un kocas\253 kayboldu. "
gameforge.locale.monster_chat_20022_3 = "Yard\253m etmek istedim, ama \231ok inat\231\253... "
gameforge.locale.monster_chat_20022_4 = "E\240er benimle evlenseydi, s\253k\253c\253 hayat\253n\253 geride b\253rakt\253rabilirdim. "
gameforge.locale.monster_chat_20022_5 = "Belki ona duygular\253m\253 daha a\231\253k ifade etmeliyim. "
gameforge.locale.monster_chat_20023_1 = "Tanr\253m hay\253r! Kar\253m fark ederse ne yapar\253m? "
gameforge.locale.monster_chat_20023_2 = "Ke\254ke sadece kitap okuyarak ya\254ayabilsem! "
gameforge.locale.monster_chat_20023_3 = "Kitaplar \231ok gizemli. "
gameforge.locale.monster_chat_20023_4 = "Bu \254ekilde sonsuza dek s\252remez ki, ama... "
gameforge.locale.monster_chat_20023_5 = "Umar\253m e\254im i\231in bir\254ey yapabilirim, ama... "
gameforge.locale.monster_chat_20024_1 = "Hadi ama! Hareketlerine biraz duygusall\253k katmal\253s\253n! "
gameforge.locale.monster_chat_20024_2 = "Ne yap\253yorsun!? Biraz daha h\253zl\253 olamaz m\253s\253n? "
gameforge.locale.monster_chat_20024_3 = "K\253l\253c\253n\253 kald\253r\253p ayn\253 \254eyi yapan bir sava\254\231\253 hayal et! "
gameforge.locale.monster_chat_20024_4 = "Nerde bu aptal? Nerede \254imdi? "
gameforge.locale.monster_chat_20024_5 = "Korkak! Yeterince cesur de\240ilsin! Ha! "
gameforge.locale.monster_chat_2091_1 = "Kes, kes... sa\231lar\253, bo\240azlar\253.. "
gameforge.locale.monster_chat_2091_2 = "Senin i\231in bir \254eyim var: sonsuz uyku! "
gameforge.locale.monster_chat_2091_3 = "Derin bir nefes al. Merak etme, bu sadece zehir! "
gameforge.locale.monster_chat_2091_4 = "Sadece y\252z\252n\252 b\253rakaca\240\253m! G\252zel bir s\252s e\254yas\253 olacak... "
gameforge.locale.monster_chat_2091_5 = {}
gameforge.locale.monster_chat_2091_6 = "Seni ipek a\240\253mla kaplay\253p sonraki \246\240\252n i\231in saklayaca\240\253m... "
gameforge.locale.monster_chat_2092_1 = "Kar\253m\253n d\253rd\253r\253na katlanam\253yorum. "
gameforge.locale.monster_chat_2092_2 = "Neden uyuyam\253yorum? "
gameforge.locale.monster_chat_2092_3 = "Ah, g\246r\252n\252\254e g\246re birileri \246r\252mcek a\240\253na tak\253lm\253\254. "
gameforge.locale.monster_chat_2092_4 = "Ben bar\253\254 yanl\253s\253y\253m. Sadece rahats\253z edilmeyi sevmiyorum. "
gameforge.locale.monster_chat_2092_5 = "Eveett, hepsini ver! "
gameforge.locale.monster_chat_2092_6 = "Kimse boyumun \246l\231\252s\252n\252 alamaz! "
gameforge.locale.monster_chat_2104_1 = "\221nsanlar\253n i\231i neden bu kadar \253slak? Bu y\252zden k\253l\253c\253m paslan\253yor! "
gameforge.locale.monster_chat_2104_2 = "Kuyru\240undaki zehir kurudu mu? "
gameforge.locale.monster_chat_2104_3 = "Eee, nas\253l d\246v\252\254t\252? "
gameforge.locale.monster_chat_2104_4 = "S\253caktan bitkinle\254mi\254 gibisin? "
gameforge.locale.monster_chat_2104_5 = "\221nsanlar\253 \231\246lde b\253rakmay\253 seviyorum. "
gameforge.locale.monster_chat_2104_6 = "Seni zavall\253, \231\246le g\246m\252leceksin! "
gameforge.locale.monster_chat_2105_1 = "Sana bir s\253r verece\240im - ben pislikten nefret ederim! "
gameforge.locale.monster_chat_2105_2 = "\199ok s\253cak de\240il mi? "
gameforge.locale.monster_chat_2105_3 = "Buras\253 tehlikeli. "
gameforge.locale.monster_chat_2105_4 = {}
gameforge.locale.monster_chat_2105_5 = "G\246zlerinin ortas\253ndan vuraca\240\253m seni! "
gameforge.locale.monster_chat_2106_1 = "Bug\252n bir\254eyler ald\253n m\253? "
gameforge.locale.monster_chat_2106_2 = "Ah evet, avlanmak i\231in birileri gelmi\254. "
gameforge.locale.monster_chat_2106_3 = "(Kahkaha) Bunu sevdim; bunu \231ok sevdim! "
gameforge.locale.monster_chat_2106_4 = "\222u taraftaki g\252zel ve tombul. O benim! "
gameforge.locale.monster_chat_2106_5 = {}
gameforge.locale.monster_chat_2106_6 = "Kan kokusunu seviyorum. "
gameforge.locale.monster_chat_2107_1 = "Bu g\252nlerde yapacak fazla bir\254ey yok. "
gameforge.locale.monster_chat_2107_2 = "Hey, bunlar ger\231ekten \254i\254man! "
gameforge.locale.monster_chat_2107_3 = "Liderimiz buna bay\253lacak... "
gameforge.locale.monster_chat_2107_4 = {}
gameforge.locale.monster_chat_2107_5 = "Hadi y\252r\252yelim. "
gameforge.locale.monster_chat_2107_6 = "Ok geliyor! "
gameforge.locale.monster_chat_2108_1 = "E\240er birini alabilirsem, alaca\240\253m... "
gameforge.locale.monster_chat_2108_2 = "Hey, neden arkana bak\253yorsun? "
gameforge.locale.monster_chat_2108_3 = "Sence kolayca yenilecek birine mi benziyorum? Hmm? "
gameforge.locale.monster_chat_2108_4 = "\199ok k\246t\252, \231\246lde bana ko\254mal\253yd\253n! "
gameforge.locale.monster_chat_2108_5 = "Ah, \254u his; Sonsuza dek ho\254uma gidecek! "
gameforge.locale.monster_chat_2108_6 = "Te\254ekk\252rler! "
gameforge.locale.monster_chat_2191_1 = "\221nsan kokular\253 al\253yorum - \231ok lezzetli! "
gameforge.locale.monster_chat_2191_2 = "G\252zel. Bana gel, bana gel... "
gameforge.locale.monster_chat_2191_3 = {}
gameforge.locale.monster_chat_2191_4 = "\199\246lde birilerine rastlamak g\252zel! "
gameforge.locale.monster_chat_2191_5 = "Dur \246yle! Kkkkk! "
gameforge.locale.monster_chat_2191_6 = "Hadi \246nce k\252\231\252k bir \253s\253r\253k alal\253m... "
gameforge.locale.monster_chat_2202_1 = "Neden bu kadar s\253cak oldu\240unu ger\231ekten anlam\253yorum. "
gameforge.locale.monster_chat_2202_2 = "Ke\254ke serin bir\254eyler olsayd\253... "
gameforge.locale.monster_chat_2202_3 = "Belki onlar\253n kanlar\253yla serinleyebilirim. "
gameforge.locale.monster_chat_2202_4 = "S\253cak, s\253cak! Kanlar\253yla serinlemeliyim. "
gameforge.locale.monster_chat_2202_5 = "Bana kan\253n\253 ver! "
gameforge.locale.monster_chat_2202_6 = "Benim gibi ol! "
gameforge.locale.monster_chat_2204_1 = "Ben burada olduk\231a, kimse giremez! "
gameforge.locale.monster_chat_2204_2 = "Neden bilmiyorum ama, beni sinirlendirmeye ba\254l\253yorsun. "
gameforge.locale.monster_chat_2204_3 = {}
gameforge.locale.monster_chat_2204_4 = "Kwuuh, nerede oldu\240unu biliyor musun? "
gameforge.locale.monster_chat_2204_5 = {}
gameforge.locale.monster_chat_2204_6 = "\199ok a\254\253r\253 zay\253f! (kahkaha) "
gameforge.locale.monster_chat_2205_1 = "Bir k\253l\253\231 ancak bir sava\254\231\253n\253n ellerinde i\254e yarar. "
gameforge.locale.monster_chat_2205_2 = "K\253l\253c\253 ellerinde tut. "
gameforge.locale.monster_chat_2205_3 = "Sava\254 geliyor. "
gameforge.locale.monster_chat_2205_4 = "Ve \254imdi, birimiz \246lene kadar sava\254aca\240\253z! "
gameforge.locale.monster_chat_2205_5 = "\214l\252me direnebildi\240in kadar direnmek istiyor musun? "
gameforge.locale.monster_chat_2205_6 = "Evet, \231ok h\253zl\253 \246lmemelisin. "
gameforge.locale.monster_chat_2206_1 = "Hayat\253n \246z\252t\252 lavd\253r. "
gameforge.locale.monster_chat_2206_2 = "Lav banyosunda kendimi yenilemeyi seviyorum! "
gameforge.locale.monster_chat_2206_3 = "Lav eskisi gibi de\240il. "
gameforge.locale.monster_chat_2206_4 = "Seni al\231ak! Huzurumu bozdun! "
gameforge.locale.monster_chat_2206_5 = "Mahremiyetime kar\253\254ma. "
gameforge.locale.monster_chat_2206_6 = "E\240er kar\253\254\253rsan, pi\254man ederim... "
gameforge.locale.monster_chat_2291_1 = "Hava g\252zel. Sadece uyumak ho\254 olacak. "
gameforge.locale.monster_chat_2291_2 = "Doyyumhwan gibi bir \252lke daha yok. "
gameforge.locale.monster_chat_2291_3 = "Neden uyumaya gitmiyorum ki? "
gameforge.locale.monster_chat_2291_4 = "Beni rahats\253z ettin. "
gameforge.locale.monster_chat_2291_5 = "Beni rahats\253z etti\240ine pi\254man olacaks\253n. "
gameforge.locale.monster_chat_2291_6 = "Ka\231mak i\231in \231ok ge\231. Ve bu se\231enek sana yard\253mc\253 olmayacak. "
gameforge.locale.monster_chat_301_1 = "\199ok s\253k\253ld\253m. Yapacak ilgin\231 bir\254ey yok mu? "
gameforge.locale.monster_chat_301_2 = "\221ki g\252n \246nce, ger\231ekten yak\253\254\253kl\253 biri gelmi\254ti. "
gameforge.locale.monster_chat_301_3 = "Hadi sa\231lar\253m\253z\253 yapal\253m, k\253z karde\254lerim! "
gameforge.locale.monster_chat_301_4 = "Sorun yok! Hehe, g\252zel g\246r\252nmek yetmez. "
gameforge.locale.monster_chat_301_5 = "Bu k\253l\253c\253 istiyor musun? \222aka yapm\253yoruz. "
gameforge.locale.monster_chat_302_1 = "Hey! Bu adam yak\253\254\253kl\253 g\246r\252n\252yor! "
gameforge.locale.monster_chat_302_2 = "Bilirsin, diyet yap\253yorum. "
gameforge.locale.monster_chat_302_3 = "Al\253\254veri\254e gitmek istiyorum. "
gameforge.locale.monster_chat_302_4 = "Bu benim okumdu! "
gameforge.locale.monster_chat_302_5 = "G\246rd\252n m\252? Kalbine ni\254an ald\253m. "
gameforge.locale.monster_chat_302_6 = "Tanr\253m! Sa\231mal\253k! "
gameforge.locale.monster_chat_303_1 = "Bu g\252nlerde, \231ocuklar\253m\253z \231ok tembelle\254mi\254. "
gameforge.locale.monster_chat_303_2 = "E\240er askerler b\252t\252n sessizlik i\231inden y\253ld\253r\253m gibi ya\240arsa ne olur? "
gameforge.locale.monster_chat_303_3 = "Neden bana \246yle bak\253yorsun? "
gameforge.locale.monster_chat_303_4 = "Tanr\253m, korkak! "
gameforge.locale.monster_chat_303_5 = "Bu kadar basite alma. "
gameforge.locale.monster_chat_303_6 = "Bu sava\254 d\252\254\252nd\252\240\252mden daha zorlu olacak. "
gameforge.locale.monster_chat_304_1 = "Siz, kocalar\253n\253z sizi terkettikten sonra kat\253ld\253n\253z. Hala bir erkek \246zl\252yorsunuz. "
gameforge.locale.monster_chat_304_2 = "Buralarda hi\231 iyi bir adam yok mu? "
gameforge.locale.monster_chat_304_3 = "Sinirlerime dokunuyorsun. "
gameforge.locale.monster_chat_304_4 = "Nas\253l bir histi? \214l\252m\252n sana bakt\253\240\253n\253 g\246remiyor musun? "
gameforge.locale.monster_chat_304_5 = "Hay\253r! Pes mi ettin? "
gameforge.locale.monster_chat_304_6 = "Izd\253rap \231abuk gelir. "
gameforge.locale.monster_chat_305_1 = "Hm... K\253l\253c\253n ilgi \231ekici g\246r\252n\252yor. "
gameforge.locale.monster_chat_305_2 = "Daha fazla dayan\253kl\253 ol ve g\252c\252n\252 artt\253r! "
gameforge.locale.monster_chat_305_3 = "Benim kadar g\252\231l\252 olabilece\240ini d\252\254\252n\252yor musun? "
gameforge.locale.monster_chat_305_4 = "Tamam, hadi ciddi olal\253m. "
gameforge.locale.monster_chat_305_5 = "Tanr\253m! Ben sadece zay\253f bir kad\253n\253m! "
gameforge.locale.monster_chat_305_6 = "Yorgun g\246r\252n\252yorsun. Neden b\253rakm\253yorsun? Hehe. "
gameforge.locale.monster_chat_306_1 = "Serangyi bug\252n ne yapacak, hm? "
gameforge.locale.monster_chat_306_2 = "Ben \231ok s\253k\253ld\253m. Hadi benimle oyna! "
gameforge.locale.monster_chat_306_3 = "\221tiraf etmeliyim, en \231ok Sura erkeklerini seviyorum. "
gameforge.locale.monster_chat_306_4 = "Hey! D\246v\252\254meye ne dersin? "
gameforge.locale.monster_chat_306_5 = "Kad\253n oldu\240um i\231in beni hafife alma! "
gameforge.locale.monster_chat_306_6 = "Ac\253 sadece an\253n sonudur. "
gameforge.locale.monster_chat_307_1 = "Ne pahas\253na olursa olsun, sadece buradan \231\253kmak istiyorum. "
gameforge.locale.monster_chat_307_2 = "Yaln\253z ya\254ayan insanlar\253n evleri g\252venli mi? "
gameforge.locale.monster_chat_307_3 = "Kapat \231eneni! "
gameforge.locale.monster_chat_307_4 = "B\253rak da seni tek bir okumla \246ld\252reyim. "
gameforge.locale.monster_chat_307_5 = "Ka\231may\253 d\252\254\252nme bile! "
gameforge.locale.monster_chat_307_6 = "O zaman, neden ba\254lam\253yoruz? "
gameforge.locale.monster_chat_394_1 = "Unutma; t\252m erkekler d\252\254mand\253r. "
gameforge.locale.monster_chat_394_2 = "E\240er g\252zel bir y\252z\252 varsa, daha yumu\254ak olabiliriz. "
gameforge.locale.monster_chat_394_3 = "Ne, sava\254mak istiyor musun? "
gameforge.locale.monster_chat_394_4 = "\199ok uzun s\252rmeyecek, ama ac\253tacak. "
gameforge.locale.monster_chat_394_5 = "Ah, ger\231ekten ac\253 \231ekiyormu\254 gibi g\246r\252n\252yorsun. "
gameforge.locale.monster_chat_394_6 = "Ho\254\231a kal; cehenneme git! "
gameforge.locale.monster_chat_401_1 = "Hm, Beyaz Yeminlilerde ne yapacaks\253n? "
gameforge.locale.monster_chat_401_2 = "Nereye gidiyorsun? "
gameforge.locale.monster_chat_401_3 = "Hey, d\246v\252\254mek istiyor musun? "
gameforge.locale.monster_chat_401_4 = "Hehe, sald\253r\253lar\253mdan ka\231\253yorsun. "
gameforge.locale.monster_chat_401_5 = "Benden ka\231abilece\240ini mi d\252\254\252n\252yorsun? "
gameforge.locale.monster_chat_401_6 = "Lanetim geliyor! "
gameforge.locale.monster_chat_402_1 = "Tanr\253m, \231ok yorgunum! "
gameforge.locale.monster_chat_402_2 = "Hey, g\252zel z\253rh! Fiyat\253 nedir? "
gameforge.locale.monster_chat_402_3 = "Ama hava bug\252n g\252zel. "
gameforge.locale.monster_chat_402_4 = "Ah, bug\252n \231ok e\240itim yapt\253n! Harika! "
gameforge.locale.monster_chat_402_5 = "Yeteneklerim hakk\253nda ne d\252\254\252n\252yorsun? \221yi mi? Hehe. "
gameforge.locale.monster_chat_402_6 = "Ne oldu? Tabii ki, bu deli bir h\253z! "
gameforge.locale.monster_chat_403_1 = "Neden avlanmaya gitmiyorum ki? "
gameforge.locale.monster_chat_403_2 = "Bug\252n kimse \254ehre sald\253rmad\253. "
gameforge.locale.monster_chat_403_3 = "E\240er d\246v\252\254mek istersen, d\246v\252\254, seni korkak! "
gameforge.locale.monster_chat_403_4 = "Hehe, sadece aceminin tekisin. "
gameforge.locale.monster_chat_403_5 = "Nerene ilk vuray\253m, koluna m\253 baca\240na m\253? "
gameforge.locale.monster_chat_403_6 = "\221\254te okum geliyor! "
gameforge.locale.monster_chat_404_1 = "Yak\253n zamanda \254ehre gidip e\240itim yapmal\253y\253m. "
gameforge.locale.monster_chat_404_2 = "Kendimi \231ok gergin hissediyorum. "
gameforge.locale.monster_chat_404_3 = "Bug\252n ne yemek var? "
gameforge.locale.monster_chat_404_4 = "\221zliyorum, atabildi\240in kadar \231\253\240l\253k at. "
gameforge.locale.monster_chat_404_5 = "\199ok mu bekledin? \221lk sen sald\253r bakal\253m! "
gameforge.locale.monster_chat_404_6 = "K\253l\253c\253n sesi heyecan verici! "
gameforge.locale.monster_chat_405_1 = "K\253l\253\231 haz\253r! "
gameforge.locale.monster_chat_405_2 = "Bakal\253m bu k\253l\253c\253n ilk kurban\253 kim olacak. "
gameforge.locale.monster_chat_405_3 = "Hey, neye bak\253yorsun sen? "
gameforge.locale.monster_chat_405_4 = "\214nce karn\253na vuraca\240\253m! "
gameforge.locale.monster_chat_405_5 = "Seni k\253l\253c\253m\253n k\253n\253 olarak kullanmak ho\254uma gidecek. "
gameforge.locale.monster_chat_405_6 = "Seni k\253l\253c\253m\253n k\253n\253 olarak kullanmak ho\254uma gidecek. "
gameforge.locale.monster_chat_406_1 = "A\231l\253ktan \246l\252yorum. "
gameforge.locale.monster_chat_406_2 = "Yiyecek bir\254ey var m\253? "
gameforge.locale.monster_chat_406_3 = "B\252t\252n bu yemeklerden sonra niye hala a\231\253m? "
gameforge.locale.monster_chat_406_4 = "Aarrgh, \246l! "
gameforge.locale.monster_chat_406_5 = "Bu d\246v\252\254e midem karar verecek! "
gameforge.locale.monster_chat_406_6 = "Bu cennet ve cehennem aras\253ndaki se\231im! "
gameforge.locale.monster_chat_491_1 = "Daha fazla dayanam\253yorum! Bedenim hevesleniyor. "
gameforge.locale.monster_chat_491_2 = "Oh evet. Biraz domuz g\246rebilirim. "
gameforge.locale.monster_chat_491_3 = "Yerde? "
gameforge.locale.monster_chat_491_4 = "Seni bir vuru\254ta \246ld\252rece\240im. "
gameforge.locale.monster_chat_491_5 = "Bu g\252zel bir an\253 olacak! "
gameforge.locale.monster_chat_491_6 = "Geber! "
gameforge.locale.monster_chat_492_1 = "Bedenim yumu\254ad\253. "
gameforge.locale.monster_chat_492_2 = "Neden daha fazla al\253\254t\253rma yapm\253yorum ki? "
gameforge.locale.monster_chat_492_3 = "Korktun mu ha? "
gameforge.locale.monster_chat_492_4 = "Ah, silah\253ma sadece yeni bir kurban. "
gameforge.locale.monster_chat_492_5 = "Sald\253r\253 \254eklimi g\246rebiliyor musun? Hay\253r m\253? Senin kayb\253n! "
gameforge.locale.monster_chat_492_6 = "Biliyor muydun? Belki de k\252\231\252k bir kesik bile sa\240l\253\240\253n i\231in k\246t\252 olabilir. "
gameforge.locale.monster_chat_493_1 = "B\246yle bir ele sahip olmak ho\254 de\240il! "
gameforge.locale.monster_chat_493_2 = "Sen neye bak\253yorsun \246yle? \222imdiye dek elleri b\246yle olan birini daha g\246rmemi\254 miydin? "
gameforge.locale.monster_chat_493_3 = "Siz insanlar beni ger\231ekten \246fkelendiriyorsunuz. "
gameforge.locale.monster_chat_493_4 = "Seni ala\254a\240\253 etmemi mi istiyorsun? E\240er istemiyorsan, bas git. Anlad\253n m\253? "
gameforge.locale.monster_chat_493_5 = "Sana en iyi vuru\254umu g\246sterece\240im! "
gameforge.locale.monster_chat_493_6 = "Ellerime bakt\253\240\253n\253 biliyorum! "
gameforge.locale.monster_chat_494_1 = "Hey sen, e\240er d\246v\252\254mek istiyorsan, buraya gel! "
gameforge.locale.monster_chat_494_2 = "Bence nefes kesiciyim! "
gameforge.locale.monster_chat_494_3 = "Neden bir\254eyler planlam\253yoruz? "
gameforge.locale.monster_chat_494_4 = "Hay\253r, gitmene izin vermiyorum. D\246v\252\254! "
gameforge.locale.monster_chat_494_5 = "Al sana! "
gameforge.locale.monster_chat_494_6 = "\214ld\252n say\253l\253r! "
gameforge.locale.monster_chat_501_1 = "Oyna benimle! Gitme! "
gameforge.locale.monster_chat_501_2 = "Kemiklerinden g\252zel bir heykel yapabilirim... "
gameforge.locale.monster_chat_501_3 = "Hen\252z al\253\254t\253rma yapmad\253k. "
gameforge.locale.monster_chat_501_4 = "Ne harika bir z\253rh! Ona sahip olmak istiyorum. "
gameforge.locale.monster_chat_501_5 = "\222imdiden sonra, sald\253r\253lar\253m\253 daha zor kar\254\253layabileceksin. "
gameforge.locale.monster_chat_501_6 = "Hehe, \254a\254\253rd\253n m\253? "
gameforge.locale.monster_chat_502_1 = "G\252zellik her\254ey de\240ildir. "
gameforge.locale.monster_chat_502_2 = "\214yle bo\254 bo\254 bakma, d\246v\252\254! "
gameforge.locale.monster_chat_502_3 = "\214yle bakmandan ho\254lanm\253yorum. D\246v\252\254! "
gameforge.locale.monster_chat_502_4 = "Benim k\253l\253c\253mla \246lmek onur verici olacakt\253r! "
gameforge.locale.monster_chat_502_5 = {}
gameforge.locale.monster_chat_502_6 = "Harika! "
gameforge.locale.monster_chat_503_1 = "Sak\253n dokunma! "
gameforge.locale.monster_chat_503_2 = "Yay\253m\253n teli kopmu\254 san\253r\253m. "
gameforge.locale.monster_chat_503_3 = "Kahretsin, bu ku\254beyinliler yine burada. "
gameforge.locale.monster_chat_503_4 = "Fena de\240il. Ama yine de \246leceksin! "
gameforge.locale.monster_chat_503_5 = "Bu \254ekilde iyi misin? Bu harika! "
gameforge.locale.monster_chat_503_6 = "Ok geliyor! "
gameforge.locale.monster_chat_504_1 = "Millet, buraya gelin! "
gameforge.locale.monster_chat_504_2 = "La, lala, \254ark\253 m\253r\253ldan\253yorum... "
gameforge.locale.monster_chat_504_3 = "Ne harika hava! "
gameforge.locale.monster_chat_504_4 = {}
