gameforge.locale.monster_chat_601_3 = "Evet. Bal\253k da olur. "
gameforge.locale.monster_chat_601_4 = "Ka\231ma! Burada kal! "
gameforge.locale.monster_chat_601_5 = "Ben kazand\253m. Bu apa\231\253k belli. "
gameforge.locale.monster_chat_601_6 = "G\246r\252yor musun? Ka\231\253rd\253n! "
gameforge.locale.monster_chat_601_7 = "Daha dikkatli ol! (kahkaha) "
gameforge.locale.monster_chat_602_1 = "Neredeyim ben? "
gameforge.locale.monster_chat_602_2 = "G\252zel hava. "
gameforge.locale.monster_chat_602_3 = "Ben indirmeye mi geldin? Ne sa\231ma! "
gameforge.locale.monster_chat_602_4 = "Sen benim av\253ms\253n. "
gameforge.locale.monster_chat_602_5 = "Ne bi\231im i\254kence, de\240il mi? Pekala, senin i\254ini direkt bitirece\240im. "
gameforge.locale.monster_chat_602_6 = "Ben \231ok g\252\231l\252y\252m, bilmiyor musun? "
gameforge.locale.monster_chat_603_1 = "S\253k\253c\253! "
gameforge.locale.monster_chat_603_2 = "T\252m bedenim sava\254mak i\231in can at\253yor. "
gameforge.locale.monster_chat_603_3 = "\221lk her kimse. "
gameforge.locale.monster_chat_603_4 = "\221lk vuru\254u sen mi yapacaks\253n? Seni buradan defedece\240im! "
gameforge.locale.monster_chat_603_5 = "Buraya bir defa girdin mi, art\253k \231\253kamazs\253n. Ka\231\253\254 yok! "
