gameforge.locale.monster_chat_604_1 = "Yeni ve lezzetli bir zehir yapt\253m. Tad\253na bakmak ister misin? "
gameforge.locale.monster_chat_604_2 = "Nas\253l \231al\253\254t\253\240\253n\253 g\246rmek isterim! "
