gameforge.locale.monster_chat_604_4 = "Seni zehirleyece\240im! "
gameforge.locale.monster_chat_604_5 = "Harika, dahi ahmak! "
gameforge.locale.monster_chat_604_6 = "Hay\253r, e\240er hemen pes edersen ne e\240lencesi kal\253r! "
gameforge.locale.monster_chat_631_1 = "Bir dakika. Avlanacak bir\254ey bak\253yorum. "
gameforge.locale.monster_chat_631_2 = "E\240er bu kadar yava\254 olursan i\254e yaramaz! "
gameforge.locale.monster_chat_631_3 = "\199ok a\231\253m! "
gameforge.locale.monster_chat_631_4 = "\221yi ki avlayacak bir\254ey buldum! "
gameforge.locale.monster_chat_631_5 = "Kurtulu\254umuza dair umutlar\253n\253 k\253rma! "
gameforge.locale.monster_chat_631_6 = "Sana ger\231ek ac\253y\253 tatt\253raca\240\253m! "
gameforge.locale.monster_chat_632_1 = "S\253k\253c\253\253\253\253\253\253! "
gameforge.locale.monster_chat_632_2 = "Yem olarak kullanabilece\240imiz bir\254ey var m\253? "
gameforge.locale.monster_chat_632_3 = "E\240er istiyorsan gel ve d\246v\252\254! "
gameforge.locale.monster_chat_632_4 = "Sava\254\231\253 olmak istiyorsan, marifetlerini g\246ster bakal\253m! "
gameforge.locale.monster_chat_632_5 = {}
gameforge.locale.monster_chat_632_6 = "E\240er hayatta kalmak istiyorsan \254ehre ka\231! "
gameforge.locale.monster_chat_633_1 = "A\231l\253k ac\253verici. "
gameforge.locale.monster_chat_633_2 = "Ah, direkt bize do\240ru geliyorlar!! "
gameforge.locale.monster_chat_633_3 = "D\246v\252\254 nas\253ld\253? "
gameforge.locale.monster_chat_633_4 = "Beni bu al\231aklarla k\253yaslama! "
gameforge.locale.monster_chat_633_5 = "\221\254te y\253ld\253r\253m gibi bir vuru\254! "
gameforge.locale.monster_chat_633_6 = "Ka\231an ki\254i ger\231ek sava\254\231\253 de\240ildir! "
gameforge.locale.monster_chat_634_1 = "Bu sefer zehir daha iyi olmal\253! "
gameforge.locale.monster_chat_634_2 = "E\240er a\231san, yarasalar lezzetli g\246r\252nmeye ba\254layabilir. "
gameforge.locale.monster_chat_634_3 = "D\246v\252\254e ne dersin? "
gameforge.locale.monster_chat_634_4 = "Bir defa zehrim v\252cuduna girdi mi, panzehiri olmad\253\240\253ndan art\253k d\246n\252\254\252 olmaz. "
gameforge.locale.monster_chat_634_5 = "Benim b\252y\252m her\254eyi yakacak, hehehe! "
gameforge.locale.monster_chat_634_6 = "Yan! Haha! "
gameforge.locale.monster_chat_635_1 = "K\253l\253c\253n\253 bilemeyi unutma! Her daim yeni bir d\246v\252\254 seni bekliyor olacak. "
gameforge.locale.monster_chat_635_2 = "Bay\253ld\253n m\253? "
gameforge.locale.monster_chat_635_3 = "\214l ki yeniden kalkabilesin! "
gameforge.locale.monster_chat_635_4 = "Beni yenmek mi? Ger\231ekten mi? "
gameforge.locale.monster_chat_635_5 = "Bir sava\254\231\253 gibi d\246v\252\254! "
gameforge.locale.monster_chat_635_6 = "Hadi, biraz daha. "
gameforge.locale.monster_chat_636_1 = "\221yi bir d\246v\252\254\231\252 ar\253yorum... "
