gameforge.locale.monster_chat_636_3 = "B\252t\252n zaman\253m\253 d\246v\252\254erek harcayabilirim! "
gameforge.locale.monster_chat_636_4 = "\199ok iyi! Tekrar dene! "
gameforge.locale.monster_chat_636_5 = "(k\253l\253\231 sallama) "
gameforge.locale.monster_chat_636_6 = "Bana vurdu\240una pi\254man olacaks\253n! "
gameforge.locale.monster_chat_636_7 = "\199ok zay\253f! Ne g\252l\252n\231! "
gameforge.locale.monster_chat_637_1 = "Rahats\253z edilmek istemiyorum. "
