gameforge.locale.monster_chat_637_5 = "Benim g\252c\252m seni \254a\254\253rtmas\253n! "
gameforge.locale.monster_chat_637_6 = "Seni ezip unufak edece\240im! "
gameforge.locale.monster_chat_691_1 = "Her daim g\252\231l\252 rakipler istemi\254imdir! "
