gameforge.locale.monster_chat_691_6 = "\214l\252nceye kadar! "
gameforge.locale.monster_chat_701_1 = "Bak, kelebek! Ne \254irin! "
gameforge.locale.monster_chat_701_2 = "Cennet ve d\252nyan\253n do\240rulu\240unu g\246rm\252yor musun? "
gameforge.locale.monster_chat_701_3 = "Daha sonra, inanmak i\231in \231ok ge\231 olacak. \222imdi inan! "
