gameforge.locale.monster_chat_702_2 = "Gizli inan\253\254\253n felsefesi y\252ce emirdir! "
gameforge.locale.monster_chat_702_3 = "Mistik ger\231ek; Kaplan Tanr\253n\253n ger\231e\240i; Sabaha Sabaha. "
gameforge.locale.monster_chat_702_4 = "Sen cennet ve d\252nyan\253n hakikatinden \254\252phe edenlerden misin? "
gameforge.locale.monster_chat_702_5 = {}
gameforge.locale.monster_chat_702_6 = "Pen\231elerimi hisset! "
gameforge.locale.monster_chat_703_1 = "Kaplan Tanr\253 sonsuzlu\240a d\246nd\252\240\252nde, b\252t\252n ac\253lar bitecek. "
gameforge.locale.monster_chat_703_2 = "Gizli mezhebin do\240rulu\240u, cennetin buyruklar\253n\253 anlamakta sakl\253d\253r. "
gameforge.locale.monster_chat_703_3 = "Sababa Sabaha. Bizi ayd\253nlat! "
gameforge.locale.monster_chat_703_4 = "Bundan sak\253n \254\252phe etme! "
gameforge.locale.monster_chat_703_5 = "Cennetin g\246k g\252r\252lt\252lerine ula\254! "
gameforge.locale.monster_chat_703_6 = "H\252k\252m verildi! "
gameforge.locale.monster_chat_704_1 = "Gizli mezhebin do\240rulu\240u, cennetin buyruklar\253n\253 anlamakta sakl\253d\253r. "
gameforge.locale.monster_chat_704_2 = "Mistik ger\231ek; Kaplan Tanr\253n\253n ger\231e\240i; Sabaha Sabaha. "
gameforge.locale.monster_chat_704_3 = "Mistik ger\231e\240e sadakat, ancak cennetin emirlerini uygulamak ve anlamaktan ge\231er. "
gameforge.locale.monster_chat_704_4 = "Bu mezhebin lideri t\252m ya\254ayan varl\253klar\253n \252zerinde bir azizdir. "
gameforge.locale.monster_chat_704_5 = "Cehenemin alevlerine ula\254! "
gameforge.locale.monster_chat_704_6 = "K\253l\253c\253m\253n tad\253na bak! "
gameforge.locale.monster_chat_705_1 = "Mistik ger\231ek; Kaplan Tanr\253n\253n ger\231e\240i; Sabaha Sabaha. "
gameforge.locale.monster_chat_705_2 = "Gizli mezhebin do\240rulu\240u, cennetin buyruklar\253n\253 anlamakta sakl\253d\253r. "
gameforge.locale.monster_chat_705_3 = "Mistik ger\231ek; Kaplan Tanr\253n\253n ger\231e\240i; Sabaha Sabaha. "
gameforge.locale.monster_chat_705_4 = "Ebedi ac\253 ve karanl\253k seni bekliyor! "
gameforge.locale.monster_chat_705_5 = {}
gameforge.locale.monster_chat_705_6 = "Bu son de\240ildi. Yaln\253zca biraz daha iyi oldu! "
gameforge.locale.monster_chat_706_1 = "Bar\253\254 ve mahremiyeti ar\253yoruz! L\252tfen! "
gameforge.locale.monster_chat_706_2 = "E\240er korku h\252kmederse, Kaplan Tanr\253'n\253n hakikati bize yard\253m edecektir! "
gameforge.locale.monster_chat_706_3 = "Mistik ger\231e\240e sadakat ancak cennetin emirlerini dinlemek ve onlar\253 uygulamakla g\246sterilir. "
gameforge.locale.monster_chat_706_4 = "Hepiniz cehenneme gidin! "
gameforge.locale.monster_chat_706_5 = "Gitmene izin vermeyece\240im! "
gameforge.locale.monster_chat_706_6 = "Sana sahip oldu\240um her\254eyi verece\240im. "
gameforge.locale.monster_chat_707_1 = "Yalvar\253yorum, bizi kurtar! "
gameforge.locale.monster_chat_707_2 = "Gizli mezhebin do\240rulu\240u, cennetin buyruklar\253n\253 anlamakta sakl\253d\253r. "
gameforge.locale.monster_chat_707_3 = "Mistik ger\231ek; Kaplan Tanr\253n\253n ger\231e\240i; Sabaha Sabaha. "
gameforge.locale.monster_chat_707_4 = "(Y\252ksek sesle kahkaha) Cehennemin kap\253lar\253 ard\253na dek a\231\253ld\253. \214l\252n! "
gameforge.locale.monster_chat_707_5 = "Seni uyar\253yorum: Beni g\252\231lerimi kullanmak zorunda b\253rakma! "
gameforge.locale.monster_chat_707_6 = "Senin \246l\252m\252n\252 g\246rd\252m! "
gameforge.locale.monster_chat_791_1 = "Kaplan Tanr\253'n\253n hakikatini sana birka\231 kelime ile nas\253l a\231\253klayay\253m? "
gameforge.locale.monster_chat_791_2 = "\221nananlar\253n ilahilerini duyuyorum. "
gameforge.locale.monster_chat_791_3 = "Bu do\240ru! Affedilmek ve kurtar\253lmak i\231in tamamen pi\254man ol ve kendini teslim et! "
gameforge.locale.monster_chat_791_4 = "Sonsuz ac\253yla yanacaks\253n, \231\252nk\252 hakikati sorgulad\253n! "
gameforge.locale.monster_chat_791_5 = "Sana \246\240reteyim. "
gameforge.locale.monster_chat_791_6 = "Ac\253 olarak alg\253lama - bu \246\240retidir. "
gameforge.locale.monster_chat_901_1 = "\222irin olmayabilirim ama \231ok e\240leniyorum, hihihi! "
gameforge.locale.monster_chat_901_2 = "Bizden biri olacaks\253n! "
gameforge.locale.monster_chat_901_3 = "Bize do\240ru gel, hihi! "
gameforge.locale.monster_chat_901_4 = "Haaa, haha! "
gameforge.locale.monster_chat_901_5 = "\221\254te ba\254l\253yoruz! "
gameforge.locale.monster_chat_903_1 = "Cehennem gibi! "
gameforge.locale.monster_chat_903_2 = "Ahhhhh! "
gameforge.locale.monster_chat_903_3 = "Bunu yaln\253z yapamay\253z! Hay\253r! "
gameforge.locale.monster_chat_903_4 = "Ac\253y\253 sen de tatmal\253s\253n! "
gameforge.locale.monster_chat_903_5 = "takasa ne dersin? Sen bana ruhunu ver ben sana ac\253m\253! "
gameforge.locale.monster_chat_903_6 = "Yak\253nda sonsuz huzuru bulacaks\253n! "
gameforge.locale.monster_chat_904_1 = "Ac\253! Ac\253! "
gameforge.locale.monster_chat_904_2 = "Ahhh, lanet olsun! Kolum yan\253yor! "
gameforge.locale.monster_chat_904_3 = "Neden ac\253 \231ekiyoruz, neden? "
gameforge.locale.monster_chat_904_4 = "Bu gizemli hastal\253ktan ac\253 \231ekmek o kadar k\246t\252 de\240il! "
gameforge.locale.monster_chat_904_5 = {}
gameforge.locale.monster_chat_904_6 = "Ahhh! "
gameforge.locale.monster_chat_905_1 = "Ahhhhh! "
gameforge.locale.monster_chat_905_2 = "Seni gebertece\240immmm! "
gameforge.locale.monster_chat_905_3 = "Bo\254 bo\254 izleme! Sen de kat\253l! "
gameforge.locale.monster_chat_905_4 = "Hadi arkada\254 olal\253m! "
gameforge.locale.monster_chat_905_5 = "Hastal\253k sana bula\254t\253 bile. "
gameforge.locale.monster_chat_905_6 = "\222imdi arkada\254\253z. "
gameforge.locale.monster_chat_906_1 = "(Kahkaha) "
gameforge.locale.monster_chat_906_2 = "Gel ve oklar\253m\253n tad\253na bak! "
gameforge.locale.monster_chat_906_3 = "Ger\231ekten sinir ediyorsun! "
gameforge.locale.monster_chat_906_4 = "Sana gizemli hastal\253k bula\254t\253raca\240\253m. "
gameforge.locale.monster_chat_906_5 = "G\252zel koku. "
gameforge.locale.monster_chat_906_6 = "Geber! "
gameforge.locale.monster_chat_907_1 = "Ve e\240er hastal\253k i\231in ba\254ka bir yol bulursam... "
gameforge.locale.monster_chat_907_2 = "(Laughter) E\240lenceli olacak! "
gameforge.locale.monster_chat_907_3 = "Sadece izleme. Konu\254 benimle. "
gameforge.locale.monster_chat_907_4 = "Ahhh, eveeet! "
gameforge.locale.monster_chat_907_5 = "\221zin ver de hastal\253\240\253 sana da ge\231ireyim! "
gameforge.locale.monster_chat_907_6 = "\221nat, bu gizemli hastal\253\240\253n en b\252y\252k sebebi! "
