gameforge.locale.questscroll5.mission_12_text = "\222u s\253ralar, Beyaz Yeminliler bir s\252r\252 soruna yol[ENTER]a\231\253yor.[ENTER]\199ok say\253da i\254portac\253y\253 yakalad\253lar ve \254ehre zarar[ENTER]verdiler. L\252tfen Beyaz Yeminliler \231etesini[ENTER]durdur. \220yelerini ve liderini \246ld\252r. "
