gameforge.locale.questscroll5.mission_14_text = "Gelen istihbarata g\246re Seungryong vadisindeki[ENTER]Orklar\253n lideri d\252nyay\253 ku\254atmay\253 planl\253yormu\254.[ENTER]Bu olaya bir bakman\253 istiyorum sava\254\231\253. Ve oraya[ENTER]gitti\240inde onlar\253n say\253lar\253n\253 da biraz azaltmay\253[ENTER]unutma. "
