gameforge.locale.questscroll5.mission_45_text = "Dokuz kuyruk, Sohan da\240\253n\253n efendisi, \254eytanlar\253[ENTER]toplamak i\231in emir vermi\254. O ordusunu kurmadan[ENTER]\246nce buzadamlar\253 ve yetileri \246ld\252rmeliyiz. L\252tfen[ENTER]bize yard\253m et.[ENTER]\214d\252llendirileceksin. "
gameforge.locale.questscroll5.mission_46_hunt = "Chunwa Bong-ki "
gameforge.locale.questscroll5.mission_46_mis = "45 a\240a\231kurba\240as\253 asker ve 35 a\240a\231kurba\240as\253 lideri[ENTER]\246ld\252r. "
gameforge.locale.questscroll5.mission_46_text = "G\246r\252n\252\254e g\246re Sar\253 Hayalet Kaplan A\240a\231[ENTER]Kurba\240alar\253yla i\254 birli\240i yapm\253\254. Hemen bu[ENTER]anla\254may\253 boz. E\240er bunu yapmazsan krall\253\240\253n sonu[ENTER]iyi olmayacak! "
gameforge.locale.questscroll5.mission_47_hunt = "Buzcanavarlar\253! Onlar\253n ger\231ek karakterleri "
gameforge.locale.questscroll5.mission_47_mis = "45 b\252y\252l\252 buz \246ld\252r. "
gameforge.locale.questscroll5.mission_47_text = "Biliyoruz ki, Sohan da\240\253ndaki yarat\253klar[ENTER]birbirleriyle s\252rekli bir haberle\254me[ENTER]i\231erisindeler. Onlar haberleri buz canavarlar\253yla[ENTER]birbirlerine g\246nderiyorlar. Onlar\253n ileti\254imini[ENTER]zay\253flatmak \231ok \246nemli, l\252tfen buz canavarlar\253n\253[ENTER]\246ld\252r. "
gameforge.locale.questscroll5.mission_48_hunt = "\222eytan Kulesinin S\253rr\253 "
gameforge.locale.questscroll5.mission_48_mis = "45 \214l\252mc\252l \222eytan M\253zrak\231\253s\253 \246ld\252r "
gameforge.locale.questscroll5.mission_48_text = "\222eytan kulesindeki \199irkin \222eytan M\253zrak\231\253lar\253n\253n[ENTER]yenilmez oldu\240u s\246yleniyor. Dedikodulara g\246re,[ENTER]\246ld\252kleri halde aya\240a kalkabiliyorlarm\253\254. E\240er bu[ENTER]do\240ruysa karanl\253k zamanlar yak\253n\253m\253zda demektir.[ENTER]L\252tfen bu konu hakk\253ndaki ger\231ekleri \246\240ren! "
gameforge.locale.questscroll5.mission_49_hunt = "\222eytan Kulesinin Efendisi "
gameforge.locale.questscroll5.mission_49_mis = "60 \214l\252mc\252l \222eytan \222aman\253 \246ld\252r "
gameforge.locale.questscroll5.mission_49_text = "Kapsaml\253 bir ara\254t\253rmadan sonra, hayalet[ENTER]askerlerin s\252rekli yeniden diriltildiklerini[ENTER]\246\240rendik. Bunun son bulmas\253 i\231in \246l\252mc\252l \254eytan[ENTER]\254amanlar\253 \246ld\252rmemiz gerek. "
gameforge.locale.questscroll5.mission_4_hunt = "Gri kurtlar\253n aciliyeti -1 "
gameforge.locale.questscroll5.mission_4_mis = "35 gri kurt \246ld\252r "
gameforge.locale.questscroll5.mission_4_text = "Gri kurtlar\253 duymu\254 muydun? Normalde kendi[ENTER]\231aplar\253nda gezinirler. Ama \254eytani chi enerjisi[ENTER]ya\240maya ba\254lad\253ktan sonra \231ok sald\253rganla\254t\253lar.[ENTER]T\252ccarlar\253m\253za ve seyahat\231ilere sald\253r\253yorlar.[ENTER]Gri kurtlar\253 \246ld\252rebilir misin? Elbette[ENTER]\246d\252llendirileceksin. "
gameforge.locale.questscroll5.mission_50_hunt = "Doyyumhwan'\253 ke\254fet "
gameforge.locale.questscroll5.mission_50_mis = "45 sava\254 kaplan\253 k\246lesi \246ld\252r. "
gameforge.locale.questscroll5.mission_50_text = "Doyyumhwan lav b\246lgesi ve bir\231ok bilinmeyen[ENTER]yarat\253kla dolu. O b\246lgeyi ke\254fetmemiz gerek. Bize[ENTER]yard\253m edebilir misin? "
gameforge.locale.questscroll5.mission_51_hunt = "Alev hayaletleri! Kimlikleri bu "
gameforge.locale.questscroll5.mission_51_mis = "45 alev hayaleti \246ld\252r "
gameforge.locale.questscroll5.mission_51_text = "Sava\254 kaplanlar\253n\253 yok etmesi i\231in olu\254turdu\240umuz[ENTER]\246zel bir grup, bilmedi\240imiz ba\254ka d\252\254manlar\253n[ENTER]sald\253r\253s\253na u\240rayarak yenildi. S\246ylediklerine[ENTER]g\246re yanan k\253zlar gibi bir\254eyler taraf\253ndan[ENTER]sald\253r\253ya u\240ram\253\254lar. Git ve ger\231e\240i \246\240ren. "
gameforge.locale.questscroll5.mission_52_hunt = "Sava\254 kaplanlar\253n\253 \246ld\252r. "
gameforge.locale.questscroll5.mission_52_mis = "60 Sava\254 Kaplan\253 K\246lesi ve 40 Sava\254 Kaplan\253 \246ld\252r. "
gameforge.locale.questscroll5.mission_52_text = "Art\253k alev hayaletleri ile sava\254abiliriz. Onlara[ENTER]kar\254\253 a\231\253k sava\254 ilan ettik ve \246yle yenece\240iz.[ENTER]Baz\253 g\246revler askeri kuvvetlerimizce devral\253nd\253.[ENTER]Ama sen sava\254 kaplanlar\253n\253n say\253s\253n\253 d\252\254\252rmeye[ENTER]yard\253mc\253 olacaks\253n. "
gameforge.locale.questscroll5.mission_53_hunt = "Alevleri \221ncele "
gameforge.locale.questscroll5.mission_53_mis = "40 Alev \246ld\252r "
gameforge.locale.questscroll5.mission_53_text = "Alev canavarlar\253 inan\253lmaz derecede ac\253mas\253zlar.[ENTER]\221nsanlar\253n derilerini y\252zerek ac\253 \231ektirmekten[ENTER]zevk al\253yorlar. Onlar\253 nas\253l \246ld\252rece\240imizi hala[ENTER]bilmiyoruz. Gidip nas\253l \246ld\252rebilece\240imizi \246\240ren. "
gameforge.locale.questscroll5.mission_54_hunt = "Alev sava\254\231\253lar "
gameforge.locale.questscroll5.mission_54_mis = "60 alev sava\254\231\253 \246ld\252r "
gameforge.locale.questscroll5.mission_54_text = "\199ok ge\231mi\254te de\240il, bir asilzadenin o\240lu[ENTER]doyyumhwaji'ye gitmi\254ti ve bir alev sava\254\231\253[ENTER]taraf\253ndan \246ld\252r\252ld\252. E\240er alev sava\254\231\253lar\253\253[ENTER]\246ld\252r\252rsen \246d\252llendirileceksin. Neden[ENTER]denemiyorsun? "
gameforge.locale.questscroll5.mission_55_hunt = "Hayalet a\240a\231lar\253 ara\254t\253r "
gameforge.locale.questscroll5.mission_55_mis = "30 hayalet a\240a\231 \246ld\252r "
gameforge.locale.questscroll5.mission_55_text = "Genellikle normal bildi\240imiz a\240a\231t\253rlar. Ama[ENTER]sebebini bilmedi\240imiz bir \254ekilde aniden[ENTER]insanlara ve hayvanlara sald\253r\253r oldular.[ENTER]Say\253lar\253 \231ok art\253yor. Onlar\253 nas\253l[ENTER]\246ld\252rebilece\240imizi \246\240ren. "
gameforge.locale.questscroll5.mission_56_hunt = "Hayalet orman\253n s\253rr\253 "
gameforge.locale.questscroll5.mission_56_mis = "40 hayalet a\240a\231 k\246k\252 ve 30 orman perisi \246ld\252r. "
gameforge.locale.questscroll5.mission_56_text = "Yap\253lan ke\254iflere g\246re hayalet orman\253nda ya\254ayan[ENTER]\231ok say\253da hayalet a\240a\231 ve orman perisi mevcut.[ENTER]E\240er onlar\253 yok edebilirsen, \231o\240almalar\253n\253 da[ENTER]engellemi\254 olacaks\253n. "
gameforge.locale.questscroll5.mission_5_hunt = "\222ehir i\231in \252z\252l\252yor. "
gameforge.locale.questscroll5.mission_5_mis = "40 yaban domuzu \246ld\252r "
gameforge.locale.questscroll5.mission_5_text = "Ge\231ti\240imiz birka\231 hafta i\231inde \254ehir insanlar\253n\253n[ENTER]\252z\252nt\252leri \231ok artt\253. Da\240lardaki yaban[ENTER]domuzlar\253na sald\253ran birileri onlar\253[ENTER]agresifle\254tirip \254ehre do\240ru p\252sk\252rt\252yor. Domuzlar[ENTER]da \231ift\231ilerimize ve onlar\253n tarlalar\253na,[ENTER]ekinlerine sald\253r\253yorlar. Yaban domuzlar\253n\253[ENTER]uzakla\254t\253rabilir misin? "
gameforge.locale.questscroll5.mission_6_hunt = "Kaplanlar ve Ay\253lar "
gameforge.locale.questscroll5.mission_6_mis = "25 kaplan ve 30 ay\253 \246ld\252r. "
gameforge.locale.questscroll5.mission_6_text = "Bunu daha \246nce duymu\254 muydun? E\240er bir kaplan[ENTER]veya ay\253 100 g\252n boyunca sarm\253sak ve so\240anla[ENTER]beslenirse b\252y\252k ay\253 veya ate\254 kaplan\253na[ENTER]d\246n\252\254\252yor. Bu b\252y\252k ihtimalle yalan bir bilgi,[ENTER]fakat yine de kontrol etmekte fayda var. Birka\231[ENTER]kaplan ve ay\253 \246ld\252rerek durumlar\253n\253 kontrol et.[ENTER]\214d\252l\252n verilecek. "
gameforge.locale.questscroll5.mission_7_hunt = "H\253rs Metin ta\254\253n\253 yok et "
gameforge.locale.questscroll5.mission_7_mis = "2 tane H\253rs Metin ta\254\253n\253 yok et "
gameforge.locale.questscroll5.mission_7_text = "\222eytani Chi enerjisiyle birlikte ta\254lar \254ehrin[ENTER]yan\253na ya\240\253yor. Ara\254t\253rmalar bu enerjinin[ENTER]hayvanlar\253 \231\253lg\253na \231evirdi\240ini s\246yl\252yor. Bu[ENTER]ta\254lar\253 yok et. Yalvar\253r\253m yok et. \214d\252l\252n\252[ENTER]alacaks\253n. "
gameforge.locale.questscroll5.mission_8_hunt = "Sava\254 Metinini yok et "
gameforge.locale.questscroll5.mission_8_mis = "2 adet Sava\254 Metin ta\254\253n\253 yok et "
gameforge.locale.questscroll5.mission_8_text = "\222eytani Chi enerjisiyle birlikte ta\254lar \254ehrin[ENTER]yan\253na ya\240\253yor. Ara\254t\253rmalar bu enerjinin[ENTER]hayvanlar\253 \231\253lg\253na \231evirdi\240ini s\246yl\252yor. Bu[ENTER]ta\254lar\253 yok et. Yalvar\253r\253m yok et. \214d\252l\252n\252[ENTER]alacaks\253n. "
gameforge.locale.questscroll5.mission_9_hunt = "\222ehir i\231in \252z\252l\252yor -2 "
gameforge.locale.questscroll5.mission_9_mis = "30 k\253rm\253z\253 yaban domuzu \246ld\252r "
gameforge.locale.questscroll5.mission_9_text = "Birka\231 zamand\253r, yaban domuzlar\253 ve onlar\253n[ENTER]liderleri olan k\253rm\253z\253 yaban domuzlar\253 ana \254ehrin[ENTER]yak\253nlar\253ndaki k\246ylere sald\253r\253yorlar. H\252k\252met[ENTER]k\253rm\253z\253 yaban domuzlar\253n\253n \246ld\252r\252lmesi emri[ENTER]verdi. Her sava\254\231\253ya 30 tane k\253rm\253z\253 yabandomuzu[ENTER]\246ld\252rme g\246revi verildi. L\252tfen sende yard\253mc\253 ol. "
gameforge.locale.questscroll_10_hunt = "Y\253lanadam askerler "
gameforge.locale.questscroll_10_mis = "Yar\253 insan-yar\253 y\253lan olan askerleri \246ld\252r. "
gameforge.locale.questscroll_10_text = "Onlara insan diyemezsin, ancak olmad\253klar\253n\253 da[ENTER]s\246yleyemezsin. Onlar insan gibi g\246r\252n\252yorlar,[ENTER]ancak kafalar\253 ve davran\253\254lar\253 daha \231ok zehirli[ENTER]y\253lanlara benziyor.[ENTER][ENTER]Onlar \231\246lde ya\254\253yorlar ve seyahat edenlere[ENTER]sald\253r\253yorlar. Onlardan 20 tanesini \246ld\252r, e\240er[ENTER]bu g\246revi yaparsan bu \246d\252l\252 alacaks\253n: "
gameforge.locale.questscroll_11_hunt = "Y\253lanadam ok\231usu "
gameforge.locale.questscroll_11_mis = "Yar\253 insan-yar\253 y\253lan olan ok\231ular\253 \246ld\252r "
gameforge.locale.questscroll_11_text = "Onlar\253n da insanlar gibi istihbarat a\240lar\253 var.[ENTER]Silah yapabiliyor, kullanabiliyor ve[ENTER]geli\254tirebiliyorlar. Ok\231ular\253 t\252ccarlar\253 \231ok uzak[ENTER]mesafelerden vurup \246ld\252r\252yor. \222imdiden \231ok fazla[ENTER]t\252ccar \246ld\252.[ENTER][ENTER]Bu ok\231ulardan 20 tane \246ld\252r. Bu g\246revi ba\254ar\253yla[ENTER]bitirirsen bu \246d\252l\252 kazanacaks\253n: "
gameforge.locale.questscroll_12_hunt = "\199\246l haydutlar\253 "
gameforge.locale.questscroll_12_mis = "\199\246l haydutlar\253n\253 \246ld\252r "
gameforge.locale.questscroll_12_text = "Yongbi \231\246l\252nde \254eytani varl\253klar ya\254\253yor. Onlar,[ENTER]genelde \231\246l haydutlar\253 olarak bilinirler ve \246yle[ENTER]al\231akt\253rlar ki belki cennet bile onlar\253n[ENTER]g\252nahlar\253na art\253k a\240l\253yordur. S\253rf e\240lence olsun[ENTER]diye t\252ccarlar\253 ka\231\253r\253yor ve \246ld\252r\252yorlar.[ENTER]Yan\253s\253ra \231\246lde kurulmu\254 k\252\231\252k k\246yleri yok[ENTER]ettiler. 12 tane \231\246l haydutu \246ld\252r. E\240er onlar\253n[ENTER]hepsini silersen bu \246d\252l\252 alacaks\253n: "
gameforge.locale.questscroll_13_hunt = "Sava\254 Kaplan\253 "
gameforge.locale.questscroll_13_mis = "Sava\254 kaplanlar\253n\253 \246ld\252r "
gameforge.locale.questscroll_13_text = "Sava\254 kaplanlar\253 olarak an\253lan hayvanlar var.[ENTER]Onlar\253n kan\253 ate\254ten ve bedenleri volkanik[ENTER]granitten olu\254mu\254tur. \221nan\253lmaz derecede g\252\231l\252 ve[ENTER]\246l\252mc\252ld\252rler! Volkanlardaki lavlarla[ENTER]beslenirler. \221nsanlar\253 avlar ve onlar\253 da yerler.[ENTER]Onlardan 20 tanesini \246ld\252r. E\240er bu g\246revi[ENTER]ba\254ar\253yla tamamlarsan bu \246d\252l\252 alacaks\253n: "
gameforge.locale.questscroll_14_hunt = "Sava\254 adamlar\253 "
gameforge.locale.questscroll_14_mis = "Sava\254 adamlar\253n\253 \246ld\252r "
gameforge.locale.questscroll_14_text = "Doyyumhwaji \231ok b\252y\252k, s\253cak ve vah\254i hayvanlarla[ENTER]dolu. Orada Chunjo, Jinno ve Shinsoo sava\254\231\253lar\253[ENTER]toplanacaklar. Korkun\231 ve g\252\231l\252 canavarlar orada[ENTER]sava\254\231\253lar\253 bekliyor. Sava\254\253n adam\253 Doyyumhwajiyi[ENTER]kontrol edecek.[ENTER]Onlarla kar\254\253la\254mak ister misin? E\240er 20 tane[ENTER]sava\254 adam\253n\253 \246ld\252r\252rsen bu \246d\252l\252 alacaks\253n: "
gameforge.locale.questscroll_15_hunt = "Taehwa sava\254\231\253lar\253 "
gameforge.locale.questscroll_15_mis = "Taehwa sava\254\231\253lar\253n\253 yok et "
gameforge.locale.questscroll_15_text = "Dinle, sen kendini korkusuz ve g\252\231l\252 bir sava\254\231\253[ENTER]m\253 san\253yorsun! Bu ate\254ler i\231indeki g\246zya\254lar\253n\253n[ENTER]sava\254 alan\253, ac\253, kan, \246l\252m sava\254lar\253n\253n oldu\240u[ENTER]yer! Ben orada bir\231ok canavarla ve su\231lularla[ENTER]ya\254\253yorum. Benimle kar\254\253la\254acak kadar cesur olan[ENTER]kim? Bana elindeki k\253l\253\231la kar\254\253 koyacak kimse[ENTER]bulunmaz.[ENTER]E\240er yeteneklerine inanc\253n varsa gel ve benimle[ENTER]kar\254\253la\254! E\240er beni ve 12 sava\254\231\253m\253 yenersen bu[ENTER]\246d\252l\252 kazanacaks\253n: "
gameforge.locale.questscroll_16_hunt = "Karanl\253k ay\253lar "
gameforge.locale.questscroll_16_mis = "Karanl\253k ay\253lar\253 \246ld\252r "
gameforge.locale.questscroll_16_text = "Korkar\253m ki bu son. Ama izin ver sana \246nemli bir[ENTER]olay anlatay\253m. Bu mektubu oku\240unda, ben \246lm\252\254[ENTER]veya yok edilmi\254 olaca\240\253m. Ben Seungryong[ENTER]vadisinde ya\254ad\253\240\253m zamanlarda \254ifal\253 bitkiler[ENTER]toplam\253\254t\253m. Fakat karanl\253k ay\253 olarak an\253lan bir[ENTER]canavar t\252r\252 var. Onlar \231\253ld\253rm\253\254 ve ailemi[ENTER]\246ld\252rm\252\254lerdi.[ENTER][ENTER]L\252tfen benim ve ailemin intikam\253n\253 al. E\240er 25[ENTER]tane karanl\253k ay\253 \246ld\252r\252rsen, bu \246d\252l\252 alacaks\253n: "
gameforge.locale.questscroll_17_hunt = "Dev karanl\253k ay\253lar "
gameforge.locale.questscroll_17_mis = "Dev karanl\253k ay\253lar\253 \246ld\252r "
gameforge.locale.questscroll_17_text = "Canavar ay\253 t\252rleri, birle\254erek yeni ve daha[ENTER]tehlikeli bir canavar t\252r\252n\252 ortaya \231\253kard\253lar.[ENTER]Bu t\252r\252n ismi Dev karanl\253k ay\253lar. Onlar normal[ENTER]karanl\253k ay\253lardan daha b\252y\252k, daha g\252\231l\252 ve[ENTER]inan\253lmaz \254eytaniler. Onlar Seungryong vadisinde[ENTER]ortaya \231\253kt\253klar\253ndan beri insanlar olmad\253klar\253[ENTER]kadar ac\253 i\231indeler.[ENTER]20 tane dev karanl\253k ay\253 \246ld\252r. E\240er bu g\246revi[ENTER]ba\254ar\253rsan bu \246d\252l\252 alacaks\253n: "
gameforge.locale.questscroll_18_hunt = "Askerler gizemli hastal\253k y\252z\252nden ac\253 \231ekiyor "
gameforge.locale.questscroll_18_mis = "Gizemli hastal\253\240a yakalanm\253\254 askerleri \246ld\252r "
gameforge.locale.questscroll_18_text = "\222ehir yok edilmi\254, \231\252r\252t\252lm\252\254 g\246r\252n\252yor. B\252t\252n bu[ENTER]ac\253n\253n sebebi herkese yay\253lmaya ba\254layan gizemli[ENTER]hastal\253k. Bu hastal\253\240a yakalananlar insanlara[ENTER]sald\253r\253yor ve onlar\253 yiyorlar. Son derece[ENTER]tehlikeliler.[ENTER]35 tane gizemli hastal\253\240a yakalanm\253\254 asker \246ld\252r.[ENTER]E\240er bu g\246revi ba\254ar\253rsan, bu \246d\252l\252 alacaks\253n: "
gameforge.locale.questscroll_19_hunt = "Gizemli hastal\253\240a yakalanm\253\254 ok\231ular "
gameforge.locale.questscroll_19_mis = "Gizemli hastal\253\240a yakalanm\253\254 ok\231ular\253 \246ld\252r "
gameforge.locale.questscroll_19_text = "Gizemli hastal\253\240a yakalanan ok\231ular, son derece[ENTER]tehlikeli olmaya ba\254l\253yorlar. Zehirli oklar[ENTER]f\253rlat\253yor, vurduklar\253 t\252ccarlar\253 ve di\240er[ENTER]insanlar\253 \254oka sokuyorlar. Bu \254ekilde onlar\253[ENTER]rahatl\253kla yakalayabiliyorlar.[ENTER][ENTER]25 tane gizemli hastal\253\240a yakalanm\253\254 ok\231u \246ld\252r.[ENTER]E\240er ba\254ar\253rsan bu \246d\252l\252 alacaks\253n: "
gameforge.locale.questscroll_1_hunt = "Ate\254 ay\253lar\253 "
gameforge.locale.questscroll_1_mis = "25 tane ate\254 ay\253s\253 \246ld\252r "
gameforge.locale.questscroll_1_text = "Ate\254 ay\253lar\253 \254ehir yak\253nlar\253nda s\253k\231a bulunurlar.[ENTER]Bozk\253rlarda ve geni\254 insan yollar\253nda gezerler.[ENTER]Her ge\231en g\252n daha \231ok insan onlar\253n kurban\253[ENTER]oluyor. Bir\231ok insan \246ld\252. Ate\254 ay\253lar\253n\253 \246ld\252r.[ENTER]25 tanesini \246ld\252rd\252\240\252nde bu \246d\252l\252 alacaks\253n: "
gameforge.locale.questscroll_20_hunt = {}
gameforge.locale.questscroll_20_mis = "4 tane d\252\254man \246ld\252r "
gameforge.locale.questscroll_20_text = "Korkar\253m ki art\253k bittim! G\246r\252\254\252m[ENTER]bulan\253kla\254\253yor... Bu mektubu okudu\240un zaman,[ENTER]bedenim par\231alanm\253\254 olacak. Bu sefiller beni[ENTER]yakalay\253p esir ald\253lar. Ellerinden ka\231abildim ama[ENTER]yaralar\253m \231ok derin ve beni mahvettiler. Seni[ENTER]tan\253m\253yorum. Ama l\252tfen intikam\253m\253 al![ENTER]Sava\254 b\246lgesinde 4 tane d\252\254man \246ld\252r. E\240er[ENTER]ba\254ar\253rsan kazanaca\240\253n \246d\252l: "
gameforge.locale.questscroll_2_hunt = "B\252y\252k kaplan "
gameforge.locale.questscroll_2_mis = "20 tane b\252y\252k kaplan \246ld\252r "
gameforge.locale.questscroll_2_text = "Bu \254eytani yarat\253\240\253n ad\253n\253 heryerde duyars\253n:[ENTER]b\252y\252k kaplan. Bu kaplanlar ana \254ehrin civar\253nda[ENTER]gezerler. \221nsanlara sald\253r\253p yiyorlar. Kurbanlar\253[ENTER]say\253s\253z.[ENTER]B\252y\252k kaplanlar\253 \246ld\252r. 20 tanesini \246ld\252rd\252\240\252nde[ENTER]bu \246d\252l\252 alacaks\253n: "
gameforge.locale.questscroll_3_hunt = "Da\240\253n K\246pek Tanr\253s\253 "
gameforge.locale.questscroll_3_mis = "Da\240\253n K\246pek Tanr\253s\253n\253 \246ld\252r "
gameforge.locale.questscroll_3_text = "Da\240\253n K\246pek Tanr\253s\253, k\246pek t\252r\252ndeki canavarlar\253n[ENTER]lideridir. \199ok g\252\231l\252 ve vah\254idir. Yak\253n ge\231mi\254te[ENTER]\254ehrin yak\253nlar\253nda t\252ccarlara sald\253r\253rken[ENTER]g\246r\252lm\252\254. \222imdiden bir s\252r\252 kurban\253 oldu.[ENTER]Yapt\253klar\253 art\253k g\246rmezden gelinemez boyuta[ENTER]ula\254t\253.[ENTER]K\246pek Tanr\253y\253 \246ld\252r. E\240er ba\254ar\253rsan bu \246d\252l\252[ENTER]alacaks\253n: "
gameforge.locale.questscroll_4_hunt = "Domuz Tanr\253 "
gameforge.locale.questscroll_4_mis = "Domuz Tanr\253y\253 \246ld\252r "
gameforge.locale.questscroll_4_text = "Y\253l\253n bu zaman\253nda, ekinler tamamen b\252y\252m\252\254 olur.[ENTER]Art\253k ekin bi\231me zaman\253d\253r; \231ift\231ilerin b\252t\252n o[ENTER]zor u\240ra\254lar\253n\253n kazanc\253n\253 alaca\240\253 zamand\253r bu.[ENTER]Fakat Domuz Tanr\253 ve onun ekibi b\252t\252n tarlalar\253[ENTER]bas\253p ekinleri yiyor. Onlar\253n a\231g\246zl\252l\252kleri[ENTER]art\253k \231ift\231ileri mahvetmi\254 durumda. Onlar\253[ENTER]\246ld\252rmeliyiz.[ENTER]Domuz Tanr\253y\253 \246ld\252r. Genelde Ana \222ehrin[ENTER]yak\253nlar\253nda bulabilirisn onu. E\240er g\246revi[ENTER]ba\254ar\253rsan bu \246d\252l\252 alacaks\253n: "
gameforge.locale.questscroll_5_hunt = "Ay\253 Tanr\253 "
gameforge.locale.questscroll_5_mis = "Ay\253 Tanr\253y\253 \246ld\252r "
gameforge.locale.questscroll_5_text = "Ay\253 Tanr\253 asl\253nda kendi do\240al ortam\253nda tehlikeli[ENTER]de\240ildir. Ancak \254u son zamanlarda \254ehre yakla\254t\253[ENTER]ve insanlara sald\253rmaya ba\254lad\253. Bir\231ok kurban\253n[ENTER]sorumlusu oldu. Ka\231 ki\254inin \254imdiye dek \246ld\252\240\252n\252[ENTER]s\246ylemek imkans\253z gibi.[ENTER]Ay\253 Tanr\253y\253 \246ld\252r. E\240er ger\231ekten onu ortadan[ENTER]kald\253rabilirsen alaca\240\253n \246d\252l: "
gameforge.locale.questscroll_6_hunt = "Kaplan Tanr\253 "
gameforge.locale.questscroll_6_mis = "Kaplan Tanr\253y\253 \246ld\252r "
gameforge.locale.questscroll_6_text = "Kaplan Tanr\253n\253n bunu yapt\253\240\253na ger\231ekten inanas\253m[ENTER]gelmiyor. Ben da\240 yolunda ne vakit kendisini[ENTER]g\246rsem ona dua eden basit bir kad\253nd\253m. Taa ki[ENTER]birg\252n Kaplan Tanr\253 ve onun yanda\254lar\253 aileme[ENTER]sald\253rana kadar. O sald\253r\253da ben de kolumu[ENTER]yitirmi\254tim. L\252tfen ailemin intikam\253n\253 al. E\240er[ENTER]Kaplan Tanr\253y\253 \246ld\252r\252rsen bu \246d\252l\252 alacaks\253n: "
gameforge.locale.questscroll_7_hunt = "Beyaz Yeminliler \231etesinin lideri "
gameforge.locale.questscroll_7_mis = "Beyaz Yeminliler \231etesinin liderini \246ld\252r "
gameforge.locale.questscroll_7_text = "Beyaz Yemin \231etesi, kocalar\253ndan ayr\253lm\253\254[ENTER]kad\253nlardan olu\254an bir \231etedir. K\246t\252 bir \254ekilde[ENTER]b\252t\252n d\252nyay\253 tehdit etmektedirler ve[ENTER]\254ehirlerimize sald\253r\253yorlar.[ENTER][ENTER]Daha fazla sald\253rmalar\253na izin veremeyiz. Beyaz[ENTER]Yeminliler \231etesinin 20 liderini \246ld\252r. E\240er bu[ENTER]g\246revi tamamlarsan bu \246d\252l\252 alacaks\253n "
gameforge.locale.questscroll_8_hunt = "Siyah R\252zgar \199etesinin lideri "
gameforge.locale.questscroll_8_mis = "Siyah R\252zgar \231etesinin liderini \246ld\252r "
gameforge.locale.questscroll_8_text = "Siyah R\252zgar \231etesinin h\253rs\253zlar\253, uzun zamandan[ENTER]beri t\252ccarlar\253m\253z\253 avl\253yorlar. Onlara geri d\246n\252p[ENTER]sald\253rabilecek kadar cesur kimse \231\253kmad\253. \199ok[ENTER]tehlikeliler. Ancak bu i\254 b\246yle gidemez.[ENTER]Siyah R\252zgar \231etesinin 20 liderini \246ld\252r. E\240er bu[ENTER]g\246revi bitirirsen alaca\240\253n \246d\252l: "
gameforge.locale.questscroll_9_hunt = "Yabanilerin \254efi "
gameforge.locale.questscroll_9_mis = "Yabanilerin \254efini \246ld\252r "
gameforge.locale.questscroll_9_text = "Yabaniler s\253n\253rlar\253m\253z\253 ge\231ip \254ehirlerimize[ENTER]sald\253rmaya ba\254lad\253klar\253ndan beri \231ok sorun[ENTER]ya\254\253yoruz. \214ld\252rd\252kleri insanlar\253n say\253s\253 y\252zleri[ENTER]ge\231ti.[ENTER]\222eytani yabaniler \231ok ac\253mas\253zlar ve onlara[ENTER]sald\253rabilecek kadar y\252rekli kimse yok. Ancak[ENTER]bunu daha fazla t\246lere edemeyiz.[ENTER]25 tane yabani \254efini \246ld\252r. E\240er ba\254ar\253rsan[ENTER]alaca\240\253n \246d\252l: "
