gameforge.locale.skill_group = {}
gameforge.locale.skill_group.board = "Bro\254\252rdeki mesaj:[ENTER]\221mparatorlu\240un huzur ve bar\253\254\253 i\231in sava\254acak[ENTER]g\246n\252ll\252 askerler ar\253yoruz![ENTER][ENTER]Orduya kat\253lmak i\231in gerekli seviye: 5 "
gameforge.locale.skill_group.dialog_assassin_1 = "Burada, d\252\254manlar\253na kar\254\253 sinsice saklan\253p[ENTER]ba\254ar\253yla pusu kurabilen, han\231er ve zehir[ENTER]kullanma sanat\253 \252zerinde ustala\254m\253\254 ninjalar[ENTER]yeti\254tiriyoruz. Sadece e\240er seviye 5 veya[ENTER]\252zerindeyseniz bu e\240itimlere kat\253labilirsiniz.[ENTER]E\240er sonsuza dek karanl\253klarda saklanacak bir[ENTER]ninja olmak istiyorsan bize gel, konu\254al\253m. "
gameforge.locale.skill_group.dialog_assassin_2 = "Burada, han\231er ve zehir kullanmak konusunda[ENTER]uzmanla\254m\253\254, karanl\253klarda iyice gizlenip[ENTER]ba\254ar\253l\253 pusular kurarak d\252\254manlar\253n\253 alt[ENTER]edebilen ninjalar yeti\254tiriyoruz. Gel yan yana[ENTER]sava\254al\253m. Haz\253r olan herkesi bekliyoruz. "
gameforge.locale.skill_group.dialog_assassin_3 = "Burada, yay kullanmakta ustala\254m\253\254 ninjalar[ENTER]yeti\254tiriyoruz. Bu nitelikteki ninjalar[ENTER]hedeflerini yanan oklarla \231ok uzak mesafelerden[ENTER]vurabilirler. E\240er sen de kat\253lmak istiyorsan gel[ENTER]ve benimle konu\254. En az seviye 5 ve \252st\252[ENTER]gerekmektedir. Uygun seviyeye geldi\240inde bir[ENTER]davet mektubu alacaks\253n. \221lgileniyorsan gel[ENTER]g\246r\252\254elim. "
gameforge.locale.skill_group.dialog_assassin_4 = "Burada, yay kullan\253m\253 \252zerinde ustala\254m\253\254[ENTER]ninjalar yeti\254tiriyoruz. Hedeflerini \231ok uzaktan[ENTER]yanan oklarla vurabilecek kahramanlardan olmak[ENTER]istiyorsan beni takip et, seni bu diyar\253n en iyi[ENTER]ok\231usu yapay\253m. "
gameforge.locale.skill_group.dialog_assassin_5 = "Yak\253n d\246v\252\254 ve uzak d\246v\252\254 yetenekleri aras\253nda[ENTER]se\231im yap ve yeteneklerine kavu\254. "
gameforge.locale.skill_group.dialog_shaman_1 = "Burada Ejder Tanr\253n\253n yolunu takip eden \254amanlar[ENTER]e\240itim al\253rlar. E\240itimlerinde t\253ls\253mlar\253 ve[ENTER]zihinsel g\252\231leri nas\253l kullanacaklar\253 \252zerinde[ENTER]uzmanla\254\253rlar. Onlar d\252\254manlar\253n\253n tekniklerini[ENTER]izler ve savunmalar\253n\253 buna g\246re yeniden[ENTER]yap\253land\253rabilirler. Ayr\253ca sava\254 meydan\253ndayken[ENTER]arkada\254lar\253na yard\253m edebilecek yetenekleri[ENTER]vard\253r. E\240er Ejder Tanr\253n\253n g\252c\252yle \231al\253\254maya[ENTER]haz\253rsan gel ve kat\253l. En az seviye 5 ve \252zeri[ENTER]kat\253labilir. Gereken seviyeye ula\254\253r ula\254maz,[ENTER]sana bir davet mektubu gelecek. Ejderha e\240itimine[ENTER]kat\253lmaya haz\253r oldu\240un zaman, tekrar bana gel. "
gameforge.locale.skill_group.dialog_shaman_2 = "Burada Ejder Tanr\253n\253n yolunu takip eden \254amanlar[ENTER]e\240itim al\253rlar. E\240itimlerinde kolye t\253ls\253mlar\253 ve[ENTER]zihinsel g\252\231leri nas\253l kullanacaklar\253 \252zerinde[ENTER]uzmanla\254\253rlar. Onlar d\252\254manlar\253n\253n tekniklerini[ENTER]izler ve savunmalar\253n\253 buna g\246re yeniden[ENTER]yap\253land\253rabilirler. Ayr\253ca sava\254 meydan\253ndayken[ENTER]arkada\254lar\253na yard\253m edebilecek yetenekleri[ENTER]vard\253r.Benimle Ejderha G\252c\252 hakk\253nda \231al\253\254maya[ENTER]haz\253r m\253s\253n? Al\231akg\246n\252ll\252 bir inanan\253n her zaman[ENTER]yan\253mda yeri vard\253r. "
gameforge.locale.skill_group.dialog_shaman_3 = "Burada Ejder Tanr\253n\253n yolunu takip eden \254amanlar[ENTER]e\240itim al\253lar. E\240itimlerinde do\240an\253n g\252c\252n\252 nas\253l[ENTER]kullanacaklar\253 \252zerinde uzmanla\254\253rlar. Onlar[ENTER]y\253ld\253r\253m, f\253rt\253na ve \254ifa sanat\253 \252zerinde[ENTER]uzmanla\254\253rlar. Ayr\253ca sava\254 meydan\253ndayken[ENTER]arkada\254lar\253na yard\253m edebilecek yetenekleri[ENTER]vard\253r. E\240er Ejder Tanr\253n\253n g\252c\252yle \231al\253\254maya[ENTER]haz\253rsan gel ve kat\253l.[ENTER]En az seviye 5 ve \252zeri kat\253labilir. Bu seviyeye[ENTER]geldi\240inde bir davet mektubu alacaks\253n. Seni[ENTER]bekliyor olaca\240\253m. "
gameforge.locale.skill_group.dialog_shaman_4 = "\254amanlar do\240an\253n ve \253\254\253\240\253n g\252\231lerini kullan\253rlar.[ENTER]burada \254im\254eklerin, f\253rt\253nalar\253n g\252c\252n\252n yan\253[ENTER]s\253ra, iyile\254tirmeyi de \246\240renirler. \221yile\254tirme[ENTER]yolunda ilerleyen \254amanlar grup halinde \231al\253\254\253r[ENTER]ve birbirlerini desteklerler.[ENTER]Ba\254kalar\253na yard\253m etmek istiyor musun?[ENTER]Senin deste\240in ac\253 \231ekenlere yard\253m edecek.[ENTER]L\252tfen bana yard\253m et. "
gameforge.locale.skill_group.dialog_shaman_5 = "Ejderha g\252c\252 ve iyile\254tirme sanat\253 aras\253nda[ENTER]se\231imini yap, ihtiyac\253n olan becerileri[ENTER]alacaks\253n. "
gameforge.locale.skill_group.dialog_sura_1 = "Ben insanlara b\252y\252y\252 nas\253l kullanacaklar\253n\253[ENTER]\246\240retirim. Z\253rhlar\253 ve k\253l\253\231lar\253 b\252y\252ler sald\253r\253[ENTER]ve savunma \246zelliklerini geli\254tiririm.[ENTER]Cehennemden d\252\254man\253n moralini mahvedecen[ENTER]yarat\253klar \231a\240\253r\253r\253m. Sadece Sura e\240itimini[ENTER]alanlar bunlar\253 yapabilir. Seviye 5 ve \252st\252[ENTER]olanlar i\231indir. Kat\253lmak istiyorsan gel[ENTER]konu\254al\253m. "
gameforge.locale.skill_group.dialog_sura_2 = "Ben insanlara b\252y\252y\252 nas\253l kullanacaklar\253n\253[ENTER]\246\240retirim. Z\253rhlar\253 ve k\253l\253\231lar\253 b\252y\252ler sald\253r\253[ENTER]ve savunma \246zelliklerini geli\254tiririm.[ENTER]Cehennemden d\252\254man\253n moralini mahveden yarat\253klar[ENTER]\231a\240\253r\253r\253m. B\252y\252l\252 silah e\240itiminin karanl\253k[ENTER]g\252\231lerini \246\240renmek istiyor musun? Bu e\240itimi[ENTER]ancak senin t\252r\252ndekiler alabilir. "
gameforge.locale.skill_group.dialog_sura_3 = "Buras\253 ilgini \231ektiyse dinle; Burada sadece[ENTER]kendini karanl\253\240a adayanlar kal\253r ve e\240itim[ENTER]al\253rlar. Z\253rhlar\253 ve k\253l\253\231lar\253 b\252y\252ler sald\253r\253 ve[ENTER]savunma \246zelliklerini geli\254tirmeyi \246\240renirler.[ENTER]Cehennemden d\252\254man\253n moralini mahveden yarat\253klar[ENTER]\231a\240\253r\253rlar. Sadece Sura e\240itimini alanlar bunlar\253[ENTER]yapabilir. Seviye 5 ve \252st\252 olanlar i\231indir.[ENTER]Kat\253lmak istiyorsan gel konu\254al\253m. Uygun seviyeye[ENTER]geldi\240inde bir davet mektubu alacaks\253n. E\240er[ENTER]karanl\253\240\253 evine \231a\240\253r\253rsan, burada karde\254lerini[ENTER]bulacaks\253n. "
gameforge.locale.skill_group.dialog_sura_4 = "Buras\253 ilgini \231ektiyse dinle; Burada sadece[ENTER]kendini karanl\253\240a adayanlar kal\253r ve e\240itim[ENTER]al\253rlar. Z\253rhlar\253 ve k\253l\253\231lar\253 b\252y\252ler sald\253r\253 ve[ENTER]savunma \246zelliklerini geli\254tirmeyi \246\240renirler.[ENTER]Cehennemden d\252\254man\253n moralini mahveden yarat\253klar[ENTER]\231a\240\253r\253rlar. Sadece Sura e\240itimini alanlar bunlar\253[ENTER]yapabilir. \221lgileniyorsan, bize kat\253l ve[ENTER]insanl\253\240\253n\253 geride b\253rak... "
gameforge.locale.skill_group.dialog_sura_5 = "Kara b\252y\252 veya b\252y\252l\252 silah sanatlar\253 aras\253nda[ENTER]se\231im yap. "
gameforge.locale.skill_group.dialog_warrior_1 = "Nerede oldu\240unu biliyor musun? Buras\253, en cesur[ENTER]ve h\253zl\253 sald\253rganlar\253n yeti\254tirildi\240i \252nitedir.[ENTER]Sald\253r\253lar\253 \231ok h\253zl\253 ve tekrarlanabilirdir. E\240er[ENTER]g\252c\252ne g\252veniyorsan gel ve konu\254al\253m. Buras\253[ENTER]k\253tadaki en m\252kemmel sava\254\231\253lar\253n \231\253kt\253\240\253 yerdir.[ENTER]Seviye 5 ve \252st\252 i\231indir. Uygun seviyeye[ENTER]geldi\240inde bir davey mektubu alacaks\253n. E\240er[ENTER]bedeninde ger\231ek g\252c\252 hissetmek istiyorsan,[ENTER]benimle gel! "
gameforge.locale.skill_group.dialog_warrior_2 = "Nerede oldu\240unu biliyor musun? Buras\253, en cesur[ENTER]ve h\253zl\253 sald\253rganlar\253n yeti\254tirildi\240i \252nitedir.[ENTER]Teknikleri \231ok h\253zl\253 ve tekrarlanabilirdir. E\240er[ENTER]g\252c\252ne g\252veniyorsan gel ve konu\254al\253m. Buras\253[ENTER]k\253tadaki en m\252kemmel sava\254\231\253lar\253n \231\253kt\253\240\253 yerdir.[ENTER]Seviye 5 ve \252st\252 i\231indir. Ne dersin? E\240itim almak[ENTER]istiyor musun? "
gameforge.locale.skill_group.dialog_warrior_3 = "Burada chi enerjisini kullanabilen sava\254\231\253lar[ENTER]yeti\254ir. Onlar yak\253n d\246v\252\254 sanatlar\253 \252zerinde[ENTER]biraz yava\254t\253rlar ancak ayn\253 anda s\252rekli[ENTER]tekrarlayan vuru\254lar yapabilirler. Bu tip[ENTER]sald\253r\253lar \231ok g\252\231l\252 ve etkilidir. Sadece 5.[ENTER]seviye ve \252zeri sava\254\231\253lar kat\253labilir. Uygun[ENTER]seviyeye geldi\240inde bir davet mektubu alacaks\253n.[ENTER]\221lgilenirsen, gel g\246r\252\254elim. "
gameforge.locale.skill_group.dialog_warrior_4 = "Burada chi enerjisini kullanabilen sava\254\231\253lar[ENTER]yeti\254ir. Onlar yak\253n d\246v\252\254 sanatlar\253 \252zerinde[ENTER]biraz yava\254t\253rlar ancak ayn\253 anda s\252rekli[ENTER]tekrarlayan vuru\254lar yapabilirler. Bu tip[ENTER]sald\253r\253lar \231ok g\252\231l\252 ve etkilidir. Sadece 5.[ENTER]seviye ve \252zeri sava\254\231\253lar kat\253labilir. Zihinsel[ENTER]sava\254 e\240itimine kat\253lmak istiyor musun? "
gameforge.locale.skill_group.dialog_warrior_5 = "Bedensel sava\254 ve zihinsel sava\254 ustal\253klar\253[ENTER]aras\253nda se\231imini yap, istedi\240in becerileri[ENTER]alacaks\253n. "
