gameforge.locale.skill_group.lets_join_skill_group_1 = "[COLOR r;1|g;0.6|b;0.6]Sava\254\231\253 e\240itimcilerinden[ENTER]anons[/COLOR][ENTER]E\240er sava\254\231\253lar\253n h\253zl\253 ve seri darbelerinden[ENTER]etkilenmi\254sen, sana bedensel sava\254 \246\240retmenine[ENTER]ba\254vurman\253 \246neririm. E\240er tek bir sald\253r\253yla bir[ENTER]canavar grubunu oldu\240u gibi yok etmek istiyorsan,[ENTER]sana zihinsel sava\254 \246\240retmenini \246neririm. \222ehir[ENTER]meydan\253n\253n yan\253nda seni bekliyoruz. "
gameforge.locale.skill_group.lets_join_skill_group_2 = "[COLOR r;1|g;0.6|b;0.6]Ninja e\240itimi hakk\253nda[ENTER]anons[/COLOR][ENTER]E\240er uzak d\246v\252\254 e\240itimi almak ve bir ok\231u olarak[ENTER]isim yapmak istiyorsan uzak d\246v\252\254\252 \246\240retmenini[ENTER]se\231, gizli g\246revleri tamamlamaya haz\253rsan hi\231[ENTER]bekleme ve yak\253n d\246v\252\254 ninja e\240itimlerine kat\253l.[ENTER]Seni \254ehir meydan\253n\253n yan\253nda bekliyor olaca\240\253z. "
gameforge.locale.skill_group.lets_join_skill_group_3 = "[COLOR r;1|g;0.6|b;0.6]Sura e\240itimcilerinden[ENTER]anons[/COLOR][ENTER]\221nsan\252st\252 g\252\231lere sahip olmak ve b\252y\252l\252 silah\253nla[ENTER]rakiplerine korku sa\231mak istiyorsan B\252y\252l\252 Silah[ENTER]e\240itimini \246neriyorum. Ancak karanl\253k g\252\231lerinden,[ENTER]lanetinden ve b\252y\252lerinden korkulan biri olmak[ENTER]istiyorsan\253z Kara B\252y\252 e\240itimi sizleri bekliyor.[ENTER]\222ehir meydan\253n\253n hemen yan\253nday\253z. "
gameforge.locale.skill_group.lets_join_skill_group_4 = "[COLOR r;1|g;0.6|b;0.6]\222aman e\240itimcilerinden[ENTER]anons[/COLOR][ENTER]E\240er yolda\254lar\253n\253n i\231indeki Ejderha Tanr\253s\253[ENTER]g\252c\252n\252 uyand\253rmak ve ate\254 p\252sk\252rtt\252\240\252 nefesini[ENTER]d\252\254manlar\253na kar\254\253 kullanmak istiyorsan, Ejderha[ENTER]G\252c\252 e\240itimini \246neriyorum.[ENTER]E\240er ba\254kalar\253n\253n ac\253 ve \252z\252nt\252lerini gideren[ENTER]ki\254i olmak istiyorsan, \221yile\254tirme \214\240retmeni'ne[ENTER]gitmeni \246neriyorum.[ENTER][ENTER]K\246y Meydan\253'nda seni bekliyorum. "
