gameforge.locale.stamina_food.butcher.start_say = "Restoranttaki ya\254l\253 adam Suhpyung:[ENTER]Benim v\252cudum art\253k eskisi gibi kullan\253labilir[ENTER]de\240il. Ben gen\231li\240imde, bir hafta durmadan[ENTER]\231al\253\254abilir ve yine de gece e\240lenmek i\231in enerji[ENTER]bulabilirdirm.[ENTER]Ama \254imdi sadece ayakta durmak bile yoruyor. Bu[ENTER]zamanlarda bir tas ye\254il kurba\240a \231orbas\253 enerji[ENTER]kazanmak i\231in \231ok iyi gelir. "
gameforge.locale.stamina_food.butcher.start_say2 = "Restoranttaki ya\254l\253 adam Suhpyung:[ENTER]Ye\254il kurba\240a \231orbas\253n\253n ne oldu\240unu bilir misin[ENTER]gen\231 adam?[ENTER]E\240er ondan bir tas i\231ersen bir daha asla[ENTER]yorulmazs\253n! B\252t\252n bir hafta tarlada \231al\253\254m\253\254[ENTER]olsan bile, geceleri kullanacak enerjin yine[ENTER]kal\253r.[ENTER]Oakgu ad\253nda bir arkada\254\253m var, bu \254ehirdeki en[ENTER]iyi ye\254il kurba\240a yapan a\254\231\253d\253r.[ENTER]Sebebi bilinmez fakat, art\253k bu \231orbalardan[ENTER]yapmay\253 b\253rakt\253. "
