gameforge.main_quest_flame_lv100._020_say = "Yak-Hwan seni ar\253yor. L\252tfen yan\253na git. "
gameforge.main_quest_flame_lv100._030_say = "Ho\254geldin. Yon-I Gezgini incelemelerini tamamlad\253.Ate\254 Diyar\253'nda g\246rd\252\240\252n \254ey karanl\253k maddeymi\254. "
gameforge.main_quest_flame_lv100._040_say = "Kalenin i\231inden ta\254\253p etraftaki \254eytanlarda[ENTER]de\240i\254ikliklere neden oluyor. Ne kadar uzun s\252re[ENTER]etkisi alt\253nda kal\253rlarsa o kadar g\252\231lenip[ENTER]sald\253rganla\254\253rlar. Bu kara maddenin \231o\240almas\253na[ENTER]engel olmal\253y\253z! "
