gameforge.main_quest_flame_lv100._160_sendLetter = "Ayla Tent\252r\252 "
gameforge.main_quest_flame_lv100._170_say = "Simyac\253 seni ar\253yor. Acil galiba. "
gameforge.main_quest_flame_lv100._180_say = "Tam bir felaket! Yak-Hwan'\253 dikkatli davranmas\253[ENTER]konusunda uyarm\253\254t\253m. O ne yap\253yor? Bizi k\253l\253\231lar[ENTER]elimizde karga\254aya s\252r\252kl\252yor. Yerle\254tikleri[ENTER]karakter \246ld\252\240\252nde kara madde b\252y\252r ve daha h\253zl\253[ENTER]\231o\240al\253r. \222imdi 300 hastal\253kl\253 \222eytan'\253n \246ld\252\240\252n\252[ENTER]duydum! Bu i\254in sonu pek iyi de\240il. "
gameforge.main_quest_flame_lv100._190_say = "Bu ko\254ullar alt\253nda kara maddeyi yok eden ayla[ENTER]tent\252r\252 de i\254e yaram\253yor. Bunlardan daha fazla[ENTER]\252retmek i\231in acilen malzemeye ihtiyac\253m var. "
