gameforge.main_quest_flame_lv100._250_say = "Verbleibende Zutaten "
gameforge.main_quest_flame_lv100._260_sayTitle = "Ayla Tent\252r\252 "
gameforge.main_quest_flame_lv100._270_say = "Bana 10 temel ta\254\253, 50 ay\253 safras\253, 10 \246r\252mce\240in[ENTER]zehir kesesi ve 200 enerji par\231as\253 getir. Bu[ENTER]malzemeleri Simyac\253'ya g\246t\252r. "
gameforge.main_quest_flame_lv100._280_say = "T\252m malzemeleri buldun! Harika, ben hemen i\254[ENTER]ba\254\253na ge\231eyim. Ayla tent\252r\252 haz\253r olur olmaz[ENTER]seni \231a\240\253r\253r\253m. "
gameforge.main_quest_flame_lv100._290_say = "Kara maddeyi hemen durduramazsak yak\253nda her \254ey[ENTER]berbat olacak. Hadi, bana ayla tent\252r\252 i\231in t\252m[ENTER]malzemeleri getir. "
