gameforge.main_quest_flame_lv100._310_say = "Simyac\253'yla konu\254. "
gameforge.main_quest_flame_lv100._320_sendLetter = "Kara Maddeyi Tut "
gameforge.main_quest_flame_lv100._330_say = "Of ya... Temel ta\254lar \231ok kaba \246\240\252t\252ld\252\240\252 i\231in[ENTER]demirciye \254ikayette bulundum. Ne mi oldu? Demirci[ENTER]al\253nd\253 ve kalan temel ta\254lar\253n\253 \246\240\252tmek[ENTER]istemiyor.[ENTER]Dikkafal\253 i\254te! Bir de sen konu\254san olmaz m\253? "
