gameforge.main_quest_lv1._50_sayReward = "\222ehir bek\231isiyle konus. Hedefi bul, okun[ENTER]g\246sterdigi yere git ve oraya t\253kla. Hedefi[ENTER]g\246remezsen, k\252\231\252k haritada yan\253p s\246nen noktay\253[ENTER]takip et. "
gameforge.main_quest_lv1._60_sayTitle = "\222ehir bek\231isi: "
gameforge.main_quest_lv1._70_say = "Sen yeni misin? G\246r\252n\252\254e g\246re, hen\252z sava\254\231\253[ENTER]olamam\253\254s\253n. \222imdiye kadar hi\231 bir sey \246\240rendin[ENTER]mi? Haline baksana!Silah\253 nasil kullanaca\240\253n\253[ENTER]bile bilmiyorsun. Dinle! Sava\254ta hayatta kalmak[ENTER]istiyorsan, hep uyan\253k olman lazim. 10. Seviyeye[ENTER]ula\254ana kadar ben sana yardi\253m edece\240im. Ben[ENTER]me\254gul bir insan\253m o nedenle vaktimi bo\254a[ENTER]harcama![ENTER]K\253p\253rda! "
gameforge.main_quest_lv1._80_say = "\222imdi git ve avlamay\253 \246\240ren! Arada k\246y meydanina[ENTER]git ve seviyen y\252kseldigi zaman bana d\246n![ENTER]Hala burada m\253s\253n? \214ylece kar\254\253mda durarak[ENTER]deneyim kazanamazs\253n! "
