gameforge.main_quest_lv10._120_sayReward = "Y\252zba\254\253'n\253n ilk g\246revi seni kom\254u k\246ye g\246t\252r\252yor.[ENTER]Orada m\252zisyen Yu-Hwan'\253 bulmal\253 ve Y\252zba\254\253'n\253n[ENTER]istedi\240i gizli belgeleri istemelisin. "
gameforge.main_quest_lv10._130_sayTitle = "M\252zisyen Yu-Hwan: "
gameforge.main_quest_lv10._140_say = "Hayat da her\254ey gibi bir r\252ya. Nereden geldik ve[ENTER]nereye gidiyoruz? D\252nya tamamen karma\254a i\231inde.[ENTER]D\252r\252stl\252k bitmi\254, kalmam\253\254...[ENTER]\222ark\253m\253 m\253 dinliyorsun? "
gameforge.main_quest_lv10._150_say = "Ah, seni Y\252zba\254\253 m\253 g\246nderdi? \222\254\254t, sesini al\231alt[ENTER]biraz...[ENTER]K\246ydeki hi\231kimse benim ger\231ek kimli\240imi bilmiyor.[ENTER]Seni Y\252zba\254\253 g\246nderdi\240ine g\246re g\252venilir[ENTER]olmal\253s\253n. Al, bu belge toplayabildi\240im t\252m[ENTER]bilgileri i\231eriyor, bunu Y\252zba\254\253'ya g\246t\252r. "
gameforge.main_quest_lv10._160_sayTitle = "M\252zisyen Yu-Hwan: "
gameforge.main_quest_lv10._170_say = "Hadi acele et! E\240er burada \231ok fazla durursan,[ENTER]k\246t\252 \254eyler olabilir. Hayat nedir? \214m\252r \231ok[ENTER]k\253sa... Nefes ald\253\240\253n m\252ddet\231e e\240lenebildi\240in[ENTER]kadar e\240len.  "
gameforge.main_quest_lv10._180_targetVid = "Y\252zba\254\253'ya geri d\246n. "
gameforge.main_quest_lv10._190_sayReward = "Casus olarak \231al\253\254an m\252zisyen Yu-Hwan sana \246nemli[ENTER]d\246k\252manlar verdi.[ENTER]Onlar\253 birinci k\246ydeki Y\252zba\254\253'ya g\246t\252r. "
gameforge.main_quest_lv10._200_say = "Bu belgeyi m\252zisyen mi g\246nderdi? Yeni bir[ENTER]macerac\253 i\231in fena de\240ilsin. Senin hakk\253nda \231ok[ENTER]iyi \254eyler bekliyorum. Yapt\253\240\253n i\254e kar\254\253l\253k bu[ENTER]\246d\252l\252 al. \220lken i\231in iyi i\254ler yapmaya devam et[ENTER]evlat! "
gameforge.main_quest_lv10._20_sayReward = "\222imdi krall\253\240\253na tam te\254ekk\252ll\252 bir sava\254\231\253[ENTER]olarak hizmet edecek kadar tecr\252be kazand\253n.[ENTER]\222imdi Y\252zba\254\253 sana yeni g\246revler verecek. Onu[ENTER]birinci k\246yde bulabilirsin. Git ve onunla konu\254;[ENTER]seni bekliyor. "
gameforge.main_quest_lv10._30_sayTitle = "Y\252zba\254\253 "
gameforge.main_quest_lv10._40_say = "Tan\253d\253k g\246r\252n\252yorsun... Ah, san\253r\253m seni[ENTER]duymu\254tum. Sen yeni macerac\253 olmal\253s\253n ve[ENTER]yeteneklerini kan\253tlad\253n. Tam olarak ne gibi[ENTER]yeteneklerin oldu\240unu a\231\253k\231as\253 bilmiyorum, ama[ENTER]ileride verece\240im g\246revlerle bunu g\246rece\240iz. "
gameforge.main_quest_lv10._50_say = "\214n\252nde kar\254\253la\254malar bekliyor, onlara[ENTER]haz\253rlanmal\253s\253n. \220\231 Krall\253\240\253n hikayesini bilir[ENTER]misin? Ya da Y\253ld\253r\253m Cenneti k\253tas\253n\253n[ENTER]hikayesini? Bilmiyorsun! E\240itimciler bu g\252nlerde[ENTER]ne \246\240retiyorlar, tanr\253m... Sana bu temel \254eyleri[ENTER]\246\240retmek zorunda m\253y\253m ben? "
gameforge.main_quest_lv10._60_say = "Peki, bak bu \231ok \246nemli \231\252nk\252 s\246zkonusu olan[ENTER]k\253tan\253n tarihini sana \246zet halinde anlataca\240\253m.[ENTER]Bir zamanlar, burada birle\254mi\254 bir krall\253k[ENTER]varm\253\254. Ne zaman ki Metin ta\254lar\253 ortaya \231\253kmaya[ENTER]ba\254lam\253\254, krall\253k \252\231 par\231aya b\246l\252nm\252\254: Shinsoo,[ENTER]ticaret krall\253\240\253, Chunjo, din krall\253\240\253 ve Jinno,[ENTER]askeri krall\253k. "
gameforge.main_quest_lv10._70_say = "Her krall\253k Metin ta\254lar\253n\253n ba\254lar\253na a\231t\253\240\253[ENTER]belalar\253 gidermeye \231al\253\254\253yor, krall\253klar\253n tekrar[ENTER]birle\254mesi i\231in \231al\253\254\253l\253yor. Sen de bunun i\231in[ENTER]\231al\253\254acaks\253n! Bu a\254\253r\253 \246nemli ve bunu unutma. "
gameforge.main_quest_lv10._80_say = "Sana ilk g\246revini veriyorum. Rahatla, basit bir[ENTER]g\246rev olacak.[ENTER]\221lerdeki k\246yde, m\252zisyen Yu-Hwan'\253 bulacaks\253n.[ENTER]\221nsanlar onun ordudan ayr\253l\253p m\252zisyen oldu\240unu[ENTER]d\252\254\252n\252rler.[ENTER]Ancak ger\231ekte, o bir casus. Onda benim ihtiyac\253m[ENTER]olan bir dok\252man var.[ENTER]Bana onu getirmelisin. Unutma, bu gizli bir g\246rev. "
gameforge.main_quest_lv10._90_say = "M-tu\254una bas ve k\246yden nas\253l \231\253kabilece\240ini g\246r.[ENTER]Haritada mavi nokta ile i\254aretlenen portal ile[ENTER]\253\254\253nlan.[ENTER]Acele et! M\252zisyen Yu-Hwan elinde b\252y\252k bir[ENTER]enstr\252man ta\254\253yor.  "
