gameforge.main_quest_lv15._100_say = "Jinno krall\253\240\253, uzun s\252redir askeri gelenekleri[ENTER]olan bir krall\253k. Kral bu k\253tay\253 g\252\231l\252 ve[ENTER]deneyimli birlikleri sayesinde birle\254tirdi. Ancak[ENTER]\254imdi Metin ta\254lar\253 y\252z\252nden tekrar b\246l\252nm\252\254[ENTER]durumda olsak bile Iryung'un g\252c\252 me\254ru olarak[ENTER]bizim krall\253\240\253m\253zdad\253r. "
gameforge.main_quest_lv15._10_qSetTitle = "\222u anki durum "
gameforge.main_quest_lv15._110_say = "Biz hala \252\231 krall\253k aras\253ndaki en g\252\231l\252 orduya[ENTER]sahibiz, ancak hala Metin ta\254lar\253 konusunda[ENTER]\231aresiz durumday\253z. E\240er ger\231ekten isteseydik,[ENTER]di\240er krall\253klar\253 rahat\231a ku\254atabilirdik. \221yi bir[ENTER]asker olabilmek i\231in \231ok zor e\240itimler alacaks\253n. "
gameforge.main_quest_lv15._120_say = "Sana yeni bir g\246rev veriyorum. Bu m\252himmat\253 kom\254u[ENTER]k\246ydeki Yu-Hwan'a yeti\254tir. Bizim krall\253\240\253m\253z \231ok[ENTER]g\252\231l\252 bir orduya sahip, fakat biz yeterince[ENTER]m\252himmat\253m\253z oldu\240u konusunda emin olmal\253y\253z.[ENTER]E\240er bu m\252himmat\253 Yu-Hwan'a yeti\254tirirsen, k\246y\252n[ENTER]savunmas\253na destek vermi\254 olacaks\253n. "
gameforge.main_quest_lv15._130_sayReward = "36.000 tecr\252be puan\253 kazand\253n.[ENTER]10.000 Yang kazand\253n.[ENTER]S\252s E\254yas\253 kazand\253n. "
gameforge.main_quest_lv15._140_sayTitle = "\222u anki durum "
gameforge.main_quest_lv15._150_sayReward = "Y\252zba\254\253 sana Yu-Hwan'a teslim edilecek \252r\252nler[ENTER]emanet etti. \221kinci k\246ye git ve \252r\252nleri ona[ENTER]g\246t\252r. "
gameforge.main_quest_lv15._160_say = "Bir zamanlar burda Sung Mahi ve Ejderha Tanr\253s\253[ENTER]sava\254t\253, o sava\254ta kan g\246vdeyi g\246t\252rd\252. O g\252nden[ENTER]beri insanlar ikiye b\246l\252nd\252 ve bitmek bilmeyen[ENTER]sava\254lar veriyorlar...[ENTER]Yine mi sen? Bir\254ey mi l\226z\253m? Y\252zba\254\253 bana \246nemli[ENTER]bir\254ey mi yolluyor?[ENTER]Sa\240ol. \222imdi yoluna devam et.[ENTER]Bizi birlikte g\246rmeleri iyi olmaz. "
