gameforge.main_quest_lv15._175_say = "Yu-Hwan'a Y\252ba\254\253'n\253n yollad\253\240\253 mallar\253 teslim[ENTER]ettin. \222imdi \246d\252l\252n\252 almak i\231in Y\252zba\254\253'n\253n[ENTER]yan\253na d\246n. "
gameforge.main_quest_lv15._180_say = "Aferin! B\246yle devam edersen k\246y\252m\252z\252n en[ENTER]vazge\231ilmez yard\253mc\253s\253 haline gelirsin. \221\254te[ENTER]\246d\252l\252n. "
gameforge.main_quest_lv15._20_say = "Krall\253klar aras\253 durumun \254u s\253ralar pek bar\253\254\231\253l[ENTER]olmad\253\240\253 haberini alm\253\254s\253nd\253r. Y\252zba\254\253'ya git.[ENTER]Sana daha ayr\253nt\253l\253 bilgi verebilir. "
gameforge.main_quest_lv15._30_say = "Mevcut durum hakk\253nda daha fazla bilgi edinme[ENTER]vaktin geldi san\253r\253m. Bizim krall\253\240\253m\253zla[ENTER]ba\254layay\253m. Sava\254\253 kazanmak i\231in, d\252\254manlar\253ndan[ENTER]\246nce kendini iyi tan\253mal\253s\253n. "
gameforge.main_quest_lv15._40_say = "Shinsoo: Bizim krall\253\240\253m\253z her zaman ticaret[ENTER]krall\253\240\253 olmu\254tur. \199ok bereketli ticaret[ENTER]yollarImIz vardir. Metin ta\254lar\253 g\246r\252nd\252kten[ENTER]sonra, ticaretimiz k\246t\252le\254meye ba\254lad\253. Biz[ENTER]ticaret krall\253\240\253y\253z, bizim orduya ihtiyac\253m\253z yok[ENTER]bu sebeple b\252y\252k bir ordumuz da olmad\253 \254imdiye[ENTER]dek.[ENTER]Biz genelde param\253zla koruyucular tutar\253z, onlar[ENTER]bize ba\240l\253d\253rlar ve g\252venilir olurlar. Biz de[ENTER]\246demelerini yapar\253z. "
gameforge.main_quest_lv15._50_say = "Koruyucular\253m\253za te\254ekk\252r etmeliyiz, sayelerinde[ENTER]ticaretimizi sa\240lam yap\253yor \252lkemizi dengede[ENTER]tutabiliyoruz. Fakat art\253k ilerde[ENTER]kar\254\253la\254aca\240\253m\253z sava\254lara haz\253rlanma vaktimiz[ENTER]geldi. Daha fazla koruyucuya ve g\252\231l\252 bir[ENTER]ekonomiye ihtiyac\253m\253z olacak.[ENTER]Bizi \231ok s\253k\253 \231al\253\254malar bekliyor ve buna sen de[ENTER]dahilsin. "
gameforge.main_quest_lv15._60_say = "Sana yeni bir g\246rev verece\240im. Bu e\254yay\253 al ve[ENTER]Yu-Hwan'a g\246t\252r. Krall\253\240\253m\253z bir ticaret[ENTER]krall\253\240\253d\253r ve amac\253m\253z iyi ticaret yapmakt\253r.[ENTER]K\226rl\253 ticaret. E\240er bunu Yu-Hwan'a ula\254t\253r\253rsan[ENTER]\252lken i\231in \231ok faydal\253 bir i\254 yapm\253\254 olacaks\253n. "
gameforge.main_quest_lv15._70_say = "Chunjo: Krall\253\240\253m\253z, velayetinde bulundu\240u Yoon[ENTER]Young taraf\253ndan y\246netilmektedir. Milletimiz,[ENTER]inanc\253m\253z \252zerine kurulmu\254 ve \254ekillenmi\254tir.[ENTER]Bu nedenle, biz Sung Mahi'nin varl\253\240\253n\253 herkesten[ENTER]\246nce bilirdik. \222amanlar\253m\253z bizi herkesten \246nce[ENTER]Metin ta\254lar\253n\253n geli\254ine haz\253rlam\253\254t\253. Bug\252n en[ENTER]iyi din adamlar\253m\253z milletin g\252venli\240i i\231in s\253k\253[ENTER]bir \254ekilde \231al\253\254maktad\253rlar. \222amanlar\253m\253z \231ok[ENTER]bilgedir. Onlar\253n mistik g\252\231leri onlar\253n[ENTER]g\252\231lerinin temelidir. Onlar olmasayd\253, daha \246nce[ENTER]bize sald\253ran d\252\254man \252lkeler bizi ele ge\231irir ve[ENTER]ku\254atabilirlerdi. "
gameforge.main_quest_lv15._80_say = "\220lkemizin insanlar\253 Ejder Tanr\253ya b\252y\252k ba\240l\253l\253k[ENTER]ve inan\231 duymaktad\253r. Ejder Tanr\253 bizi Sung[ENTER]Mahi'nin dirili\254inden korumaktad\253r. Kendimizi[ENTER]barbarca sald\253r\253lara kar\254\253 korumal\253y\253z ve[ENTER]imparatorlu\240u tekrar birle\254tirip kontrol alt\253na[ENTER]almal\253y\253z. "
gameforge.main_quest_lv15._90_say = "Sana yeni bir g\246rev verece\240im. Bu Ejder Tanr\253[ENTER]biblosunu al ve kom\254u k\246ydeki Yu-Hwan'a g\246t\252r.[ENTER]\221nan\231 ve ba\240l\253l\253\240\253m\253z krall\253\240\253m\253z i\231in en \246nemli[ENTER]\254eydir. E\240er bunu Yu-Hwan'a ula\254t\253r\253rsan,[ENTER]k\246yl\252lerin g\246z\252nde harika bir yer edinirsin. "
