gameforge.main_quest_lv30._10_targetVid = "Uriel'i bul "
gameforge.main_quest_lv30._110_say = "Uriel hakl\253ym\253\254: Ta\254 An\253t\253n \252zerinde ger\231ekten de[ENTER]yaz\253tlar vard\253. Okuyamad\253n ama bir kopyas\253n\253[ENTER]\231\253kard\253n. \222imdi notlar\253 Uriel'e g\246t\252r. "
gameforge.main_quest_lv30._120_say = "Hasun Ta\254 An\253t\253n\253 buldun mu? Ah elinde bir kopya[ENTER]var. \199ok iyi! Bu e\254siz bir tarihi ke\254if! Bir[ENTER]bakal\253m. Hmm... Bu Metin ta\254lar\253yla ilgili bir[ENTER]bilgi gibi duruyor. Fakat hepsini de\254ifre[ENTER]edemiyorum. Bu yaz\253 \231ok eski ve baz\253 harfler eski[ENTER]dillere ait. \222imdi ne yapaca\240\253z? "
gameforge.main_quest_lv30._130_say = "Ah, bir fikrim var! Seungryong vadisini biliyor[ENTER]musun? Orada gizemli bir eski b\246lge var. E\240er[ENTER]oradaki eski yaz\253tlar\253 bulursan onlar\253[ENTER]inceleyerek kay\253p harflerin neler oldu\240unu[ENTER]bulabilirim. Seungryong vadisine git ve Seul Rong[ENTER]Ta\254 An\253t\253n\253 bul. "
