gameforge.main_quest_lv30._150_say = "Ara\254t\253rmac\253 Uriel bilmedi\240i baz\253 harfleri[ENTER]\231\246zebilmek i\231in daha fazla eski yaz\253ta ihtiya\231[ENTER]duruyor.[ENTER]Seungryong vadisine git ve Seul Rong Ta\254 An\253t\253n\253n[ENTER]\252zerindeki yaz\253tlara bak. "
gameforge.main_quest_lv30._160_say = "Yaz\253tlar\253 buldun mu? Ah! Sayende k\253sa s\252rede[ENTER]metin ta\254lar\253n\253n s\253rr\253n\253 \231\246zebilece\240im.[ENTER]Ara\254t\253rmalar\253m d\252\254\252nd\252\240\252mden daha \231abuk sonu\231[ENTER]verecek. Te\254ekk\252rler, minnettar\253m! Tekar[ENTER]yard\253m\253na ihtiyac\253m olursa sana haber veririm. Ve[ENTER]\231abalar\253n\253n kar\254\253l\253\240\253nda bu k\252\231\252k \246d\252l\252 l\252tfen[ENTER]kabul et. "
gameforge.main_quest_lv30._20_sendLetter = "Metin Ta\254lar\253n\253n S\253rr\253 "
gameforge.main_quest_lv30._30_say = "Uriel sonunda Metin ta\254lar\253n\253n s\253rr\253 hakk\253nda[ENTER]biraz bilgi elde etti. Bilge Uriel'i bul.[ENTER]G\246revini bitirdi\240inde bir miktar Yang ve tecr\252be[ENTER]puan\253 kazanacaks\253n. "
gameforge.main_quest_lv30._40_sayTitle = "Uriel: "
gameforge.main_quest_lv30._50_say = "Y\252zba\254\253 seni zaten bana g\246ndermi\254ti. \199ok[ENTER]yetenekliymi\254sin. Senden bir iyilik isteyece\240im.[ENTER]Metin ta\254lar\253n\253 biliyorsun, birka\231 tane[ENTER]patlatm\253\254t\253n.[ENTER]Metin ta\254lar\253 g\246klerden gelmi\254. \222eytani enerji[ENTER]ta\254\253yorlar, salg\253n hastal\253klar yayarak hayvanlar\253[ENTER]delirtiyorlar. D\252nyam\253za nas\253l geldiklerini ve[ENTER]i\231lerinde ne oldu\240unu bilmiyoruz hen\252z.[ENTER]Bu benim ara\254t\253rmalar\253m\253 \231ok zorla\254t\253r\253yor. \222u[ENTER]s\253ralar, Metin ta\254lar\253n\253n s\253rr\253 hakk\253nda bir[ENTER]anahtar buldum. "
gameforge.main_quest_lv30._60_say = "Kolay maymun zindan\253nda antik krall\253ktan kalma[ENTER]bir an\253t varm\253\254. San\253r\253m o an\253t Metin ta\254lar\253[ENTER]konusunda bizi ayd\253nlatacak bilgiler i\231eriyor.[ENTER]E\240er bana o tableti getirebilirsen b\252y\252k bir[ENTER]ihtimalle Metin ta\254lar\253n\253n gizemini[ENTER]\231\246zebilece\240im. L\252tfen bana kolay maymun[ENTER]zindan\253nda bulunan tabletteki bilgileri getir! "
gameforge.main_quest_lv30._70_sayReward = "122.000 tecr\252be puan\253 kazand\253n.[ENTER]20.000 Yang kazand\253n.[ENTER]G\252m\252\254 Bilezik kazand\253n. "
