gameforge.main_quest_lv32._120_sayTitle = "Sat\253c\253: "
gameforge.main_quest_lv32._130_say = "D\252nya metin ta\254lar\253yla \231alkalanmaya ba\254lad\253\240\253[ENTER]zaman, ticaret daha da zorla\254t\253. Ne sat\253n almak[ENTER]istiyorsun?[ENTER]Ah, bilge Uriel mi g\246nderdi seni?[ENTER][ENTER]O d\252zenli bir m\252\254terim. S\252rekli farkl\253 mekanlarda[ENTER]antik yaz\253tlar arar. Yapt\253\240\253 i\254i \254ahsen e\240lenceli[ENTER]bulurum. Ha ha ha.[ENTER][ENTER]Eski kitaplar hakk\253nda bir\254eyler mi \246\240renmek[ENTER]istiyorsun? Hmm... Eski kitaplar hakk\253nda... "
gameforge.main_quest_lv32._140_say = "Birka\231 g\252n \246nce bir\254ey duydum, ama bunu sana[ENTER]kar\254\253l\253ks\253z anlatmam... E\240er istedi\240im \254eyi[ENTER]yaparsan, sana bilgiyi verece\240im. \222imdilik, \231ok[ENTER]say\253da silah ticareti mevcut. Elimde hi\231 kalmad\253.[ENTER]Herkes silah ar\253yor, heryrede! \221ste\240im \254u, bana[ENTER]20 tane G\252m\252\254 K\253l\253\231 +0 getirirsen bilgi senin[ENTER]olur. "
