gameforge.main_quest_lv32._350_sayTitle = "Kitab\253n ilk sayfas\253: "
gameforge.main_quest_lv32._360_sayReward = "Taejo krall\253\240\253ndan Lee Seop, ku\254atmalar yaparak[ENTER]krall\253\240\253n\253n topraklar\253n\253 geni\254letiyor. Askeri[ENTER]birlikleri olan heryeri ku\254atmay\253 ama\231 edinmi\254.[ENTER]Hen\252z bizimkini ku\254atmad\253, bunu ba\254armadan onu[ENTER]durdurmal\253y\253z. Se\231eneklerimiz \231ok s\253n\253rl\253, bundan[ENTER]dolay\253 ba\254ar\253 i\231in yasak b\252y\252lere ba\254vurmam\253z[ENTER]gerekecek! "
gameforge.main_quest_lv32._370_sayTitle = "Kitab\253n ilk sayfas\253n\253n devam\253: "
gameforge.main_quest_lv32._380_sayReward = "Kurtulu\254umuzun tek yolu bu. Ba\254ar\253l\253 olup[ENTER]olamayaca\240\253m\253z\253 bilmiyoruz, ancak kesinlikle[ENTER]denemeliyiz. Onlar bize sald\253rmadan \246nce[ENTER]yasaklanm\253\254 b\252y\252c\252l\252\240\252 \246\240renmemiz gerek. Eski[ENTER]s\246ylentilere bak\253l\253rsa, Ejderha Vadisinde bu[ENTER]bilgileri bulabiliriz. "
gameforge.main_quest_lv32._390_say = "\221\231eri\240e bak\253l\253rsa, bu \252lkede eski inan\231lar varm\253\254[ENTER]zaman\253nda. Lee Seop heryeri ku\254atmadan \246nce her[ENTER]\252lkenin kendi inanc\253 ve karakteristi\240i varm\253\254.[ENTER]Krall\253klardaki loncalar sayg\253nl\253\240\253 en y\252ksek[ENTER]s\253n\253fm\253\254. "
gameforge.main_quest_lv32._400_say = "Bu kitab\253 muhtemelen eski loncalardan birinin[ENTER]ba\254kan\253 yazm\253\254. \214ncelikle Ejderha Vadisine[ENTER]gitmeliyiz. Eminim ki orada kay\253p sayfalar[ENTER]hakk\253nda daha \231ok \254ey bulaca\240\253z. \222imdi kom\254u[ENTER]k\246yde Ejderha Vadisini \231ok iyi bilen bir avc\253[ENTER]var. Ejderha Vadisine gitmeden \246nce avc\253n\253n da[ENTER]yan\253na u\240ra. Belki o bir\254eyler biliyordur. "
gameforge.main_quest_lv32._40_say = "Selamlar. Son yapt\253\240\253n \231al\253\254ma \231ok yard\253mc\253 oldu.[ENTER]Yard\253m\253nla art\253k ger\231ekten i\254e yarar bir\254eyler[ENTER]yapabiliyorum. Ama bir sorunum var, \254eytan-kad\253n[ENTER]ve meteorlar hakk\253nda ara\254t\253rmalar yaparken antik[ENTER]dilde yaz\253lm\253\254 eski bir kitap buldum. Anlamak hi\231[ENTER]de kolay de\240il ama eminim \246nemli bir\254eyler[ENTER]yaz\253yor i\231inde. "
