gameforge.main_quest_lv32._50_say = "Sayfalar\253n eski olmas\253 b\252y\252k sorun, bu onlar\253[ENTER]\231\246zmeyi \231ok zorla\254t\253r\253yor. Kitap \231a\240lar boyunca[ENTER]elden ele gezmi\254 ve bu ona \231ok zarar vermi\254. 13[ENTER]tane sayfas\253 kay\253p. Onlar\253 benim i\231in bulabilir[ENTER]misin? Bu 13 sayfada muhtemelen sava\254\253n nas\253l[ENTER]bitebilece\240ine dair bilgiler var. \199ok \246nemli..! "
gameforge.main_quest_lv32._510_sayTitle = "Yang-Shin: "
gameforge.main_quest_lv32._520_say = "Ejder vadisi hakk\253nda bir\254eyler mi \246\240renmek[ENTER]istiyorsun? Neden b\246yle tehlikeli bir yeri[ENTER]ara\254t\253r\253yorsun ki? Ejder vadisi tamamen ork[ENTER]askerleriyle dolu ve gizli mezhebin adamlari da[ENTER]var. Harika bir avc\253 olarak ben bile oraya[ENTER]gitmekten ho\254lanm\253yorum. Uzak durmak daha iyi. "
gameforge.main_quest_lv32._530_say = "Ne? Eski sayfalar\253 m\253 ar\253yorsun? Hmm! Ba\254ka bir[ENTER]avc\253dan \246\240rendi\240ime g\246re ork b\252y\252c\252lerinde birka\231[ENTER]sayfas\253 varm\253\254. E\240er \231ok merak ediyorsan, git bak[ENTER]bakal\253m. Ben s\246yledim, oras\253 \231ok tehlikeli bir[ENTER]yer. Kendine \231ok dikkat et! "
