gameforge.main_quest_lv32._60_say = "Eski sayfalardan birini bulursan, bana getir. Ben[ENTER]\231\246zmeyi deneyece\240im. Hm... Bakmaya nereden[ENTER]ba\254lamal\253s\253n... Birka\231 zaman \246nce, kom\254u k\246ydeki[ENTER]bir seyyar sat\253c\253y\253 duymu\254tum. S\246ylentilere g\246re[ENTER]o eski sayfalardan birini buldu\240unu s\246yl\252yordu.[ENTER]Git ve onu g\246r, bak bakal\253m ne \246\240renebilirsin. "
gameforge.main_quest_lv32._610_sayReward = "Karab\252y\252 ile u\240ra\254an b\252y\252c\252ler bulundu. Ejderha[ENTER]vadisinde saklan\253yorlar. \220zerinden \231a\240lar ge\231en[ENTER]yasaklanm\253\254 b\252y\252c\252l\252\240\252 biliyorlar. Bize[ENTER]verdikleri sayfalardaki bilgileri okuyunca bu[ENTER]sanat\253n kullan\253lmas\253 i\231in \246zel bir alan[ENTER]gerekti\240ini anlad\253k. Bu alan tamamen \254eytani[ENTER]enerjiyle dolu olmal\253. B\246yle bir alan var mi?[ENTER]Zaman kalmad\253. En k\253sa s\252rede b\246yle bir alan[ENTER]bulmal\253y\253m. "
gameforge.main_quest_lv32._620_say = "Hmm, yasaklanm\253\254 b\252y\252 sanat\253, tamamen \254eytani[ENTER]enerjiyle dolu bir alan gerekiyor! Her\254eyin[ENTER]\254eytani enerjiye d\246n\252\254m\252\254 oldu\240u bir alan. Hmm,[ENTER]kesinlikle Karanl\253k Tap\253nak bu i\254 i\231in[ENTER]yarat\253lm\253\254. Oras\253 sadece insanlar\253n de\240il,[ENTER]hayvanlar\253n bile girmek istemedi\240i bir yer. Gizli[ENTER]g\252\231lerin yarat\253klara h\252kmetti\240i yer... "
gameforge.main_quest_lv32._630_say = "Gizli g\252\231lerle yasaklanm\253\254 b\252y\252 sanat\253 aras\253nda[ENTER]bir ba\240 var, daha da \246nemlisi karanl\253k tap\253na\240a[ENTER]girmek i\231in bir anahtar gerekiyor. Anahtar\253 bul[ENTER]ki s\253rr\253 \231\246zmeye ba\254layabilelim.[ENTER][ENTER]\221kinci sayfa i\231in \246d\252l\252n... "
