gameforge.main_quest_lv40._280_sayTitle = "D\246rd\252nc\252 sayfa: "
gameforge.main_quest_lv40._290_sayReward = "Ben maymunlar\253n ya\254ad\253\240\253 b\252y\252k bir ma\240araday\253m,[ENTER]ancak san\253r\253m burada k\246t\252 enerji yetersiz. Zaman[ENTER]doluyor... \214zel bir metod hala yok ve insanlar[ENTER]korkular\253na yenik d\252\254meye ba\254lad\253lar. Lee Seop[ENTER]bizim krall\253\240\253m\253za yeti\254meden \246nce uygun bir yer[ENTER]bulabilecek miyiz acaba? Ah, akl\253ma korkun\231[ENTER]d\252\254\252nceler geliyor... "
