gameforge.main_quest_lv40._30_sayTitle = "\220\231\252nc\252 sayfay\253 buldun "
gameforge.main_quest_lv40._310_sayReward = "En yak\253n zamanda di\240er yeri de bulmal\253y\253m. Hen\252z[ENTER]bir\254ey kaybetmedik. \214r\252mcek ma\240aralar\253n\253[ENTER]deneyece\240im. Bu defa olmas\253n\253 umuyorum... "
gameforge.main_quest_lv40._320_say = "Hm. Maymun zindan\253 arad\253\240\253m\253z yer de\240il... Buna[ENTER]g\246re, \246r\252mcek ma\240aralar\253n\253 denemeliyiz. Bir\231ok[ENTER]insan bizim k\246y\252m\252ze geliyor. Y\252zba\254\253 \231o\240undan[ENTER]bir\231ok bilgi edinmi\254. Kalbinin ac\253yla dolmas\253n\253n[ENTER]sebebi bu. "
gameforge.main_quest_lv40._330_say = "Sebebini bilmiyorum ama, iyi hissetmiyorum.[ENTER]Bakal\253m Y\252zba\254\253dan ne \246\240renebilece\240iz. Ah, az[ENTER]daha unutuyordum. D\246rd\252nc\252 sayfa i\231in \246d\252l\252n\252[ENTER]vereyim. "
