gameforge.main_quest_lv40._480_say = "Ah pekala, kabul ediyorum. Ama bunu sadece, bana[ENTER]\231ok fazla Yang verece\240ini s\246yledi\240i i\231in kabul[ENTER]ettim. Yabanc\253lar\253n ne istedi\240ini bilmiyorum. Ama[ENTER]bana bir g\246rev verdiler: Vah\254i Y\252zba\254\253lar\253[ENTER]\246ld\252rmek zorunday\253m. "
gameforge.main_quest_lv40._490_say = "Vah\254i Y\252zba\254\253'dan daha fazla bilgi alabilirsin.[ENTER]Yabanc\253lar benden onlar\253 \246ld\252rmemi istediler. Ah,[ENTER]bir fikrim var: Neden onlar\253 benim yerime sen[ENTER]\246ld\252rm\252yorsun? L\252tfen? "
