gameforge.main_quest_lv40._50_say = "Ah, bir sonraki ipucunu da buldun mu?! Bu \252\231\252nc\252[ENTER]sayfa, bakal\253m ne diyor. "
gameforge.main_quest_lv40._510_say = "Detayl\253 ara\254t\253rmalardan sonra, vah\254i Y\252zba\254\253lar\253n[ENTER]bu yabanc\253lar\253n geli\254inden sorumlu oldu\240unu[ENTER]\246\240rendim. Sayfalar\253n ne dedi\240ini anlayabilmek[ENTER]i\231in birka\231 vah\254i Y\252zba\254\253 \246ld\252rmem gerek. Vah\254i[ENTER]Y\252zba\254\253lar ikinci k\246y\252n civar\253nda bulunuyorlar. "
gameforge.main_quest_lv40._520_sendLetter = "Be\254inci sayfay\253 buldun "
gameforge.main_quest_lv40._530_say = "Detayl\253 ara\254t\253rmalardan sonra, bu kadar[ENTER]yabanc\253n\253n gelmesinin tek sorumlusunun vah\254i[ENTER]Y\252zba\254\253lar oldu\240unu \246\240rendim. Daha sonrada[ENTER]Y\252zba\254\253y\253 \246ld\252rd\252m ve di\240er sayfay\253 ald\253m. Bu[ENTER]be\254inci sayfa. Bu sayfada \231\246zemedi\240im baz\253[ENTER]harfler var. En iyisi bu sayfay\253 bilge Uriel'e[ENTER]g\246t\252rmek, o bunlar\253 benim i\231in \231\246zebilir. "
