gameforge.main_quest_lv40._70_sayReward = "\222eytani enerjinin d\246n\252\254t\252\240\252 yere geldik. Ancak bu[ENTER]yetersiz... Bu b\252y\252y\252 nerede yapacaks\253n? Yongbi[ENTER]\231\246l\252ndeki gizli yer hakk\253nda bilgiler var. B\252t\252n[ENTER]umudumuzla oraya \253\254\253nlanaca\240\253z. "
gameforge.main_quest_lv40._80_say = "Hmm.. Ejderha vadisindeki ama\231lar\253n\253[ENTER]ba\254aramad\253lar... Hmm.. Yongbi \231\246l\252nde \231ok nadiren[ENTER]insanlara rastlars\253n ve b\252y\252k \231o\240unlu\240u hala[ENTER]ke\254fedilmemi\254tir. \199ok karma\254\253k, kendilerini[ENTER]nereye \253\254\253nl\253yorlar acaba? San\253r\253m en iyisi[ENTER]maymun zindan\253na gitmek. O derin bir zindan,[ENTER]\254eytani enerjinin dolu oldu\240u bir yer. "
gameforge.main_quest_lv40._90_say = "L\252tfen Jungsun Dong'a git ve ba\254ka an\253tlar bul.[ENTER]Biraz \254ans\253n yard\253m\253yla an\253tlar\253n yan\253nda daha[ENTER]fazla sayfa bulabilirsin. Ah, bu arada \252\231\252nc\252[ENTER]sayfa i\231in \246d\252l\252n\252 de almay\253 unutma. "
