gameforge.main_quest_lv47._150_say = "\214r\252mcek zindan\253nda ba\254ka bir an\253t buldun ve[ENTER]alt\253nc\253 sayfa da an\253t\253n hemen alt\253nda[ENTER]gizlenmi\254ti. Sayfay\253 Bilge Uriel'e g\246t\252r. "
gameforge.main_quest_lv47._160_npcChat = "Alt\253nc\253 sayfa "
gameforge.main_quest_lv47._170_say = "\214r\252mcek zindan\253 nas\253ld\253? Alt\253nc\253 sayfay\253[ENTER]bulabildin mi? Bu harika! Bakal\253m ne yaz\253yor.[ENTER]Buldu\240un \231ok iyi oldu, \231\252nk\252 \231ok fazla ki\254i[ENTER]bunlar\253 ar\253yor. Bu bilgi \231ok \246nemli olmal\253. "
gameforge.main_quest_lv47._180_say = "Ah, bu sayfay\253 okumak \231ok zor. Bunu \231\246zmek i\231in[ENTER]daha \231ok zamana ihtiyac\253m olacak. \221\231erdi\240i[ENTER]metinlere bak\253l\253rsa \231ok \246nemli bilgiler[ENTER]olmal\253lar. Belki gizli b\252y\252n\252n bize nas\253l[ENTER]yard\253mc\253 olabilece\240ini bu sayfadan \246\240renebilirim.[ENTER]Gizli b\252y\252 yasaklanm\253\254 ve bu yasak inan bana[ENTER]bo\254una de\240il. "
gameforge.main_quest_lv47._190_say = "Bu sayfay\253 \231\246zmek i\231in daha \231ok zamana ihtiyac\253m[ENTER]var. Bu arada, m\252zisyen Yu-Hwan'a gitsen iyi[ENTER]olacak. Ara\254t\253rmalar\253m\253z\253 destekleyecek baz\253[ENTER]\254eyler bildi\240ini duydum. Sen ona bakarken, ben de[ENTER]alt\253nc\253 sayfaya yak\253ndan bir bakm\253\254 olaca\240\253m.[ENTER]Alt\253nc\253 sayfa i\231in \246d\252l\252n burada. "
