gameforge.main_quest_lv47._270_npcChat = "Haber var m\253? "
gameforge.main_quest_lv47._280_say = "Hayat \231ok k\253sa, tad\253n\253 \231\253karmaya bak! Lay lay[ENTER]laay! Ah, yine sen gelmi\254sin. Herhalde seni Bilge[ENTER]Uriel g\246nderdi. Benden biraz bilgi toplamam\253[ENTER]istemi\254ti. B\252t\252n krall\253klar\253n etrafta \246nemli[ENTER]d\246k\252manlar arad\253\240\253n\253 duydum. Ama ne yaz\253k ki[ENTER]kimse bana i\231eri\240inden bahsetmedi. "
gameforge.main_quest_lv47._290_say = "Sadece sava\254 insana bu korku hissini ya\254atabilir.[ENTER]Her daim d\252\254manlar\253n\253n g\252\231lerine kar\254\253 haz\253rl\253kl\253[ENTER]olmal\253s\253n. Ge\231enlerde birka\231 \254ey duydum.[ENTER]Duydu\240uma g\246re \231\246l haydutlar\253 bizim i\231in \246nemli[ENTER]bir\254eyleri \231alm\253\254lar. San\253r\253m gidip onlardan ne[ENTER]oldu\240unu \246\240renebilir ve alabilirsin. "
