gameforge.main_quest_lv47._410_say = "Eski g\252nl\252\240\252n yedinci sayfas\253n\253 buldun. Onu[ENTER]Uriel'e g\246t\252r. "
gameforge.main_quest_lv47._420_say = "\221yi haber. Alt\253nc\253 sayfan\253n \231\246z\252lmesi tamamland\253.[ENTER]Ne? Ba\254ka bir tane daha m\253 buldun? Harika! Senin[ENTER]onlar\253 buldu\240un h\253zda \231\246zemiyorum. Hm.. Bir[ENTER]bakal\253m.. Ah!? Bu dilde mi yaz\253lm\253\254? Bunu nereden[ENTER]buldun? Bu karakterler ve kullan\253lan dil[ENTER]kal\253plar\253 sadece asil hanedan ailesi taraf\253ndan[ENTER]kullan\253l\253r. "
gameforge.main_quest_lv47._430_say = "Bu yaz\253 tipi \231ok nadiren ve \231ok az ki\254i[ENTER]taraf\253ndan kullan\253l\253r ve bunu \231\246zmek zordur. \199\246l[ENTER]haydutlar\253 taraf\253ndan soyulan birka\231 \254\252pheli[ENTER]yabanc\253 vard\253, onlar da bu yaz\253y\253[ENTER]kullan\253yorlard\253. Ama\231lar\253 nedir acaba? Haha! Bu[ENTER]i\254te iyice derine iniyoruz. E\240er b\246yle devam[ENTER]edecekse, \231ok dikkatli olmal\253y\253z. \214nemli hi\231bir[ENTER]noktay\253 atlamamam\253z gerek. "
