gameforge.main_quest_lv47._450_sayTitle = "Alt\253nc\253 sayfa: "
gameforge.main_quest_lv47._460_sayReward = "Zaman ak\253yor. \214r\252mcek Zindan\253nda kara b\252y\252[ENTER]yapmay\253 bile denedik ama yine de i\254e yaramad\253.[ENTER]G\246zden ka\231\253rd\253\240\253m\253z \254ey ne? Baz\253 gizemcilerimiz[ENTER]kara b\252y\252n\252n daha b\252y\252k kurbanlar istedi\240ini[ENTER]s\246yl\252yor. E\240er bu do\240ruysa, ola\240an\252st\252 b\252y\252k bir[ENTER]g\252\231 olmal\253. "
gameforge.main_quest_lv47._470_sayReward = "Peri masallar\253na ve efsanelere g\246re, bu tip[ENTER]b\252y\252ler kurban olarak insan ister. Ama sunakta[ENTER]onlar\253n sevdi\240i ki\254ileri \246ld\252r\252rsem itibar\253m[ENTER]ayaklar alt\253na d\252\254er. Uygun bir temsilciye[ENTER]ihtiyac\253m\253z var. \199\246ldeki Y\253lan K\253l\253\231\253lar\253[ENTER]deneyece\240iz. "
gameforge.main_quest_lv47._480_say = "Aha! \221nsanlar\253 kurban edemeyecekleri i\231in, Y\253lan[ENTER]Sava\254\231\253lar\253 kurban etmeyi se\231tiler. Bu geli\254meden[ENTER]ho\254land\253\240\253m s\246ylenemez. Bu i\254in sonu k\246t\252[ENTER]olacak... Yine de yapt\253klar\253 \254eyleri tekrarlamaya[ENTER]devam etmeliyiz. \199\246le git ve biraz Y\253lan K\253l\253\231\253[ENTER]ve Y\253lan Ok\231u \246ld\252r. Ne bulaca\240\253m\253z\253 kim[ENTER]bilebilir. Bu arada: \246d\252l\252n bu \231antan\253n i\231inde. "
