gameforge.main_quest_lv47._560_sayTitle = "Sekizinci sayfa: "
gameforge.main_quest_lv47._570_sayReward = "Gerekli kurbanlar bulundu. \222ansl\253y\253z. Bu bir[ENTER]i\254aret mi acaba? Bir t\246ren \231an\253na ihtiyac\253m\253z[ENTER]var. San\253r\253m \246r\252mceklerde b\246yle bir \231an oldu\240unu[ENTER]hat\253rl\253yorum. Hemen yola \231\253k\253yoruz. "
gameforge.main_quest_lv47._580_say = "Ah, tekrar \246r\252mcek zindan\253, ilgin\231. Oraya gidip[ENTER]\231an\253 aramal\253y\253z. Bu yorucu bir yolculuk olacak,[ENTER]bu nedenle \246nce biraz dinlen ve \246yle gel. Ben de[ENTER]o s\253rada biraz d\252\254\252n\252r ve bu yaz\253lar\253 terc\252me[ENTER]ederim. Geri geldi\240inde sana yeni bir g\246rev[ENTER]verece\240im. Endi\254elenme, sekizinci sayfa i\231in[ENTER]\246d\252l\252n i\254te burada. "
gameforge.main_quest_lv47._590_sayReward = "Tecr\252be puan\253: 3.000.000[ENTER]Yang: 70.000[ENTER]Cesaret Pelerini: 20[ENTER]Not: Bir sonraki g\246revi alabilmen i\231in seviye 50[ENTER]olmal\253s\253n. "
gameforge.main_quest_lv47._60_sayReward = "Lee Seop suvarileriyle birlikte Taejo Krall\253\240\253'na[ENTER]geldi ve orada bir s\252re kalmak istedi. Bu s\253rada[ENTER]b\252y\252kl\252 k\252\231\252kl\252 meteorlar \252lkenin \252st\252ne ya\240maya[ENTER]ba\254lad\253.[ENTER]Ortamda kaos, y\253k\253m ve \231at\253\254ma vard\253. Koskoca[ENTER]krall\253k k\252\231\252c\252k 3 krall\253\240a bile b\246l\252nd\252. En[ENTER]k\246t\252s\252 de bu 3 krall\253k birlikte k\246t\252l\252\240e kar\254\253[ENTER]sava\254mak yerine birbirleriyle sava\254\253yorlard\253.[ENTER]Ejder Ejderha Tanr\253 art\253k bizlerle konu\254muyor.[ENTER]Bazen bir taraf\253 tutuyor bazen de di\240erini.[ENTER]Herkes kendi \231\253kar\253 i\231in sava\254\253yor ve bu s\253rada[ENTER]felaket giderek daha k\246t\252ye gidiyor... "
gameforge.main_quest_lv47._70_sayTitle = "Uriel: "
gameforge.main_quest_lv47._80_say = "Bu d\246nemimizin ilk g\252nlerine tan\253kl\253k etmek gibi.[ENTER]Paha bi\231ilemez! Ah, evet, \246deme. \221\254te harika[ENTER]\231al\253\254man i\231in \246d\252l\252n. Ve bir\254ey daha: Bizim gibi[ENTER]bu ara\254t\253rman\253n pe\254ine d\252\254en ba\254kalar\253 da var.[ENTER]Yani kaybedecek vaktimiz yok.Bu sayfan\253n sonunda[ENTER]Lee Seop'un \246r\252mcek zindan\253nda \254eytani g\252\231leri[ENTER]arad\253\240\253 yaz\253yor. E\240er orada bir\254eyler bulursan[ENTER]bana haber ver.[ENTER]Sab\253rs\253zlan\253yorum! "
