gameforge.main_quest_lv50._235_sayTitle = "Kitab\253n onuncu sayfas\253: "
gameforge.main_quest_lv50._240_sayReward = "\221lk sald\253r\253y\253 geri p\252sk\252rtmeyi ba\254ard\253k.[ENTER]Ancak yeni bir sald\253r\253 da yolda. Bu alanda Lee[ENTER]Seops'un \231elik kuvvetlerinin ilerleyememesi bize[ENTER]avantaj sa\240l\253yor \231\252nk\252 \231ok say\253da olduklar\253 i\231in[ENTER]kazanmam\253z m\252mk\252n de\240il. Ara\254t\253rmalar\253m\253z\253 kara[ENTER]b\252y\252 ile tamamlamaktan ba\254ka \231aremiz yok. Gecenin[ENTER]karanl\253\240\253nda d\252\254man hatt\253n\253 yar\253p ge\231ece\240iz sonra[ENTER]da \214r\252mcek Zindan\253'na d\246nece\240iz. Dua ediyorum,[ENTER]kazanmak i\231in de\240il sadece bir k\253v\253lc\253m umut[ENTER]\253\254\253\240\253 i\231in... "
