gameforge.main_quest_lv50._360_sayReward = "Ahh, hay\253r. B\252y\252 ba\254ar\253s\253z oldu. Yan etkileri[ENTER]y\252z\252nden herkes ak\253l hastal\253klar\253 ya\254ad\253. Tamamen[ENTER]hayal k\253r\253kl\253\240\253, art\253k enerjimiz ve sava\254a[ENTER]kat\253lacak kimsemiz kalmad\253. Lee Seop'un z\253rhl\253[ENTER]birlikleri \231ok yak\253nda olmal\253.[ENTER][ENTER]Hay\253r! Bize b\252y\252 hakk\253nda bilgi veren ki\254iler[ENTER]yalan s\246yledi! Lanet olsun! Yalan!!! "
gameforge.main_quest_lv50._365_sayTitle = "Onbirinci sayfan\253n devam\253: "
gameforge.main_quest_lv50._370_sayReward = "K\253zg\253nl\253kla ejderha vadisine gidip bize bu[ENTER]bilgiyi veren ki\254ileri bulmaya gittik ama onlar[ENTER]da kaybolup gitmi\254! \222imdi izini takip edip[ENTER]bulmay\253 deneyece\240iz. Bilgi edinir edinmez,[ENTER]yolumuza devam edece\240iz. "
gameforge.main_quest_lv50._380_say = "Haha! Sonunda, d\252\254\252nd\252kleri gibi b\252y\252 \231al\253\254mam\253\254.[ENTER]Tam bir hayal k\253r\253kl\253\240\253. Karanl\253k sayfalarda[ENTER]yazan bilgiler \231ok \254\252pheli, ara\254t\253rmaya devam[ENTER]etmeliyiz... Yan etkilerinden hi\231 s\246z[ENTER]etmemi\254lerdi. \199ok yakla\254t\253k, ne kadar tehlikeli[ENTER]olsa da devam etmeliyiz. "
