gameforge.main_quest_lv55._350_sayReward = "...Bitti...[ENTER]\221lk ba\254ta her\254ey yolunda g\246r\252n\252yordu. Odan\253n i\231i[ENTER]enerji ve ho\254 seslerle doldu, sonra i\231imi birden[ENTER]tuhaf bir his kaplad\253. Alt\253 silah arkada\254\253m yere[ENTER]d\252\254t\252. Tap\253nak sallanmaya ba\254lad\253. Sonra aniden[ENTER]y\253ld\253r\253m \231akt\253 ve arkaya f\253rlat\253ld\253k. Kuvvet[ENTER]hatlar\253 koptu.. \222imdi ortal\253k sakin. Yolda\254lar\253m[ENTER]\246ld\252 ve yerde yat\253yor. B\252y\252, fiyaskoyla[ENTER]sonu\231land\253. Beceremedik. "
gameforge.main_quest_lv55._360_say = "Bu nedir? B\246yle bir\254ey beklemiyorduk. Eski b\252y\252[ENTER]son umudumuzdu, fakat bize bir hi\231 getirdi...[ENTER]Bana sorarsan, onlar ac\253mas\253z yarat\253klar\253 tamamen[ENTER]kontrol alt\253na alamad\253klar\253 i\231in \246yle oldu. E\240er[ENTER]b\252y\252 tehlikeli de\240ilse, orada ba\254ka ve \231ok b\252y\252k[ENTER]bir g\252\231 daha olmal\253.[ENTER]\222imdi biraz mola vermeliyiz. Gidip biraz[ENTER]yataca\240\253m, ba\254\253m a\240\253r\253yor.[ENTER][ENTER]B\252t\252n bu \231eviriler ve hayal k\253r\253kl\253\240\253 i\231in[ENTER]te\254ekk\252r ederim. "
