gameforge.main_quest_lv66._100_say = "\221nan\253lmaz! Bunun ne anlama geldi\240ini anl\253yor[ENTER]musun? \222eytan Kulesi'nde asl\253nda hi\231 \254eytan ve[ENTER]hayaletler yoktu. Bu Ejderha Rahibesinin miras\253.[ENTER]Lee Seops'un s\252vari s\253n\253f\253n\253 \252mitsiz son bir[ENTER]denemeyle yok etme \231abas\253 \254eytanlara bu karanl\253k[ENTER]rit\252el nedeniyle d\252nyam\253z\253n kap\253s\253n\253 a\231t\253.[ENTER]Sonunda bunu hayat\253yla \246dedi. "
gameforge.main_quest_lv66._10_sendLetter = "G\252nl\252k "
gameforge.main_quest_lv66._110_say = "Demek ki Lusifer, \254eytan heyetiyle birlikte bu[ENTER]\254ekilde d\252nyam\253za geldi. Yine de karanl\253k[ENTER]milletin ve Ejderha Rahibeleri'nin b\252y\252k g\246revi[ENTER]ba\254ar\253s\253z oldu: Sung Mahi'nin b\252y\252s\252[ENTER]ger\231ekle\254medi, Lee Seop ise g\252\231 kazand\253 ve bir[ENTER]d\252nya krall\253\240\253 daha kurdu.[ENTER]Yard\253m\253n sayesinde hayat\253m\253n b\252y\252k gizemini[ENTER]\231\246zd\252m! "
gameforge.main_quest_lv66._120_say = "\214d\252l olarak sana kutsanm\253\254 par\254\246men vermek[ENTER]istiyorum. L\252tfen hediyemi kabul et, \231ok rica[ENTER]ediyorum. "
gameforge.main_quest_lv66._130_sendLetter = "Mektubun var. "
gameforge.main_quest_lv66._140_say = "K\246y meydan\253n\253n n\246bet\231isinin sana bir mektubu var.[ENTER]Oku ve gizemli g\246nderenin kim oldu\240unu \246\240ren. "
gameforge.main_quest_lv66._150_say = "Son zamanlarda pek g\246r\252nm\252yorsun. Sana bu mektubu[ENTER]vermemi istediler - kimden oldu\240unu bilmiyorum,[ENTER]bana kendini tan\253tmad\253. "
gameforge.main_quest_lv66._160_say = "Mektubun yaz\253ld\253\240\253 ka\240\253t \231ok eski g\246r\252n\252yor.[ENTER]Aceleyle \254unlar yaz\253lm\253\254:[ENTER]Yedi Ejderha Rahibesi ve Sung Mahi ile ilgili[ENTER]\246nemli bilgilere sahibin. \222eytan Kulesi'nin arka[ENTER]k\253sm\253nda, Hwang Tap\253na\240\253'nda seni bekliyorum.[ENTER]Beni a\240ac\253n g\246lgesinde bulacaks\253n. Acele et,[ENTER]fazla vaktimiz yok! "
gameforge.main_quest_lv66._170_sendLetter = "Anonim Mektup "
gameforge.main_quest_lv66._180 = "Hwang Tap\253na\240\253'na git ve \222eytan Kulesi'nin arka[ENTER]taraf\253nda gizemli mektup g\246ndereniyle bulu\254. "
gameforge.main_quest_lv66._190_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._200_say = "Ho\254geldin! \214nce izninle kendimi tan\253tay\253m: Ad\253m[ENTER]Lee Chung.[ENTER]Yabanc\253 birinin talimat\253na uyman cesaretli[ENTER]oldu\240unu g\246steriyor. Yan\253lmam\253\254\253m - sen de buna[ENTER]pi\254man olmayacaks\253n.[ENTER]S\246yleyeceklerimi iyi dinle! "
gameforge.main_quest_lv66._20_say = "Uriel'in hayatta kalan son Ejderha Rahibesiyle[ENTER]ilgili haberleri var. G\252nl\252\240\252 \222eytan Kulesi'nde[ENTER]olmal\253. Konuyla ilgili ayr\253nt\253l\253 bilgi almak i\231in[ENTER]Uriel'e git. "
gameforge.main_quest_lv66._210_sendLetter = "Yeni K\246t\252l\252k "
gameforge.main_quest_lv66._220_say = "Lee Chung'un anlatacaklar\253n\253 iyi dinle. "
gameforge.main_quest_lv66._230_say = "Hwang Tap\253na\240\253'na gelmeni gerektiren bir durum[ENTER]var: Son zamanlarda burada tuhaf \254eyler oluyor.[ENTER]K\253sa zaman \246nce de \222eytan Kulesi'nin arka[ENTER]taraf\253nda devasa bir ma\240araya giden bir yol[ENTER]bulduk! "
gameforge.main_quest_lv66._240_say = "Devasa bir ma\240ara m\253? Peki i\231inde ne var? "
gameforge.main_quest_lv66._250_say = "Bu ma\240arada bizi yeni, ak\253l almaz bir k\246t\252l\252k[ENTER]bekliyor: Casuslar\253m\253z \254eytanlar\253 bile geride[ENTER]b\253rakan, deh\254et verici bir yarat\253ktan bahsetti.[ENTER]Korkutucu g\246r\252nt\252s\252 ve canl\253lara kar\254\253 doymak[ENTER]bilmeyen a\231 g\246zl\252l\252\240\252 nedeniyle onun \254eytan[ENTER]d\252nyas\253n\253n on b\252y\252k \254eytan\253ndan biri olan[ENTER]efsanevi Agwi oldu\240unu d\252\254\252n\252yoruz.[ENTER]E\240er hakl\253ysak insano\240lu b\252y\252k tehlike alt\253nda. "
gameforge.main_quest_lv66._260_say = "\222eytanlardan daha korkutucu demek... Bu yarat\253k[ENTER]ger\231ekten de \231ok g\252\231l\252 ve k\246t\252 olmal\253. "
gameforge.main_quest_lv66._270_say = "Evet \246yle. Adamlar\253m ve ben defalarca \222eytan[ENTER]Katakombu'na girmeyi denedik. Ama her seferinde[ENTER]ba\254ar\253s\253z olduk ve b\252y\252k kay\253plar verdik.[ENTER]Bu i\254te m\252kemmel bir sava\254\231\253ya ihtiyac\253m\253z var -[ENTER]seni buraya \231a\240\253rmam\253z\253n nedeni bu. Bize yard\253m[ENTER]edecek misin? "
gameforge.main_quest_lv66._280_say = "Evet, sana yard\253m edece\240im. "
gameforge.main_quest_lv66._290_say = "Oh, art\253k daha \252mitliyiz! Bizim taraf\253m\253zda[ENTER]oldu\240unu bildi\240im i\231in sana bir ger\231e\240i[ENTER]a\231\253klayaca\240\253m: Ben, G\246lge Sava\254\231\253lar\253 Kumandan\253,[ENTER]Lee Chung. Lee Seops'un gizli, se\231kin bir[ENTER]birli\240iyiz. "
gameforge.main_quest_lv66._300_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._30_say = "Ah seni b\246yle sa\240l\253kl\253 durumda g\246rmek ne g\252zel.[ENTER]Yeni bir maceraya haz\253r m\253s\253n? Karanl\253k millet ve[ENTER]yedi Ejderha Rahibesiyle ilgili hala \246nemli[ENTER]bilgilerimiz eksik. Son Ejderha Rahibesi kara[ENTER]b\252y\252y\252 yapmadan \246nce g\252nl\252\240\252 \222eytan Kulesi'ne[ENTER]gizlemi\254 olmal\253. Yola koyul ve bana o g\252nl\252\240\252[ENTER]getir. \222eytan Kral\253 onu elinde tutuyor olabilir. "
gameforge.main_quest_lv66._310_say = "G\246lge Sava\254\231\253lar\253 evveli ezeli gizliden gizliye[ENTER]Sung Mahi'nin yeniden dirili\254ini engelleme[ENTER]\231abas\253nda. Bu bizim g\246revimiz. Birlikte Agwi'yi[ENTER]tekrar ma\240aras\253na g\246ndermeye ve d\252nyam\253za nas\253l[ENTER]geldiklerini \246\240renmeye \231al\253\254al\253m! "
gameforge.main_quest_lv66._320_sendLetter = "Zaman yok "
gameforge.main_quest_lv66._330_say = "G\246lge Sava\254\231\253lar\253n\253n kumandan\253 Lee Chung seni[ENTER]ar\253yor. \199ok acil. "
gameforge.main_quest_lv66._340_say = "Senden acil bir ricam var. Kar\254\253 taraftaki yaral\253[ENTER]askeri g\246r\252yor musun? O benim emrimde \222eytan[ENTER]Katakombu'nu ara\254t\253ran casuslar\253mdan biri. Bu[ENTER]g\246rev s\253ras\253nda Agwi taraf\253ndan sald\253r\253ya u\240rad\253[ENTER]ve zehirlendi. Zehir v\252cuduna yay\253lmaya ba\254lad\253[ENTER]bile, fazla vakti kalmad\253. "
gameforge.main_quest_lv66._350_say = "Panzehire ihtiyac\253 var - hem de hemen![ENTER]Sen alabilir misin? K\253rm\253z\253 Orman'da k\253rm\253z\253[ENTER]orman perilerinde bulabilirsin. O, benim en[ENTER]\246nemli sava\254\231\253lar\253mdan biri - can\253n\253 kurtar ben[ENTER]de sana %s vereyim. "
gameforge.main_quest_lv66._360_say = "Panzehiri getirece\240im! "
gameforge.main_quest_lv66._370_say = "Te\254ekk\252r ederim! Hen\252z hayatta ama her ge\231en[ENTER]saniye daha da zay\253fl\253yor. Kaybedecek vaktimiz[ENTER]yok! "
gameforge.main_quest_lv66._380_notice = "%d dakikan kald\253. "
gameforge.main_quest_lv66._390_sendLetter = "Panzehir "
gameforge.main_quest_lv66._400_say = "Lee Chung sayesinde panzehiri K\253rm\253z\253 Orman'da[ENTER]bulabilece\240ini biliyorsun. Bunun i\231in %d K\253rm\253z\253[ENTER]Orman Perisi yakala.[ENTER][ENTER]K\253rm\253z\253 Orman, Hayalet Orman'dan daha tehlikeli,[ENTER]kendine dikkat et. "
gameforge.main_quest_lv66._40_say = "\222eytan Kral\253'n\253 alt ettin ve Ejderha Rahibesi'nin[ENTER]g\252nl\252\240\252n\252 ele ge\231irdin. Bunu Bilge Uriel'e g\246t\252r.[ENTER]O inceler. "
gameforge.main_quest_lv66._410_say = "S\252re ge\231ti. Asker \246lmek \252zere, ona hemen[ENTER]panzehiri g\246t\252r. "
gameforge.main_quest_lv66._420_say = "%d dakikan kald\253. "
gameforge.main_quest_lv66._430_say = "Nihayet panzehiri buldun! Onu hemen Lee Chung'a[ENTER]g\246t\252r. "
gameforge.main_quest_lv66._440_say = "Buraya, \231abuk! Son anda yeti\254ebildin. \199ok[ENTER]rahatlad\253m. Adamlar\253mla ben sana \231ok minnetar\253z. "
gameforge.main_quest_lv66._450_say = "Yard\253m\253n sayesinde askerim hayatta kald\253.[ENTER]Kurtard\253\240\253n i\231in i\254te \246d\252l\252n. "
gameforge.main_quest_lv66._460_say = "\199ok zaman harcad\253n. Son g\252c\252yle hayatta kalmaya[ENTER]\231al\253\254\253yor. Neyse ki son anda yeti\254ebildin. "
gameforge.main_quest_lv66._470_say = "\221\254e yar\253yor san\253r\253m. Ama \231ok ucu ucuna yeti\254tin,[ENTER]ama panzehiri bulmak amac\253yla bu kadar \231ok zaman[ENTER]kaybetti\240in i\231in neredeyse \246l\252yordu.[ENTER]\199ok \252zg\252n\252m, ama \246d\252l olarak verebilece\240im tek[ENTER]\254ey bu. "
gameforge.main_quest_lv66._480_sendLetter = "Rapor "
gameforge.main_quest_lv66._490_say = "Casus kendine geldi. \222eytan Katakombu'nda neler[ENTER]g\246rd\252\240\252n\252 dinle. "
gameforge.main_quest_lv66._500_say = "Beni kurtard\253\240\253n i\231in te\254ekk\252r ederim. \222eytan[ENTER]Katakombu'nda inan\253lmaz \254eyler g\246rd\252m. Ama sonra[ENTER]yakaland\253m ve... "
gameforge.main_quest_lv66._50_say = "Buldun! Son Ejderha Rahibesi'nin g\252nl\252\240\252![ENTER]Ellerim heyecandan tir tir titriyor. \221\231indekileri[ENTER]incelemek i\231in biraz zamana ihtiyac\253m olacak. Sen[ENTER]bu arada dinlen. Daha \231ok \254ey \246\240rendi\240im zaman[ENTER]seni \231a\240\253r\253r\253m. "
gameforge.main_quest_lv66._510_say = "Neler g\246rd\252n? "
gameforge.main_quest_lv66._520_say = "Kara pelerinli, y\252zleri kara kap\252\254onlar\253yla[ENTER]\246rt\252l\252 insanlar vard\253.[ENTER]Ettikleri bir iki lak\253rd\253dan Karanl\253\240\253n K\246leleri[ENTER]olduklar\253n\253 anlad\253m. Ama dahas\253 da var: Kad\253n[ENTER]siluetine benzeyen deh\254etli bir ruh, ba\254lar\253n\253n[ENTER]\252zerinde u\231uyordu. Karanl\253\240\253n K\246leleri bunlara[ENTER]Banshee diyordu. "
gameforge.main_quest_lv66._530_say = "Bu kula\240a pek iyi gelmiyor. Karanl\253\240\253n K\246leleri[ENTER]ve Banshee'nin amac\253 ne? "
gameforge.main_quest_lv66._540_say = "Banshee kara b\252y\252yle cehennem yar\253\240\253ndan gelen[ENTER]Agwi'ye \254eytans\253 varl\253klara b\252y\252 yapt\253.[ENTER]Agwiler'in Kral\253na Azrail diyorlard\253. "
gameforge.main_quest_lv66._550_say = "Lee Chung'a bunu rapor etmek i\231in hemen yola[ENTER]koyuldum. Ama aya\240\253m tak\253ld\253 ve d\252\254t\252m.[ENTER][ENTER]Ah, bu arada Kumandan Lee Chung sana \246nemli bir[ENTER]\254ey s\246yleyecekti. En iyisi hemen yan\253na git. "
gameforge.main_quest_lv66._560_sendLetter = "Karanl\253k Tehdit "
gameforge.main_quest_lv66._570_say = "Lee Chung'a git ve onunla \222eytan Katakombu'ndaki[ENTER]yeni tehditle ilgili konu\254. "
gameforge.main_quest_lv66._580_say = "Casusumun raporu korkutucu, de\240il mi? Agwiler'in[ENTER]ortaya \231\253kmas\253ndan bir t\252r tarikat olan[ENTER]Karanl\253\240\253n K\246leleri sorumluymu\254. Son Ejderha[ENTER]Rahibesi'nin ruhunu uyand\253rd\253lar.[ENTER]O da, k\246t\252n\252n g\246r\252nt\252s\252 Banshee olarak d\252nyaya[ENTER]geri d\246nd\252 ve b\252y\252l\252 g\252\231leri sayesinde \222eytan[ENTER]Tanr\253s\253 Sung Mahi'yi \231a\240\253racak. "
gameforge.main_quest_lv66._590_say = "Ne? Bu Banshee son Ejderha Rahibesi'nin ruhu[ENTER]muymu\254? "
gameforge.main_quest_lv66._600_say = "Kesinlikle. Ejderha k\252lt\252ndeki karde\254leri[ENTER]aras\253nda g\246ky\252z\252n\252n d\246rt kutsal n\246bet\231isini[ENTER]\231a\240\253rma ve kara b\252y\252 yapma g\252c\252ne bir tek o[ENTER]sahipti. Art\253k bu yeni tehdidin arkas\253nda kim[ENTER]oldu\240unu biliyoruz: Karanl\253\240\253n K\246leleri ve[ENTER]Banshee karanl\253k milletin deh\254et verici eserini[ENTER]tamamlamaya ve Sung Mahi'yi uyand\253rmaya[ENTER]\231al\253\254\253yor! "
gameforge.main_quest_lv66._60_sendLetter = "Bulmacan\253n \199\246z\252m\252 "
gameforge.main_quest_lv66._610_say = "Sana \231ok \254ey bor\231luyuz: En iyi adamlar\253mdan[ENTER]birini \246l\252mden kurtard\253n ve bu \254ekilde Agwi'nin[ENTER]birden bire belirmesi ve \222eytan Katakombu'ndaki[ENTER]yeni tehditlerle ilgili bilgiler edinebildik.[ENTER]\222imdi biraz dinlen - sonra uygun bir taktik[ENTER]d\252\254\252n\252r\252z. "
gameforge.main_quest_lv66._620_say = "Macera seviye 72'ye ula\254t\253\240\253nda devam edecek. "
gameforge.main_quest_lv66._70_say = "Uriel seni ar\253yor. G\252nl\252\240\252 okudu. "
gameforge.main_quest_lv66._80_say = "Ah \231ok g\252zel! \221\254te buradas\253n. Son Ejderha[ENTER]Rahibesinin yazd\253klar\253 ger\231ekten hayret verici.[ENTER]\221yi dinle: "
gameforge.main_quest_lv66._90_say = "Kaderim m\252h\252rl\252! Kendimi bu kulenin en \252st kat\253na[ENTER]kilitledim. Lee Seops'un adamlar\253 hapishanemin[ENTER]\246n\252ndeki son kap\253y\253 da k\253rmak \252zere. \199\253k\253\254\253m[ENTER]yok... Yenildim...[ENTER][ENTER]Hay\253r, b\246yle sona eremez! Her \254ey bo\254a gidemez![ENTER]K\246t\252lerin eski g\252c\252 kara b\252y\252y\252 tek ba\254\253ma yenmek[ENTER]ve karanl\253k g\252\231leri yan\253ma \231a\240\253rmak zorunday\253m.[ENTER]Bu \246l\252m ferman\253m demek. Ama kendimle birlikte[ENTER]d\252\254manlar\253m\253 da yok olu\254a g\246nderece\240im - yapt\253\240\253m[ENTER]en son \254ey bu olsa da! "
gameforge.main_quest_lv7 = {}
gameforge.main_quest_lv7._100_say = "Ne, hala teslim etmedin mi? O olta nehrin[ENTER]k\253y\253s\253ndaki bal\253k\231\253 i\231in. Acele et, acilen oltaya[ENTER]ihtiyac\253 var. "
gameforge.main_quest_lv7._10_targetVid = "Bir ba\254ka iyilik "
gameforge.main_quest_lv7._110_npcChat = "Bu oltay\253 demirci g\246nderdi "
gameforge.main_quest_lv7._120_say = "Te\254ekk\252rler! Art\253k emektar ve eski oltamdan[ENTER]kurtulabilirim. Bal\253k\231\253l\253k sadece ge\231im kayna\240\253m[ENTER]de\240il, ayn\253 zamanda hayat\253m\253n en b\252y\252k keyfi![ENTER]Bal\253k\231\253l\253k hakk\253nda bilgin var m\253? "
gameforge.main_quest_lv7._130_say = "\221lk olarak, oltay\253 eline al. Ucuna bir yem tak ve[ENTER]onu bal\253k\231\253l\253k yetene\240ini kullanarak nehre salla.[ENTER]E\240er bir bal\253\240\253n tak\253ld\253\240\253n\253 hissedersen[ENTER](kabarc\253klar g\246r\252n\252r), yetene\240ini tekrar kullan.[ENTER]Bu i\254i becerene kadar tekrar dene.[ENTER]Yakalayabilece\240in bir\231ok bal\253k var. Bal\253k sa\240l\253k[ENTER]i\231in \231ok iyidir ve bazen nehirden de\240erli \254eyler[ENTER]de \231\253k\253yor. K\253saca bo\254 zaman\253n oldu\240unda gel[ENTER]burada de\240erlendir! "
gameforge.main_quest_lv7._140_say = "Ah evet, olta i\231in \246deme burada. Bu paray\253[ENTER]demirciye g\246t\252r. "
gameforge.main_quest_lv7._150_sayItem = "Oltan\253n paras\253 "
gameforge.main_quest_lv7._160_sayReward = "Oltay\253 bal\253k\231\253ya g\246t\252rd\252n. \214demeyi de demirciye[ENTER]g\246t\252r ve \246d\252l\252 al. "
gameforge.main_quest_lv7._170_say = "Bal\253k\231\253y\253 buldun mu?[ENTER]Harika. Bu teslimat\253 yaparak bana zaman[ENTER]kazand\253rd\253n. \214d\252l olarak sana bir miktar Yang ve[ENTER]1500 tecr\252be puan\253 verece\240im. "
gameforge.main_quest_lv7._180_sendLetter = "Geli\254tirme bileti "
gameforge.main_quest_lv7._190_sayReward = "Bu biletle, Demirci, ekipman\253ndan bir par\231ay\253[ENTER]\252cretsiz ar\253nd\253racak. Ar\253nd\253rma penceresini a\231mak[ENTER]i\231in ilgili par\231ay\253 Demirci'nin \252zerine \231ek. "
gameforge.main_quest_lv7._200_sayItem = "Bir defal\253k \252cretsiz ar\253nd\253rma bileti "
gameforge.main_quest_lv7._20_sayReward = "L\252tfen demirciye git. Ufak bir teslimat i\254i var. "
gameforge.main_quest_lv7._210_sayTitle = "\221pucu: "
gameforge.main_quest_lv7._220_sayReward = "1) Bilet envanterde g\246sterilmez.[ENTER]2) Ba\254ar\253l\253 bir ar\253nd\253rma garantisi - her zamanki[ENTER]gibi - verilmez. "
gameforge.main_quest_lv7._230_sayTitle = "Bilet kullan\253ld\253. "
gameforge.main_quest_lv7._240_sayReward = "\220cretsiz ar\253nd\253rma biletini zaten kulland\253n.[ENTER]Bilet sadece bir ar\253nd\253rma i\231in ge\231erli. "
gameforge.main_quest_lv7._30_say = "Hey, macerac\253! Bana bir iyilik yapar m\253s\253n?[ENTER]Genelde insanlardan bu tip iyilikler istemem,[ENTER]ancak sen g\252venilir g\246r\252n\252yorsun. "
gameforge.main_quest_lv7._40_say = "Bal\253k\231\253 i\231in bir olta yapt\253m, ancak maalesef \231ok[ENTER]me\254gul\252m ve ona oltas\253n\253 g\246t\252remiyorum. Oltay\253[ENTER]benim i\231in bal\253k\231\253ya g\246t\252r\252r m\252s\252n? "
gameforge.main_quest_lv7._50_sayItem = "\199ok esnek bir bal\253k\231\253 oltas\253 "
gameforge.main_quest_lv7._60_say = "Bal\253k\231\253, nehrin civar\253nda bir yerde olmal\253. E\240er[ENTER]oltay\253 ona g\246t\252r\252rsen, bir z\253rh par\231as\253n\253[ENTER]ar\253nd\253raca\240\253m.[ENTER]Bu adil bir anla\254ma, degil mi? "
gameforge.main_quest_lv7._70_sendLetter = "Bal\253k\231\253y\253 bul "
gameforge.main_quest_lv7._80_sayReward = "Demirci, bal\253k\231\253 i\231in bir olta yapt\253. Bal\253k\231\253y\253[ENTER]bul ve oltay\253 ona teslim et. "
gameforge.main_quest_lv7._90_npcChat = "Bu olta kimin? "
gameforge.main_quest_lv72 = {}
gameforge.main_quest_lv72._100_say = "G\246ky\252z\252n\252n g\246zya\254\253 t\252m p\253r\253lt\253s\253n\253 kutsanm\253\254 a\240a\231[ENTER]re\231inesi, mavi kristal esans\253 ve k\253rm\253z\253 cehennem[ENTER]kuvars\253ndan al\253r. Mavi kristal esans\253 Buz Da\240\253[ENTER]Hakimi taraf\253ndan bulunmal\253. "
gameforge.main_quest_lv72._10_sendLetter = "A\254\253nm\253\254 Ta\254 Levha "
gameforge.main_quest_lv72._110_say = "Bu yaz\253t\253n \246nemli bir notunu ald\253n. Lee Chung'a[ENTER]az \246nce okuduklar\253n hakk\253nda rapor ver. "
gameforge.main_quest_lv72._120_say = "Sa\240 salim d\246nd\252n demek! Y\252z\252n\252n ifadesinden[ENTER]anlad\253\240\253m kadar\253yla ba\254ar\253l\253 oldun! "
