gameforge.main_quest_lv78._130_say = "Lee Chung ve b\252y\252c\252ler meclisi son madde olan[ENTER]kutsanm\253\254 a\240a\231 re\231inesinin k\253rm\253z\253 k\246t\252[ENTER]a\240a\231lardan elde edilebilece\240ini saptad\253. K\253rm\253z\253[ENTER]Orman'da k\253rm\253z\253 k\246t\252 a\240a\231 av\253na \231\253k ve 100[ENTER]porsiyon kutsanm\253\254 a\240a\231 re\231inesi topla. "
gameforge.main_quest_lv78._140_say = "Bu g\246ky\252z\252 g\246zya\254\253n\253n \252retiminin son a\254amas\253.[ENTER]Kendine dikkat et, K\253rm\253z\253 Orman \246ld\252r\252c\252 yarat\253k[ENTER]kayn\253yor. "
