gameforge.main_quest_lv78._170_say = "Kutsanm\253\254 a\240a\231 re\231inesi mi bu? Muazzam g\252c\252n\252[ENTER]hissedebiliyorum. Harika! Ne yaz\253k ki bir \231ok[ENTER]b\252y\252c\252y\252 g\246reve g\246ndermek zorunda kald\253m. Bir[ENTER]s\252re burada olmayacaklar. Memleketinde Baek-Go[ENTER]ad\253nda bir eczac\253 yok mu? "
gameforge.main_quest_lv78._180_say = "Evet, ger\231ekten de var. "
gameforge.main_quest_lv78._190_say = "Ah, iyi denk geldi! Bu \252\231 maddeyi al ve[ENTER]Baek-Go'ya geri g\246t\252r. Bunlardan g\246ky\252z\252n\252n[ENTER]g\246zya\254\253n\253 elde edebilir. "
gameforge.main_quest_lv78._200_say = "Yorucu bir yolculuk ge\231irdin. L\252tfen bu \246d\252l\252[ENTER]\231abalar\253n\253n bir kar\254\253l\253\240\253 olarak kabul et. "
gameforge.main_quest_lv78._20_say = "G\246lge Sava\254\231\253lar\253 Kumandan\253 Lee Chung, k\253rm\253z\253[ENTER]cehennem kuvars\253 hakk\253nda yeni bilgiler edindi.[ENTER]Bu ta\254\253 \252retmek i\231in \252\231 \231e\254it maddeye ihtiya\231[ENTER]duyulur: Doyyumhwan volkan topra\240\253, alev yelesi[ENTER]ve temel ta\254\253.[ENTER]Bu maddeleri ele ge\231irmek i\231in Ate\254 Diyar\253'nda[ENTER]Alev, Alev Sava\254\231\253lar\253 ve Sava\254 Kaplan\253 avla ve[ENTER]sonras\253nda bunlar\253 20 adet k\253rm\253z\253 cehennem[ENTER]kuvars\253na d\246n\252\254t\252r.[ENTER]Sava\254maya ba\254lamadan \246nce Lee Chung'u bul. "
gameforge.main_quest_lv78._210_sendLetter = "G\246ky\252z\252n\252n G\246zya\254\253 "
gameforge.main_quest_lv78._220_say = "L\252tfen memleketine geri d\246n, Baek-Go'yu bul ve[ENTER]Lee Chung ad\253na ondan bu \252\231 maddeyle g\246ky\252z\252n\252n[ENTER]g\246zya\254\253n\253 olu\254turmas\253n\253 rica et. "
gameforge.main_quest_lv78._230_say = "Uzun zamand\253r yoktun. Sana bir \254ey oldu diye[ENTER]endi\254elendim. Seni bana getiren nedir? "
gameforge.main_quest_lv78._240_say = "Lee Chung beni senden bir \254ey rica etmekle[ENTER]g\246revlendirdi. "
gameforge.main_quest_lv78._250_say = "Lee Chung mu?! G\246lge Sava\254\231\253lar\253 Kumanda... ay,[ENTER]\254\254tt! Sessiz! \214n\252nde bir G\246lge Sava\254\231\253s\253 duruyor.[ENTER]Ama \231ok gizli ve k\246ydeki kimse bunu duymamal\253.[ENTER]Lee Chung'un ricas\253 ne? "
gameforge.main_quest_lv78._260_say = "Bu \252\231 maddeyle g\246ky\252z\252n\252n g\246zya\254\253n\253 olu\254turman\253[ENTER]istiyor. "
gameforge.main_quest_lv78._270_say = "G\246y\252z\252n\252n g\246zya\254\253 demek... Emrinde o kadar \231ok[ENTER]b\252y\252c\252 var ki, en zor g\246revleri neden hep bana[ENTER]veriyor?[ENTER]...[ENTER]Neyse. \221\254te-g\246ky\252z\252nun g\246zya\254\253. Ola\240an\252st\252 g\252zel![ENTER]Onu el\231iyle do\240rudan Lee Chung'a g\246nderirim, her[ENTER]\254ey haz\253r oldu\240unda sana haber verir.[ENTER]Bana ne i\254e yarad\253\240\253n\253 anlat\253r m\253s\253n? "
gameforge.main_quest_lv78._280_say = "Ne yaz\253k ki sana daha fazla ayr\253nt\253 anlatamam.[ENTER]Sadece \254unu bil yeter: Bu ta\254 \254eytan ve di\240er[ENTER]k\246t\252 varl\253klar\253 defetmek i\231in kutsal g\252\231leri[ENTER]\231a\240\253r\253yor. "
gameforge.main_quest_lv78._290_say = "\199ok ilgin\231. Sana g\246revinde ba\254ar\253lar dilerim.[ENTER]Kahramanl\253klar\253n\253n \246d\252l\252 olarak iki k\252\231\252len kafa[ENTER]alacaks\253n. Bir ba\254ka g\246ky\252z\252 g\246zya\254\253na daha[ENTER]ihtiya\231 duydu\240una bana gelebilirsin, nas\253lsa[ENTER]nas\253l yap\253laca\240\253n\253 biliyorum.[ENTER]Aa, bir de Lee Chung'a sevgi ve selamlar\253m\253 ilet[ENTER]l\252tfen. "
gameforge.main_quest_lv78._300_say = "Seviye 84'e ula\254t\253\240\253nda macera devam edecek. "
gameforge.main_quest_lv78._30_say = "B\252y\252c\252lerimiz g\246ky\252z\252n\252n g\246zya\254\253n\253 \252retmek i\231in[ENTER]gerekli olan k\253rm\253z\253 cehennem ta\254\253n\253n ate\254in[ENTER]g\252c\252n\252 i\231inde bar\253nd\253rd\253\240\253n\253 saptad\253. Ate\254 Diyar\253[ENTER]yarat\253klar\253n\253n g\252c\252n\252n kayna\240\253 da bu kuvars[ENTER]olmal\253. "
gameforge.main_quest_lv78._40_say = "K\253rm\253z\253 cehennem ta\254\253 \252\231 maddeyle \252retilir:[ENTER]Volkan topra\240\253, alev yelesi ve temel ta\254\253.[ENTER]Hepsini Ate\254 Diyar\253'nda bulabilirsin. "
gameforge.main_quest_lv78._50_say = "Ba\254ard\253n! Nihayet %d adet k\253rm\253z\253 cehennem[ENTER]kuvars\253na sahibiz. Cesaretin ve m\252cadele g\252c\252n[ENTER]beni her seferinde yeniden \254a\254\253rt\253yor. "
gameforge.main_quest_lv78._60_say = "Bir madde eksik. Volkan topra\240\253, alev yelesi ve[ENTER]temel ta\254\253na ihtiya\231 duyuyoruz. "
gameforge.main_quest_lv78._70_say = "\220zg\252n\252m, ama bir g\252nde sadece yedi k\253rm\253z\253[ENTER]cehennem kuvars\253 \252retebilirim. Bu i\254lem sihir[ENTER]yeteneklerimi zorluyor. Sonu\231ta ben b\252y\252c\252[ENTER]de\240ilim. "
