gameforge.main_quest_lv84._210_say = "Ger\231ekten b\252y\252k i\254 ba\254ar\253d\253n, senden ba\254ka kimse[ENTER]bunu yapamazd\253. Bana ne zaman ihtiyac\253n olursa,[ENTER]hep yan\253nda olaca\240\253m. Ho\254\231akal! "
gameforge.main_quest_lv84._30_say = "G\246ky\252z\252n\252n g\246zya\254\253 \254imdi elimizde oldu\240una g\246re[ENTER]Karanl\253\240\253n K\246leleri'ni alt etmemiz ve Agwileri bu[ENTER]d\252nyadan kovmam\253z da an meselesi![ENTER]Ancak g\252c\252 sadece \222eytan Katakombu'un belirli bir[ENTER]yerinde kullan\253ld\253\240\253nda geli\254ir. "
