gameforge.main_quest_lv90._020_say = "Yolculu\240un uzun ve zorlu ge\231ti. Ama nihayet[ENTER]hedefine ula\254t\253n: Karanl\253k Ejderha Kayas\253. Amiral[ENTER]Angmur'la konu\254. Onu Ejderha Ate\254i Burnu'nda[ENTER]bulabilirsin. "
