gameforge.main_quest_lv91._390_say = "Harika, art\253k mektubun \254ifresini \231\246zebilirim. \221yi[ENTER]i\254 \231\253kard\253n! Bunu minnettarl\253\240\253m\253n bir simgesi[ENTER]olarak kabul et. "
