gameforge.main_quest_lv91._440_say = "*f\253s\253l f\253s\253l* ... Ah, geldin mi! Yard\253m\253n[ENTER]sayesinde mesaj\253n b\252y\252k bir k\253sm\253n\253 \231\246zd\252m. Ama[ENTER]son k\253sm\253nda t\253kand\253m.[ENTER]Senden bir daha yard\253m istemek zorunday\253m. Acilen[ENTER]kabuk tozuna ihtiyac\253m var. Bunu Kabuk[ENTER]Kabilesi'ndeki General Istakoz veya Kral[ENTER]Yenge\231'te bulabilirsin. "
gameforge.main_quest_lv91._450_say = "Kabuk Tozu "
gameforge.main_quest_lv91._460_say = "Evet, bu sadece Kabuk Kabilesi'nde bulunur. Bu[ENTER]tozun biraz\253 bile \246l\252mc\252ld\252r! \220\231 doz i\254imi g\246r\252r.[ENTER]Ba\254ar\253lar. "
gameforge.main_quest_lv91._470_say = "Hemen yola \231\253k\253yorum. "
gameforge.main_quest_lv91._480_sayTitle = "Kabuk Tozu "
gameforge.main_quest_lv91._490_say = "Kabuk Kabilesi'nden General Istakoz ve Kral[ENTER]Yenge\231'in kar\254\253s\253na \231\253k ve \252\231 doz kabuk tozu ele[ENTER]ge\231ir. "
gameforge.main_quest_lv91._500_say = "Kabuk tozu \231ok zehirlidir. Etkisinin biraz[ENTER]zay\253flamas\253 i\231in bir g\252n beklemem gerek. Yar\253n[ENTER]tekrar gel, o zaman sana belki daha fazla bilgi[ENTER]verebilirim. "
