gameforge.main_quest_lv91._570_say = "Amiral Angmur acilen seni ar\253yor. Ne istedi\240ini[ENTER]\246\240ren. "
gameforge.main_quest_lv91._580_say = "Sonunda geldin! Ejderha Tanr\253s\253'na \254\252k\252rler olsun.Yon-I Gezgini kabuk tozundan zehirlenmi\254. "
gameforge.main_quest_lv91._590_say = "Acele etmek istedi ve dikkatsiz davrand\253.[ENTER]\222ans\253m\253za b\252t\252n \254ifa bitkileri stokumuz t\252kendi.[ENTER]Kaya \199i\231e\240'ni bul - k\246k\252 zehre panzehir olabilir.[ENTER]Onu nerede bulaca\240\253n\253 bu harita \252zerinde[ENTER]i\254aretledim. "
gameforge.main_quest_lv91._600_say = "Elbette. "
gameforge.main_quest_lv91._610_say = "Sana g\252venebilece\240imi biliyordum. L\252tfen acele[ENTER]et, fazla vaktimiz kalmad\253! "
gameforge.main_quest_lv91._620_sayTitle = "Yon-I Gezgini'ni kurtar! "
gameforge.main_quest_lv91._630_say = "Zehirlenen Yon-I Gezgini'ni iyile\254tirmek i\231in[ENTER]kaya \231i\231e\240i k\246k\252 bul. "
gameforge.main_quest_lv91._640_1_notice = "Yon-I Gezgini'ne kaya \231i\231e\240i k\246k\252 getir. "
gameforge.main_quest_lv91._650_say = "*\246h\246 \246h\246*[ENTER]*ah anam anam*[ENTER]Ah, sen miydin. Kendimi \231ok k\246t\252 hissediyorum.[ENTER]Kaya \231i\231e\240i k\246k\252n\252 bulabildin mi? "
