gameforge.main_quest_lv91._670_say = "Oh, kendimi daha iyi hissediyorum. Demek ki[ENTER]vaktim daha gelmemi\254. Te\254ekk\252r ederim. Bunu \246d\252l[ENTER]olarak kabul et. Art\253k kalan i\254lerimi[ENTER]bitirebilirim. Amiral Angmur mektubu \231\246zer \231\246zmez[ENTER]seni bilgilendirecek. "
gameforge.main_quest_lv91._680_say = "Yon-I Gezgini seninle konu\254mak istiyor. "
