gameforge.main_quest_lv92._020_say = "Karanl\253\240\253n K\246leleri'nin son mektubu K\253z\253lh\253rs\253z[ENTER]\199etesi'nde. Amiral Angmur sana daha ayr\253nt\253l\253[ENTER]bilgi verecek. "
gameforge.main_quest_lv92._030_say = "Karanl\253\240\253n K\246leleri'nin komplolar\253na gittik\231e[ENTER]yakla\254\253yoruz. Son mektup K\253z\253lh\253rs\253z \199etesi'nin[ENTER]elinde. "
gameforge.main_quest_lv92._040_say = "K\253z\253lh\253rs\253z \199etesi mi? "
gameforge.main_quest_lv92._050_say = "Bunlar Karanl\253k Ejderha Kayas\253'na s\252rg\252n edilen[ENTER]bir grup su\231ludur. K\253z\253lh\253rs\253zlar konusundaki[ENTER]tuhafl\253k, insanlar\253n \254eytanlarla birlik[ENTER]olmas\253d\253r. "
gameforge.main_quest_lv92._060_say = "\221nsanlar\253 yemek yerine onlarla birlik olan[ENTER]canavarlar m\253? \199ok ilgin\231. "
gameforge.main_quest_lv92._070_say = "Onlar\253 ortak bir hedef bir araya getiriyor: Alt\253n.K\253z\253lh\253rs\253z \199etesi'nin kamp\253 buradan pek uzakta[ENTER]say\253lmaz. K\253z\253lh\253rs\253z Cellat'\253n ve Siyah[ENTER]General'in i\254ini bitir. Mektup ikisinden birinde. "
gameforge.main_quest_lv92._080_say = "Ama bize kar\254\253 vaktinde uyar\253ld\253lar ve mektubu[ENTER]d\246rt par\231aya b\246ld\252ler. Hepsini bulmal\253y\253z. "
gameforge.main_quest_lv92._090_say = "Tamam. "
gameforge.main_quest_lv92._100_say = "Te\254ekk\252rler! "
gameforge.main_quest_lv92._110_sayTitle = "K\253z\253lh\253rs\253z Mektubu "
gameforge.main_quest_lv92._120_say = "K\253z\253lh\253rs\253z Cellat'a ve Siyah General'e kar\254\253[ENTER]sava\254. Mektubun d\246rt par\231as\253n\253 da bul. "
gameforge.main_quest_lv92._130_say = "Mektup daha tam de\240il. T\252m par\231alar\253 bul. "
gameforge.main_quest_lv92._140_1_notice = "K\253z\253lh\253rs\253z mektubunun t\252m par\231alar\253n\253 buldun. "
gameforge.main_quest_lv92._140_2_notice = "Bunlar\253 Amiral Angmur'a g\246ster. "
gameforge.main_quest_lv92._150_say = "Amiral Angmur'la konu\254. "
gameforge.main_quest_lv92._160_say = "Aferin. Bunu minnettarl\253\240\253m\253n bir simgesi olarak[ENTER]al. "
gameforge.main_quest_lv92._170_sendLetter = "K\253z\253lh\253rs\253z Mektubu "
gameforge.main_quest_lv92._180_say = "Amiral Angmur'un yard\253ma ihtiyac\253 var. "
gameforge.main_quest_lv92._190_say = "\221yi ki geldin. Bir sorunumuz var. "
gameforge.main_quest_lv92._200_say = "Konu ne? "
gameforge.main_quest_lv92._210_say = "K\253z\253lh\253rs\253z mektubunun be\254inci bir par\231as\253 daha[ENTER]varm\253\254. O olmadan di\240erlerinin hi\231 de\240eri yok. En[ENTER]cesur adamlar\253mdan biri olan Bae-Yong'u g\246nderdim[ENTER]- ama ba\254\253na bir \254ey gelmi\254 olmal\253. \199oktan geri[ENTER]d\246nm\252\254 olmal\253yd\253. Onu aramaya \231\253kabilir misin? "
gameforge.main_quest_lv92._220_say = "Tabii! \222u an nerede olabilece\240i konusunda bir[ENTER]fikrin var m\253? "
gameforge.main_quest_lv92._230_say = "Bir tahminim var, evet. En son Nefrit K\246rfezi'ne[ENTER]gitmek istiyordu. Ama oraya var\253p varmad\253\240\253n\253[ENTER]kimse bilmiyor. "
gameforge.main_quest_lv92._240_say = "Hemen yola \231\253k\253yorum. "
gameforge.main_quest_lv92._250_sayTitle = "Kay\253p Asker "
gameforge.main_quest_lv92._260_say = "Mektubun be\254inci par\231as\253n\253 bul. Bunun i\231in Nefrit[ENTER]K\246rfezi'ndeki Bae-Yong'u ara. "
gameforge.main_quest_lv92._270_say = "Bae-Yong'u daha bulamad\253n m\253? \214l\252m kal\253m meselesi.L\252tfen aramaya devam et. "
gameforge.main_quest_lv92._280_say = "*\246h\246 \246h\246*[ENTER]Beni buldu\240un i\231in te\254ekk\252r ederim. Sava\254ta a\240\253r[ENTER]yaraland\253m ve korkar\253m fazla vaktim kalmad\253 ...[ENTER]Al, bunu bir K\253z\253lh\253rs\253z'dan ald\253m. Bunu Amiral'e[ENTER]g\246t\252r. Hadi, git! Ben arkandan geliyorum ...[ENTER](Kollar\253nda \246l\252yor.) "
gameforge.main_quest_lv92._290_1_notice = "Bae-Yong \246lmeden \246nce sana eksik son mektup[ENTER]par\231as\253n\253 verdi. "
gameforge.main_quest_lv92._290_2_notice = "\222imdi Amiral Angmur'a geri d\246n. "
gameforge.main_quest_lv92._300_say = "D\246nd\252n demek! Bae-Yong'u bulabildin mi? "
gameforge.main_quest_lv92._310_say = "Evet, ama ... "
gameforge.main_quest_lv92._320_say = "Ama ne?[ENTER]Hay\253r. \214ld\252 m\252 yoksa? "
gameforge.main_quest_lv92._330_say = "Onun i\231in yapabilece\240im hi\231bir \254ey kalmam\253\254t\253.[ENTER]Ba\254\253n sa\240olsun. Cesur bir adamd\253 - son mektup[ENTER]par\231as\253n\253 hayat\253yla korudu. Al, i\254te burada. "
gameforge.main_quest_lv92._340_say = "Bae-Yong'u kaybetmek \231ok ac\253 verici. Ama onunla[ENTER]gurur duyuyorum. G\246revini yerine getirdi - art\253k[ENTER]mektubun t\252m par\231alar\253 bizde. "
gameforge.main_quest_lv92._350_say = "Her \254ey i\231in te\254ekk\252r ederim. Al, i\254te \246d\252l\252n.[ENTER]Bae-Yong i\231in Tap\253nak'ta bir mum yakaca\240\253m. Sonra[ENTER]g\246r\252\254\252r\252z. "
gameforge.main_quest_lv92._360_say = "Amiral Angmur'a git. "
gameforge.main_quest_lv92._370_sendLetter = "K\253z\253lh\253rs\253z mektubunun \254ifresini \231\246z "
gameforge.main_quest_lv92._380_say = "Amiral Angmur'un K\253z\253lh\253rs\253z \199etesi'yle ilgili[ENTER]\246nemli haberleri var. S\246yleyeceklerini iyi dinle. "
gameforge.main_quest_lv92._390_say = "Ah, geldin mi. Karanl\253\240\253n K\246leleri s\252rekli ba\254[ENTER]a\240r\253t\253yor. Bu mektup da \254ifreli. Al bunu Yon-I[ENTER]Gezgini'ne g\246t\252r. "
gameforge.main_quest_lv92._400_say = "Peki. "
gameforge.main_quest_lv92._410_say = "\222ifreli mektubu Yon-I Gezgini'ne g\246t\252r. "
gameforge.main_quest_lv92._420_say = "Ay! Neden \246yle sessiz sessiz yakla\254\253yorsun?[ENTER]Sana nas\253l yard\253mc\253 olabilirim? "
gameforge.main_quest_lv92._430_say = "Bu K\253z\253lh\253rs\253zlar\253n mektubu. Ama di\240erleri gibi[ENTER]bu da \254ifreli. "
gameforge.main_quest_lv92._440_say = "Dur bir bakay\253m.[ENTER]Bu Tritonlar'\253n yaz\253s\253. \199\246zmenin \231ok zor[ENTER]olaca\240\253n\253 sanm\253yorum. "
gameforge.main_quest_lv92._450_say = "Harika. Ne kadar s\252rer? "
gameforge.main_quest_lv92._460_say = "Aceleci olma. \222ifreyi \231\246zmek \231ok zor de\240il. Ama[ENTER]gerekli ara\231 gere\231 olmadan da bu i\254i[ENTER]ger\231ekle\254tiremeyiz. "
gameforge.main_quest_lv92._470_say = "Tabii ki hay\253r. Bu fazla kolay olurdu. "
gameforge.main_quest_lv92._480_say = "G\246r\252yorum ki hala \231ok esprilisin, haha.[ENTER]Mektubu \231\246zmek i\231in oin puluna ihtiyac\253m var. Bu[ENTER]nadir pulu Triton Kabilesi'nde sadece General[ENTER]Kappa ve Triton'un bizzat kendisi ta\254\253yabilir.[ENTER]L\252tfen on adet getir. "
gameforge.main_quest_lv92._490_say = "Hemen yola koyuluyorum. "
gameforge.main_quest_lv92._500_sayTitle = "Oin pullar\253 bul! "
gameforge.main_quest_lv92._510_say = "Sadece Triton, Tritonlar\253n Kral\253 ve General Kappa[ENTER]oin pulu ta\254\253r. "
gameforge.main_quest_lv92._520_say = "Bu pul olmadan mektubu \231\246zemem. Buna kesinlikle[ENTER]ihtiyac\253m var. "
gameforge.main_quest_lv92._530_1_notice = "Triton oin pullar\253n\253 buldun. "
gameforge.main_quest_lv92._530_2_notice = "Bunlar\253 hemen Yon-I-Gezgin'e g\246t\252r. "
gameforge.main_quest_lv92._540_say = "\221yi i\254 \231\253kard\253n. Mektubu \231\246zer \231\246zmez Amiral[ENTER]Angmur'a haber verece\240im. Art\253k biraz dinlenmen[ENTER]gerek. Bunu minnettarl\253\240\253m\253n bir simgesi olarak[ENTER]al. "
gameforge.main_quest_lv92._550_say = "Yon-I Gezgini seninle konu\254mak istiyor. "
gameforge.main_quest_lv92._560_sendLetter = "Karanl\253k Planlar "
gameforge.main_quest_lv92._570_say = "Karanl\253\240\253n K\246leleri'nin mektubunun \254ifresi[ENTER]\231\246z\252ld\252. Amiral Angmur sana bu karanl\253k planlar\253[ENTER]anlatacak. "
gameforge.main_quest_lv92._580_say = "Gizli mesaj\253 tamamen \231\246zmeyi ba\254ard\253k. Gnoll[ENTER]mektubunu hat\253rl\253yor musun? Burada adan\253n[ENTER]derinliklerinde ya\254ayan ejderhalar ve onlar\253[ENTER]uyand\253rman\253n ve kudurtman\253n bir y\246ntemi[ENTER]anlat\253l\253yordu. Karanl\253k Ejderhalar\253n bu sayede[ENTER]hangi amaca ula\254mak istediklerini \246\240rendik. "
gameforge.main_quest_lv92._590_say = "Bir ejderha, akl\253 cehennem yar\253\240\253 kadar[ENTER]karanl\253kken \246ld\252rd\252\240\252nde gecenin incisini[ENTER]t\252k\252r\252r.[ENTER]Bu inci sayesinde ise Sung Mahi'nin sonsuz g\252c\252[ENTER]d\252nyaya geri d\246nd\252r\252lebilir. Karanl\253k planlar\253 da[ENTER]buymu\254 me\240er! "
gameforge.main_quest_lv92._600_say = "Bundan sonraki ad\253mlar\253m\253z\253 dikkatli atmal\253y\253z.[ENTER]Bir geli\254me oldu\240unda seni haberdar ederim. Her[ENTER]\254ey i\231in te\254ekk\252rler. "
gameforge.main_quest_lv92._610_say = "Seviye 93'e ula\254t\253\240\253nda macera devam edecek. "
