gameforge.main_quest_lv93._030_say = "Karanl\253\240\253n K\246leleri'ni yak\253n takipteyiz. "
gameforge.main_quest_lv93._040_say = "Onlar\253 yenmek i\231in seni g\252\231lendirmeliyiz. \221\231[ENTER]\253\254\253\240\253 biliyor musun? Bu birle\254tirilmi\254 enerjidir.[ENTER]Baz\253 efsanevi varl\253klar ve bitkiler bu g\252c\252[ENTER]i\231lerinde ta\254\253r. Yon-I Gezgini bundan bir[ENTER]g\252\231lendirme maddesi \252retebilir. Hemen yan\253na git. "
