gameforge.main_quest_lv93._060_say = "Aaa, i\254te kurtar\253c\253m![ENTER]\221\231 \253\254\253k, evet ... G\252\231lendirici maddem seni[ENTER]Karanl\253\240\253n K\246leleri'ne kar\254\253 ayn\253 d\252zeyde bir[ENTER]rakip haline getirecek. "
