gameforge.main_quest_lv93._260_say = "Yon-I Gezgini seni ar\253yor. "
gameforge.main_quest_lv93._270_say = "\199ok g\252zel, geldin demek. Yard\253m\253na ihtiyac\253m var.[ENTER]G\252\231lendirme iksirimin etkisini tam olarak[ENTER]g\246stermesi i\231in bir malzeme daha laz\253m: milenyum[ENTER]esans\253. "
gameforge.main_quest_lv93._280_say = "Milenyum esans\253 m\253? Hi\231 duymad\253m. "
gameforge.main_quest_lv93._290_say = "Bu \231e\254itli bitki esanslar\253ndan olu\254an \231ok etkili[ENTER]bir kar\253\254\253md\253r. Octavio'yu tan\253r m\253s\253n?[ENTER]Anakara'da oturur ve milenyum esans\253n\253 yapabilen[ENTER]tek ki\254idir.[ENTER]Ona git. Umar\253m bize yard\253m eder. Bazen biraz dik[ENTER]kafal\253l\253\240\253 tutar. "
