gameforge.main_quest_lv93._320_say = "Octavio'yu bul. Octavio anakarada ya\254ar ve[ENTER]milenyum esans\253n\253 \252retebilen tek ki\254idir. "
gameforge.main_quest_lv93._330_say = "Merhaba! Sana ne getirebilirim? Samgyetang ister[ENTER]misin? Evin spesiyalitesidir ... "
