gameforge.main_quest_lv93._350_say = "Aman dikkat, sessiz konu\254uz! Milenyum esans\253 ...[ENTER]Hay\253r olmaz. Sana bunu kim s\246yledi? Esans\253n[ENTER]verdi\240i g\252\231le herkes ba\254a \231\253kamaz. Bu riske[ENTER]girmek istemem. Ve s\246ylediklerini ba\254kas\253[ENTER]duymadan gitsen iyi olur. "
gameforge.main_quest_lv93._360_say = "Octavio, bekle biraz ve beni dinle! Beni Karanl\253k[ENTER]Ejder Kayas\253'ndan Yon-I Gezgini g\246nderdi. Esansa[ENTER]ihtiyac\253m\253z var. O olmadan karanl\253\240\253n k\246lelerine[ENTER]kar\254\253 hi\231 \254ans\253m\253z yok. Bildi\240imiz d\252nyan\253n sonu[ENTER]\231ok yak\253n. Onu ancak sen kurtarabilirsin. L\252tfen! "
gameforge.main_quest_lv93._370_say = "Yon-I Gezgini diyorsun yani? Eski bir[ENTER]arkada\254\253md\253r. \221yi bir \254i\254e \254arap e\254li\240inde ne ho\254[ENTER]sohbetler ettik. D\252\254\252nmem gerek. Yar\253n tekrar[ENTER]gel, o zaman sana cevab\253m\253 veririm. "
