gameforge.main_quest_lv93._410_say = "Octavio seninle konu\254mak istiyor. "
gameforge.main_quest_lv93._420_say = "B\252t\252n gece rican\253 d\252\254\252nd\252m. B\252y\252k bir risk[ENTER]al\253yorum. Ama do\240ru olan\253 yapt\253\240\253mdan \254\252phem yok.[ENTER]Evet, sana yard\253m edece\240im. "
gameforge.main_quest_lv93._430_say = "Harika! "
gameforge.main_quest_lv93._440_say = "Ama stoklar\253mda kalmad\253. Bana birka\231 malzeme[ENTER]bulabilir misin? Sana esans\253 sonra veririm. "
gameforge.main_quest_lv93._450_say = "Tabii. Ne laz\253m? "
gameforge.main_quest_lv93._460_say = "Gango k\246k\252, tue mantar\253 ve alp g\252l\252 eksik. Her[ENTER]birinden 200 adet topla. "
gameforge.main_quest_lv93._470_say = "Hemen yola \231\253k\253yorum. Bunlar\253 nerede bulabilirim? "
gameforge.main_quest_lv93._480_say = "Bu bitkileri k\253tan\253n her yerinde bulabilirsin.[ENTER]Sen yola \231\253k, ben de haz\253rl\253klara ba\254lay\253m. "
