gameforge.main_quest_lv93._510 = "Bu bitkileri k\253tan\253n her yerinde bulabilirsin.[ENTER]Sen yola \231\253k, ben de haz\253rl\253klara ba\254lay\253m. "
gameforge.main_quest_lv93._520_say = "Harika, geri d\246nd\252n. \220stelik her \254ey yan\253nda.[ENTER]\214yleyse hemen i\254 ba\254\253na ge\231iyorum. Beni rahats\253z[ENTER]etme. Yar\253n yine bu saatlerde gel. Esans o zamana[ENTER]kadar bitmi\254 olmal\253. "
