gameforge.main_quest_lv94._790_say = "Kikloplar'\253n Y\253ld\253r\253m Da\240lar\253'nda neler yapt\253\240\253n\253[ENTER]\246\240rendin mi? "
gameforge.main_quest_lv94._800_say = "Kikloplar itiraf etmek istemese de sonunda onlar\253[ENTER]\254unlar\253 bana vermeye ikna ettim: siyah bir ta\254 ve[ENTER]bir ka\240\253t par\231as\253. "
gameforge.main_quest_lv94._810_say = "Kara alt\253n\253n damarlar\253n\253 tespit ettik ve bunu[ENTER]sizler i\231in \231\253karmaya ba\254lad\253k. Devir teslim i\231in[ENTER]anla\254t\253\240\253m\253z gibi Y\253ld\253rm Da\240\253'n\253n i\231inde[ENTER]g\246r\252\254\252r\252z. "
gameforge.main_quest_lv94._820_say = "Kara alt\253n... Bu sadece Y\253ld\253r\253m Da\240lar\253'nda[ENTER]g\246r\252len bir maden. Karanl\253\240\253n K\246leleri bununla ne[ENTER]yap\253yor ki? "
gameforge.main_quest_lv94._830_say = "Bununla ne ama\231lad\253klar\253n\253 ne pahas\253na olursa[ENTER]olsun \246\240renmeliyiz. "
gameforge.main_quest_lv94._840_say = "Burada \254u yaz\253yor: "
gameforge.main_quest_lv94._850_sendLetter = "Kara Alt\253n "
gameforge.main_quest_lv94._860_say = "Amiral Angmur seninle bu kara alt\253n hakk\253nda[ENTER]konu\254mak istiyor. "
gameforge.main_quest_lv94._870_say = "Simyac\253 bu kara alt\253n\253 inceleyemedi. Par\231a \231ok[ENTER]k\252\231\252k. Hangi \246zelliklere sahip oldu\240unu ve[ENTER]Karanl\253\240\253n K\246leleri'nin bunu neden istedi\240ini[ENTER]mutlaka \246\240renmeliyiz! Y\253ld\253r\253m Da\240lar\253'na geri[ENTER]d\246n\252p kara alt\253ndan birka\231 numune daha[ENTER]getirebilir misin? "
gameforge.main_quest_lv94._880_say = "\214nce Simyac\253'ya git, o sana ka\231 numuneye ihtiyac\253[ENTER]oldu\240unu s\246yler. "
gameforge.main_quest_lv94._890_say = "Simyac\253'yla konu\254. "
gameforge.main_quest_lv94._900_say = "Selam. Angmur seni g\246revin konusunda[ENTER]bilgilendirdi mi? "
gameforge.main_quest_lv94._910_say = "Evet. Kara alt\253ndan ka\231 numuneye ihtiyac\253n var? "
gameforge.main_quest_lv94._920_say = "Hm, dur bir d\252\254\252neyim. \221nceleme i\231in %d numune[ENTER]yeter san\253r\253m. "
gameforge.main_quest_lv94._930_say = "Anla\254\253ld\253. "
gameforge.main_quest_lv94._940_sayTitle = "Y\253ld\253r\253m Da\240lar\253'ndaki Alt\253n "
gameforge.main_quest_lv94._950_sayTitle = "Simyac\253'ya git. "
gameforge.main_quest_lv94._960_say = "Y\253ld\253r\253m Da\240lar\253'nda kara alt\253n numuneleri ara. "
gameforge.main_quest_lv94._970_1_notice = "Bir kara alt\253n damar\253 buldun ve madenden bir[ENTER]numune ald\253n. "
gameforge.main_quest_lv94._970_2_notice = "Bunlar\253 Simyac\253'ya g\246t\252r. "
gameforge.main_quest_lv94._980_say = "Aa, demek kara alt\253n buldun. G\246ster hemen! Hm,[ENTER]\231izi\240i yok ve yeterince b\252y\252k... evet, bunu[ENTER]incelemede kullanabilirim. Geriye kald\253 %d adet[ENTER]kara alt\253n daha. "
gameforge.main_quest_lv94._990_say = "Bu numune i\254ime yaramaz. \221yi bir inceleme i\231in[ENTER]fazla hafif. Bana ba\254ka bir tane getir. "
