gameforge.main_quest_lv95._020_say = "Amiral Angmur seni ar\253yor. Kara alt\253nla ilgili[ENTER]yeni bilgiler edinmi\254. "
gameforge.main_quest_lv95._030_say = "Kara alt\253n canl\253lar\253n yak\253n\253ndayken t\252m[ENTER]enerjilerini emer ve bu enerjiyi ba\254ka v\252cutlara[ENTER]aktar\253r. Karanl\253\240\253n K\246leleri Sung Mahi'ye[ENTER]\231ald\253klar\253 g\252c\252 vermek istiyor! Dev Kaptan Kanca[ENTER]Y\253ld\253r\253m Da\240lar\253'nda b\252y\252k miktarda kara alt\253n[ENTER]depoluyor. Bunlar\253 hemen topla! "
