gameforge.main_quest_lv95._090_say = "Kaybedecek vaktimiz yok. Kaptan Kanca'y\253 alt et[ENTER]ve kara alt\253n\253 ele ge\231ir! "
gameforge.main_quest_lv95._100_1_notice = "Kara alt\253ndan eser yok. Kaptan Kanca yan\253nda[ENTER]sadece bir mektup ta\254\253yordu. "
gameforge.main_quest_lv95._100_2_notice = {}
gameforge.main_quest_lv95._110_say = "Amiral Angmur'a rapor et. "
gameforge.main_quest_lv95._120_say = "Aa, demek Kaptan Kanca'ya kar\254\253 kendini[ENTER]kan\253tlad\253n. Bu ne? Mektup mu? Hemen g\246ster! "
gameforge.main_quest_lv95._130_say = {}
gameforge.main_quest_lv95._140_say = "Lanet olsun. Kaptan Kanca kara alt\253n\253 Banshee'ye[ENTER]g\246ndermi\254 bile. Son c\252mlesi bulmaca gibi: Hayat[ENTER]laneti Karanl\253k Ordusu'nu zaman\253n sisinden[ENTER]kurtaracak. "
gameforge.main_quest_lv95._150_say = "Nakliyat\253 durdurmal\253y\253z! Banshee s\253\240\253na\240\253n\253n[ENTER]do\240udaki Gautama U\231urumu'nda oldu\240unu tahmin[ENTER]ediyoruz \150 koyu bir sisle kapl\253, terk edilmi\254 bir[ENTER]yer.[ENTER]Burada \214c\252ler ve Lemur'lar dola\254\253r. "
gameforge.main_quest_lv95._160_say = {}
gameforge.main_quest_lv95._170_say = "Kara alt\253n\253n hangi rota \252zerinden Banshee'lere[ENTER]getirilece\240ini \246\240renir \246\240renmez sana haber[ENTER]verece\240im. "
gameforge.main_quest_lv95._180_sendLetter = "Nakliyat\253 yakala "
gameforge.main_quest_lv95._190_say = "Amiral Angmur'a git. Kara alt\253n nakliyat\253yla[ENTER]ilgili detayl\253 bilgi ald\253. "
gameforge.main_quest_lv95._200_say = "Casuslar\253m \214c\252 Komutan\253 Kaptan \222rak'\253n kara[ENTER]alt\253n\253 Gautama U\231urumu'na g\246t\252rmekte oldu\240unu[ENTER]\246\240rendi. Kara alt\253n\253 kemerindeki bir kesede[ENTER]sakl\253yor. Bu keseyi ele ge\231ir. "
gameforge.main_quest_lv95._210_say = {}
gameforge.main_quest_lv95._220_say = "Anlad\253m. Hemen aramaya ba\254l\253yorum. "
