gameforge.main_quest_lv95._240_say = "Banshee'lere ula\254madan Kaptan \222rak'\253 bul ve kara[ENTER]alt\253n\253n oldu\240u keseyi ele ge\231ir. "
gameforge.main_quest_lv95._250_say = "Kaptan \222rak kolay lokma de\240il. Ama sen onu[ENTER]yenebilirsin! Bir daha dene. "
