gameforge.main_quest_lv95._280_say = "Kara alt\253n bu kesede mi? G\246ster hemen! Aa? Burada[ENTER]sadece bir ka\240\253t par\231as\253 var... "
gameforge.main_quest_lv95._290_say = "Kara alt\253n tam olarak i\254ledikten sonra[ENTER]nakledilecek. "
gameforge.main_quest_lv95._300_say = "Lanet olsun, kara alt\253n hala yanl\253\254 ellerde.[ENTER]Neyse, en az\253ndan Banshee'ler bunu k\246t\252[ENTER]emellerine alet etmeden \246nce i\254lenmesi[ENTER]gerekti\240ini \246\240rendik. "
gameforge.main_quest_lv95._310_say = "Hen\252z ge\231 de\240il. Kara alt\253n\253n \254u an kimde[ENTER]oldu\240unu ve i\254lenip i\254lenmedi\240ini ara\254t\253raca\240\253m.[ENTER]Bir \254eyler \246\240rendi\240im zaman seni \231a\240\253rt\253r\253m. Al,[ENTER]bu \246d\252l\252n.[ENTER]Yak\253nda g\246r\252\254\252r\252z! "
gameforge.main_quest_lv95._320_sendLetter = "\221\254lenme s\252recini durdur "
gameforge.main_quest_lv95._330_say = "Amiral Angmur'a git. Kara alt\253nla ilgili yeni[ENTER]bilgiler ald\253. "
gameforge.main_quest_lv95._340_say = "Dev \214c\252'n\252in kara alt\253n\253n i\254lenme s\252recini bizzat[ENTER]g\246zlem alt\253nda tuttu\240unu ve i\254lem tamamlan\253nca[ENTER]alt\253nlar\253 bizzat Banshee'lere g\246t\252rece\240ini[ENTER]\246\240rendik. "
gameforge.main_quest_lv95._350_say = "\222u an Gautama U\231urumu'nda. Kara alt\253n\253n hedefe[ENTER]ula\254mas\253n\253 engelle. Acele et, sak\253n ge\231 kalma! "
