gameforge.main_quest_lv95._440_say = "Ne \231abuk! Kara alt\253n\253 ele ge\231irdin mi? "
gameforge.main_quest_lv95._450_say = "Hay\253r, ge\231 kald\253m. Banshee'ler taraf\253ndan al\253nm\253\254. "
gameforge.main_quest_lv95._460_say = "Ejderha Tanr\253s\253 bize ac\253s\253n. Ama \246yle kolay kolay[ENTER]pes etmeyiz. Bansheeler'in nerede oldu\240unu[ENTER]\246\240renmek i\231in casuslar\253m\253 g\246nderece\240im.[ENTER]\214\240rendi\240im anda sana haber veririm. \222imdi biraz[ENTER]dinlen ve bu \246d\252l\252 kabul et. "
gameforge.main_quest_lv95._470_sendLetter = "Hayat Laneti "
gameforge.main_quest_lv95._480_say = "Amiral Angmur'a git, sana yeni bilgiler verecek. "
gameforge.main_quest_lv95._490_say = "Hayat laneti ve Karanl\253k Ordu'yla ne[ENTER]kastedildi\240ini anlad\253k. Bir zamanlar Karanl\253k[ENTER]Ejderha Kayas\253'nda hain bir b\252y\252c\252 ya\254arm\253\254. T\252m[ENTER]k\253tan\253n hakimiyetini ele ge\231irmenin hayalini[ENTER]kurup bunun i\231in zalimce her \254eyi yapm\253\254: Hayat[ENTER]laneti denilen bir kara b\252y\252yle \246l\252leri diriltip[ENTER]kendi i\231in m\252cadele etmeleri amac\253yla sava\254a[ENTER]s\252rm\252\254. "
gameforge.main_quest_lv95._500_say = {}
gameforge.main_quest_lv95._510_say = "\214l\252 diriltmesi - d\252\254\252nd\252\240\252mde bile t\252ylerim[ENTER]\252rperiyor. Karanl\253\240\253n K\246leleri kara alt\253n[ENTER]yard\253m\253yla namevtler ordusu kuruyor. Onlar\253[ENTER]durdurmal\253y\253z! "
gameforge.main_quest_lv95._520_say = "Gautama U\231urumu'ndaki eski harabelerde Lemur[ENTER]B\252y\252c\252'y\252 bul. O bu lanet hakk\253nda bir \254eyler[ENTER]biliyor. Nazik\231e sorarsan sana her \254eyi anlat\253r. "
gameforge.main_quest_lv95._530_say = "Nazik\231e rica etmek, demek. Anlad\253m. "
