gameforge.main_quest_lv95._550_say = "Lemur B\252y\252c\252'y\252 alt et, hayat laneti ve \246l\252[ENTER]diriltme hakk\253nda bilgi topla. "
gameforge.main_quest_lv95._560_say = "Kaybedecek vaktimiz yok. Lemur B\252y\252c\252'y\252 alt et[ENTER]ve ondan hayat laneti hakk\253ndaki bilgi al. "
gameforge.main_quest_lv95._570_1_notice = "Lemur B\252y\252c\252s\252'n\252 alt ettin ve \252zerinde yaz\253lar[ENTER]olan ta\254 bir levha buldun. "
