gameforge.main_quest_lv95._600_sayReward = "\214l\252leri dirilmek i\231in \252\231 \254ey gerekir:[ENTER]1. insans\253 bir beden[ENTER]2. ...[ENTER]Lemur levha k\253r\253k. Yaz\253n\253n geri kalan\253 eksik. "
gameforge.main_quest_lv95._610_say = "Korkar\253m, bir kez daha yollara d\252\254eceksin. Bu[ENTER]levhan\253n geri kalan\253na ihtiyac\253m\253z var. Bu[ENTER]levhan\253n iki par\231as\253 daha olmas\253 laz\253m. "
gameforge.main_quest_lv95._620_say = "Burada buraya kadarki ba\254ar\253n\253n kar\254\253l\253\240\253 bir[ENTER]\246d\252l\252 var. \222imdi Lemur levhan\253n geri kalan[ENTER]k\253s\253mlar\253n\253 aramaya \231\253k. "
