gameforge.main_quest_lv95._690_sayReward = "\214l\252leri diriltmek i\231in \252\231 \254ey gerekir:[ENTER]1. insans\253 bir beden[ENTER]2. kara alt\253n[ENTER]3. A\240a\231 \222eytan\253'n\253n kabu\240u[ENTER]Sadece \252st\252n yeteneklere sahip bir b\252y\252c\252 hayat[ENTER]lanetini yapabilir ve devam ettirebilir.[ENTER]\214ld\252\240\252ndeyse t\252m namevter ordusu onunla birlikte[ENTER]\246l\252r. "
gameforge.main_quest_lv95._700_say = "Bu y\252zden son zamanlarda mezarl\253klar\253m\253za zarar[ENTER]veriliyor ve mezardaki cesetler \231al\253n\253yor. Demek[ENTER]ki hayata d\246nd\252r\252l\252p namevtler ordusu olarak[ENTER]\252zerimize y\252r\252t\252lecekler. Ne i\240ren\231 bir fikir! "
gameforge.main_quest_lv95._710_say = "Bu al\231ak\231a plan\253n \246n\252ne ge\231meliyiz! "
gameforge.main_quest_lv95._720_say = "Zamana kar\254\253 yar\253\254mam\253z laz\253m. Sadece Banshee bu[ENTER]denli b\252y\252k bir laneti yapabilecek g\252\231te \150 ama[ENTER]nerede sakland\253\240\253n\253 bilmiyoruz. Karanl\253k Ulu[ENTER]Rahibe'nin s\253\240\253na\240\253n\253 bulmak i\231in birka\231 adam\253m\253[ENTER]g\246nderece\240im. Yeni bir \254ey duyar duymaz seni[ENTER]\231a\240\253rt\253r\253m. "
