gameforge.main_quest_lv96._350_sayTitle = "Alt\253n Av\253 "
gameforge.main_quest_lv96._360_say = "\214c\252ler'e kar\254\253 sava\254 ve para keseleri topla. Her[ENTER]alt\253 para ara\231 olarak kullan\253lamaz \150 bunlar\253[ENTER]Yon-I Gezgini'ne incelet. "
