gameforge.main_quest_lv96._490_say = {}
gameforge.main_quest_lv96._500_say = "Vakit daral\253yor. A\240a\231 \222eytanlar\253'ndan odun yap\253n[ENTER]ve K\246leler kabu\240u ele ge\231irmeden siz al\253n. "
gameforge.main_quest_lv96._510_1_notice = "T\252m A\240a\231 \222eytanlar\253'n\253 yendin, ama biri elini[ENTER]senden daha \231abuk tuttu: Kabuk kendi kabileleri[ENTER]taraf\253ndan soyuldu. "
gameforge.main_quest_lv96._510_2_notice = "Olanlar\253 Amiral Angmur'a anlat. "
gameforge.main_quest_lv96._520_say = "Amiral Angmur'a rapor et. "
gameforge.main_quest_lv96._530_say = "Sa\240 salim geri d\246nmen ne g\252zel! Ba\254arabildin mi?[ENTER]Ne?! T\252m A\240a\231 \222eytanlar\253'n\253n kabu\240u soyulmu\254tu ve[ENTER]taze sava\254 izleri mi vard\253? \214yleyse Karanl\253\240\253n[ENTER]K\246leleri senden \246nce gelmi\254 olmal\253. "
gameforge.main_quest_lv96._540_say = {}
gameforge.main_quest_lv96._550_say = "E\240er a\240a\231 kabu\240unu buldularsa hayat lanetini[ENTER]yapman\253n da bir yolunu bulurlar. Yani bunun[ENTER]ka\231\253\254\253 yok - sava\254a giriyoruz. Bansheeler bizden[ENTER]daha fazla saklanamayacak. Adamlar\253m pe\254lerinde.[ENTER]Onlar\253 buldu\240umuz anda seni \231a\240\253rtaca\240\253m. "
