gameforge.main_quest_lv96._570_counterName = "(Kalan: %s %s, %s %s) "
gameforge.main_quest_lv96._580_sayReward = "%s: %d tane "
gameforge.main_quest_lv96._590_say = "Demek ki alt\253n paralar ara\231 olarak kullan\253l\253yor.[ENTER]Tamam, \246yleyse Yon-I Gezgini'ne bundan sonraki[ENTER]ad\253mlar\253m\253z\253 dan\253\254ay\253m. Birazdan sana d\246nerim. "
