gameforge.main_quest_lv97._010_sendLetter = "Banshee'yi durdur "
gameforge.main_quest_lv97._020_say = "Bansheeler'in s\253\240\253na\240\253 bulundu! Daha fazla bilgi[ENTER]almak i\231in Amiral Angmur'a git. "
gameforge.main_quest_lv97._030_say = "Adamlar\253m nihayet Gautama U\231urumu'ndaki[ENTER]Bansheeler'in \252ss\252n\252 buldu. Orman\253n[ENTER]karanl\253klar\253na g\246m\252lm\252\254 ve kara b\252y\252s\252n\252 oradan[ENTER]etrafa sa\231\253yor.[ENTER]Ayr\253ca ejderha k\252lt\252ne mensup eski bir Tap\253nak[ENTER]K\246lesi'ni diriltti ve onunla birlikte hayat\253n[ENTER]lanetini haz\253rlayacak. "
gameforge.main_quest_lv97._040_say = "Onun yard\253m\253 olmadan Bansheeler lanetin varl\253\240\253n\253[ENTER]koruyamacak. Tap\253nak K\246lesi Mu-Shu'yu ma\240lup et[ENTER]ki yolda\254lar\253m\253z\253n ruhlar\253 \254ad olsun ve bizi[ENTER]musibete u\240ratmas\253n. "
gameforge.main_quest_lv97._050_say = "Tap\253nak K\246lesi'ne belli ettirmeden yakla\254mak[ENTER]neredeyse imkans\253z. Kara b\252y\252s\252ne dal\253p gitti\240i[ENTER]an\253 kolla! "
gameforge.main_quest_lv97._060_say = "Peki. "
gameforge.main_quest_lv97._070_say = "Dikkatli ol! Hayattayken Ulu Rahibe'nin[ENTER]koruyucusuydu ve uzmanl\253k alan\253 sadece b\252y\252[ENTER]de\240il.[ENTER]K\253l\253\231 kullanma alan\253nda da iyi bir e\240itimden[ENTER]ge\231ti. "
gameforge.main_quest_lv97._080_sayTitle = "Tap\253nak K\246lesi "
gameforge.main_quest_lv97._090_say = "Bansheeler'in Tap\253nak K\246lesi Mu-Shu'yu Gautama[ENTER]U\231urumu'nda ma\240lup et. "
gameforge.main_quest_lv97._100_notice = "\214ld\252r\252c\252 vuru\254 sonucunda Tap\253nak K\246lesi yere[ENTER]y\253\240\253ld\253. "
gameforge.main_quest_lv97._110_say = "Sersemler! Bansheeler'in size kurdu\240u tuza\240a[ENTER]nas\253l da d\252\254t\252n\252z. Benimle vakit ge\231irirken, Ulu[ENTER]Rahibemiz ger\231ek Tap\253nak K\246lesi Yah-Ki'yle[ENTER]birlikte lanete ba\254lad\253. Umar\253m ba\254ar\253l\253 olurlar! "
gameforge.main_quest_lv97._120_say = "Bir dubl\246r size yanl\253\254 izi takip ettirdi! \220zerini[ENTER]aray\253nca, daha \246nce Martyaxvar'da buldu\240un[ENTER]tasmaya benzer bir tasma buluyorsun. \221\231 cebinde[ENTER]bir belge var. "
gameforge.main_quest_lv97._130_say = "Amiral Angmur'a rapor et. "
gameforge.main_quest_lv97._140_say = "D\246nd\252n demek! Tap\253nak K\246lesi ma\240lup edildi mi? "
gameforge.main_quest_lv97._150_say = "Hay\253r, bir dubl\246r bizi yan\253ltt\253. Ger\231ek tap\253nak[ENTER]k\246lesi \246l\252lerin ruhunu \231a\240\253rmaya rahat rahat[ENTER]haz\253rlanabildi. Buyur, \254u belgeyi buldum. "
gameforge.main_quest_lv97._160_say = "T\252h! Nas\253l da bizi oyuna getirdi!? Belgeyi bana[ENTER]g\246sterir misin? "
gameforge.main_quest_lv97._170_say = {}
gameforge.main_quest_lv97._180_say = {}
gameforge.main_quest_lv97._190_say = "H\253m, \254ifreli. Ama belki bu mesajda \252slerinin[ENTER]nerede oldu\240una ait bir ipucu vard\253r. Buna benzer[ENTER]yaz\253 i\254aretlerini daha \246nceden g\246rm\252\254t\252m...galiba[ENTER]Saray Bek\231isi Yak-Hwan k\253sa bir s\252re \246nce bana[ENTER]buna benzer bir \254ey g\246stermi\254ti. Ona git ve buna[ENTER]bir g\246z ats\253n. "
gameforge.main_quest_lv97._200_sendLetter = "Belgenin \254ifresini \231\246z "
gameforge.main_quest_lv97._210_say = "Yak-Hwan'a git ve ona \254ifreli belgeyi g\246ster. "
gameforge.main_quest_lv97._220_say = "Selam! Ad\253m Yak-Hwan. Seninle tan\253\254mak benim i\231in[ENTER]bir \254eref. Kahramanl\253klar\253n\253 duymayan yok! Sana[ENTER]nas\253l yard\253mc\253 olabilirim? H\253, \254ifreli bir mesaj.[ENTER]Dur bir bakay\253m. "
gameforge.main_quest_lv97._230_say = "Evet, bu yaz\253 i\254aretlerini rahatl\253kla \231\246zerim.[ENTER]Yaln\253z bunun i\231in fosil toprak gerekiyor.[ENTER]Simyac\253'da bir tutam bulunuyordur. Ondan fosil[ENTER]toprak almaya git. "
gameforge.main_quest_lv97._240_say = {}
gameforge.main_quest_lv97._250_say = {}
gameforge.main_quest_lv97._260_say = "Elbette. "
gameforge.main_quest_lv97._270_sayTitle = "Fosil Toprak "
gameforge.main_quest_lv97._280_say = "Simyac\253'ya git ve ondan fosil toprak iste. "
gameforge.main_quest_lv97._290_say = "Unuttun mu? Bana fosil toprak getirecektin. "
gameforge.main_quest_lv97._300_notice = "Simyac\253 sana fosil topra\240\253 verdi. \222imdi[ENTER]Yak-Hwan'a geri d\246n. "
gameforge.main_quest_lv97._310_say = "Aa, fosil toprak. Aferin, \254imdi i\254imin ba\254\253na[ENTER]ge\231eyim. Sonucunu Amiral'e bildirece\240im. "
gameforge.main_quest_lv97._320_sendLetter = "Arka kap\253dan "
gameforge.main_quest_lv97._330_say = "Amiral Angmur seni ar\253yor. "
gameforge.main_quest_lv97._340_say = "Sadece Tap\253nak K\246lesi Yah-Ki'nin kald\253\240\253 yeri[ENTER]biliyoruz. Fakat o \252s kaleye benziyor. Bek\231iler[ENTER]orada gece g\252nd\252z devriye geziyor. \214n cepheden[ENTER]sald\253rmak \254u anki durumda intihar etmek demek. "
gameforge.main_quest_lv97._350_say = "Bu y\252zden arkadan sald\253rmak istiyoruz. Adamlar\253m[ENTER]uygun bir yer ar\253yor. Vakit kazanmam\253z i\231in[ENTER]bek\231ileri oyala. "
gameforge.main_quest_lv97._360_say = {}
gameforge.main_quest_lv97._370_say = "En b\252y\252k tehlikeyi, Kara \214l\252m Tugay\253 dedikleri[ENTER]bir bek\231i grupu olu\254turuyor. Bu tugay\253n[ENTER]mensuplar\253 Moghu, Karnifeks ve General Albus.[ENTER]Liderleri de Skeletos. G\246zc\252 Birli\240imi[ENTER]ke\254fetmemeleri i\231in onlar\253 ortadan kald\253r. "
gameforge.main_quest_lv97._380_say = "Tamam. "
gameforge.main_quest_lv97._390_sayTitle = "Kara \214l\252m Tugay\253 "
gameforge.main_quest_lv97._400_say = "Moghu, Karnifeks, General Albus ve Skeletos'tan[ENTER]olu\254an Kara \214l\252m Tugay\253'n\253 ortadan kald\253r. "
gameforge.main_quest_lv97._410_say = "G\246zc\252 Birli\240i'ni ke\254fetmemeleri i\231in Kara \214l\252m[ENTER]Tugay\253 mensuplar\253n\253 ortadan kald\253r. "
gameforge.main_quest_lv97._420_say = "Amiral Angmur'a rapor et. "
gameforge.main_quest_lv97._430_say = "Plan\253m\253z bo\254a \231\253kmad\253! Kara \214l\252m Tugay\253'n\253[ENTER]oyalad\253\240\253n s\252rede, adamlar\253m uygun bir pusu yeri[ENTER]buldu. Sald\253r\253 stratejimiz belirlenir[ENTER]belirlenmez, seni \231a\240\253rtaca\240\253m. "
gameforge.main_quest_lv97._440_sendLetter = "Tap\253nak K\246lesi "
gameforge.main_quest_lv97._450_say = "Amiral Angmur'un yard\253m\253na ihtiyac\253 var! "
gameforge.main_quest_lv97._460_say = "\221yiki buradas\253n. Kara \214l\252m Tugay\253'n\253n lideri[ENTER]Skeletos \246lmedi. Adamlar\253m \252sse h\252c\252m edecekleri[ENTER]s\253rada onlar\253n \252zerlerine sald\253rd\253. Kimse onu[ENTER]ezip ge\231emiyor. "
gameforge.main_quest_lv97._470_say = {}
gameforge.main_quest_lv97._480_say = "Sen onu daha \246nce de yenmi\254tin. L\252tfen Gautama[ENTER]U\231urumu'ndaki admalar\253ma yard\253m et! Skeletos'a[ENTER]g\252n\252n\252 g\246ster. Ard\253ndan \252sse h\252c\252m et ve Tap\253nak[ENTER]K\246lesi Yah-Ki'yi yok et. "
