gameforge.main_quest_lv97._500_say = {}
gameforge.main_quest_lv97._510_sayTitle = "Yah-Ki'yi yok et "
gameforge.main_quest_lv97._520_say = "Tap\253nak K\246lesi Yah-Ki'yi ma\240lup et ve \246l\252ler[ENTER]ordusunu \231a\240\253rmas\253na engel ol. "
gameforge.main_quest_lv97._530_say = "Karar g\252n\252 geldi. Biz d\252\254ersek, b\252t\252n d\252nya d\252\254er.E\240er zafere ula\254\253rsak, kahramanl\253klar\253m\253z[ENTER]y\252zy\253llar boyunca \254ark\253lara d\246k\252lecek. Karanl\253\240\253n[ENTER]K\246leleri'ni durdur. Yah-Ki'yi yok et! "
gameforge.main_quest_lv97._540_say = "Neden geldin? Sava\254\253 hen\252z kazanmad\253k! Yah-Ki'yi[ENTER]yen. \220mitlerimizi bo\254a \231\253karma. "
gameforge.main_quest_lv97._550_1_notice = "D\252\254man\253 dize getirdin ve zafer kazand\253n! "
gameforge.main_quest_lv97._550_2_notice = "Dinlenecek vaktin yok; Tap\253nak K\246lesi Yah-Ki snei[ENTER]bekliyor. "
gameforge.main_quest_lv97._560_notice = "Yendin! yah-Ki, insan\253n i\231ine i\254leyen bir \231\253\240l\253k[ENTER]atarak yere y\253\240\253l\253yor. "
gameforge.main_quest_lv97._570_say = "Ayyyyy! Olamaz! Bir faniye yenildim...Ah Banshee,[ENTER]affet! Ba\254aramad\253m. G\246revimi yerine getireme.. "
gameforge.main_quest_lv97._580_say = "Cans\253z bedenini ar\253yorsun ve bir m\252h\252rl\252 mektup[ENTER]buluyorsun. Bu mektubu Amiral Angmur'a g\246t\252r. "
gameforge.main_quest_lv97._590_say = "Oh, ejderha tanr\253s\253 seni korusun! Sa\240 salim geri[ENTER]d\246nd\252n. Tap\253nak K\246lesi'ni yendin mi? "
gameforge.main_quest_lv97._600_say = "Hemde nas\253l, onu geldi\240i yere, cehennemin dibine[ENTER]g\246nderim. \214l\252rken Banshee'den ba\254ar\253l\253 olamad\253\240\253[ENTER]i\231in af diledi. Bunu da \252st\252nde buldum. "
gameforge.main_quest_lv97._610_say = "M\252h\252rl\252 mektup. G\246ster! "
gameforge.main_quest_lv97._620_sayReward = "Efendim,[ENTER]Tuza\240\253m\253za d\252\254t\252ler ve her \254ey planlad\253\240\253n\253z gibi[ENTER]oldu. \214l\252ler ordusunu \231a\240\253rma rit\252eli devam[ENTER]ediyor. Bu saatten sonra hi\231 kimse bize engel[ENTER]olamayacak. Ruhsuz bedenler ayaklanmaya[ENTER]ba\254lad\253\240\253nda, Ejderha Ate\254 Burnu'na do\240ru[ENTER]ilerleyip halk\253n\253 topra\240a g\246mece\240iz. Ard\253ndan[ENTER]Anakara'ya gidip sizinle Ate\254 Diyar\253'nda[ENTER]bulu\254aca\240\253z. Ge\231ti\240imiz yerleri inim inim[ENTER]inletece\240iz![ENTER]\214n\252n\252zde sayg\253yla e\240iliyorum, Sad\253k K\246len "
gameforge.main_quest_lv97._630_say = "Bu, Banshee'ye bir mesaj! Oho, bu u\240ursuz cad\253[ENTER]Karanl\253\240\253n Ordusu gelecek diye Ate\254 Diyar\253'nda[ENTER]bo\240u bo\254una bekliyor. Te\254ekk\252r ederim. Yard\253m[ENTER]etmeseydin \214l\252ler Ordusu, Ejderha Ate\254i Burnu'nu[ENTER]halk\253yla birlikte yerle bir edecekti. Sadece bizi[ENTER]kurtamakla kalmad\253n. Sayende ecdad\253m\253z da rahat[ENTER]uyuyacak. T\252m tabya halk\253n\253 temsilen sana \254u[ENTER]\246d\252l\252 veriyorum. "
gameforge.main_quest_lv97._640_sayTitle = "Seviye 98'e ula\254t\253\240\253nda macerana devam[ENTER]edebilirsin. "
gameforge.main_quest_lv97._650_say = "\220ss\252 bulmak uzun s\252rd\252. L\252tfen, daha fazla zaman[ENTER]kaybedemeyiz! "
gameforge.main_quest_lv97._660_say = "Yak-Hwan'a fosil toprak m\253 laz\253m? \222ansa bak[ENTER]bitmemi\254. \221\254te, buyur. \222imdi bunu ona g\246t\252r ve[ENTER]benden selam s\246yle. "
