gameforge.main_quest_lv98._020_say = "Amiral Angmur'un yard\253m\253na ihtiyac\253 var. Yan\253na[ENTER]git. "
gameforge.main_quest_lv98._030_say = "Geldi\240in i\231in sa\240ol. Sava\254 geriye izlerini[ENTER]b\253rakmadan ge\231medi. Tabyaya sald\253r\253ld\253, koruyucu[ENTER]setin b\252y\252k bir k\253sm\253 y\253k\253ld\253. Bu bar\253\254 s\252reci[ENTER]uzun s\252rmeyecek. Bar\253\254 s\252recini lehimize kullan\253p[ENTER]tabyay\253 yeniden in\254a edelim. "
