gameforge.new_christmas = {}
gameforge.new_christmas._010_npcChat = "Ho ho ho! "
gameforge.new_christmas._020_say = "Ah, sen miydin![ENTER]Uzun zaman oldu g\246r\252\254meyeli.[ENTER]Bir y\253l ge\231ti \252zerinden, ho ho![ENTER]Belki neden k\246yde oldu\240umu merak ediyorsundur.[ENTER]Sana anlataca\240\253m \133 "
gameforge.new_christmas._030_say = "Zaman zor. Art\253k kimse kitap ve benzeri \254eyler[ENTER]almak istemiyor.[ENTER]Hele \254u ileri ya\254\253mda ren geyikli k\253za\240\253mla[ENTER]havada u\231mak benim i\231in \231ok yorucu.[ENTER]Bu nedenle bu sene noeli burada, k\246yde kutlamaya[ENTER]karar verdim. "
gameforge.new_christmas._040_say = "Ba\254ka sorun varsa, istedi\240in zaman bana[ENTER]gelebilirsin. Mutlu Noeller! "
gameforge.new_christmas._050_npcChat = "Bir pun\231 ister misin? "
gameforge.new_christmas._060_say = "Ho ho ho! Bunun ne oldu\240unu biliyorsundur, de\240il[ENTER]mi? K\253\254 aylar\253nda bundan iyi i\231ecek yok![ENTER]Lezzetli bir meyve suyu al, bir tutam tar\231\253n,[ENTER]biraz karanfil ... mmmmh! "
gameforge.new_christmas._070_say = "Bu so\240ukta bir yudum pun\231 iyi gelir![ENTER]Sana verdi\240i g\252\231 sayesinde daha h\253zl\253 hareket[ENTER]edebilirsin. Denemek ister misin?[ENTER]Harika, hemen d\246nerim! "
gameforge.new_christmas._080_say = "Pun\231 ho\254una gitti herhalde, ho ho![ENTER]\221\231ini nas\253l \253s\253tt\253\240\253n\253 hissediyor musun?[ENTER]Hele o tatl\253 ve meyvemsi tad\253.[ENTER]Mutlu Noeller! "
gameforge.new_christmas._090_npcChat = "Daha fazla pun\231 l\252tfen! "
gameforge.new_christmas._100_say = "Ah, bir saniye![ENTER]Bir \254ey unuttum![ENTER]Pun\231u sana sadece g\252nde bir kez haz\253rlayabilirim,[ENTER]daha fazlas\253na malzemelerim yetmez.[ENTER]Ayr\253ca \246mr\252 sadece 20 saattir. Bir \254i\254ede 6[ENTER]porsiyon vard\253r, bir yudumun etkisi 30 dakika[ENTER]s\252rer. Yani iyi b\246l\252\254t\252r! "
gameforge.new_christmas._110_say = "Buyur! \199ok beklemek zorunda kald\253n.[ENTER]Bu muhte\254em i\231ecek sana kanat takt\253r\253r, ho ho ho![ENTER]Afiyet olsun. Mutlu Noeller! "
gameforge.new_christmas._120_say = "Ne, daha da m\253 istiyorsun?[ENTER]Kusura bakma ama yeterince i\231tin zaten.[ENTER]Son hakk\253n\253n \252zerinden daha 24 saat ge\231medi.[ENTER]Bunun fazlas\253 zarar! Daha sonra gel.[ENTER]Yine de iyi bayramlar! "
