gameforge.new_christmas_sock = {}
gameforge.new_christmas_sock._010_npcChat = "\199oraplara ne oldu? "
gameforge.new_christmas_sock._020_say = "\199oraplar! Neredeyse unutuyordum![ENTER]Hediyelerimi \254\246minenin \252zerine as\253lan \231oraplara[ENTER]saklamak istiyordum.[ENTER]Ama \254u lanet yarat\253klar hepsini \231alm\253\254![ENTER]Bunlar\253 geri almama yard\253m et. "
gameforge.new_christmas_sock._030_say = "\199oraplar\253 bulmak o kadar kolay de\240il.[ENTER]Bunlar\253n aramak i\231in ren geyikleri yavrular\253[ENTER]bulmal\253s\253n. "
gameforge.new_christmas_sock._040_say = "Ne kadar tatl\253 de\240il mi?[ENTER]\220stelik m\252kemmel bir koku alma duyusu var.[ENTER]\199orap bulmada uzman![ENTER]2 saat boyunca yan\253nda kal\253r ve aramada sana[ENTER]yard\253mc\253 olur. Sonra yorulur ve ancak 24 saat[ENTER]sonra devam edebilir. E\240er o kadar beklemek[ENTER]istemezsen sol alt tarafta d\246nen paran\253n arkas\253na[ENTER]bak - orada ba\254ka bir ren geyi\240i yavrusunun daha[ENTER]bekledi\240ini duydum. Ama ertesi g\252n beni ziyaret[ENTER]etmene de sevinirim! "
gameforge.new_christmas_sock._050_npcChat = "Sana \231orap getiririm! "
gameforge.new_christmas_sock._060_say = "Bana en az 5 \231orap getirirsen bir \246d\252l[ENTER]kazan\253rs\253n. I\240\240 giyilmi\254 \231oraplar\253n kokusuna[ENTER]tahamm\252l etmek \231ok zor! Yeterince toplad\253\240\253nda[ENTER]tekrar gel. \221yi Noeller! "
gameforge.new_christmas_sock._070_say = "Ho ho ho, yeterince \231orap toplad\253n.[ENTER]\214yleyse bir bakay\253m.[ENTER]\214\240\240 bu koku \133 Bunlar do\240ru \231oraplar![ENTER]Mutlu Noeller! "
gameforge.new_christmas_sock._080_npcChat = " - Ren Geyi\240i Yavrusu "
gameforge.new_christmas_sock._090_say = "Bug\252n benden bir Ren Geyi\240i Yavrusu M\252hr\252 ald\253n[ENTER]zaten. Korkar\253m bu k\252\231\252k Ren Geyi\240i Yavrusu'nun[ENTER]\246nce k\252\231\252k bir molaya ihtiyac\253 var. Ancak yar\253n[ENTER]aramaya devam edebilir. E\240er o kadar beklemek[ENTER]istemiyorsun a\254a\240\253da d\246nen paran\253n arkas\253na bak -[ENTER]orada bir Ren Geyi\240i Yavrusu daha oldu\240unu[ENTER]duydum. Ama beni yar\253n bir kez daha ziyaret[ENTER]etmene de \231ok sevinirim! "
gameforge.new_christmas_sock._100_say = "\199oraplar\253n\253 bug\252n bana getirdin bile. Sadece 24[ENTER]saatte bir \231orap teslim edebilece\240ini unutma. "
