gameforge.new_quest_lv17._020_say_title = "Chaegirab i\231in hediye "
gameforge.new_quest_lv17._021_say = "Chaegirab Amcam hayat\253n\253 bilime adad\253 ve ne kadar[ENTER]Yang'i varsa ara\254t\253rmaya yat\253rd\253. Bana her zaman[ENTER]iyi davranm\253\254t\253r. Bu y\252zden O'na bir hediyeyle[ENTER]s\252rpriz yapmak istiyorum. Uriel'e gidip bir fikri[ENTER]var m\253 diye sorar m\253s\253n? Kendisi amcam\253n ya\254l\253[ENTER]hocas\253d\253r ve amcam\253 yak\253ndan tan\253r. "
gameforge.new_quest_lv17._030_say = "Ama amcama sak\253n \231akt\253rma! "
gameforge.new_quest_lv17._031_say = "Bana yard\253m edecek misin? "
gameforge.new_quest_lv17._039_say_title = "Uriel: "
gameforge.new_quest_lv17._040_say_title = "Uriel'le konu\254 "
gameforge.new_quest_lv17._040_target = "Uriel: "
gameforge.new_quest_lv17._041_say = "Uriel'le eski \246\240rencilerinden Chaegirab hakk\253nda[ENTER]konu\254. "
gameforge.new_quest_lv17._042_say = "Uriel'i burada bulabilirsin: %s "
gameforge.new_quest_lv17._050_say_title = "Wonda-Rim, Chaegirab'a hediye vermek istiyor... "
gameforge.new_quest_lv17._051_say = "Ara\254t\253rmac\253n\253n mutlulu\240u m\252tevazidir ve[ENTER]ara\254t\253rman\253n kendisidir. Chaegirab'a[ENTER]ara\254t\253rmas\253nda yard\253mc\253 olacak bir \254ey yaparsan,[ENTER]bu O'nun i\231in en b\252y\252k mutluluk olur.[ENTER]Mu-Rang-Kurdu \252lkemizdeki ender bulunan[ENTER]misafirlerden biridir ve O'nun postunu almak her[ENTER]biyolo\240u mutlu eder. 5 post yetecektir.[ENTER]Wonda-Rim'e b\246yle s\246yle. "
gameforge.new_quest_lv17._052_say = "B\246yle bir post, biyolo\240u kesin etkileyecek. "
gameforge.new_quest_lv17._060_select = "Tamam, O'na s\246yleyece\240im. "
gameforge.new_quest_lv17._065_say_title = "Tekrar Wonda-Rim'e git "
gameforge.new_quest_lv17._066_say = "Chaegirab'\253n hediyesi i\231in Uriel'in g\252zel bir[ENTER]fikri vard\253. Wonda-Rim'e geri git ve O'na bundan[ENTER]s\246z et. "
gameforge.new_quest_lv17._067_say = "Wonda-Rim'i burada bulabilirsin: %s. "
gameforge.new_quest_lv17._070_say = "Uriel'in tavsiyesi kula\240a ho\254 geliyor. Amcama iyi[ENTER]bir s\252rpriz yapmak istedi\240ime g\246re bu postlardan[ENTER]bulmam laz\253m. Benim i\231in ava \231\253k\253p, 5 Mu-Rang[ENTER]haklar m\253s\253n? "
gameforge.new_quest_lv17._071_say = "Postlar\253n\253 soymak i\231in Mu-Rang-Kurtlar\253'ndan[ENTER]\246ld\252rmem gerek. "
gameforge.new_quest_lv17._072_say = "\221yi bir hediye i\231in 5 par\231a yeter. "
gameforge.new_quest_lv17._073_say = "Haydi ba\254layal\253m! "
gameforge.new_quest_lv17._074_notice = "\221yi korunmu\254 bir post ele ge\231irdin. "
gameforge.new_quest_lv17._075_say = "Mu-Rang-Kurtlar\253'n\253 avla ve postlar\253n\253 al. "
gameforge.new_quest_lv17._076_say_reward = "\222u ana kadar 5 posttan %s tanesini toplad\253n. "
gameforge.new_quest_lv17._081_say_title = "Wonda Rim i\231in Post "
gameforge.new_quest_lv17._082_say = "Yeteri kadar post toplad\253n. Onlar\253 Wonda-Rim'e[ENTER]g\246t\252r. "
