gameforge.new_quest_lv17._120_target = "Chaegirab Amca "
gameforge.new_quest_lv17._121_say = "Wonda-Rim senden kurt postlar\253n\253 Chaegirab'a[ENTER]g\246t\252rmeni rica etti. "
gameforge.new_quest_lv17._122_say = "Chaegirab'\253 burada bulabilirsin: %s. "
gameforge.new_quest_lv17._130_say = "Hmm... Demek b\246yle yapmaya \231al\253\254\253yor. "
gameforge.new_quest_lv17._131_say = "Kimden bu postlar? Wonda-Rim'den mi? Kurtlar\253[ENTER]O'nun i\231in mi haklad\253n?[ENTER]Ba\254kas\253n\253 kendisi i\231in \231al\253\254t\253ran bir ye\240enim[ENTER]oldu\240u i\231in utan\231 duyuyorum. Harcad\253\240\253n zaman ve[ENTER]katland\253\240\253n zahmet i\231in \231ok \252z\252lsem de, bu[ENTER]postlar\253 kabul edemeyece\240im. "
gameforge.new_quest_lv17._132_say_reward = "Wonda-Rim'e, O'nun i\231y\252z\252n\252 anlad\253\240\253m\253 s\246yle![ENTER]E\240er beni mutlu etmek istiyorsa, ava kendisi[ENTER]\231\253kmal\253! "
gameforge.new_quest_lv17._140_say = "Chaegirab postlar\253 kabul etmedi ve Wonda-Rim'in[ENTER]davran\253\254\253 kar\254\253s\253nda \231ok k\253zg\253n. Seni Wonda-Rim'e[ENTER]geri yollad\253. "
gameforge.new_quest_lv17._141_say = "Amcam ne dedi? Umar\253m hediye ho\254una gitmi\254tir? "
gameforge.new_quest_lv17._142_1_select = "Evet, g\246zleri ya\254ard\253. "
gameforge.new_quest_lv17._142_2_select = "Hi\231 de de\240il. "
gameforge.new_quest_lv17._143_say = "\199ok g\252zel! Ba\254kalar\253n\253 mutlu etmek ne g\252zel bir[ENTER]duygudur. Elbette \246d\252l\252n\252 alacaks\253n. \221\254te burada,[ENTER]al hadi! "
gameforge.new_quest_lv17._144_say_reward_a = "20.000 tecr\252be puan\253 kazand\253n.[ENTER]20.000 Yang kazand\253n.[ENTER]Alt\253n Par\231as\253 kazand\253n. "
gameforge.new_quest_lv17._144_say_reward_b = "Wonda-Rim'i kand\253rd\253\240\253n i\231in s\253ralama puan\253[ENTER]kaybettin! "
gameforge.new_quest_lv17._145_say = "Senden postlar\253 almad\253 m\253? Hmm... Benim yerime[ENTER]senin ava \231\253km\253\254 olman iyi bir fikir de\240ildi[ENTER]ger\231ekten de. Bir dahakine ba\254ka t\252rl\252 yapaca\240\253m. "
gameforge.new_quest_lv17._146_say_reward = "Ama b\252t\252n \231aban\253n bo\254a gitmemesi laz\253m.[ENTER]Yang-Shin'e git. Postlar\253 senden iyi bir fiyata[ENTER]alacakt\253r. "
gameforge.new_quest_lv17._147_say = "Olaylar nas\253l da can s\253k\253c\253 geli\254iyor. En az\253ndan[ENTER]hala elinde post var. Yayang'taki avc\253[ENTER]Yang-Shin'e git ve postlar\253n\253 O'na sat. "
gameforge.new_quest_lv17._148_say = "Olaylar nas\253l da can s\253k\253c\253 geli\254iyor. En az\253ndan[ENTER]hala elinde post var. Bokjung'taki avc\253[ENTER]Yang-Shin'e git ve postlar\253n\253 O'na sat. "
gameforge.new_quest_lv17._149_say = "Olaylar nas\253l da can s\253k\253c\253 geli\254iyor. En az\253ndan[ENTER]hala elinde post var. Bakra'daki avc\253 Yang-Shin'e[ENTER]git ve postlar\253n\253 O'na sat. "
gameforge.new_quest_lv17._151_say = "Mu-Rang postlar\253 m\253? Bunlar i\254ime \231ok yarar.[ENTER]Bundan kendime bir pijama tak\253m\253 \231\253kart\253r\253m.[ENTER]Kar\254\253l\253\240\253nda \254u Yang kesenini al. Ayr\253ca \254u[ENTER]kitab\253 d\252n buldum. Belki burdan ba\254layabilirsin. "
