gameforge.new_quest_lv22._019_say_title = "\222eytan Kulesi Bek\231isi "
gameforge.new_quest_lv22._021_say = "\222eytan kulesi bek\231isi olan karde\254imle ilgili[ENTER]endi\254elerim var. Son zamanlarda kendini huzursuz[ENTER]hissediyordu. \220stelik hastal\253k da O'nu iyice[ENTER]beter etti: ba\254 a\240r\253s\253ndan beyni \231atl\253yor ve[ENTER]v\252cudunda lekeler \231\253kt\253 ama yerini de[ENTER]b\253rakam\253yor. O'na Baek-Go'nun ila\231lar\253ndan[ENTER]getirebilir misin? "
gameforge.new_quest_lv22._022_say = "Ben kendim gitmek isterdim ama bildi\240in gibi[ENTER]\222eytan Kulesi, Seungryong Vadisi'nin ortas\253ndaki[ENTER]Hwang Tap\253na\240\253'n\253n i\231inde. Orada sadece tehlikeli[ENTER]yarat\253klar falan var... "
gameforge.new_quest_lv22._023_say = "Yine geldin demek. \222ikayetleri unuttun mu? Biri[ENTER]sana bir \254ey dedi\240inde ona iyice kulak ver.[ENTER]Karde\254imin ba\254 a\240r\253s\253 ve v\252cunda lekeler var.[ENTER]Baek-Go'ya b\246yle de. "
gameforge.new_quest_lv22._024_select = "Karde\254e yard\253m et "
gameforge.new_quest_lv22._025_say_title = "Baek-Go'nun \221la\231lar\253 "
gameforge.new_quest_lv22._026_say = "\222eytan kulesi bek\231isinin ila\231lar\253 i\231in[ENTER]Baek-Go'yla konu\254. "
gameforge.new_quest_lv22._027_say = "Baek-Go'yu burada bulabilirsin: %s. "
gameforge.new_quest_lv22._030_target = "Baek-Go: "
gameforge.new_quest_lv22._031_say = "Sana ila\231 m\253 laz\253m? Hangi ilac\253 verece\240imi \254ansa[ENTER]b\253rakmak tehlikeli olur! Bana derman olaca\240\253m[ENTER]hastal\253\240\253n belirtilerini tam olarak s\246ylemen[ENTER]laz\253m. "
gameforge.new_quest_lv22._032_1_select = "Ba\254 a\240r\253s\253 ve v\252cutta lekeler "
gameforge.new_quest_lv22._032_2_select = "Bo\240az a\240r\253s\253 ve kas\253lma "
gameforge.new_quest_lv22._032_3_select = "Bilmiyorum ki. "
gameforge.new_quest_lv22._035_say = "Bu bana tam olarak iblis uyuzu gibi geliyor. E\240er[ENTER]etrafta \231ok fazla kene bula\254m\253\254 canavar varsa[ENTER]ge\231mez. Ona derman olacak bir ila\231 yapabilirim.[ENTER]Tabii bunun i\231in bana baz\253 malzemeler getirmen[ENTER]laz\253m. "
gameforge.new_quest_lv22._040_say = "\221htiyac\253m olan: "
gameforge.new_quest_lv22._041_say_reward = "Avlaman gereken: "
gameforge.new_quest_lv22._042_say = "Ayr\253ca \254unlara da iytiyac\253m olacak: "
gameforge.new_quest_lv22._043_say = "\222imdiye kadar b\246yle bir hastal\253\240\253 hi\231 duymad\253m.[ENTER]K\246y gardiyan\253n\253n sana belirtileri do\240ru[ENTER]s\246yledi\240ine emin misin? En iyisi bir daha sor[ENTER]bakal\253m. "
gameforge.new_quest_lv22._044_say = "Belirtileri bilmeden ila\231 yapamam. Git ve bir[ENTER]kere daha sor. "
gameforge.new_quest_lv22._050_set_title = "\221la\231 "
gameforge.new_quest_lv22._056_notice = "G\252zel. Geriye sadece %s demet bitki kald\253. "
gameforge.new_quest_lv22._057_notice = "Tamam, bana laz\253m olan b\252t\252n bitkiler bu kadar.[ENTER]\222imdi h\253zl\253ca Baek-Go'ya git. "
gameforge.new_quest_lv22._058_notice = "G\252zel, art\253k sadece %s karaci\240er kald\253. "
gameforge.new_quest_lv22._060_notice = "Hmm bir ci\240er. Daha %s tane daha laz\253m. "
gameforge.new_quest_lv22._061_notice = "\221htiyac\253m olan b\252t\252n ci\240erlerin bu kadar olmas\253[ENTER]laz\253m. \222imdi vakit kaybetmeden Baek-Go'ya git. "
gameforge.new_quest_lv22._062_notice = "Maalesef bu ci\240er i\254e yaramaz. "
gameforge.new_quest_lv22._063_say = "Daha %s x \222ifal\253 Bitkiye ihtiyac\253n var. "
gameforge.new_quest_lv22._064_say = "Daha %s x kaplan ci\240erine ihtiyac\253n var. "
gameforge.new_quest_lv22._065_say = "Art\253k ila\231 i\231in gereken b\252t\252n malzemeleri[ENTER]toplad\253n. Haydi yola \231\253k ve onlar\253 Baek-Go'ya[ENTER]g\246t\252r. "
gameforge.new_quest_lv22._066_say = "Baek-Go'nun yapaca\240\253 ila\231 i\231in malzeme topla: "
gameforge.new_quest_lv22._070_say = "Sa\240 ol. B\246ylece iblis uyuzu tedavisi i\231in gereken[ENTER]ilac\253 yapabilirim. "
gameforge.new_quest_lv22._071_say = "Bitti! \221stedi\240in ila\231 burada. Ama taze malzemeler[ENTER]kulland\253\240\253mdan ila\231 \231abuk bozulabilir. Onu %s[ENTER]dakika i\231erisinde ula\254t\253rman gerek! "
gameforge.new_quest_lv22._072_say = "Bek\231inin karde\254ini Hwang Tap\253na\240\253'n\253n ortas\253nda[ENTER]bulabilirsin. Ama yolda dikkatli ol. \199\252nk\252[ENTER]tehlikeli yarat\253klar Seungryong Vadisi'ni mesken[ENTER]tutmu\254 durumda! "
gameforge.new_quest_lv22._073_say = "Bunlar yetmez. Yolda gelirken malzemeleri mi[ENTER]kaybettin? Eksik olan bile\254enleri tamamlamadan[ENTER]senin i\231in hi\231 bir \254ey yapamam. "
gameforge.new_quest_lv22._080_target = "\222eytan Kulesi Bek\231isi "
gameforge.new_quest_lv22._082_set_clock = "Kalan s\252re "
gameforge.new_quest_lv22._083_say = "Hala yeterince zaman\253n var ama acele etmen gerek.[ENTER]Haydi bakal\253m, ila\231lar bozulmadan Seungryong'taki[ENTER]\222eytan Kulesi Bek\231isi'ne. "
gameforge.new_quest_lv22._084_say = "\199ok yava\254t\253n, s\252re doldu. Ama yine de ila\231lar\253[ENTER]\222eytan Kulesi Bek\231isi'ne g\246t\252r. Belki hala[ENTER]faydas\253 dokunur. "
gameforge.new_quest_lv22._085_say = "Bana ila\231lar\253 getirdi\240in i\231in te\254ekk\252r ederim. Bu[ENTER]ka\254\253nt\253 beni neredeyse \246ld\252recek. "
gameforge.new_quest_lv22._086_say = "Vaaay.. bunun tad\253 da g\252zelmi\254. Ka\254\253nt\253lar\253n[ENTER]ge\231ti\240ini hissetmeye ba\254lad\253m bile. "
gameforge.new_quest_lv22._087_say = "Bunun i\231in \246zel bir \246d\252l\252 hakettin! "
gameforge.new_quest_lv22._088_say_reward = "50.000 Tecr\252be puan\253 kazand\253n.[ENTER]12.000 Yang kazand\253n.[ENTER]Alt\253n bezeli ayakkab\253+4 kazand\253n.[ENTER]5 Mor iksir kazand\253n. "
gameforge.new_quest_lv22._089_say = "Peh, bunun tad\253 i\240ren\231mi\254. Bu ila\231 bozuk. Yolda[ENTER]ne kadar vakit ge\231irdin? Dilim nem tutmu\254 maymun[ENTER]zindan\253na d\246nd\252. "
gameforge.new_quest_lv22._090_say = "Aaa bir dakika... \254imdi daha iyi sanki. Cidden[ENTER]etkisi var bunun! O zaman ben de sana \246yle gaddar[ENTER]olmam. Al bakal\253m, bu da senin \246d\252l\252n. "
gameforge.new_quest_lv22._091_say = "Anla\254\253lan ilac\253 kaybettin. L\252tfen bir kere daha[ENTER]ava \231\253k ve Baek-Go'nun yeni bir ila\231 yapmas\253 i\231in[ENTER]gereken malzemeleri topla. Yoksa, bu ka\254\253nt\253lar[ENTER]b\246yle devam ederse, ben kendim iblis olaca\240\253m. "
gameforge.new_quest_lv22._095_say_reward = "50.000 Tecr\252be puan\253 al\253rs\253n.[ENTER]8.000 Yang al\253rs\253n. "
gameforge.new_quest_lv22._098_say = "\221lac\253 yine mi kaybettin? Hayat\253mda senden daha[ENTER]da\240\253n\253k kafal\253 biriyle daha kar\254\253la\254mad\253m! Neyse,[ENTER]bu konuda yapabilece\240imiz fazla bir\254ey yok. "
gameforge.new_quest_lv22._100_say_reward = "25.000 tecr\252be puan\253 kazand\253n. "
gameforge.new_quest_lv26 = {}
gameforge.new_quest_lv26._010_target = "Yang-Shin: "
gameforge.new_quest_lv26._020_say_title = "Yang-Shin: "
gameforge.new_quest_lv26._020_set_title = "Ka\231ak "
gameforge.new_quest_lv26._021_say = "Avc\253 Yang-Shin ava \231\253k\253lacak iyi bir yer bulmakta[ENTER]zorlan\253yor. O'na u\240ra ve bir yard\253m\253n olur mu[ENTER]diye bak bakal\253m. "
gameforge.new_quest_lv26._025_say = "Metin ta\254lar\253 ortaya \231\253kt\253\240\253ndan beri, hi\231 bir[ENTER]\254ey eskisi gibi de\240il. Yabani hayvanlar da[ENTER]neredeyse kuduz gibi davrand\253klar\253ndan pek \231ok[ENTER]yerde ava \231\253kmak imkans\253z oldu. Ama d\253\254ar\253da,[ENTER]vah\254i bir yerlerde gezgin Nakajima ya\254\253yor[ENTER]olmal\253. Nerede ava \231\253k\253laca\240\253n\253 biliyordur kesin.[ENTER]O'nu bulup sorar m\253s\253n? "
gameforge.new_quest_lv26._030_target = "Nakajima: "
gameforge.new_quest_lv26._031_say = "Buradaki en iyi av yerini bilmek istiyorsun[ENTER]demek? \214yle aceleci olma. Senin i\231in bir \254ey[ENTER]yapmam i\231in senin de bana bir iyili\240in dokunmas\253[ENTER]laz\253m. "
gameforge.new_quest_lv26._032_say = "\222unu bilmen laz\253m ki, ben d\253\254ar\253da kendi arzumla[ENTER]ya\254am\253yorum. Askerlerin zulm\252nden ka\231t\253\240\253m i\231in[ENTER]saklanmam gerek. Sevgili kar\253c\253\240\253m Ah-Yu'nun[ENTER]ya\254ad\253\240\253m\253 bilmesini isterdim. O'na bu haberi[ENTER]g\246t\252r\252r m\252s\252n?[ENTER]Ama unutma, O'nu sadece kulaklar\253ndan tan\253rs\253n![ENTER]Bunun i\231in sana O'nu ilk kez nerede \246pt\252\240\252m\252 sana[ENTER]s\246ylemesi laz\253m. O'nunla tam orada bulu\254aca\240\253m ve[ENTER]sende ava \231\253k\253lacak yeri bulmu\254 olacaks\253n. "
gameforge.new_quest_lv26._034_say_title = "Nakajima: "
gameforge.new_quest_lv26._035_say_title = "Ah-Yu: "
gameforge.new_quest_lv26._036_say_title = "Nakajima'y\253 Ara "
gameforge.new_quest_lv26._037_say = "Nakajima'n\253n ava \231\253k\253lacak iyi yerlerden haberi[ENTER]var. O'nu ara. "
gameforge.new_quest_lv26._038_say = "Nakajima'y\253 burada bulabilirsin: %s. "
gameforge.new_quest_lv26._040_say = "Nakajima sen misin? Beni Yang-Shin yollad\253! Ava[ENTER]\231\253kabilece\240i iyi bir yer ar\253yor. Belki senin bir[ENTER]fikrin vard\253r. \222\246yle \231ok tehlikeli olmayan bir[ENTER]yer...? "
gameforge.new_quest_lv26._050_target = "Ah-Yu: "
gameforge.new_quest_lv26._051_say = "Nakajima kendini askerlerden saklayan bir asker[ENTER]ka\231a\240\253d\253r. Kar\253s\253 Ah-Yu, O'nun sava\254ta \246ld\252\240\252n\252[ENTER]san\253yor. O'na Nakajima'n\253n hala hayatta oldu\240unu[ENTER]s\246yle. "
gameforge.new_quest_lv26._052_say = "Ah-Yu'yu burada bulabilirsin: %s. "
gameforge.new_quest_lv26._057_say = "Nakajima... ya\254yor mu? Sevgili kocac\253\240\253m hayatta[ENTER]m\253? Ah sana nas\253l te\254\254ek\252r etsem azd\253r![ENTER]O'nun sana s\246zetti\240i yer Yonjang Vadisi'dir.[ENTER]O'nunla orada bulu\254mak i\231in hemen yola \231\253k\253yorum. "
gameforge.new_quest_lv26._058_say = "Bizi tekrar kavu\254turdu\240un i\231in sana te\254ekk\252r[ENTER]ederim. \222u g\252lleri al, belki onlar\253 sevdi\240in[ENTER]birine arma\240an edersin? Ve \254imdi... \214z\252r dilerim[ENTER]ama acele etmem laz\253m! "
gameforge.new_quest_lv26._061_say = "Yani, Nakajima ile kar\253s\253 Ah-Yu'nun ilk[ENTER]\246p\252\254t\252kleri yer olan Yonjang Vadisi bug\252n i\231in[ENTER]iyi bir av yeri. "
gameforge.new_quest_lv26._062_say = "Yang-Shin bunu duydu\240unda \231ok memnun kalacak.[ENTER]O'nu burada bulabilece\240ini biliyorsun: %s. O[ENTER]halde oraya git ve g\252zel haberi yeti\254tir. "
gameforge.new_quest_lv26._063_say = "Yonjang Vadisi mi? Bak bu akl\253ma yatt\253. O b\246lgeye[ENTER]bula\254m\253\254 metin ta\254\253 oldu\240unu daha \246nce hi\231[ENTER]duymad\253m. \214n\252m\252zdeki g\252nlerde iyi \252r\252n[ENTER]toplayaca\240\253m kesindir! Hakketti\240in \246d\252l burada,[ENTER]al hadi. "
gameforge.new_quest_lv26._064_sayReward = "35.000 Tecr\252be Puan\253 kazand\253n. "
gameforge.new_quest_lv26._065_sayReward = "17.500 Yang al\253rs\253n. "
gameforge.new_quest_lv28 = {}
gameforge.new_quest_lv28._010_target = "Yu-Hwan: "
gameforge.new_quest_lv28._011_say = "M\252zisyen Yu-Hwan'\253n yard\253m\253na ihtiyac\253 var.[ENTER]Acele et ve mesele neymi\254 \246\240ren! "
gameforge.new_quest_lv28._015_npcChat = "Ah-Yu'nun Endi\254esi "
gameforge.new_quest_lv28._016_say = "Ah-Yu'nun, Yu-Hwan'a kar\254\253 g\252ven sorunu var.[ENTER]O'na git ve sana daha rahat a\231\253labilir mi diye[ENTER]anlamaya \231al\253\254. "
gameforge.new_quest_lv28._017_say = "Ah-Yu'yu burada bulabilirsin: %s. "
gameforge.new_quest_lv28._018_select = "Hemen Ah-Yu ile konu\254aca\240\253m! "
gameforge.new_quest_lv28._019_say_title = "Ah-Yu: "
gameforge.new_quest_lv28._020_say_title = "Yu-Hwan: "
gameforge.new_quest_lv28._021_say = "Ah-Yu'yu tan\253r m\253s\253n? \221ksirlerim i\231in bitki[ENTER]toplar. \222imdiye kadar hep keyfi yerindeydi ama[ENTER]d\252n tamamen alt\252st olmu\254 g\246rd\252m. Ne var ki, derdi[ENTER]neymi\254 anlatmak da istemedi. Herhalde benim i\231in[ENTER]\231al\253\254t\253\240\253ndad\253r(?). L\252tfen O'na git ve derdi[ENTER]neymi\254 \246\240ren. Belki sana daha \231ok g\252venir! "
gameforge.new_quest_lv28._022_say = "Yu-Hwan'\253n benimle ilgilenmi\254 olmas\253 \231ok ince bir[ENTER]davran\253\254. Evet, bir sorun var... Bunun hakk\253nda[ENTER]konu\254mak istemiyordum ama beni i\231in i\231in[ENTER]kemiriyor! \222u avc\253 Yang-Shin var ya... Kocam[ENTER]Nakajima'n\253n asker ka\231a\240\253 oldu\240unu \246\240rendi\240inden[ENTER]beri bana \254antaj yap\253yor. O'nu ispiyonlamakla[ENTER]beni tehdit ediyor! Yaparsa \246ld\252r\252rler O'nu... "
gameforge.new_quest_lv28._023_say = "Bu defa da suskunlu\240unu bozmamak i\231in benden ay\253[ENTER]pen\231esi istedi. Ama buray\253 terkedip ava \231\253kamam.[ENTER]Yang-Shin'in istediklerini getirerek bana yard\253m[ENTER]eder misin? "
gameforge.new_quest_lv28._024_set_title = "Ay\253 Av\253 "
gameforge.new_quest_lv28._025_notice = "Haydi ava! Ay\253 pen\231esi bulman\253n en iyi yolu Bera[ENTER]haklamakt\253r. "
gameforge.new_quest_lv28._026_notice = "Bir ay\253 pen\231esi ele ge\231irdim! "
gameforge.new_quest_lv28._027_notice = "Hepsi bu kadar olmal\253. Haydi Yang-Shin'e! "
gameforge.new_quest_lv28._028_notice = "Bu ay\253n\253n pen\231esi i\254e yaramaz \231\253kt\253. "
gameforge.new_quest_lv28._029_say = "Hala %s x ay\253 pen\231esine ihtiyac\253n var. "
gameforge.new_quest_lv28._031_say_reward = "Avlaman gereken: "
gameforge.new_quest_lv28._032_say = "Ah-Yu senden Yang-Shin'in taleplerini yerine[ENTER]getirmeni istedi. "
gameforge.new_quest_lv28._032_say_reward = "Hala %s x ay\253 pen\231esine ihtiyac\253n var. Ele[ENTER]ge\231irmek i\231in Bera'y\253 hakla. "
gameforge.new_quest_lv28._035_target = "Yang-Shin: "
gameforge.new_quest_lv28._036_say = "\221stenilen ay\253 pen\231elerini ele ge\231irdin. Bunlar\253[ENTER]Yang-Shin'e g\246t\252r\252p Ah-Yu'nun borcunu \246de. "
gameforge.new_quest_lv28._037_say = "Yang-Shin'i burada bulabilirsin: %s. "
gameforge.new_quest_lv28._038_say_title = "Yang-Shin: "
gameforge.new_quest_lv28._040_npcChat = "\222antaj "
gameforge.new_quest_lv28._041_say_title = "Ay\253 Pen\231esi "
gameforge.new_quest_lv28._042_say = "Ay\253 pen\231elerini bana m\253 getirdin? Benim hakk\253mda[ENTER]yanl\253\254 d\252\254\252ncelere kap\253lma! Avlanacak hayvanlar\253n[ENTER]iyice azald\253\240\253 veya metin ta\254lar\253 y\252z\252nden[ENTER]\246ld\252r\252c\252 canavarlara d\246n\252\254t\252\240\252 zor bir d\246nemden[ENTER]ge\231iyoruz ve ben de ba\254\253m\253n \231aresine bakmaya[ENTER]\231al\253\254\253yorum. Avc\253 olarak ya\254amak \231ok tehlikeli[ENTER]olmaya ba\254lad\253. "
gameforge.new_quest_lv28._043_say = "L\252tfen Ah-Yu'ya daha fazla korkmas\253na l\252z\252m[ENTER]olmad\253\240\253n\253 ilet. Bana g\252venebilir. En az\253ndan[ENTER]bana tekrar bir \254ey laz\253m olana kadar.... he he[ENTER]he! "
gameforge.new_quest_lv28._044_say = "Bana bir \254ey vermeden ge\231i\254tirmek mi istiyorsun?[ENTER]Taze ay\253 pen\231esi is-te-dim! "
gameforge.new_quest_lv28._045_say_reward = "Ah-Yu'ya yard\253m etmen g\252zel bir davran\253\254. Tabii[ENTER]bu, ben ne istersem onu yapman gerekti\240i anlam\253na[ENTER]geliyor. O halde bana iki ay\253 pen\231esi getirene[ENTER]kadar ava \231\253k bakal\253m \254imdi! "
gameforge.new_quest_lv28._046_say = "Ah-Yu'ya, Yang-Shin'in senin yard\253m\253ndan dolay\253[ENTER]O'na \254antaj yapmaktan vazge\231ti\240ini s\246yle. "
gameforge.new_quest_lv28._051_say = "Sen bizim kurtar\253c\253m\253zs\253n! Sana sonsuz \254\252kran[ENTER]bor\231luyum. Al hadi, bu Yang'lerim senin olsun.[ENTER]\199ok de\240il ama bunlar\253 fazlas\253yla hakettin. "
gameforge.new_quest_lv28._055_1_select = "\199ok te\254ekk\252rler, \231ok i\254ime yarayacaklar! "
gameforge.new_quest_lv28._055_2_select = "Hay\253r, bunu kabul edemem. "
gameforge.new_quest_lv28._056_say = "Neyim varsa hepsi bu kadar. Bu insanl\253ktan \231\253km\253\254[ENTER]tefeciden kurtuldu\240um s\252rece buna de\240er. "
gameforge.new_quest_lv28._057_say = "\199ok sa\240 ol! B\246ylece Ejderha Tanr\253s\253'n\253n yan\253ndaki[ENTER]yerini garantiye ald\253n! "
gameforge.new_quest_lv28._058_say_reward = "%s Yang al\253rs\253n. "
gameforge.new_quest_lv28._059_say_reward = "%s Tecr\252be puan\253 al\253rs\253n. "
gameforge.new_quest_lv28._070_say = "\221htiyac\253m olan: "
