gameforge.new_quest_lv29._010_target = "Yonah: "
gameforge.new_quest_lv29._015_npcChat = "Par\231alanm\253\254 Porselen "
gameforge.new_quest_lv29._020_say_title = "Yonah: "
gameforge.new_quest_lv29._021_say = "Benim k\253ymetli Seladon Porselenim! \220\231 nesildir[ENTER]ailemizin elinde. Ve \254imdi paha bi\231ilmez[ENTER]vazolardan \252\231\252 par\231aland\253. K\253sa bir s\252re \246nce \254u[ENTER]k\252\231\252k \231apulcu Taurean'\253 depoya girerken g\246rd\252m.[ENTER]Bu talihsizli\240in sorumlusunun O oldu\240una eminim! "
gameforge.new_quest_lv29._022_say = "Bu O'nun ilk kafas\253zl\253\240\253 de\240il ama bu sefer bariz[ENTER]\254ekilde \231izmeyi a\254t\253. Birinin O'nu adamak\253ll\253[ENTER]h\253rpalamas\253 laz\253m! Bunun i\231in zaman\253n var m\253yd\253[ENTER]acaba? "
gameforge.new_quest_lv29._023_1_select = "Ne demezsin, seve seve! "
gameforge.new_quest_lv29._023_2_select = "Bu beni ilgilendirmiyor. "
gameforge.new_quest_lv29._024_say = "Yaramaz \231ocuklar\253 terbiye edecek vaktim yok.[ENTER]O'nu kendin ha\254laman laz\253m. Ama bunu[ENTER]yapabilece\240inden \254\252pheliyim... "
gameforge.new_quest_lv29._030_target = "Taurean: "
gameforge.new_quest_lv29._031_say = "Yonah'\253n paha bi\231ilmez aile yadigar\253 Seladon[ENTER]Porseleni vazolar\253ndan \252\231\252 k\253r\253ld\253. Bunun[ENTER]Taurean'\253n i\254i oldu\240unu d\252\254\252n\252yor. Taurean'a git[ENTER]ve O'nu sorguya \231ek. "
gameforge.new_quest_lv29._032_say = "Taurean'\253 burada bulabilirsin: %s. "
gameforge.new_quest_lv29._033_say_title = "Taurean: "
gameforge.new_quest_lv29._034_say_reward = "Niye bana surat as\253yorsun? K\246t\252 bir \254ey yapmad\253m[ENTER]ben... "
gameforge.new_quest_lv29._035_say_reward = "Yonah'\253n vazolar\253na ne yapt\253n? "
gameforge.new_quest_lv29._036_say_reward = "Vazo mu? Yonah m\253? Neden s\246zetti\240ini cidden[ENTER]anlam\253yorum! "
gameforge.new_quest_lv29._037_say_reward = "O zaman \252\231 tanesinin niye k\253r\253ld\253\240\253n\253 a\231\253kla[ENTER]bakal\253m. "
gameforge.new_quest_lv29._038_say_reward = "Yemin ederim ki, ne bug\252n bir vazoya dokundum ne[ENTER]de Yonah'\253 g\246rd\252m. Tam aksine b\252t\252n g\252n Harang'la[ENTER]dala\254t\253m. Hatta beni bir ka\231 saatli\240ine samanl\253\240a[ENTER]kilitledi! \221stersen git O'na sor! Do\240ruyu[ENTER]s\246yl\252yorum! "
gameforge.new_quest_lv29._040_target = "Harang: "
gameforge.new_quest_lv29._041_say = "Taurean, su\231suz oldu\240unu iddia ediyor: B\252t\252n g\252n[ENTER]Harang'la oynam\253\254 ve o y\252zden vazolar\253 k\253rm\253\254[ENTER]olamazm\253\254. Harang'a git ve do\240ru muymu\254 diye sor. "
gameforge.new_quest_lv29._042_say_reward = "Harang, bug\252n Taurean'\253 g\246rd\252n m\252 hi\231? "
gameforge.new_quest_lv29._043_say_title = "Harang: "
gameforge.new_quest_lv29._044_say_reward = "Taurean m\253? Eveeet b\252t\252n g\252n beraber oynad\253k. Bir[ENTER]\254ey mi oldu? "
gameforge.new_quest_lv29._045_say_reward = "Yonah'a g\246re; Taurean b\252g\252n O'nun vazolar\253ndan[ENTER]\252\231\252n\252 k\253rm\253\254. "
gameforge.new_quest_lv29._046_say_reward = "Yonah k\246t\252 d\252\254\252n\252yor. Zaten ne zaman yak\253n\253na[ENTER]gitsek bizi kovar. Durmadan porselenlerini[ENTER]d\252\254\252n\252r. K\253ymetli vazolar\253na sadece \254u seyis[ENTER]arkada\254\253 dokunabilir. Belki de O k\253rm\253\254t\253r(?)! "
gameforge.new_quest_lv29._047_say = "Harang'\253 burada bulabilirsin: %s. "
gameforge.new_quest_lv29._050_target = "Seyis: "
gameforge.new_quest_lv29._051_say = "Harang, Taurean'\253n su\231suz oldu\240u y\246n\252ndeki[ENTER]ifadelerini do\240rulad\253. \221kisi de birden bir i\254[ENTER]\231eviriyor olabilir. Ama karar\253n\253 vermeden \246nce[ENTER]Yonah'\253n arkada\254\253 olan seyisi de sorgulamal\253s\253n. "
gameforge.new_quest_lv29._052_say = "Tanr\253 iyili\240ini versin Yonah. Porselenlerinin[ENTER]derdine d\252\254m\252\254, k\246y\252n \231ocuklar\253n\253 t\246hmet alt\253nda[ENTER]b\253rak\253yor. Bu i\254in su\231lusu metin ta\254lar\253! Topra\240\253[ENTER]zehirlediklerinden beri yeralt\253 zenginli\240imiz[ENTER]art\253k eskisi gibi de\240il. Porselenler de[ENTER]k\253r\253lganla\254t\253. Ama Yonah bunu anlamak[ENTER]istemiyor... "
gameforge.new_quest_lv29._053_say = "O'nun i\231in biraz saman toplarsan, sand\253\240\253ndaki[ENTER]porselenlerinin aras\253n\253 daha sa\240lam doldurabilir.[ENTER]Bunun O'nu biraz sakinle\254tirece\240i kesin. "
gameforge.new_quest_lv29._054_say = "Seyisi bulabilece\240in muhtemel yerler:[ENTER]%s veya %s. "
gameforge.new_quest_lv29._061_say = "Yonah'\253n k\253r\253lan vazolar\253n\253n sorumlusunun Taurean[ENTER]olmad\253\240\253 a\254ikar. Bunun nedeni metin ta\254lar\253ndan[ENTER]yay\253lan ve maddeyi sertle\254tiren k\246t\252 sa\231\253lma.[ENTER]Yonah'\253n porselenlerini daha iyi paketleyebilmesi[ENTER]i\231in saman topla! Baz\253 k\246yl\252lerin kendi[ENTER]samanlar\253ndan biraz\253n\253 sana verecekleri kesin. "
gameforge.new_quest_lv29._062_say = "K\246y kaps\253n\253n \246n\252nde bulabilece\240in %s ve %s has\253r[ENTER]\254apka giyerler. Kesin onlardan iyi bir miktar[ENTER]saman \231\253kar. "
gameforge.new_quest_lv29._063_notice = "Bunlardan bana iyi bir deste has\253r \231\253kar. %s[ENTER]desteye daha ihtiyac\253m var. "
gameforge.new_quest_lv29._064_notice = "Bu \254apka has\253rdan de\240il, hindistan cevizi[ENTER]lifinden yap\253lm\253\254. Bu i\254ime yaramaz. "
gameforge.new_quest_lv29._065_1_say = "G\246rd\252\240\252m kadar\253yla epey saman\253n var. Bunlardan[ENTER]biraz\253n\253 Yonah'a verirsen O'nu kesin[ENTER]sakinle\254tirirsin. "
gameforge.new_quest_lv29._065_notice = "Bu \254apka has\253rdan de\240il, hindistan cevizi[ENTER]lifinden yap\253lm\253\254. Bu y\252zden \231ok hasar g\246rm\252\254... "
gameforge.new_quest_lv29._066_say = "Yabani piyade ve g\252\231l\252 yabani askerleri[ENTER]\246ld\252rebilirsin. Onlar\253n has\253r \254apkalar\253ndan da[ENTER]saman \231\253kar. "
gameforge.new_quest_lv29._067_say_reward = "\222u ana kadar %s deste samandan %s adedini[ENTER]toplad\253n. "
gameforge.new_quest_lv29._068_notice = "Bir deste saman ele ge\231irdin. "
gameforge.new_quest_lv29._070_npcChat = "Samanl\253k "
gameforge.new_quest_lv29._071_say_reward = "Taurean sen bana daha \246nce samanl\253kta bulundu\240unu[ENTER]s\246ylemi\254tin. Belki yan\253na biraz saman alm\253\254s\253nd\253r[ENTER]ha? "
gameforge.new_quest_lv29._072_say_reward = "Hihihi, bir bakal\253m... sa\231\253ma ba\254\253ma,[ENTER]ayakkab\253lar\253m\253n i\231ine dolmu\254tu. Bak i\254te? \222urada[ENTER]birka\231 sap kalm\253\254, bunu da al! "
gameforge.new_quest_lv29._073_notice = "Bu saman \231ok de\240il ama k\252\231\252k bir deste \231\253kar.[ENTER]Daha %s deste daha laz\253m. "
gameforge.new_quest_lv29._074_say_reward = "Ger\231ekten ben de\240ildim! Harang sana bizim[ENTER]samanl\253kta d\246v\252\254t\252\240\252m\252z\252 anlatmad\253 m\253? "
gameforge.new_quest_lv29._075_say_reward = "Az \246nce samanl\253ktayd\253n de\240il mi? Acaba yan\253na[ENTER]biraz saman ald\253n m\253? "
gameforge.new_quest_lv29._076_say_reward = "Samanl\253kta oldu\240umu nereden biliyorsun sen? Yoksa[ENTER]\252st\252mde saman m\253 g\246rd\252n? Cidden buraya bir ka\231[ENTER]saman sap\253 yap\253\254m\253\254! "
gameforge.new_quest_lv29._077_say_reward = "Benim olsun mu? "
gameforge.new_quest_lv29._078_say_reward = "Benden taraf... "
gameforge.new_quest_lv29._079_say_reward = "Zaman\253m yok \254imdi. Taurean'a u\240ray\253p \254u vazo[ENTER]hikayesinden dolay\253 O'nu sakinle\254tirmem laz\253m! "
gameforge.new_quest_lv29._080_npcChat = "Yonah i\231in Saman "
gameforge.new_quest_lv29._081_say_reward = "Ah\253rda Yonah'a g\246t\252rebilmem i\231in fazla Saman var[ENTER]m\253? "
gameforge.new_quest_lv29._082_say_title = "Seyis: "
gameforge.new_quest_lv29._083_say_reward = "Daha fazla saman\253m\253z kalmad\253. Yabani hayvanlar ve[ENTER]k\246y\252n d\253\254\253ndan gelen haydutlar daha fazla[ENTER]bi\231memizi engelliyor. "
gameforge.new_quest_lv29._084_say_reward = "Ama sana az\253c\253k verebilirim! "
gameforge.new_quest_lv29._085_notice = "\199ok de\240il ger\231ekten de ama bir deste \231\253kar. %s[ENTER]deste daha laz\253m. "
gameforge.new_quest_lv29._086_say_reward = "\220zg\252n\252m, senin i\231in yapabilece\240im bir \254ey yok. "
gameforge.new_quest_lv29._090_send_letter = "K\246tek yerine Saman "
gameforge.new_quest_lv29._091_say = "Yonah i\231in yeterince saman toplad\253n. \222imdi[ENTER]bunlar\253 O'na vermek i\231in \254uraya git: %s "
gameforge.new_quest_lv29._101_say_reward = "Taurean'\253n su\231u yok. Metin ta\254lar\253ndan sa\231\253lan[ENTER]\253\254\253n, porseleni k\253r\253lganla\254t\253rd\253. "
gameforge.new_quest_lv29._102_say_title = "Yonah: "
gameforge.new_quest_lv29._103_say_reward = "Sen ne s\246yl\252yorsun burda? Bu tamamen sa\231mal\253k. O[ENTER]k\252\231\252k palavrac\253 seni kand\253rm\253\254. "
gameforge.new_quest_lv29._104_say_reward = "Taurean b\252t\252n g\252n boyunca Harang'la dala\254m\253\254. "
gameforge.new_quest_lv29._105_say_reward = "Sana seyis arkada\254\253ndan hem selam hem de saman[ENTER]getirdim ki, vazolar\253n\253 daha iyi saklayabilesin. "
gameforge.new_quest_lv29._106_say_reward = "Tamam, tepkimden dolay\253 utand\253\240\253m\253 kabul ediyorum[ENTER]ama sen de \254unu akl\253ndan \231\253karma; bu vazolar bana[ENTER]ailemi hat\253rlatt\253\240\253ndan onlara \231ok d\252\254k\252n\252m.[ENTER]Vazolardan biri k\253r\253ld\253\240\253nda, ben de kendimden[ENTER]bir \254eyler kaybeder gibi olurum... "
gameforge.new_quest_lv29._107_say_reward = "Senden ve Taurean'dan \246z\252r dilerim. Zahmetinden[ENTER]dolay\253 bu k\252\231\252k \246d\252l\252 hakettin! "
gameforge.new_quest_lv29._108_notice = "%s Bonus tecr\252be puan\253 al\253rs\253n! "
gameforge.new_quest_lv29._109_say_reward = "Sana seyis arkada\254\253ndan hem selam hem de saman[ENTER]getirdim ki, vazolar\253n\253 daha iyi saklayabilesin. "
gameforge.new_quest_lv29._110_say_reward = "\199ok ince bir davran\253\254 ama vazolar\253m\253n ger\231ekten[ENTER]de g\252vende olabilmesi i\231in bana %s deste daha[ENTER]saman getirir misin? "
gameforge.new_quest_lv29._111_say_reward = "San\253r\253m daha fazla saman bulmak gittik\231e[ENTER]zorla\254acak ama vazolar\253m benim i\231in kutsald\253r.[ENTER]Sana \231ok i\231ten \254\252kran bor\231lu olurum ve biraz da[ENTER]Yang veririm. "
gameforge.new_quest_lv29._112_say_reward = "O halde \254u ars\253z afacan Harang da Taurean'la[ENTER]birlikte i\254in par\231as\253. "
gameforge.new_quest_lv29._113_say_reward = "\214yle anla\254\253l\253yor ki; Ben bu iki ufakl\253\240\253 daha[ENTER]\246nce ambar\253n yak\253n\253nda g\246rd\252m dedi\240imde bana[ENTER]kimse inanmam\253\254. "
gameforge.new_quest_lv29._114_say_reward = "Dert etme. Hizmetin kar\254\253l\253\240\253ndaki tazminat\253n[ENTER]burada. "
gameforge.new_quest_lv29._115_say_reward = "Al hadi, %s Yang. "
gameforge.new_quest_lv42 = {}
gameforge.new_quest_lv42._010_send_letter = "Gurrrulll "
gameforge.new_quest_lv42._020_target = "Octavio: "
gameforge.new_quest_lv42._021_say = "Karn\253m t\253pk\253 bir yaban domuzununki gibi[ENTER]gurluduyor. Bir ara Octavio'ya u\240rasam iyi olur[ENTER]herhalde. Bu civar\253n en iyi bal\253k g\252vecini O[ENTER]yapar. "
gameforge.new_quest_lv42._022_say_title = "Octavio: "
gameforge.new_quest_lv42._023_say = "G\252ve\231te bal\253k m\253? \222u kafalar\253yla birlikte[ENTER]pi\254irileninden mi? \220zg\252n\252m, mutfa\240\253m ka\231 g\252nd\252r[ENTER]bal\253k y\252z\252 g\246rmedi. Normalde bal\253k\231\253, y\252ksek g\246l[ENTER]bal\253klar\253ndan getirir, ben de g\252ve\231 yapard\253m. "
gameforge.new_quest_lv42._024_say = "Ama ka\231 zamand\253r ortalarda g\246r\252nm\252yor. O'na bir[ENTER]u\240ray\253p, ne olmu\254 diye sorar m\253s\253n? "
gameforge.new_quest_lv42._025_say = "Octavio'yu burada bulabilirsin: %s. "
gameforge.new_quest_lv42._026_select = "Bal\253k\231\253'y\253 bulmaya gidiyorum! "
gameforge.new_quest_lv42._030_target = "Bal\253k\231\253: "
gameforge.new_quest_lv42._031_say = "Denizdeki iyi g\252nler geride kald\253! Bal\253klar her[ENTER]g\252n korkun\231 bir \254ekilde biraz daha azal\253yor![ENTER]Metin ta\254lar\253 denize d\246k\252ld\252\240\252nden beri, dostane[ENTER]balinalar deniz canavarlar\253na d\246n\252\254t\252. Bu zamanda[ENTER]ava \231\253kmak y\252rek ister. "
gameforge.new_quest_lv42._032_say = "Art\253k m\253zraklar\253m\253z balinalara i\254lemiyor.[ENTER]Derileri bir dev \246c\252n\252nkinden daha sert oldu! "
gameforge.new_quest_lv42._033_say = "Muhtemelen Yonah ne yap\253laca\240\253n\253 biliyordur. O[ENTER]y\253llarca denize a\231\253larak balina avlam\253\254t\253. "
gameforge.new_quest_lv42._034_say_title = "Bal\253k\231\253: "
gameforge.new_quest_lv42._035_say = "Octavia y\252ksek deniz bal\253klar\253n\253 bekliyor.[ENTER]Nakliyat\253n neden aksad\253\240\253n\253 bal\253k\231\253ya sor. "
gameforge.new_quest_lv42._036_say = "Bal\253k\231\253y\253 burada bulabilirsin: %s. "
gameforge.new_quest_lv42._037_send_letter = "K\253zg\253n Deniz Canavar\253 "
gameforge.new_quest_lv42._038_say = "Bal\253k\231\253 senden, k\246t\252 huylu balinalar\253n nas\253l[ENTER]avlanabilecekleri konusunda Yonah'a dan\253\254man\253[ENTER]istedi. "
gameforge.new_quest_lv42._039_say = "Yonah'\253 burada bulabilirsin: %s. "
gameforge.new_quest_lv42._040_target = "Yonah: "
gameforge.new_quest_lv42._041_say = "Balinalar\253n ba\254\253na ne geldi\240ini duydum zaten.[ENTER]Bal\253k\231\253lar i\231in \231ok k\246t\252 olmu\254. Denize a\231\253lmaya[ENTER]cesaret etseler bile, m\253zraklar\253 balina[ENTER]derisinden ge\231emeyecek kadar zay\253f. Balina avc\253s\253[ENTER]olarak \231al\253\254t\253\240\253m zamanlarda, derisi ya\254l\253 ve[ENTER]p\252t\252r p\252t\252r olan balinalar i\231in \246zel silahlar[ENTER]kullan\253rd\253k. Bu silahlar her \254eyi delebilirdi... "
gameforge.new_quest_lv42._042_say = "\214zel bir teknikle sertle\254tirilmi\254 balina tutma[ENTER]m\253zra\240\253 s\246zkonusu. Sadece demirci b\246yle m\253zraklar[ENTER]yapabilir. "
gameforge.new_quest_lv42._043_say_reward = "Demirciye git. "
gameforge.new_quest_lv42._044_say_title = "Yonah: "
gameforge.new_quest_lv42._045_say = "Yonah, balina av\253 i\231in \231ok sa\240lam ve keskin[ENTER]m\253zraklar tavsiye etti. Demirciye gidip, b\246yle[ENTER]m\253zraklar yapabilir mi diye sor. "
gameforge.new_quest_lv42._050_target = "Demirci. "
gameforge.new_quest_lv42._051_say = "Do\240rudur, s\246z etti\240in t\252rden m\253zraklar\253 bilirim[ENTER]ve bunlar\253 yapmak elimden gelir. Lakin, yeteri[ENTER]sa\240laml\253\240\253 yakalayabilmek i\231in elmas ta\254\253na[ENTER]ihtiyac\253m var. "
gameforge.new_quest_lv42._052_say = "\221htiyac\253m olan: "
gameforge.new_quest_lv42._053_say_reward = "Bunun i\231in i\254lemen gereken: "
gameforge.new_quest_lv42._054_say_title = "Demirci. "
gameforge.new_quest_lv42._060_set_title = "Elmas Ta\254\253 "
gameforge.new_quest_lv42._061_notice = "G\246rece\240iz. Ta\254\253 \231\253karmak i\231in bana bir kazma[ENTER]laz\253m. Benimki buralarda bir yerde mi, yoksa[ENTER]Deokbae'ye gidip yeni bir tane mi alsam? "
gameforge.new_quest_lv42._062_say = "Hala %s x elmas ta\254\253na ihtiyac\253n var. "
gameforge.new_quest_lv42._063_say = "Laz\253m olan her\254ey sende var. \222imdi aceleyle[ENTER]demirciye git. "
gameforge.new_quest_lv42._064_say = "Harika, ihtiyac\253m olan her \254ey burada. Yar\253n ayn\253[ENTER]saatte tekrar gel ve m\253zraklar\253n\253 al. B\246yle bir[ENTER]demirin i\254lenmesi laz\253m! "
gameforge.new_quest_lv42._065_say = "Elmas ta\254\253 \231\253kartmak i\231in elmas damar\253n\253 kazmayla[ENTER]i\254lemen gerek. "
gameforge.new_quest_lv42._066_say = "\214zel balina av\253 m\253zra\240\253 yapmak i\231in demirciye[ENTER]elmas ta\254\253 laz\253m. Elmas ta\254\253 \231\253kartmak i\231in elmas[ENTER]damar\253 bul. Da\240 kaz\253s\253 i\231in kazman yoksa,[ENTER]Deokbae'den bir tane alabilirsin. "
gameforge.new_quest_lv42._067_say = "Demirciyi burada bulabilirsin: %s. "
gameforge.new_quest_lv42._068_say = "M\253zrak yap\253m\253na ba\254layabilmemiz i\231in hala %s x[ENTER]elmas ta\254\253na ihtiyac\253m\253z var. "
gameforge.new_quest_lv42._070_set_title = "M\253zraklar "
gameforge.new_quest_lv42._071_set_clock = "Bekleme s\252resi "
gameforge.new_quest_lv42._072_say = "Demircinin elindeki i\254in bitmi\254 olmas\253 laz\253m. Ona[ENTER]git ve \246zel balina av\253 m\253zraklar\253n\253 al. "
gameforge.new_quest_lv42._073_say = "Maalesef m\253zraklar hen\252z bitmedi. Biraz daha[ENTER]sabretmen gerek. "
gameforge.new_quest_lv42._074_say = "M\253zraklar\253n burada i\254te. Bunlar\253 bal\253k\231\253ya g\246t\252r. "
gameforge.new_quest_lv42._075_say = "Senden m\253zraklar bitene kadar beklemeni[ENTER]istemi\254tim. Sonra tekrar gel. "
gameforge.new_quest_lv42._079_say = "Demirciden balina av\253 m\253zraklar\253n\253 ald\253n. \222imdi[ENTER]onlar\253 bal\253k\231\253ya g\246t\252r. "
gameforge.new_quest_lv42._080_say = "Harika! Bu m\253zraklar ger\231ekten \231ok etkileyici![ENTER]Nihayet kendimizi balinalar\253n sald\253r\253s\253ndan[ENTER]koruyup savunabilece\240iz. L\252tfen Octavio'ya[ENTER]yak\253nda taze bal\253klar\253 tekrar hesaba[ENTER]katabilece\240ini s\246yle. "
gameforge.new_quest_lv42._081_say_reward = "500.000 Yang al\253rs\253n. "
gameforge.new_quest_lv42._082_say_reward = "\214zel bir takdir olarak a\254a\240\253dakileri al\253rs\253n: 3x "
gameforge.new_quest_lv42._083_say = "Bir balinay\253 p\252sk\252rtmek i\231in bu kadar m\253zrak[ENTER]yetmez. Bunlarla ancak onu g\253d\253klayabiliriz! "
gameforge.new_quest_lv42._084_say_reward = "L\252tfen tekrar demirciye gidip kendine yeni[ENTER]m\253zraklar yapt\253r. "
gameforge.new_quest_lv42._090_say = "Bal\253k\231\253lar\253n te\231hizatlar\253 tamamd\253r. \222imdi tekrar[ENTER]a\231\253k denizde ava \231\253kabilirler. Octavio'ya git ve[ENTER]O'nu yeni teslimatlar alaca\240\253na dair sakinle\254tir. "
gameforge.new_quest_lv42._095_say = "Sen neler s\246yl\252yorsun b\246yle yahu? Dostane[ENTER]balinalar sald\253rgan deniz canavarlar\253na m\253[ENTER]d\246n\252\254t\252? Ama bu deh\254et bir olay... Bal\253k\231\253lara[ENTER]yard\253m etti\240in i\231in te\254ekk\252r ederim. Sofram\253n[ENTER]b\252y\252k k\253sm\253 bal\253k\231\253lar\253n eline bakar. "
gameforge.new_quest_lv42._096_say = "A\231l\253k meselene gelince: Elbette sana g\252ve\231te[ENTER]bal\253k sunam\253yorum ama biraz su\254iye ne dersin? "
gameforge.new_quest_lv42._098_say_reward = "750.000 Tecr\252be puan\253 al\253rs\253n.[ENTER]2 tane su\254i al\253rs\253n. "
gameforge.new_quest_lv43 = {}
gameforge.new_quest_lv43._005_send_letter = "Wonda-Rim'i Ziyaret "
gameforge.new_quest_lv43._006_send_letter = "\214ks\252z \199ocuk "
gameforge.new_quest_lv43._010_target = "Wonda-Rim: "
gameforge.new_quest_lv43._011_say = "\199oktand\253r Wonda-Rim'den bir haber almad\253n. Belki[ENTER]bu arada amcas\253yla aras\253 d\252zelmi\254, Mu-Rang[ENTER]postuyla ilgili sorunlar unutulmu\254tur. O'nu bir[ENTER]ziyaret et bakal\253m. "
gameforge.new_quest_lv43._012_say = "Wonda-Rim'i burada bulabilirsin: %s. "
gameforge.new_quest_lv43._020_say = "Tekrar u\240ram\253\254 olman \231ok g\252zel. "
gameforge.new_quest_lv43._021_say_title = "Wonda-Rim: "
gameforge.new_quest_lv43._022_say = "Chaegirab Amcam'\253n yan\253nda b\252y\252d\252m. Asl\253nda[ENTER]aram\253z iyiydi... ama ne zaman annemle babam\253[ENTER]sorsam konuyu sapt\253r\253r. \214lm\252\254ler, o kadar...[ENTER]b\252t\252n s\246yledi\240i bu. "
gameforge.new_quest_lv43._023_say_reward = "Ben de bir g\252n evlenip aile kurmak istiyorum. O[ENTER]y\252zden kim oldu\240umu, nerden geldi\240imi bilmem[ENTER]laz\253m. Amcamla konu\254up ebeveynlerimi sorar m\253s\253n?[ENTER]Ama l\252tfen seni benim g\246nderdi\240imi a\240z\253ndan[ENTER]ka\231\253rma. "
gameforge.new_quest_lv43._024_select = "Onunla konu\254aca\240\253m! "
gameforge.new_quest_lv43._025_say = "Wonda-Rim, Chaegirab'\253n ger\231ek ye\240eni de\240ildir,[ENTER]sadece O'nun yan\253nda b\252y\252d\252. Ama art\253k O'nun i\231in[ENTER]ge\231ek ebeveylerinin kim oldu\240unu \246\240renme vakti[ENTER]geldi. Chaegirab'a Wonda-Rim'in aslen nereden[ENTER]geldi\240ini sor. "
gameforge.new_quest_lv43._026_say = "Chaegirab'\253 burada bulabilirsin: %s. "
gameforge.new_quest_lv43._030_target = "Chaegirab: "
gameforge.new_quest_lv43._031_say_title = "Chaegirab: "
gameforge.new_quest_lv43._032_say = "Wonda-Rim... evet, O'nun ger\231ek amcas\253 de\240ilim.[ENTER]Ebeveynlerinin kim olduklar\253n\253 bilmiyorum.[ENTER]\222imdiye kadar \246\240renmeye haz\253r olmad\253\240\253n\253[ENTER]d\252\254\252nd\252\240\252mden, ger\231e\240i O'ndan saklad\253m. Ama belki[ENTER]de zaman\253 gelmi\254tir art\253k. "
gameforge.new_quest_lv43._033_say = "O'nu Seungryong Vadisi'nde, bir Ork sava\254\231\253lar\253[ENTER]ordusunun yan\253nda buldum. Wonda-Rim'in asl\253n\253n ne[ENTER]oldu\240una ili\254kin ipucu, bulunsa bulunsa onlardan,[ENTER]yani Orklar'dan bulunur. "
gameforge.new_quest_lv43._034_say = "O'na kar\254\253 \231ok kat\253 olsam da, ben her zaman O'nun[ENTER]amcas\253 olaca\240\253m. Hatta, hala b\246yle yaramaz bir[ENTER]adam olmaya devam etse bile. "
gameforge.new_quest_lv43._035_say_reward = "Seungryong Vadisi'ne y\246nel ve Wonda-Rim'in asl\253[ENTER]hakk\253nda bir ipucu bulana dek Ork sava\254\231\253s\253[ENTER]hakla. "
gameforge.new_quest_lv43._036_say = "\214lesiye d\246v\252lm\252\254 bir Ork sava\254\231\253s\253n\253n kirli[ENTER]\231antas\253nda eski bir mektup ke\254fettin. Yaz\253y\253[ENTER]okumak \231ok g\252\231 ama Wonda-Rim ad\253n\253 okuyabildin.[ENTER]Arad\253\240\253n ipucu bu olsa gerek. Mektubu Wonda-Rim'e[ENTER]g\246t\252r. "
gameforge.new_quest_lv43._041_say = "Durma o zaman! Wonda-Rim'in asl\253n\253 bulman\253n yolu[ENTER]Ork sava\254\231\253s\253 \246ld\252rmekten ge\231iyor. Belki[ENTER]yanlar\253nda ta\254\253d\253klar\253 bir ipucu vard\253r! "
gameforge.new_quest_lv43._043_notice = "Wonda-Rim hakk\253nda ipucu... "
gameforge.new_quest_lv43._045_say = "Sana bildi\240im her \254eyi s\246yledim. Elimizdeki tek[ENTER]\231\253k\253\254 noktas\253 Ork sava\254\231\253lar\253. Sorunumuz ise...[ENTER]Onlarla mant\253kl\253 konu\254mak pek m\252mk\252n de\240il. "
gameforge.new_quest_lv43._049_say = "Mektup mu? Bir bakay\253m... Yaz\253s\253 okunakl\253 de\240il.[ENTER]Bir sald\253r\253dan s\246zediyor; Orklar tarlay\253 ete\254e[ENTER]vermi\254ler... can\253n\253 kurtaran ka\231\253yor...[ENTER]\231ocuklar\253n\253 b\253rakmak zorunda kalm\253\254lar...[ENTER]vee burada da benim ad\253m var. "
gameforge.new_quest_lv43._050_say = "Bunu bana getirdi\240in i\231in sana te\254ekk\252r ederim.[ENTER]Ne oldu\240unu biliyorum nihayet. "
gameforge.new_quest_lv43._051_say = "Chaegirab'la konu\254mam laz\253m. Belli ki beni[ENTER]kurtarmak i\231in kendini tehlikeye atm\253\254. O'na[ENTER]lay\253k bir ye\240en olmaya \231al\253\254aca\240\253m. G\246r\252\254mek[ENTER]\252zere dostum! "
gameforge.new_quest_lv43._052_say_title = "Bilgi: "
gameforge.new_quest_lv43._053_say_reward = "32.000 Yang al\253rs\253n. "
gameforge.new_quest_lv43._054_say_reward = "1.250.000 Tecr\252be puan\253 al\253rs\253n. "
gameforge.new_quest_lv43._060_say = "Amcam Chaegirab ile konu\254tun mu? \221pucu var m\253? Ne[ENTER]diyorsun sen? E\240er g\246sterecek bir\254eyin yoksa,[ENTER]tahmin etmeye geri d\246neceksin demektir![ENTER][ENTER]L\252tfen amcama tekrar sor. Sonu\231ta bunun i\231in sana[ENTER]para \246d\252yorum. "
gameforge.new_quest_lv52 = {}
gameforge.new_quest_lv52._010_send_letter = "Y\252zba\254\253n\253n Mektubu "
gameforge.new_quest_lv52._020_say_title = "Sad\253k Hem\254ehri "
gameforge.new_quest_lv52._021_say_reward = "Bana bir iyilik yapman\253 rica ediyorum.[ENTER]Baek-Go'nun ila\231lar\253na ra\240men hala geceleri[ENTER]uyuyam\253yorum, yatakta d\246n\252p duruyorum. O'nu bulup[ENTER]daha g\252\231l\252 uyku ilac\253 var m\253ym\253\254 diye sorar[ENTER]m\253s\253n? "
gameforge.new_quest_lv52._022_say = "Baek-Go'yu burada bulabilirsin: %s. "
gameforge.new_quest_lv52._030_set_title = "Gece S\252kuneti "
gameforge.new_quest_lv52._035_target = "Baek-Go: "
gameforge.new_quest_lv52._040_say = "Y\252zba\254\253n\253n uyku sorunu var. Baek-Go'ya gidip[ENTER]y\252zba\254\253 i\231in daha g\252\231l\252 bir uyku ilac\253 var m\253ym\253\254[ENTER]diye sor. "
gameforge.new_quest_lv52._041_say = "Y\252zba\254\253 i\231in uyku ilac\253 m\253? Maalesef bende, sana[ENTER]verebilece\240im daha g\252\231l\252s\252 yok. Arzu etti\240in[ENTER]etkiyi g\246sterebilecek bitkisel bir ilac\253 sadece[ENTER]Yu-Hwan yapabilir. "
gameforge.new_quest_lv52._042_say = "Ha, benim mektubu ald\253n demek. Ne yapaca\240\253m\253[ENTER]bilmiyorum ger\231ekten. Geceleri huzur diye bir \254ey[ENTER]kalmad\253. L\252tfen bana yard\253m et ve tavsiyeleri[ENTER]i\231in Baek-Go'ya dan\253\254. "
gameforge.new_quest_lv52._042_select = "O zaman ben Yu-Hwan'a gitsem iyi olacak! "
gameforge.new_quest_lv52._043_say = "Baek-Go'yu burada bulabilirsin: %s. "
gameforge.new_quest_lv52._044_say_title = "Baek-Go: "
gameforge.new_quest_lv52._045_say = "Yu-Hwan'\253 burada bulabilirsin: %s. "
gameforge.new_quest_lv52._046_say = "\214yleyse Y\252zba\254\253'ya git ve ona yard\253m[ENTER]edemeyece\240ini s\246yle. "
gameforge.new_quest_lv52._049_say_title = "Yu-Hwan: "
gameforge.new_quest_lv52._050_target = "Yu-Hwan: "
gameforge.new_quest_lv52._051_say = "Baek-Go'nun bu t\252rden daha g\252\231l\252 ilac\253 yok. Arzu[ENTER]edilen etkiyi g\246sterecek bir bitkiyi, bilse bilse[ENTER]Yu-Hwan bilir. "
gameforge.new_quest_lv52._052_say = "Y\252zba\254\253y\253 iyi tan\253r\253m. Sen de mutlaka[ENTER]biliyorsundur; ka\231 zamand\253r O'nun gizli i\254lerini[ENTER]hallediyorum. O y\252zden sana diyece\240im o ki,[ENTER]derdine derman olacak bir bitki yok. "
gameforge.new_quest_lv52._053_say = "Y\252zba\254\253n\253n uyuyamas\253n\253n sebebi ba\254ka bir \254ey.[ENTER]\221nan bana kendisi de fark\253nda zaten. Ama bu, onun[ENTER]kendisinin \231\246zebilece\240i bir mesele. Onun yerine[ENTER]ben yapamam. Ona git ve konu hakk\253nda konu\254. "
gameforge.new_quest_lv52._054_say_title = "Y\252zba\254\253 "
gameforge.new_quest_lv52._055_say_reward = "Ha, benim mektubu ald\253n demek. Ne yapaca\240\253m\253[ENTER]bilmiyorum ger\231ekten. L\252tfen Baek-Go'ya git ve[ENTER]sor ki, ben de geceleri tekrar uyuyabileyim. "
gameforge.new_quest_lv52._055_select = "Emredersiniz! "
gameforge.new_quest_lv52._056_say = "Te\254ekk\252rler! "
gameforge.new_quest_lv52._056_say_reward = "Bunu yapt\253m zaten ama Baek-Go'nun bu t\252rden daha[ENTER]g\252\231l\252 ilac\253 yok. Bir de Yu-Hwan'\253 bulup, yard\253mc\253[ENTER]olabilir mi diye O'na soraca\240\253m. "
gameforge.new_quest_lv52._060_target = "Y\252zba\254\253 "
gameforge.new_quest_lv52._061_say = "Yu-Hwan ba\254ka birinin s\253rr\253 hakk\253nda konu\254mak[ENTER]istemiyor, bu muhtemelen naho\254 bir konu. Yolu[ENTER]yok, bu konuda Y\252zba\254\253 ile konu\254mal\253s\253n. E\240er[ENTER]konunun ne oldu\240unu \246\240renemezsek onun uyku[ENTER]sorununu \231\246zemeyiz. %s istikametine git. "
gameforge.new_quest_lv52._062_say_reward = "Daha g\252\231l\252 bir uyku ilac\253 yok. Ama uykusuzluk[ENTER]sorununuzun ger\231ek nedenini \246\240renebilirsem, belki[ENTER]yine de size yard\253mc\253 olabilirim y\252zba\254\253. "
gameforge.new_quest_lv52._063_say_reward = "Bu \246yle senin gibi gen\231 bir adama anlatabilece\240im[ENTER]t\252rden bir \254ey de\240il. "
gameforge.new_quest_lv52._064_say_reward = "Bu \246yle senin gibi gen\231 bir han\253ma[ENTER]anlatabilece\240im t\252rden bir \254ey de\240il. "
gameforge.new_quest_lv52._065_say_reward = "Ama yak\253n bir zamanda uyuyamazsam, er ya da ge\231[ENTER]akl\253m\253 yitirece\240im. B\246yle olmas\253 da laz\253m...[ENTER]Unutma! Senden ba\254kas\253 bilmeyecek: Her gece d\246rt[ENTER]ruh beni rahats\253z eder ama en k\246t\252s\252 bu de\240il...[ENTER]Onlar\253n \246l\252m\252nden ben sorumluyum. "
gameforge.new_quest_lv52._066_say_reward = "Bunlar d\246rt askerdir. Seungryong Vadisi'nde[ENTER]i\254nceciler ve haberciler taraf\253ndan i\254kenceye[ENTER]u\240ray\253p \246ld\252r\252ld\252klerini iddia ediyorlar. Onlara[ENTER]oraya, \246l\252me gitme emrini veren bendim! "
gameforge.new_quest_lv52._067_say_reward = "Bu ruhlara kar\254\253 ne yap\253labilir? "
gameforge.new_quest_lv52._068_say_reward = "\214\231 almak istiyorlar! Ama ne yapabilirim ki? E\240er[ENTER]intikam almak i\231in k\246yden \231\253k\253p gitsem; k\246y[ENTER]lidersiz kalacak ve yok edilecek. Yok e\240er[ENTER]kal\253rsam da ben akl\253m\253 kaybedece\240im. "
gameforge.new_quest_lv52._069_say_reward = "E\240er b\252t\252n k\246y ve k\246y halk\253n\253 korumakla sorumlu[ENTER]olmasayd\253m hemen giderdim. Sadece \254\246yle bir \231\253k\253\254[ENTER]yolu g\246r\252yorum: "
gameforge.new_quest_lv52._070_say_reward = "Benim yerime ba\254ka biri intikam almal\253! Ama daha[ENTER]fazla adam\253, onlar\253n sonu anlam\253na gelecek bu[ENTER]vadiye nas\253l g\246nderebilirim!? Nas\253l olur da daha[ENTER]rahat uyuyabilmek i\231in b\246yle bir \254ey isterim? "
gameforge.new_quest_lv52._071_say_reward = "Bu \246yle kolay bir karar de\240il. "
gameforge.new_quest_lv52._080_1_select = "K\246y\252n huzuru... "
gameforge.new_quest_lv52._080_2_select = "Kolay olacak... "
gameforge.new_quest_lv52._080_3_select = "B\246yle bir \254ey istenmez! "
gameforge.new_quest_lv52._081_say_reward = "...sizin kayg\253lar\253n\253zdan daha a\240\253r bas\253yor.[ENTER]Adamlar\253n\253z\253n \246c\252n\252 alaca\240\253m. Geri d\246nmeyecek[ENTER]olursam, geceleyin g\246r\252\254\252r\252z! "
gameforge.new_quest_lv52._082_say_reward = "... bu habercilerden ve i\254kencecilerden kurtulmak[ENTER]kolay olacak. Bu gece rahat uyuyacaks\253n\253z. Size[ENTER]s\246z veriyorum! "
gameforge.new_quest_lv52._083_say_reward = "\221\254kencecilere ve habercilere kafa tutmak intihar[ENTER]demektir. Size burada ne kadar ihtiya\231[ENTER]duyuldu\240unu ruhlara a\231\253klamaya \231al\253\254\253n! "
gameforge.new_quest_lv52._084_say_reward = "Hakl\253s\253n\253z. Ger\231i k\246y ve benim i\231in b\252y\252k bir[ENTER]g\246revi yerine getirmek i\231in kendili\240inden teklif[ENTER]edersiniz diye umut etmi\254tim. "
gameforge.new_quest_lv52._090_1_select = "\221yi o zaman... "
gameforge.new_quest_lv52._090_2_select = "Hay\253r, bunun alt\253ndan kalkamam! "
gameforge.new_quest_lv52._091_say_reward = "...madem son umudunuz benim, o halde bu[ENTER]habercileri ve i\254kencecileri temizleyece\240im! "
gameforge.new_quest_lv52._092_say_reward = "Bunu denemeye kalksam, sizi geceleri rahats\253z[ENTER]edecek fazladan bir ruh daha olur. "
gameforge.new_quest_lv52._093_say_reward = "\221yi, g\252zel. O zaman m\252saade et de, zahmetin[ENTER]kar\254\253l\253\240\253nda seni biraz Yang'le \246d\252llendireyim. "
gameforge.new_quest_lv52._093_say_reward_exp = "20.000 Tecr\252be puan\253 al\253rs\253n. "
gameforge.new_quest_lv52._093_say_reward_gold = "25.000 Yang kazand\253n. "
gameforge.new_quest_lv52._100_notice = "Konu\254ma sona erdi. "
gameforge.new_quest_lv52._110_say_reward = "\221\254te b\246yle bir \254ey diyece\240ini umdum. Maalesef[ENTER]hangi haberci ve i\254kencecilerin onlar\253[ENTER]\246ld\252rd\252\240\252n\252 bilmiyorum. Ruhlardan biri[ENTER]kurtuldu\240unda bunu hissedebilece\240imi umuyorum. "
gameforge.new_quest_lv52._111_say_reward = "Sana bir mektup yollayaca\240\253m. Ruhlar bana[ENTER]intikam\253n, Ejder Tanr\253s\253 \220\231geni'nde ger\231ekle\254mesi[ENTER]gerekt\240ini s\246ylediler. Orada \252\231genin k\246\254elerini[ENTER]belli eden \252\231 direk olmas\253 laz\253mm\253\254. "
gameforge.new_quest_lv52._120_set_title = "4 \214l\252n\252n \221ntikam\253 "
gameforge.new_quest_lv52._125_say_title = "Y\252zba\254\253n\253n Mektubu "
gameforge.new_quest_lv52._130_say_reward = "\221ntikam\253 al\253nacak daha 3 asker var! "
gameforge.new_quest_lv52._131_say = "Anla\254\253lan ba\254ar\253l\253 olmu\254sun. Az \246nce \246ld\252r\252len[ENTER]askerlerimden birinin sesini i\254ittim. Bana adalet[ENTER]yerine geldi\240i i\231in beni affetti\240ini s\246yledi. Bu[ENTER]tamamen senin ba\254ar\253n! "
gameforge.new_quest_lv52._132_say = "L\252tfen karanl\253k i\254kenceciyi ve haberciyi[ENTER]\246ld\252rerek, \246len \246teki askerlerin de \246c\252n\252 al.[ENTER]Onlar\253 sadece Ejder Tanr\253s\253 \220\231geni'nin \252\231 b\252y\252k[ENTER]dire\240inde kurtarabilece\240ini unutma. "
gameforge.new_quest_lv52._140_say_reward = "Sadece 2 askerin intikam\253 kald\253! "
gameforge.new_quest_lv52._141_say = "Askerlerimden birinin daha katilini enseledin![ENTER]\222afak vakti \246lenlerden birinin veda edercesine[ENTER]elini kald\253rd\253\240\253n\253 g\246rm\252\254 gibi oldum. "
gameforge.new_quest_lv52._150_say_reward = "1 askerin intikam\253 kald\253! "
gameforge.new_quest_lv52._151_say = "Sen inan\253lmazs\253n! Az \246nce \246len askerlerden[ENTER]birinin ruhu yan\253ma geldi ve benimle vedala\254t\253.[ENTER]San\253r\253m, art\253k son katili bulmak zor olacak. "
gameforge.new_quest_lv52._160_say = "Y\252zba\254\253ya huzursuzluk veren ruhlar, y\252zba\254\253n\253n[ENTER]verdi\240i g\246revde \246len gen\231 askerlerdir. Karanl\253k[ENTER]i\254kenceci, karanl\253k haberci, b\252y\252k i\254kenceci ve[ENTER]b\252y\252k haberci taraf\253ndan \246ld\252r\252lm\252\254lerdir. "
gameforge.new_quest_lv52._161_say = "Askerlerin intikam\253n\253 almak i\231in; Ejder Tanr\253s\253[ENTER]\220\231geni'ndeki \252\231 b\252y\252k direkte bu i\254in[ENTER]sorumlular\253n\253 temizlemelisin. "
gameforge.new_quest_lv52._162_say = "Ejder Tanr\253s\253 \220\231geni, Seungryong Vadisi'nin[ENTER]ortas\253ndad\253r. "
gameforge.new_quest_lv52._170_send_letter = "Birinci askerin intikam\253 al\253nd\253 "
