gameforge.new_quest_lv52._181_say = "Sonuncu katili de buldun! Sonuncu asker az \246nce[ENTER]bana g\246r\252nd\252 ve sana cesaretinden dolay\253 te\254ekk\252r[ENTER]etmemi diledi. Senin i\231in de bir \254ey b\253rakt\253: %s "
