gameforge.new_quest_lv52._183_say_reward = "Hem benim, hem k\246y i\231in \231ok b\252y\252k bir g\246revi[ENTER]yerine getirdin. Ruhun bana senin i\231in b\253rakt\253\240\253[ENTER]\246d\252l\252n burada: %s "
