gameforge.new_quest_lv54._030_say = "Birliklerimizin morali \254u anda pek iyi de\240il,[ENTER]taze erzak \231ok zorlu bir yoldan geliyor. \199ok[ENTER]\246nemli iksir kaynaklar\253m\253zdan biri olan Sat\253c\253,[ENTER]haftalard\253r bize ihtiyac\253m\253z olandan daha az[ENTER]iksir temin edebildi. "
gameforge.new_quest_lv54._031_say_reward = "L\252tfen Sat\253c\253ya git ve sorunun nerden[ENTER]kaynakland\253\240\253n\253 \246\240ren. "
