gameforge.new_quest_lv54._040_say_title = "Sat\253c\253: "
gameforge.new_quest_lv54._040_set_title = "Taze Erzak "
gameforge.new_quest_lv54._050_target = "Sat\253c\253: "
gameforge.new_quest_lv54._051_say = "Evet, son zamanlarda taze erzak sa\240lamakta sorun[ENTER]ya\254\253yorum. Daha s\253k ortaya \231\253kan e\254kiyalar ve[ENTER]vah\254i canavarlar y\252z\252nden yollar tehlikeli olmaya[ENTER]ba\254lad\253. Hepsinden \246te, kaplanlara kar\254\253 bana mal[ENTER]getiren t\252ccarlar\253n hi\231 bir \254ans\253 yok. "
gameforge.new_quest_lv54._052_say = "Belki y\252zba\254\253 askerleriyle yard\253m edebilir.[ENTER]L\252tfen ona git ve t\252ccarlar\253 korumak i\231in[ENTER]askerleriyle yolu kollar m\253 diye sor. "
gameforge.new_quest_lv54._054_say = "Sat\253c\253ya git ve taze iksir nakliyat\253n\253n neden[ENTER]aksad\253\240\253n\253 \246\240ren. "
gameforge.new_quest_lv54._055_say = "Sat\253c\253y\253 burada bulabilirsin: %s. "
gameforge.new_quest_lv54._056_say_title = "Y\252zba\254\253 "
gameforge.new_quest_lv54._060_say = "Yollar\253 kollamak m\253? Evet... asl\253na bakarsan[ENTER]severek yapard\253m. Ama di\240er krall\253klardan gelen[ENTER]t\252ccarlar\253 da kollayacak kadar askerim yok. "
gameforge.new_quest_lv54._061_say = "Ayr\253ca biz askerlerin, kaplan avlamas\253 da yasak.[ENTER]Bu sadece avc\253lar loncas\253na ba\240l\253 avc\253lara[ENTER]verilen bir izin. Bu kurallar\253 \231i\240nemenin k\246ydeki[ENTER]bar\253\254 ortam\253na faydas\253 dokunmaz. "
gameforge.new_quest_lv54._062_say_reward = "O nedenle Yang-Shin'e gitmen laz\253m. Kendisi[ENTER]avc\253lar loncas\253n\253n \252yesidir. Belki kaplan[ENTER]sorununun \231\246z\252m\252 i\231in sana yard\253mc\253 olabilir. "
gameforge.new_quest_lv54._064_say = "Y\252zba\254\253ya git ve O'nu, kaplanlara kar\254\253 ticaret[ENTER]yolunu kollamas\253 i\231in ikna et. "
gameforge.new_quest_lv54._065_say = "Y\252zba\254\253y\253 burada bulabilirsin: %s. "
gameforge.new_quest_lv54._070_target = "Yang-Shin: "
gameforge.new_quest_lv54._071_say = "Avc\253lar\253m\253ndan pek \231o\240u askere al\253nd\253 ve sava\254ta[ENTER]\246ld\252. Bu y\252zden vah\254i hayvanlar\253n say\253s\253n\253[ENTER]dengede tutacak unsur neredeyse kalmad\253.[ENTER]\214zellikle vah\254i kediler kendi b\246lgelerine iyice[ENTER]yay\253l\253p ge\231enlere deh\254et sa\231\253yor. "
gameforge.new_quest_lv54._072_say = "Bize bu i\254te yard\253m edersen, sana \246d\252l olarak[ENTER]\246len arkada\254\253m Mi-Song'tan kalan bu de\240erli[ENTER]Kaplan Kalkan\253+3'\252 veririm. Bunun kar\254\253l\253\240\253nda[ENTER]kaplan say\253s\253n\253 ciddi \254ekilde azaltmal\253s\253n. "
gameforge.new_quest_lv54._073_say = "\214zellikle Lanetli Beyaz Kaplanlar'\253n art\253\254\253[ENTER]kontrolden \231\253kt\253. "
gameforge.new_quest_lv54._074_say = "Kan\253t olarak ihtiyac\253m olan: "
gameforge.new_quest_lv54._075_say = "Avlaman gereken: "
gameforge.new_quest_lv54._076_say = "Yang-Shin'i bul ve ticaret yollar\253n\253 kaplanlara[ENTER]kar\254\253 g\252venli hale getirmesi i\231in O'nu ikna et. "
gameforge.new_quest_lv54._077_say_title = "Yang-Shin: "
gameforge.new_quest_lv54._078_say = "Yang-Shin'i burada bulabilirsin: %s. "
gameforge.new_quest_lv54._080_set_title = "Kaplan Postu "
gameforge.new_quest_lv54._081_notice = "Vay, e\254siz bir numune. %s tane daha! "
gameforge.new_quest_lv54._082_notice = "Tamamd\253r! \199abuk Yang-Shin'e git. "
gameforge.new_quest_lv54._083_notice = "Maalesef bu kaplan postu i\254e yaramaz. "
gameforge.new_quest_lv54._084_say = "Daha %s x I\254\253lt\253l\253 Kaplan Postu laz\253m. "
gameforge.new_quest_lv54._085_say = "Lanetli beyaz kaplan hakla ve onlardan \253\254\253lt\253l\253[ENTER]kaplan postu ele ge\231ir. "
gameforge.new_quest_lv54._090_npcChat = "Elimde kaplan postu var. "
gameforge.new_quest_lv54._091_say = "Bu bana uzun s\252re yetmez. Bu kadar az postla[ENTER]yollar\253n kesin kes g\252vende oldu\240una nas\253l[ENTER]s\246yleyebilirim? "
gameforge.new_quest_lv54._092_say = "Offf nihayet! Bu postlardan \231ok b\252y\252k kazan\231[ENTER]sa\240layaca\240\253m. Hala burda m\253s\253n? Sa\240 ol, sayende[ENTER]yollar en sonunda tekrar g\252venli! Y\252zba\254\253n\253n seni[ENTER]krallar gibi kar\254\253layaca\240\253na inanc\253m tam. "
gameforge.new_quest_lv54._093_say = "\222imdi yok ol. Postlar\253 temizlemem laz\253m. "
gameforge.new_quest_lv54._094_say = "Ah, y\252zba\254\253 sana hi\231bir \246d\252l vermedi mi? Bu benim[ENTER]sorunum de\240il. Ve \254ayet beni postlar y\252z\252nden[ENTER]karalamaya kalkarsan: Onlar\253 unut, bir daha geri[ENTER]vermem! "
gameforge.new_quest_lv54._095_say_reward = "Ama sana bir kalkan s\246z\252 vermi\254tim. Elbette onu[ENTER]alacaks\253n. Bu kirli \254eyin bana daha fazla faydas\253[ENTER]yoktu zaten. "
gameforge.new_quest_lv54._096_say = "\214d\252l: "
gameforge.new_quest_lv54._097_say_reward = "Bir tane Kaplan Kalkan\253+3 al\253rs\253n. "
gameforge.new_quest_lv54._098_say = "Beni bir ka\231 postla kaz\253klayaca\240\253n\253 m\253[ENTER]san\253yorsun? Bunlarla bor\231lar\253m\253... \254ey, yani[ENTER]demek istedi\240im; b\246yle yaparsan yollar hi\231 bir[ENTER]zaman g\252vende olmazlar! "
gameforge.new_quest_lv54._099_say_reward = "%s post toplayana kadar ava \231\253k! "
gameforge.new_quest_lv54._100_say = "Hepsi bu kadar. \199abuk Yang-Shin'e git. "
gameforge.new_quest_lv54._101_say_reward = "3.750.000 Tecr\252be puan\253 al\253rs\253n. "
gameforge.new_quest_lv54._102_say_reward = "125.000 Yang al\253rs\253n. "
