gameforge.new_quest_lv7._020_say_title = "K\253z \199ocu\240un D\252\240\252n\252 "
gameforge.new_quest_lv7._021_say = "\199ocuklar\253n\253z var m\253? O zaman derdimi[ENTER]anlars\253n\253z... k\253z\253mdan s\246z edece\240im! K\253z\253m,[ENTER]akl\253n\253 ba\254\253ndan alan bu adamla tan\253\254t\253ktan sonra[ENTER]onunla birlikte ba\254ka bir kral\253\253\240a ka\231t\253. "
gameforge.new_quest_lv7._022_say = "Adam Chunjo'dan geliyordu. Tabii ki kar\254\253 \231\253kt\253m![ENTER]Shinsoolu bir han\253mefendi, Chunjolu, akl\253 bir[ENTER]kar\253\254 havada biriyle evlenmez sand\253m. Tart\253\254t\253p[ENTER]k\252st\252k. O da adamla Chunjo'ya ka\231t\253. "
gameforge.new_quest_lv7._023_say = "Adam Jinno'dan geliyordu. Tabii ki kar\254\253 \231\253kt\253m![ENTER]Chunjolu bir han\253mefendi, Jinnolu, kafas\253[ENTER]\231al\253\254mayan, t\252ys\252z\252n tekiyle evlenmez sand\253m.[ENTER]Tart\253\254t\253p k\252st\252k. O da adamla Jinno'ya ka\231t\253. "
gameforge.new_quest_lv7._024_say = "Adam Shinsoo'dan geliyordu. Tabii ki kar\254\253[ENTER]\231\253kt\253m! Jinnolu bir han\253mefendi, Shinsoolu, para[ENTER]savurmaya al\253\254m\253\254 bir muhallebi \231ocu\240uyla[ENTER]evlenmez sand\253m. Tart\253\254t\253p k\252st\252k. O da adamla[ENTER]Shinsoo'ya ka\231t\253. "
gameforge.new_quest_lv7._030_say = "Orada onunla evlenmek istedi\240ini duydum. "
gameforge.new_quest_lv7._031_say = "\222imdi de k\253z\253m benden bir i\254aret bekliyor. Ne[ENTER]yapay\253m? O benim tek \231ocu\240um! Elbette hay\253r[ENTER]dualar\253m\253 alacak. L\252tfen benim i\231in ya\254l\253 kad\253na[ENTER]git ve ondan haz\253rl\253klara yard\253m etmesini rica[ENTER]et. "
gameforge.new_quest_lv7._040_target = "Ya\254l\253 Kad\253n "
gameforge.new_quest_lv7._041_say = "Ya\254l\253 kad\253n\253 bul ve d\252\240\252n haz\253rl\253klar\253na[ENTER]ba\254lanmas\253n\253 s\246yle. "
gameforge.new_quest_lv7._042_say = "Ya\254l\253 kad\253n\253 burada bulabilirsin: %s. "
gameforge.new_quest_lv7._051_say = "Bir d\252\240\252n m\252 dedin? Eveet.. bu bir kad\253n\253n[ENTER]hayat\253ndaki en \246nemli anlardan biridir.[ENTER]Gelinlikten ve damad\253n smokininden tut, d\252\240\252n[ENTER]seramonisiyle evlilik y\252z\252\240\252ne d\246necek olan ni\254an[ENTER]y\252z\252\240\252ne kadar her \254eyin ba\254tan sona do\240ru olmas\253[ENTER]gerekir. Gelinin babas\253 seramoni i\231in gereken[ENTER]paray\253 sa\240layabilece\240ini bildirirse, o zaman[ENTER]\231als\253n davullar! "
gameforge.new_quest_lv7._052_say = "En \246nemlisi \231i\231eklerdir - damad\253n sevgilisine[ENTER]verece\240i bir buket \231i\231ek olmadan hi\231 bir d\252\240\252n[ENTER]ger\231ekle\254mez. Buketin i\231inde \254u \231i\231ekler olmal\253: "
gameforge.new_quest_lv7._054_say = "\221htiyac\253m olan: "
gameforge.new_quest_lv7._055_say = "Avlaman gereken: "
gameforge.new_quest_lv7._056_say = "Bana ayr\253ca laz\253m olanlar: "
gameforge.new_quest_lv7._060_say = "\199i\231eklerin \252\231\252n\252 de toplad\253\240\253nda tekrar bana gel.[ENTER]Yapraklar\253n\253n taze olup olmad\253\240\253na bakt\253ktan[ENTER]sonra onlardan bir buket yapaca\240\253m. Sen de onu[ENTER]k\253zkarde\254ime g\246t\252receksin. Seramoniyi o yapacak. "
gameforge.new_quest_lv7._081_say = "Her \231e\254itten bir \231i\231ek topla. A\231 Alfa Kurdu, A\231[ENTER]Mavi Kurt ve A\231 Alfa Mavi Kurdu haklad\253\240\253nda bu[ENTER]\231i\231eklerden alabilirsin. "
gameforge.new_quest_lv7._082_say = "Bu solgun \231i\231ekle s\252s yap\253lmaz. Bu kadar \231aba[ENTER]bo\254una! "
gameforge.new_quest_lv7._083_say = "Bu solgun \231i\231ekle s\252s yap\253lmaz. Bu kadar \231aba[ENTER]bo\254una! "
gameforge.new_quest_lv7._084_say = "Bu solgun \231i\231ekle s\252s yap\253lmaz. Bu kadar \231aba[ENTER]bo\254una! "
