gameforge.new_quest_lv7._085_2_say_reward = "Sana %s tane daha Portakal Rengi \199i\231ek laz\253m.[ENTER]Bunu, A\231 Mavi Kurt \246ld\252rerek ele ge\231irebilirsin. "
