gameforge.new_quest_lv7._091_say = "Ba\254ard\253n! G\252zel bir buket i\231in bu kadar \231i\231ek[ENTER]yeterli olur. \222imdi elini \231abuk tut ve bunlar\253[ENTER]daha canl\253yken ya\254l\253 kad\253na g\246t\252r! "
gameforge.new_quest_lv7._092_say = "D\252\240\252n buketi i\231in \231i\231ek topla. "
gameforge.new_quest_lv7._110_say = "G\252zel \231i\231ekler ama g\246steri\254li bir d\252\240\252n i\231in[ENTER]zay\253f kal\253r. "
