gameforge.new_quest_lv7._112_say = "Bu \231i\231eklerden g\246steri\254li bir buket \231\253kar. "
gameforge.new_quest_lv7._115_say = "Sa\240 ol, \231ok g\252zel g\246r\252n\252yor! Bu buketi al ve[ENTER]k\253zkarde\254ime do\240ru yola \231\253k. "
