gameforge.new_quest_lv7._125_notice = "Buras\253 do\240ru krall\253k. Ya\254l\253 kad\253n\253n k\253zkarde\254i[ENTER]burada ya\254\253yor olmal\253. "
gameforge.new_quest_lv7._129_say = "Buras\253 do\240ru krall\253k, burada Octavio'yu[ENTER]bulmal\253y\253m. "
gameforge.new_quest_lv7._130_say = "Do\240ru yere benziyor. \222imdi ya\254l\253 kad\253n\253n[ENTER]k\253zkarde\254ini ara. "
gameforge.new_quest_lv7._131_say = "Anla\254\253lan buras\253 do\240ru krall\253k de\240il. "
gameforge.new_quest_lv7._132_say_reward = "Chunjo Krall\253\240\253'ndaki Bokjung b\246lgesine[ENTER]gitmelisin. "
gameforge.new_quest_lv7._133_say_reward = "Jinno Krall\253\240\253'ndaki Bakra b\246lgesine gitmelisin. "
gameforge.new_quest_lv7._134_say_reward = "Shinsoo Krall\253\240\253'ndaki Yayang b\246lgesine[ENTER]gitmelisin. "
gameforge.new_quest_lv7._135_say = "Shinsoo Krall\253\240\253'ndaki Yongan'da bulunan[ENTER]Octavio'ya geri git. "
gameforge.new_quest_lv7._136_say = "Chunjo Krall\253\240\253'ndaki Joan'da bulunan Octavio'ya[ENTER]geri git. "
gameforge.new_quest_lv7._137_say = "Jinno Krall\253\240\253'ndaki Pyungmo'da bulunan[ENTER]Octavio'ya geri git. "
gameforge.new_quest_lv7._140_say = "Octavio'nun k\253z\253n\253n kap\253ya dayanan d\252\240\252n\252n\252n[ENTER]\231i\231ekleri burada. Geline hay\253r dualar\253 e\254li\240inde[ENTER]verilmesi laz\253m. Bunlar\253n kimden geldi\240ini[ENTER]anlayacak. "
gameforge.new_quest_lv7._141_say = "Bunlar\253n g\252zelli\240i mucizevi! Gelin, bunlarla[ENTER]adeta \253\254\253k sa\231acak. B\246ylelikle seramoni[ENTER]haz\253rl\253klar\253 tamamlanm\253\254 oldu. L\252tfen Octavio'ya[ENTER]d\252\240\252ne davetli oldu\240unu ilet. Biliyorum, buna \231ok[ENTER]sevinecek. "
gameforge.new_quest_lv7._142_say = "Haydi Octavio'ya, daha neyi bekliyorsun? "
gameforge.new_quest_lv7._143_say = "Octavio'n\253n k\253zkarde\254inin d\252\240\252n\252 i\231in \231i\231ekler mi[ENTER]getirdin? Ne kadar iyisin! Ama...nerdeler?[ENTER]Gelirken kay\253p m\253 ettin? "
gameforge.new_quest_lv7._144_say_reward = "Kendi krall\253\240\253na geri d\246n ve yeni bir buket \231i\231ek[ENTER]getir. "
gameforge.new_quest_lv7._145_say = "\199i\231ekler solmadan, \231abuk ya\254l\253 kad\253n\253n[ENTER]k\253zkarde\254ine git. "
gameforge.new_quest_lv7._150_say = "Niye kurba\240a \231orbas\253 kokuyorsun sen? Neyse,[ENTER]\246nemli olan g\252zel haberler getirdi\240in. "
gameforge.new_quest_lv7._151_say = "Sana \231ok te\254ekk\252r ederim. K\253z\253m\253n d\252\240\252n\252nde[ENTER]bulunaca\240\253m i\231in \246yle mutluyum ki! "
gameforge.new_quest_lv7._152_say = "Al, bu da kar\254\253l\253\240\253nda haketti\240in \246d\252l\252n: "
gameforge.new_quest_lv7._153_say_reward = "Usta bir sava\254\231\253n\253n kendi elleriyle yapt\253\240\253 bir[ENTER]silah. Bunu itinayla kullan! "
gameforge.new_quest_lv7._154_say_reward = "%s Tecr\252be puan\253 al\253rs\253n. "
gameforge.new_quest_lv7._155_say_reward = "%s Yang al\253rs\253n. "
gameforge.new_quest_lv7._160_say = "Beni uzak akrabalar\253mdan biriyle kar\253\254t\253r\253yor[ENTER]olmal\253s\253n. Benim ne k\253z\253m var, ne de d\252\240\252n[ENTER]yapacak kadar Yang'im. "
gameforge.new_quest_lv7._165_say = "Ama konu\240um olup, bir ka\254\253k kurba\240a \231orbas\253[ENTER]denemek istemez misin? Teyzemden ald\253\240\253m eski bir[ENTER]tarife g\246re yapt\253m. "
