gameforge.new_quest_lv75._010_target = "Heuk-Young: "
gameforge.new_quest_lv75._020_set_title = "Bir Efsanenin G\252nl\252\240\252 "
gameforge.new_quest_lv75._021_say = "Bu sava\254\231\253 kal\253nt\253s\253n\253 buldum. Bu Heuk-Yong'un[ENTER]arad\253\240\253 Sura m\253 bilmiyorum ama eminim[ENTER]ilgilenecektir. "
gameforge.new_quest_lv75._022_say = "Burada sadece bir Sura \246lmemi\254. Ba\254ka kal\253nt\253lar[ENTER]da g\246r\252yorum. Acaba Efsanevi Sava\254\231\253 da[ENTER]aralar\253nda m\253yd\253? Heuk-Yong'a bunu bildirmeliyim. "
gameforge.new_quest_lv75._023_say = "Yeratl\253 Buz Goleminin i\231inde donmu\254 eski bir[ENTER]sayfa buldum. Hemen hemen okuyabiliyorum ama bu[ENTER]Heuk-Yong'un ilgilenece\240i bir ipucu olabilir. "
gameforge.new_quest_lv75._024_say = "Heuk-Yong'un ilgilenebilece\240i bir\254eyler buldum.[ENTER]Ona gidip eski sayfay\253 vermeliyim. Daha sonra ona[ENTER]cesedi de anlatabilirim. "
gameforge.new_quest_lv75._025_say = "Heuk-Yong, Efsane Sura hakk\253nda g\246zlerimi a\231\253k[ENTER]tutmam\253 s\246yledi. Ancak ne arayaca\240\253m hakk\253nda hi\231[ENTER]bir fikrim yok... "
gameforge.new_quest_lv75._030_say = "Efsane sava\254\231\253 Akuma'y\253 ara. O \254imdiye kadar[ENTER]d\252nyaya gelmi\254 en \252nl\252 Surayd\253 - ayr\253ca yenilmez[ENTER]bir sava\254\231\253yd\253. S\246ylentiye g\246re daha \246nce[ENTER]imparatorla bile sava\254m\253\254. San\253r\253m y\252zy\253llar \246nce[ENTER]Akuma'n\253n kayboldu\240u yer buras\253. L\252tfen[ENTER]ipu\231lar\253na bak ve nerede oldu\240unu bul. "
gameforge.new_quest_lv75._040_say = "sahte "
gameforge.new_quest_lv75._050_npcChat = "Yenik Sava\254\231\253lar\253 Ara\254t\253r "
gameforge.new_quest_lv75._060_say = "Bu bir sava\254\231\253n\253n kal\253nt\253lar\253na benziyor. Sol kol[ENTER]insans\253 de\240il...bu bir Sura olmal\253. Heuk-Yong'a[ENTER]bunu anlatmal\253y\253m. "
gameforge.new_quest_lv75._070_notice = "Bir kitap sayfas\253...Yeralt\253 Goleminin i\231inde[ENTER]donmu\254... "
gameforge.new_quest_lv75._090_say = "Sana tam olarak ne arad\253\240\253m\253z\253 s\246yleyemem. Sadece[ENTER]git biraz dola\254 ve bir\254ey bulursan geri gel. "
gameforge.new_quest_lv75._100_say = "Ne buldun? Bir bakay\253m! "
gameforge.new_quest_lv75._105_say = "Bir not... bu nas\253l bir yaz\253? \199ok eski olmal\253.[ENTER]\199ok \246nemli bi\254ey bulmu\254 olabilirsin. Yaz\253lar[ENTER]tan\253d\253k geliyor. Sanki bu sayfa bir kitab\253n[ENTER]par\231as\253. "
gameforge.new_quest_lv75._109_say = "Ba\254ka sayfalar da bulursak, bir anlam\253 olabilir.[ENTER]Ba\254ka ipu\231lar\253 bul! "
gameforge.new_quest_lv75._110_say = "\221\254te yine sen. Bir\254ey buldun mu? Anlat bana! "
gameforge.new_quest_lv75._115_say = "\214l\252 bir Sura...bu o olabilir, ama belki de sadece[ENTER]adamlar\253ndan biridir. Emin olmak i\231in daha fazla[ENTER]kan\253ta ihtiyac\253m var. Bunun kim oldu\240unu bulmak[ENTER]i\231in daha \231ok kan\253t bul. Silahlar, tak\253lar veya[ENTER]notlar gibi. "
gameforge.new_quest_lv75._120_say = "Bir Sura iskeleti ve kitap sayfas\253 m\253? Par\254\246mene[ENTER]bakmama izin ver... Hmm, Akuma'n\253n kal\253nt\253lar\253n\253[ENTER]bulmu\254 olabilirsin. Ancak daha fazla kan\253t gerek.[ENTER]L\252tfen ba\254ka kitap sayfalar\253 bulmaya \231al\253\254. "
gameforge.new_quest_lv75._130_say = "\222imdiye kadar biraz kan\253t buldum ancak efsanevi[ENTER]Sura'n\253n burada olup olmad\253\240\253ndan emin de\240ilim.[ENTER]Daha fazla bilgiye ihtiyac\253m var. "
gameforge.new_quest_lv75._140_1_select = "\221yi "
gameforge.new_quest_lv75._140_2_select = "Buz Canavar\253 "
gameforge.new_quest_lv75._140_3_select = "Umutsuzlu\240un k\253y\253s\253nda "
gameforge.new_quest_lv75._140_4_select = "Karanl\253k deh\254et "
gameforge.new_quest_lv75._140_5_select = "\214l\252m\252n y\252z\252 "
gameforge.new_quest_lv75._140_6_select = "Sava\254\231\253n\253n kaderi "
gameforge.new_quest_lv75._140_7_select = "Hay\253r, ilgilenmiyorum. "
gameforge.new_quest_lv75._150_say = "Sadece c\252mle par\231alar\253n\253 de\254ifre edebiliyorum.[ENTER]Sayg\253de\240er ya\254amdan ve a\254\253r\253 macera sevgisinden[ENTER]bahsediyor... "
gameforge.new_quest_lv75._160_1_say = "Sararm\253\254 par\254\246mendeki yaz\253, sanki ya\254l\253 ve zay\253f[ENTER]biri taraf\253ndan yaz\253lm\253\254 gibi soluk ve titrek:[ENTER]...Buz Yarat\253klar\253. Sura g\252\231lerim bile onlar\253[ENTER]yenmeme yetmedi. Baz\253lar\253 hala ma\240arada dola\254\253yor[ENTER]ve beni bulmamalar\253 i\231in \231ok dikkatli olmal\253y\253m.[ENTER]K\253sa zaman \246ncesine kadar bana koruma[ENTER]\246nermi\254lerdi, ama \254imdi... Bu noktada sayfa[ENTER]g\246zden kayboluyor. "
gameforge.new_quest_lv75._160_2_say = "Sayfa \231ok eski. \220stteki tarihten bunun bir g\252nl\252k[ENTER]oldu\240u anla\254\253l\253yor: Ma\240aray\253 ararken farkl\253[ENTER]davrand\253\240\253m\253 ilk kez fark etmiyorum. Kendimle \231ok[ENTER]\246v\252n\252yordum ve mutluydum! T\252m bunlar beni ani[ENTER]\246l\252m\252me s\252r\252kledi... \214l\252m kelimesinin alt\253[ENTER]\231izilmi\254ti. "
gameforge.new_quest_lv75._160_3_say = "Par\254\246men \231ok y\253pranm\253\254 ve yer yer kopmu\254. Sadece[ENTER]\254unlar okunuyor: ...\221mparator mahkemesi...[ENTER]bilginler bunu \231aresizce \246\240renmek istedi\240imi[ENTER]d\252\254\252nd\252klerinde...[ENTER]kap\253 kolayca a\231\253ld\253 ama... karanl\253kta \246l\252m ve[ENTER]karga\254a... B\252y\252k ve dik bir y\253rt\253k gerisini[ENTER]okuman\253 engelliyor. "
gameforge.new_quest_lv75._160_4_say = "Par\254\246menin bu sayfas\253nda bir karalama bulacaks\253n:[ENTER]Bu bir kad\253n\253n y\252z\252. Bunun alt\253nda tan\253d\253k baz\253[ENTER]kelimeler yaz\253l\253. Ancak bunlar daha titrek ve[ENTER]huzursuz: \214l\252md\252 beni pen\231esine alan - bunu d\252n[ENTER]fark ettim. Korku beni almadan ve geri \231ekilmeden[ENTER]\246nce yarat\253\240a sadece bir an bakt\253m. Ah Sumni,[ENTER]ke\254ke bilseydim! Bu tarif edilemez korkuyu[ENTER]bilseydim, bu noktaya gelmezdim! "
gameforge.new_quest_lv75._160_5_say = "Hee-Se Hanedan\253nda Akuma isimli efsanevi bir Sura[ENTER]ya\254am\253\254t\253. Sava\254ta \231ok yetenekliydi ve her[ENTER]rakibini, kendi g\252c\252n\252 test etmek i\231in[ENTER]kullan\253rd\253. Bir g\252n, gizli bir yer hakk\253nda[ENTER]m\252h\252rlenmi\254 notlar buldu ve hayat\253n\253 bu yeri[ENTER]bulmaya adad\253. Kap\253lar\253n nas\253l a\231\253ld\253\240\253n\253[ENTER]\246\240rendi. Eylemlerini bitirdikten sonra a\254k\253[ENTER]Sumni'ye geri d\246nmeye s\246z verdi... ancak geri[ENTER]d\246nemedi. "
gameforge.new_quest_lv75._170_say = "Yaz\253lar \231ok eski g\246r\252n\252yor... sanki yazar\253n\253n[ENTER]g\252c\252 kalmam\253\254 gibi \231ok titrek ve e\240ri b\252\240r\252... "
gameforge.new_quest_lv75._171_say = "Bunun bir anlam\253 yok. Ba\254ka sayfalara ihtiyac\253m\253z[ENTER]var. "
gameforge.new_quest_lv75._172_say = "Burada neler oldu\240unu anlamaya ba\254l\253yorum. Ama[ENTER]hala emin olmad\253\240\253m bir \231ok \254ey var. "
gameforge.new_quest_lv75._173_say = "Detaylar\253 bilmek ister miydin? "
gameforge.new_quest_lv75._174_say = "Ba\254ka bir sayfa! Bunu kim yazd\253ysa \231ok \231aresiz[ENTER]olmal\253. Ne s\246yledi\240ini \246zetlemeli miyim? "
gameforge.new_quest_lv75._175_say = "Baz\253 sayfalar o kadar k\246t\252 durumda ki ne[ENTER]yazd\253\240\253n\253 sadece tahmin edebiliyorum. Ancak,[ENTER]y\253llar \246nce bu ma\240arada neler oldu\240unu anlamaya[ENTER]ba\254l\253yorum. "
gameforge.new_quest_lv75._176_say = "\199ok fazla kay\253p yok. Ne buldu\240umu bilmek ister[ENTER]misin? "
gameforge.new_quest_lv75._177_say = "\199ok kay\253p sayfa yok gibi g\246r\252n\252yor. "
gameforge.new_quest_lv75._178_say = "\222imdiye kadar ne buldu\240umu bilmek istemiyor musun? "
gameforge.new_quest_lv75._180_notice = "Yeralt\253 Buz Yarat\253klar\253ndan son sayfay\253 buldum. "
gameforge.new_quest_lv75._185_send_letter = "B\252t\252n sayfalar bulunmu\254 olmal\253! "
gameforge.new_quest_lv75._190_notice = "Bu sayfay\253 Yeralt\253 Buz Goleminden buldum. "
gameforge.new_quest_lv75._195_send_letter = "Bir sayfa buldum! "
gameforge.new_quest_lv75._200_npcChat = "Yenik Sava\254\231\253lar\253 Ara\254t\253r "
gameforge.new_quest_lv75._210_say = "\221nsan iskeletlerinin yan\253nda 3 narin par\254\246men[ENTER]var. Y\253rt\253k kenarlar\253, bir kitaptan[ENTER]kopar\253ld\253klar\253n\253 anlat\253yor. Yaz\253lar soluk ve[ENTER]okumas\253 zor. "
gameforge.new_quest_lv75._220_say = "San\253r\253m bu yeterli. Bunu Heuk-Yong'a g\246t\252rece\240im. "
gameforge.new_quest_lv75._230_say = "Bunlar kimin kal\253nt\253lar\253? Emin oldu\240um bir\254ey var[ENTER]ki, \252zerinde bug\252n kullan\253labilecek hi\231bir\254ey[ENTER]yokmu\254. "
gameforge.new_quest_lv75._240_send_letter = "Sayfalar\253 ald\253m! "
gameforge.new_quest_lv75._250_say = "Heuk-Yong'a geri d\246nmeliyim. Belki o par\231alar\253[ENTER]birle\254tirir. "
gameforge.new_quest_lv75._270_say = "Ma\240arada bu kadar \231ok \254ey bulmana \254a\254\253rd\253m. Bu[ENTER]sayfalar bir kitab\253n par\231as\253 gibi. Burada[ENTER]yaz\253lanlar ger\231ekten ilgin\231. Duydu\240um t\252m[ENTER]hikayelerle birle\254tirince bir anlam kazan\253yor...[ENTER]E\240er bana sayfalar\253 verirsen onlar\253 kitap haline[ENTER]getirece\240im. S\252rg\252n ma\240aras\253na girdi\240inde i\254e[ENTER]yarayabilir. E\240er senin i\254ine yaramazsa, senden[ENTER]sat\253n alabilecek birini bulabiliriz. "
gameforge.new_quest_lv75._280_say = "Sayfalar\253 kitap haline getirdim ve baz\253 notlar\253m\253[ENTER]da ekledim. Sana yararl\253 olabilir. \221stersen sana[ENTER]hikayenin geri kalan\253n\253 da anlatabilirim. "
gameforge.new_quest_lv75._290_1_select = "Evet, daha fazla anlat! "
gameforge.new_quest_lv75._290_2_select = "Hay\253r, ilgilenmiyorum! "
gameforge.new_quest_lv75._310_say = "Benden ne istiyorsun? Okudu\240umu g\246rm\252yor musun? "
gameforge.new_quest_lv75._320_say = "Soon: "
gameforge.new_quest_lv75._330_say = "Elinde tuttu\240un \231ok ilgin\231 bir kitap. Nereden[ENTER]geldi? Bakabilir miyim? "
gameforge.new_quest_lv75._340_say = "Bunlar S\252rg\252n Ma\240aras\253ndan gelen notlar de\240il mi?[ENTER]Eski g\246r\252n\252yorlar. Yaz\253m al\253\254\253lmam\253\254 ve telaffuz[ENTER]\231ok eski... Bu t\252r bir kitab\253 elde etmek kolay[ENTER]olmam\253\254t\253r. Bunu ellerimde tutmak \231ok ho\254. Bunu[ENTER]satmak ister misin? "
gameforge.new_quest_lv75._350_1_select = "Evet "
gameforge.new_quest_lv75._350_2_select = "Hay\253r "
gameforge.new_quest_lv75._360_say = "Kitap i\231in ka\231 Yang istersin? "
gameforge.new_quest_lv75._370_say = "Haha... \231ok \254akac\253s\253n. Seninle i\254 yapmak kolay[ENTER]de\240il. Tamam, Efsanevi G\252nl\252k i\231in sana 500.000[ENTER]Yang veriyorum. Al ya da git! "
gameforge.new_quest_lv75._380_1_select = "500.000 Yang alaca\240\253m. "
gameforge.new_quest_lv75._380_2_select = "Unut bunu. "
gameforge.new_quest_lv75._390_say = "Tamam, unut bunu. "
gameforge.new_quest_lv75._400_say = "Hay\253r, \252zg\252n\252m benim i\231in \231ok pahal\253. "
gameforge.new_quest_lv75._410_say = "Ba\254ka bir \246neri yapay\253m. Sana Efsanevi G\252nl\252k[ENTER]i\231in %s Yang verece\240im. "
gameforge.new_quest_lv75._420_say = "Anla\254t\253k m\253? "
gameforge.new_quest_lv75._425_say = "Bu benim son teklifim! "
gameforge.new_quest_lv75._430_1_select = "%s Yang alaca\240\253m. "
gameforge.new_quest_lv75._430_2_select = "San\253r\253m i\254 yapamayaca\240\253z. "
gameforge.new_quest_lv75._440_say = "Nas\253l istersen... "
gameforge.new_quest_lv75._450_say = "Bu ucuz de\240il. Ama c\246mert olaca\240\253m. "
gameforge.new_quest_lv75._460_say = "Bu c\246mertli\240imin s\253n\253r\253. Sana Efsanevi G\252nl\252k[ENTER]i\231in 500.000 Yang verece\240im. "
gameforge.new_quest_lv75._470_say = "Al ya da git! "
gameforge.new_quest_lv75._480_say = "Tamam, unut bunu. "
gameforge.new_quest_lv75._490_say = "Ne utan\231 verici. Neyse, belki fikrini[ENTER]de\240i\254tirirsin. "
