gameforge.new_quest_lv80._060_say = "Bu Karamsar Ah\254ap Maskeyi al ve Doyyumhwan[ENTER]b\246lgesine git. Orada Alev Hayaletlerini bul.[ENTER]Onlar\253 tan\253yor olmal\253s\253n - tamamen alevle kapl\253[ENTER]k\252resel yarat\253klar. "
gameforge.new_quest_lv80._070_say = "E\240er onlardan birini \246ld\252r\252rsen, maske harekete[ENTER]ge\231ecek ve k\252llere d\246n\252\254ecek. \221lk seferde[ENTER]olmazsa, cesaretini kaybetme. "
