gameforge.new_quest_lv80._180_say_reward = "Yan\253mda "
gameforge.new_quest_lv80._190_say_reward = "ta\254\253mal\253y\253m. Soon'a g\246re Alev Hayaletleri[ENTER]\246ld\252rd\252\240\252mde maske Efsunlu K\252llere d\246n\252\254ecek. "
