gameforge.new_quest_lv80._310_set_title = "Karanl\253k Tap\253nak "
gameforge.new_quest_lv80._320_say = "S\252rg\252n Ma\240aras\253na gitmeli ve Siyah Buzu sunakta[ENTER]kurban etmeliyim. Kurban Suna\240\253n\253 bulmak kolay[ENTER]olmayacak. "
gameforge.new_quest_lv80._330_npcChat = "Siyah Buzu Kurban Et! "
gameforge.new_quest_lv80._340_say = "Suna\240a vard\253\240\253nda \231evrene bir karanl\253k yay\253l\253yor.[ENTER]Karanl\253kta sahipsiz sesler sana sonsuz[ENTER]\253zd\253raplar\253n\253 f\253s\253ld\253yorlar.[ENTER]Buras\253 ger\231ekten lanetli bir yer. Siyah Buzu[ENTER]ger\231ekten kurban etmek istiyor musun? "
