gameforge.new_quest_lv80._470_say = "Siyah Buzu kurban edemem... bana yanl\253\254 geliyor![ENTER]Soon'a gidip bu g\246revi tamamlayamayaca\240\253m\253[ENTER]s\246yleyece\240im. "
gameforge.new_quest_lv80._475_npcChat = "Siyah Buz "
