gameforge.new_quest_premium_lv4._160_say = "\221htiyac\253n olan Leylak Dal\253 say\253s\253: %s "
gameforge.new_quest_premium_lv4._170_say = "Bu yeterli de\240il. Bu leylak sadece birka\231 damlaya[ENTER]yeter. "
gameforge.new_quest_premium_lv4._180_say = "Ahh, leylak! \222imdi sadece Misk Ya\240\253na ihtiyac\253m[ENTER]var. Onu \246zel marketten sipari\254 edebilirsin.[ENTER]D\246nen para sana rehberlik edecek. Biraz Ejderha[ENTER]Markas\253na ihtiyac\253n olacak, ama san\253r\253m kenarda[ENTER]biraz saklam\253\254s\253nd\253r \246yle de\240il mi? Sana sonsuza[ENTER]dek minnettar olaca\240\253m. Sipari\254ini daha sonra[ENTER]depocudan alabilirsin. Sonunda b\252t\252n malzemeler[ENTER]tamamlanacak. "
gameforge.new_quest_premium_lv4._190_say = "L\252tfen \231abuk ol ve bana Misk Ya\240\253 getir. Bunun[ENTER]i\231in \246d\252l\252n\252 alacaks\253n! "
gameforge.new_quest_premium_lv4._200_say_reward = "Bana %s Leylak dal\253 getirene kadar avlanmaya[ENTER]devam et! "
gameforge.new_quest_premium_lv4._20_sayTitle = "Birtanem "
gameforge.new_quest_premium_lv4._210_say = "Onlar\253 almak i\231in Mavi Kurtlar\253 \246ld\252r. "
gameforge.new_quest_premium_lv4._220_say = "\221\254te bu kadar. \222imdi Silah Sat\253c\253s\253na d\246n. "
gameforge.new_quest_premium_lv4._230_qSetTitle = "Misk Ya\240\253 "
gameforge.new_quest_premium_lv4._240_say = "\199ok te\254ekk\252r ederim. \222imdi yeni bir koku[ENTER]\252retebilirim. "
gameforge.new_quest_premium_lv4._250_say = "Muhabbet ku\254uma, bu gece tekrar penceresinde[ENTER]\254ark\253 s\246yleyece\240imi haber verebilirsin. Mutlu[ENTER]olacakt\253r. "
gameforge.new_quest_premium_lv4._260_say = "Bir \246d\252l\252 hakettin: "
gameforge.new_quest_premium_lv4._270_say_reward = "Yang: %d "
gameforge.new_quest_premium_lv4._280_say = "Misk Ya\240\253 olmadan kokuyu \252retemem. L\252tfen d\246nen[ENTER]paran\253n sana rehberlik etmesine izin ver ve ba\254ka[ENTER]bir numune getir. "
gameforge.new_quest_premium_lv4._290_say_reward = "%s adet Misk Ya\240\253 ile geri gel. "
gameforge.new_quest_premium_lv4._300_say = "Silah Sat\253c\253s\253na Misk Ya\240\253 g\246t\252rmeliyim. D\246nen[ENTER]paray\253 takip etmeli ve koku ya\240\253n\253 sipari\254[ENTER]ederek, depocudan almal\253y\253m. "
gameforge.new_quest_premium_lv4._30_say = "Birtanemi, Silah Sat\253c\253s\253n\253 \246zledim. Haftalard\253r[ENTER]penceremin alt\253nda \254ark\253 s\246ylemiyor ve g\252nlerdir[ENTER]de ondan haber alamad\253m. Muhtemelen babamdan[ENTER]korkuyor. Sorunun ne oldu\240unu \246\240renir misin? "
gameforge.new_quest_premium_lv4._310_say_title = "Silah Sat\253c\253s\253 "
gameforge.new_quest_premium_lv4._320_say = "Ah, te\254ekk\252r ederim. Sadece engel mi \231\253km\253\254? \199ok[ENTER]rahatlad\253m. Bu gece onu bekleyece\240im. "
gameforge.new_quest_premium_lv4._330_say_reward = "\199abalar\253n sonucunda: %s tecr\252be puan\253 kazand\253n. "
gameforge.new_quest_premium_lv4._340_say = "\199abucak Satc\253ya d\246n. "
gameforge.new_quest_premium_lv4._350_npcChat = "Leylak "
gameforge.new_quest_premium_lv4._35_qSetTitle = "Silah Sat\253c\253s\253 ile konu\254 "
gameforge.new_quest_premium_lv4._360_npcChat = "Misk Ya\240\253 "
gameforge.new_quest_premium_lv4._40_qSetTitle = "Yeni bir koku "
gameforge.new_quest_premium_lv4._45_qSetTitle = "Mavi Kurt \214ld\252r "
gameforge.new_quest_premium_lv4._50_targetVid = "Silah sat\253c\253s\253: "
gameforge.new_quest_premium_lv4._55_qSetTitle = "Silah Sat\253c\253s\253na geri d\246n "
gameforge.new_quest_premium_lv4._60_sayTitle = "Serseri "
gameforge.new_quest_premium_lv4._65_qSetTitle = "Misk Ya\240\253n\253 Silah Sat\253c\253s\253na g\246t\252r "
gameforge.new_quest_premium_lv4._70_say = "Bu do\240ru, art\253k penceresinin alt\253nda \254ark\253[ENTER]s\246ylemiyorum \231\252nk\252... of, bu konuda konu\254maya \231ok[ENTER]tan\253yorum ama v\252cut kokum \231ok tiksindirici olmaya[ENTER]ba\254lad\253. S\252rekli y\253kan\253yorum ama koku gitmiyor.[ENTER]Ben de muhabbet ku\254umu kendinden ge\231irecek bir[ENTER]koku \252retmek istiyorum. Ne de olsa g\246r\252n\252\254 onun[ENTER]i\231in \231ok \246nemli. "
gameforge.new_quest_premium_lv4._75_qSetTitle = "Sat\253c\253ya git "
gameforge.new_quest_premium_lv4._80_say = "Bir koku \252retmeye ger\231ekten ihtiyac\253m var.[ENTER]Tiksindirici kokumdan kurtulmam\253n tek yolu bu. "
gameforge.new_quest_premium_lv4._90_say = "Bunun i\231in \231e\254itli malzemeleri kar\253\254t\253rmal\253y\253m.[ENTER]\214nce bunlar kar\253\254mal\253: "
gameforge.notify_test_server = {}
gameforge.notify_test_server._10_chat = "Deneme sunucusu "
gameforge.npc_talk = {}
gameforge.npc_talk._100_say = "Ben ger\231ekten ya\254l\253 bir adam\253m, ancak hala[ENTER]sa\240l\253kl\253 ve dincim. \199\252nk\252 bir s\253rr\253m var.[ENTER]Gango K\246k\252 Suyu ve Tue Mantar\253ndan yap\253lan \246m\252r[ENTER]uzat\253c\253 bir kar\253\254\253m buldum. E\240er bu kar\253\254\253mdan[ENTER]istersen, malzemeleri Yu-Hwan'a g\246t\252rmelisin,[ENTER]senin i\231in o iksiri yapacakt\253r. "
gameforge.npc_talk._10_say = "Sessiz ve disiplinli ol. Kendine hakim ol.[ENTER]Herhangi bir sorun ba\254latma. Yolda\254lar\253na sayg\253l\253[ENTER]olmay\253 \246\240renmelisin. Anlad\253n m\253? "
gameforge.npc_talk._110_npcChat = "\199ok g\252\231l\252 g\246r\252n\252yorsun... "
gameforge.npc_talk._120_say = "Y\253llardan beridir, g\252c\252m\252z\252n s\253rr\253 ailemiz i\231in[ENTER]nesilden nesile ge\231er. Babam bana demi\254ti ki,[ENTER]e\240er \231an \231i\231e\240ini do\240ru \254ekilde kar\253\254t\253r\253rsan[ENTER]sana g\252\231 verecek bir iksir yapabilirsin. Bildi\240im[ENTER]kadar\253yla Baek-Go bu iksiri yapabiliyor. Tek[ENTER]ihtiyac\253n ona \231an \231i\231e\240i[ENTER]g\246t\252rmek.  "
gameforge.npc_talk._130_npcChat = "Git, onu da\240lara s\246yle... "
gameforge.npc_talk._140_sayTitle = "M\252zisyen Yu-Hwan: "
gameforge.npc_talk._150_say = "...tepelere ve her yere...[ENTER]Sen de m\252zi\240i sever misin? Burada her t\252r par\231ay\253[ENTER]s\246ylerim, sava\254a dahil olmuyorum. Ancak e\240er[ENTER]\252lkem beni korumazsa, sevdi\240im bu i\254i yapmaya[ENTER]devam edemem. "
gameforge.npc_talk._160_npcChat = "Neden bu kadar \231ok okuyorsun? "
gameforge.npc_talk._170_sayTitle = "Kitapkurdu Soon: "
gameforge.npc_talk._180_say = "Ah, macerac\253. D\252nya sorunlarla dolu, ve tek[ENTER]kurtulu\254 yolu bilgi. Her zaman kitaplar\253na sayg\253[ENTER]g\246stermelisin. Onlar sana k\246t\252 zamanlarda yard\253m[ENTER]ederler. \221nan bana! "
gameforge.npc_talk._190_npcChat = "\199ocuklar\253n var m\253? "
gameforge.npc_talk._200_say = "Asl\253nda hi\231 \231ocuk istemiyordum, ancak... Sihir[ENTER]enerjimi artt\253rmak i\231in Kaki \199i\231ekleri toplay\253p[ENTER]do\240ru \254ekilde haz\253rl\253yorum. Bunu Baek-Go buldu.[ENTER]100 adet iksir yapmak i\231in bir tane \231i\231e\240e[ENTER]ihtiyac\253 var.Ancak Kaki \231i\231e\240inin bir de yan[ENTER]etkisi var. E\240er bir kad\253n bu \231i\231ekten yap\253lm\253\254[ENTER]bir kolye takarsa k\253sa zamanda o\240lu olur.[ENTER]Aram\253zda kals\253n, kar\253m utanmazca kulland\253 bunu. "
gameforge.npc_talk._20_npcChat = "Mmm, buras\253 harika kokuyor... "
gameforge.npc_talk._210_npcChat = "Aya\240\253na ne oldu? "
gameforge.npc_talk._220_sayTitle = "Handu-Up: "
gameforge.npc_talk._230_say = "\221yile\254iyor. Y\252r\252rken bir Gango K\246k\252ne tak\253ld\253m ve[ENTER]aya\240\253m burkuldu.Neyse ki doktor Baek-Go'yu[ENTER]tan\253yorum, beni muayene etti ve bir tavsiye[ENTER]verdi: K\252\231\252k yaralar\253 iyile\254tirmek i\231in Gango[ENTER]K\246k\252 suyu kullanabilirmi\254im.[ENTER]B\246ylece su\231lu k\246kleri \231aya kar\253\254t\253rd\253m ve yol[ENTER]a\231t\253klar\253 ac\253y\253 dindirdiler... "
gameforge.npc_talk._240_npcChat = "Sen kimsin? "
gameforge.npc_talk._250_sayTitle = "Wonda-Rim: "
gameforge.npc_talk._260_say = "Ben Wonda-Rim, Chaegirab'\253n ye\240eniyim. Amcam \231ok[ENTER]me\254hur! Onu tan\253yor musun? Bir \231ok iksiri ve[ENTER]bitkiyi ara\254t\253r\253yor. Ara\254t\253rmalar\253 s\253ras\253nda 100[ENTER]Bo suyu ile Dutu kar\253\254t\253r\253nca b\252y\252l\252 enerjilere[ENTER]kar\254\253 \231ok g\252\231l\252 bir savunma elde ettiren bir[ENTER]iksir bulmay\253 ba\254ard\253. Bildi\240im kadar\253yla bu[ENTER]iksiri Huahn-So yapabiliyor.[ENTER]Kendisine gereken malzemeleri g\246t\252r. "
gameforge.npc_talk._270_npcChat = "Bu kadar yara izi nas\253l oldu? "
gameforge.npc_talk._280_sayTitle = "Hain Balso: "
gameforge.npc_talk._290_say = "\199ok iyi bir sava\254\231\253 de\240ilim ve sava\254larda \231ok s\253k[ENTER]yaralan\253r\253m. D\246v\252\254lerde yaraland\253ktan sonra[ENTER]Yu-Hwan'a beni yaralardan korumas\253 i\231in bir iksir[ENTER]yapmas\253n\253 s\246ylemi\254tim. Bana \199an\231i\231e\240i ve[ENTER]Leylaktan olu\254an bir iksir yapt\253, ancak pek i\254e[ENTER]yaramad\253. Belki de benim beceriksizli\240im. Senin[ENTER]i\254ine yarayacakt\253r. "
gameforge.npc_talk._300_npcChat = "Neden insanlar sana hain diyor? "
gameforge.npc_talk._30_sayTitle = "Restoran sahibi Octavio: "
gameforge.npc_talk._310_say = "Bir sava\254tan ka\231t\253m ve Siyah R\252zgar \199etesine[ENTER]kat\253ld\253m. Yolda\254lar\253m bu y\252zden beni asla[ENTER]affetmiyorlar. Sonradan Siyah R\252zgar \199etesinin[ENTER]masum insanlar\253 \246ld\252rd\252\240\252n\252 anlad\253m ve hemen[ENTER]onlar\253 terk ettim. Korkun\231tu! "
gameforge.npc_talk._320_say = "Masum insanlar\253n vebalini mi ta\254\253yorsun?[ENTER]\214yleyse ismini ger\231ekten hakediyorsun. Onlar\253[ENTER]g\252zel bir hayattan kopartm\253\254s\253n. "
gameforge.npc_talk._330_say = "Buras\253 adaletsiz bir d\252nya. Ama art\253k asla k\246t\252[ENTER]bir\254ey yapmayaca\240\253m.[ENTER]insanlar\253n beni hain olarak \231a\240\253rmas\253n\253[ENTER]istemiyorum.[ENTER]Bana biraz Yang verebilir misin? "
gameforge.npc_talk._340_npcChat = "Sana neden bilge diyorlar? "
gameforge.npc_talk._350_sayTitle = "Bilge Uriel: "
gameforge.npc_talk._360_say = "Bu engin d\252nyada \246\240renecek \231ok \254ey var. Cehalet[ENTER]ve silahl\253 kuvvetleri birle\254tirmek \231ok berbat bir[ENTER]kar\253\254\253m. Cahil askerlerle ya\254amak istemiyorsun[ENTER]de\240il mi? Bilgelik g\252\231t\252r! "
gameforge.npc_talk._370_npcChat = "Kaynaklar\253m senin ila\231 yapt\253\240\253n\253 s\246yledi? "
gameforge.npc_talk._380_say = "Elimden geleni yap\253yorum. Bu tehlikeli d\252nyada[ENTER]bir\231ok insan her g\252n yaralan\253yor. Bizim o kadar[ENTER]ila\231 ve doktorumuz yok. Zaman \231ok zor![ENTER]Bana daha sonra yard\253m edebilir misin? "
gameforge.npc_talk._390_npcChat = "Av i\254leri nas\253l gidiyor? "
gameforge.npc_talk._400_sayTitle = "Avc\253 Yang-Shin: "
gameforge.npc_talk._40_say = "Ho\254geldin! Restoran\253m\253z uluslararas\253 bir zincirin[ENTER]par\231as\253d\253r. Gel ve bizi bir dene. "
gameforge.npc_talk._410_say = "Hmm, Metin ta\254lar\253n\253n d\252\254mesiyle birlikte[ENTER]hayvanlar vah\254ile\254ti. Bug\252nlerde, tavuk avlamak[ENTER]bile seni \246ld\252rebilir. Avc\253lar\253n i\254i \231ok zor.[ENTER]Neyse ki ben en iyilerden biriyim! "
gameforge.npc_talk._420_npcChat = "Bu dikkatini neye bor\231lusun? "
gameforge.npc_talk._430_say = "Ben ba\254ar\253l\253 bir ok\231uyum \231\252nk\252 benim \246zel bir[ENTER]re\231etem var, hehe! \222eftali \199i\231e\240i Suyu ve Leylak[ENTER]kar\253\254t\253r\253rsan elde edece\240in iksir senin ni\254an[ENTER]alma kabiliyetini inan\253lmaz art\253r\253r. E\240er bu[ENTER]sayd\253klar\253m\253 Yu-Hwan'a g\246t\252r\252rsen senin i\231in[ENTER]iksiri yapacakt\253r. "
gameforge.npc_talk._440_npcChat = "Ne g\252zel bir \231i\231ek tac\253... "
gameforge.npc_talk._450_say = "Ben karde\254imle birlikte \254eftali \231i\231e\240i[ENTER]topluyorum. Ama bug\252n yaln\253zd\253m. \199ok g\252zel[ENTER]de\240iller ama \246zel bir etkileri var. E\240er sen de[ENTER]onlardan birini al\253p Baek-Go'ya g\246t\252rebilirsen,[ENTER]seni \231evikle\254tirecek bir iksir yapabilir. "
gameforge.npc_talk._460_npcChat = "Karde\254in nerede? "
gameforge.npc_talk._470_say = "Bu g\252nlerde, karde\254im \231ok seyahat ediyor, onu[ENTER]art\253k g\246remiyorum ve endi\254eleniyorum. "
gameforge.npc_talk._480_npcChat = "Pirin\231 pastas\253 m\253 sat\253yorsun? "
gameforge.npc_talk._490_sayTitle = "Pirin\231 hamuru sat\253c\253s\253 Yu-Rang: "
gameforge.npc_talk._500_say = "Sava\254 y\252z\252nden, pirin\231 hamuru satmak \231ok[ENTER]zorla\254t\253. Haydutlara \231ok te\254ekk\252r etmek laz\253m,[ENTER]sayelerinde b\252t\252n m\252\254terilerimi kaybettim. Sadece[ENTER]art\253k hayat\253m\253 s\252rd\252rebilmek i\231in ne yapaca\240\253m\253[ENTER]bilmiyorum. "
gameforge.npc_talk._50_say = "Bu b\252y\252k bir restoran, ancak dekorasyonu \231ok[ENTER]basit. "
gameforge.npc_talk._510_npcChat = "Senden kimler al\253\254veri\254 ediyor? "
gameforge.npc_talk._520_say = "Pastalar\253m\253n \231o\240unu seyyahlara sat\253yorum.[ENTER]Bir g\252n, gizemli bir s\252vari geldi ve benden[ENTER]pirin\231 pastas\253 almak istedi\240ini s\246yledi. Fakat[ENTER]bana para yerine Zin Suyunun re\231etesini verdi. Bu[ENTER]iksir sald\253r\253 g\252c\252n\252 artt\253rabiliyormu\254.[ENTER]Re\231eteyi Huhan-Son'a satt\253m. Ona Sim-suyu ve Alp[ENTER]g\252l\252 g\246t\252r\252rsen senin i\231in Zin Suyu yapabilir. "
gameforge.npc_talk._530_npcChat = "Neden bu kadar \252zg\252ns\252n? "
gameforge.npc_talk._540_say = "Yeni evli \231ift olarak tatl\253 r\252yalar\253m\253z[ENTER]merhametsiz\231e parampar\231a edilece\240ini bilmeliydim.[ENTER][ENTER]\220h\252, \252h\252... l\252tfen bu cinayetin intikam\253n\253 al. "
gameforge.npc_talk._550_npcChat = "Sava\254ta \231ok ki\254i \246ld\252... "
gameforge.npc_talk._560_say = "Sava\254ta bir\231ok adam kaybettik, biz kad\253nlar[ENTER]olarak topland\253k ve Huahn-So'dan savunmam\253z\253[ENTER]g\252\231lendirecek olan Dok-suyunu geli\254tirmesini[ENTER]istedik. Uzun ara\254t\253rmalardan sonra, e\240er[ENTER]Dok-suyuna alp g\252l\252 eklenirse \231ok daha g\252\231l\252[ENTER]olaca\240\253n\253 buldu. Kendisine git, o Sambo-suyu[ENTER]yapabiliyor. Gerekli \254eyleri g\246t\252rmeyi de unutma. "
gameforge.npc_talk._570_npcChat = "Ah, ne \254irin bir \231ocuk... "
gameforge.npc_talk._580_sayTitle = "Ah-Yu: "
gameforge.npc_talk._590_say = "Bir kez daha \231\253\240l\253k at\253yor... Ne istedi\240ini[ENTER]\231\246zemiyorum \254eker falan m\253 acaba... Ahh hay\253r! "
gameforge.npc_talk._600_npcChat = "Siz ikiniz kimsiniz? "
gameforge.npc_talk._60_npcChat = "Bana \231\246mlek\231ilik hakk\253nda bir\254eyler anlat. "
gameforge.npc_talk._610_say = "Evlad\253m! Kocam sava\254ta d\252\254t\252, art\253k ben kendime[ENTER]bakmak zorunday\253m. Art\253k \231o\231u\240uma ve kendime ben[ENTER]bakmaya \231al\253\254\253yorum. Bo-suyu ile hayat\253m\253[ENTER]geli\254tirebilece\240imi \246\240rendim. Yu-Hwan'a 100[ENTER]kaki\231i\231e\240i suyu ve Tue mantar\253 g\246t\252rmeliyim ki[ENTER]bana ondan yaps\253n.[ENTER]\222imdi bir \254ekilde bu malzemeleri bulmal\253y\253m... "
gameforge.npc_talk._620_npcChat = "Senin kocan kim? "
gameforge.npc_talk._630_sayTitle = "Aranyo: "
gameforge.npc_talk._640_say = "Benim kocam olacak adam, kitaplar\253yla evli. O[ENTER]art\253k benimle ilgilenmiyor. Ama ben \231irkin bir[ENTER]kad\253n de\240ilim. "
gameforge.npc_talk._650_npcChat = "\221\254ler nas\253l? "
gameforge.npc_talk._660_say = "Sava\254 ba\254lad\253\240\253ndan beri ticaret art\253k \231ok[ENTER]k\246t\252le\254ti. T\252ccarlar birli\240i birli\240inin \231ok g\252\231l\252[ENTER]oldu\240u zamanlar art\253k geride kald\253. Art\253k vah\254i[ENTER]hayvanlar\253 g\246rmezden gelemiyoruz, ayr\253ca Beyaz[ENTER]Yeminliler \231etesi ve Siyah R\252zgar \231etesi de[ENTER]cabas\253. "
gameforge.npc_talk._670_npcChat = "Neden moralin bozuk? "
gameforge.npc_talk._680_sayTitle = "Taurean: "
gameforge.npc_talk._690_say = "Harang k\246t\252 bir k\253z! Ondan nefret ediyorum! Ben[ENTER]zay\253f\253m ve o hep bana \231at\253yor! "
gameforge.npc_talk._700_say = "Sen erkeksin, kaslar\253n var. Aras\253ra onlara \231al\253\254! "
gameforge.npc_talk._70_sayTitle = "\199\246mlek\231i Yonah: "
gameforge.npc_talk._710_npcChat = "Ne yap\253yorsun? "
gameforge.npc_talk._720_sayTitle = "Harang: "
gameforge.npc_talk._730_say = "Taurean'\253 bekliyorum. Beraber oyun oynar\253z ve \231ok[ENTER]da kavga ederiz. Ne korkak ama! E\240er kendi[ENTER]iste\240iyle gelmezse onu \231ok fena yapaca\240\253m! "
gameforge.npc_talk._740_npcChat = "Taurean senden korkuyor. "
gameforge.npc_talk._750_say = "Taurean benden daha g\252\231l\252. Bu y\252zden onu yenmek[ENTER]i\231in bir yol d\252\254\252nd\252m. Beyaz bir Ninja Y\246ng Suyu[ENTER]ile Dutu kar\253\254t\253r\253rsam sald\253r\253 h\253z\253m\253n artaca\240\253n\253[ENTER]s\246yledi.[ENTER]Sonunda Taurean'\253 yenebilece\240im! E\240er sen de[ENTER]h\253zl\253 sald\253rmak istiyorsan, malzemeleri[ENTER]Huahn-So'ya g\246t\252r. Sana iksir yapacakt\253r. "
gameforge.npc_talk._760_npcChat = "Yeni g\246r\252\254... "
gameforge.npc_talk._770_say_title = "Seon-Pyeong: "
gameforge.npc_talk._780_say = "Arkada\254\253m, d\252nya cevaplanmam\253\254 sorularla dolu. Ve[ENTER]ben cevap ve bilgi ar\253yorum. Destans\253 Silahlar\253[ENTER]ve zihin ta\254lar\253n\253 hi\231 duydun mu? "
gameforge.npc_talk._790_npcChat = "Ne yap\253yorsun? "
gameforge.npc_talk._800_say = "Bilinmeyeni ara\254t\253rd\253\240\253m\253 zaten biliyorsundur. \222u[ENTER]anda iyi silahlar yapman\253n ve zihin ta\254lar\253n\253n[ENTER]g\252c\252n\252 artt\253rman\253n yolunu ar\253yorum. "
gameforge.npc_talk._80_say = "\199\246mlek\231ili\240i seviyorum. Ellerinle \231amuru[ENTER]\254ekillendirmek ve bir\254ey yaratmak \231ok tatmin[ENTER]edici... Genelde basit \254eyler yap\253yorum.[ENTER]Do\240udaki da\240lar\253n eteklerinde y\246ntemler \231ok daha[ENTER]geli\254mi\254. Bir defas\253nda, orada baz\253 \231\246mlek\231iler[ENTER]g\246rm\252\254 ve \231ok etkilenmi\254tim.[ENTER]Zaman\253m oldu\240unda deneyler yap\253yorum. Ama hala[ENTER]ustal\253klar\253n\253 \231\246zemedim. "
gameforge.npc_talk._810_npcChat = "Silah ara\254t\253rmas\253... "
gameforge.npc_talk._820_say = "\221lgin\231, de\240il mi? Bununla ilgili daha fazla[ENTER]\254eyler mi \246\240renmek istiyorsun? \214yleyse bana[ENTER]65'lik silahlardan bir +9 silah getir: Bunun[ENTER]d\253\254\253nda bir adet eskrim bro\254\252r\252 ve iki adet[ENTER]kutsama ka\240\253d\253 l\226z\253m. Onlardan sana destans\253 bir[ENTER]silah yapmaya \231al\253\254aca\240\253m. "
gameforge.npc_talk._830_say = "Ancak, i\254e yarayaca\240\253n\253 garanti edemem. "
gameforge.npc_talk._840_npcChat = "Zihin Ta\254lar\253... "
gameforge.npc_talk._850_say = "Zihin Ta\254lar\253 \231ok kullan\253l\253yor ancak buna ra\240men[ENTER]\231o\240u ki\254i ger\231ek g\252\231lerini bilmiyor.[ENTER]Ara\254t\253rmalar\253m sonucunda bilgiler elde ettim.[ENTER]E\240er bana ba\254ka bir Zihin Ta\254\253 getirirsen, onu[ENTER]senin i\231in geli\254tirebilirim. "
gameforge.npc_talk._90_npcChat = "Ya\254\253na g\246re \231ok hayat dolusun... "
gameforge.olympic_badge = {}
gameforge.olympic_badge._010_npcChat = "Kahramanl\253k Madalyas\253 "
gameforge.olympic_badge._020_say = "\221mdat! "
gameforge.olympic_badge._030_say = "Al\231ak h\253rs\253z tak\253m\253...[ENTER]D\252n gece evime h\253rs\253zlar girdi![ENTER]Kahramanl\253k madalyas\253n\253 \231ald\253lar. Selefim bu[ENTER]madalyaya, muharebe alan\253ndaki galibiyeti[ENTER]\221mparatoruna bildirmek i\231in katetti\240i 42,195[ENTER]kilometrelik yol kar\254\253l\253\240\253nda lay\253k g\246r\252lm\252\254t\252.[ENTER]\222imdi de elden gitti! "
gameforge.olympic_badge._040_say = "Off yaa...ailem i\231in paha bi\231ilmez de\240erdeydi.[ENTER]\222imdi ne yapaca\240\253m ben? "
gameforge.olympic_badge._050_say = "Bana yard\253m edecek misin? "
gameforge.olympic_badge._060_npcChat = "Kahramanl\253k Madalyas\253 "
gameforge.olympic_badge._070_say = "Nihayet d\246nd\252n! Kahramanl\253k madalyas\253n\253 buldun mu? "
gameforge.olympic_badge._080_say = "Neden? Bu yankesiciler benim madalyam\253 ne[ENTER]yapacaklar? Ba\254ka biri i\231in ne de\240eri olabilir[ENTER]ki?! Onu bulmama yard\253mc\253 olabilir misin? "
gameforge.olympic_badge._090_npcChat = "Kahramanl\253k madalyas\253n\253 bul! "
gameforge.olympic_badge._100_say = "Ellerin bo\254 mu d\246n\252yorsun? Ah olamaz, \231ok[ENTER]\231aresizim. Sen bana yard\253m edemeyeceksin de kim[ENTER]edecek? Aramaya devam et. L\252tfen! "
gameforge.olympic_badge._110_say = "Madalyam\253 buldun! Ama dur...bu sadece par\231as\253.[ENTER]Rezalete bak\253n, onu be\254 par\231aya b\246lm\252\254ler! L\252tfen[ENTER]bana t\252m par\231alar\253 getir! Ancak bu \254ekilde[ENTER]madalyay\253 birle\254tirebilirim belki. "
gameforge.olympic_badge._120_say = "Al\231ak yankesiciler k\253ymetli aile yadigar\253m\253[ENTER]k\253rd\253! T\252m par\231alar\253 buldu\240un i\231in sana[ENTER]minettar\253m. Art\253k par\231alar\253 birle\254tirebilirim. "
gameforge.olympic_badge._130_say = "Sonsuz te\254ekk\252rler! Ailemin onurunu kurtard\253n.[ENTER]Verdi\240in onca emekler elbette bo\254a gitmedi. \221\254te[ENTER]hak etti\240in \246d\252l! "
gameforge.olympic_badge._140_say = "Bu g\246revi ger\231ekten ret mi ediyorsun? \222imdi[ENTER]'evet' dersen bu g\246revi bir daha alamayacaks\253n. "
gameforge.olympic_badge._150_say = "\222u an vaktinin olmamas\253n\253 anlay\253\254la kar\254\253l\253yorum.[ENTER]M\252sait oldu\240unda tekrar gel. Ama beni \231ok[ENTER]bekletme! "
gameforge.olympic_badge._160_say = "Ge\231 kald\253n ne yaz\253k ki, bana yard\253mc\253[ENTER]olamayacaks\253n art\253k. Yolun a\231\253k olsun! "
gameforge.olympic_badge._170_say = "Beni soyan canavarlar\253 avla! Ama dikkatli ol, \231ok[ENTER]g\252\231l\252ler, en az 30. seviyeye sahipler.[ENTER]Kahramanl\253k madalyas\253n\253 bana getirirsen seni[ENTER]bolca m\252kafatland\253raca\240\253m! "
gameforge.olympic_badge._180_say = "Kahramanl\253k madalyas\253n\253 bul ve Yu-Hwan'a g\246t\252r. "
gameforge.olympic_badge._190_say = "Yu-Hwan senden yard\253m rica ediyor. Onun yan\253na[ENTER]git! Kendisini ikinci k\246yde bulabilirsin. "
