gameforge.spider_dungeon_3floor_boss._100_say = "\214r\252mcek Zindan\253'na gitmeye cesaret edemedim deme[ENTER]sak\253n?! M\252kkemmel bir tekniye sahip tecr\252beli bir[ENTER]sava\254\231\253s\253n. Birka\231 \246r\252mce\240i halletmek senin i\231in[ENTER]zor olmamal\253. Ma\240araya girebilmek i\231in ge\231i\254[ENTER]biletine ihtiyac\253n oldu\240unu biliyorsun ama de\240il[ENTER]mi? "
gameforge.spider_dungeon_3floor_boss._10_npcChat = "Yuvaya giri\254 "
gameforge.spider_dungeon_3floor_boss._110_sendLetter = "Yeni tehlike "
gameforge.spider_dungeon_3floor_boss._120_say = "Yaz\253n\253n tam kopyas\253n\253 ald\253n. Onu \254imdi Y\252zba\254\253ya[ENTER]g\246ster. "
gameforge.spider_dungeon_3floor_boss._130_say = "Aferin, ba\254ard\253n! G\246ster bi...[ENTER]H\253m, bu yaz\253lar\253 \231\246zemiyorum, bir kelime dahi[ENTER]anlam\253yorum. Bilgin Uriel'e dan\253\254 en iyisi. "
gameforge.spider_dungeon_3floor_boss._140_say = "Bilgin Urel'in yan\253na git ve yaz\253y\253 ona g\246ster.[ENTER]Yaz\253y\253 \231evirmesini bilir muhakkak. "
gameforge.spider_dungeon_3floor_boss._150_say = "Y\252zba\254\253, benden bu yaz\253y\253 de\254ifre etmemi mi[ENTER]istiyor? Hayhay. Zekam\253 ispatlayacak zorlu[ENTER]m\252cadeleleri severim. G\246ster bakal\253m.[ENTER]Bu...ama bu korkun\231 bir \254ey. Buyur, \231eviriyi bu[ENTER]ka\240\253d\253n \252zerine yaz\253yorum. Onu bir an \246nce[ENTER]Y\252zba\254\253ya g\246t\252r, ard\253ndan benim yan\253ma gel.[ENTER]Burada yaz\253lanlar do\240ruysa hepimiz b\252y\252k[ENTER]tehlikedeyiz! Hadi hadi! "
gameforge.spider_dungeon_3floor_boss._160_say = "Y\252zba\254\253ya daha gitmedin mi? L\252tfen ama, acele[ENTER]etmelisin. Kaybedecek zaman\253m\253z yok. Bu mektubu[ENTER]muhakkak okumal\253! "
gameforge.spider_dungeon_3floor_boss._170_sayTitle = "Uriel'in mektubunu teslim et "
gameforge.spider_dungeon_3floor_boss._180_say = "Amma da dikkafal\253ym\253\254 \254u ya\254l\253 adam...Te\254ekk\252r[ENTER]etseydi bir yeri mi eksilirdi? Aman neyse.[ENTER]Bilgilerin \231ok \246nemli oldu\240unu s\246yledi\240i i\231in[ENTER]hemen Y\252zba\254\253ya iletece\240im. "
gameforge.spider_dungeon_3floor_boss._190_npcChat = "Urel'in Mektubu "
gameforge.spider_dungeon_3floor_boss._200_say = "Aman\253n! \214r\252mcek Zindan\253'n\253n \252\231\252nc\252 kat\253na devasa[ENTER]bir \254eytani bir arachnida yerle\254ti. Yaz\253dan[ENTER]anla\254\253ld\253\240\253 \252zere bu gizli yuvaya \246zel bir[ENTER]anahtarla girilebiliyor. \221lk \246nce Uriel'in yan\253na[ENTER]git ve ona \254u anahtar\253 sor. Sonra da becerikli[ENTER]sava\254\231\253lar\253n\253 bir araya topla ve \214r\252mcek[ENTER]Barones'in gizlendi\240i yere birlikte h\252cum edin![ENTER]\221\254te sana bir tane ge\231it bileti daha. "
gameforge.spider_dungeon_3floor_boss._20_say = "Bu kap\253y\253 sadece arachnida anahtar\253 a\231ar. "
gameforge.spider_dungeon_3floor_boss._210_npcChat = "Arachnida Anahtar\253 "
gameforge.spider_dungeon_3floor_boss._220_say = "Bir an \246nce Uriel'i bulmal\253y\253m. "
gameforge.spider_dungeon_3floor_boss._230_say = "Ah, geldin. \214yleyse Y\252zba\254\253 sana \214r\252mcek[ENTER]Barones'i yok etme emrini verdi, do\240ru mu? Ancak[ENTER]Barones'in yuvas\253na giden kap\253 kapal\253 ve sadece[ENTER]arachna anahtar\253yla a\231\253labilir. \220retimi \231ok zor.[ENTER]Ama bana bir \246r\252mcek zehir kesesi, bir \246r\252mcek[ENTER]yumurta kesesi, bir \246r\252mcek a\240\253, \246r\252mcek g\246zleri,[ENTER]\246r\252mcek bacaklar\253 ve krali\231e \246r\252mcek zehrini[ENTER]getirirsen, sana bir tane arachna anahtar\253[ENTER]\252retebilirim. "
gameforge.spider_dungeon_3floor_boss._240_say = "Sana arachna anahtar\253 \252retmemi mi istiyorsun?[ENTER]Bunun i\231in bir \246r\252mcek zehir kesesine, bir[ENTER]\246r\252mcek yumurta kesesine, bir \246r\252mcek a\240\253na,[ENTER]\246r\252mcek g\246zlerine, \246r\252mcek bacaklar\253na ve krali\231e[ENTER]\246r\252mcek zehrine ihtiyac\253m var. T\252m malzemeleri[ENTER]temin edebildin mi? "
gameforge.spider_dungeon_3floor_boss._250_say = "Harika! Arachnida anahtar\253 \252retimi i\231in t\252m[ENTER]gerekli malzemeleri temin ettin. Bir saniye[ENTER]bekle. \220retimi uzun s\252rmez... "
gameforge.spider_dungeon_3floor_boss._260_say = "Oh, ba\254ard\253k! \221\254te arachnida anahtar\253. \214r\252mcek[ENTER]Barones'in sakland\253\240\253 yere giden kap\253y\253 a\231ar.[ENTER]Sana ve yolda\254lar\253na uzun bacakl\253 yarat\253klara[ENTER]kar\254\253 m\252cadelenizde ba\254ar\253lar dilerim! Ama acele[ENTER]etmelisiniz, anahtar dayan\253kl\253 de\240il. 24 saat[ENTER]sonra par\231alan\253r ve eski halini al\253r. "
gameforge.spider_dungeon_3floor_boss._270_say = "Ay ay! Kimse anas\253n\253n karn\253ndan usta olarak[ENTER]do\240muyor. Bu anahtar\253n \252retimi i\231in uygulanan[ENTER]y\246ntemin pek kolay bir y\246ntem olmad\253\240\253n\253[ENTER]bilmelisin. En ufak bir hatada bile t\252m emekler[ENTER]bo\254a \231\253kabiliyor. Ne yaz\253k ki o kadar zahmetle[ENTER]toplad\253\240\253n \246r\252mcek malzemeleri de ziyan oldu. Bir[ENTER]daha ki sefer kesin ba\254ar\253r\253z! "
gameforge.spider_dungeon_3floor_boss._280_say = "Bir \254ey eksik, arachnida anahtar\253n\253 bu \254ekilde[ENTER]\252retmem m\252mk\252n de\240il. Laz\253m olanlar\253 bir kez daha[ENTER]hat\253rlatay\253m: bir \246r\252mcek zehir kesesi, bir[ENTER]\246r\252mcek yumurta kesesi, bir \246r\252mcek a\240\253, \246r\252mcek[ENTER]g\246zleri, \246r\252mcek bacaklar\253 ve krali\231e \246r\252mcek[ENTER]zehri. "
gameforge.spider_dungeon_3floor_boss._300_say = "Grup liderin, zindana girdi. Sen de girmek[ENTER]istiyor musun? "
gameforge.spider_dungeon_3floor_boss._30_npcChat = "\214Z3 G\246revi s\253f\253rla "
gameforge.spider_dungeon_3floor_boss._310_say = "\199ok beklettin. Anahtar k\253r\253ld\253 bile. Buraya[ENTER]girebilmek i\231in yeni bir tane yapt\253r. "
gameforge.spider_dungeon_3floor_boss._320_say = "Barones'in yuvas\253nda zaten bir grup bulunuyor ve[ENTER]\214r\252mcek Barones'e sald\253r\253yor. "
gameforge.spider_dungeon_3floor_boss._330_say = "\214nceki grubun g\246revi bitmeden giremezsin. %s[ENTER]dakika sonra tekrar gel. "
gameforge.spider_dungeon_3floor_boss._340_say = "Barones'in yuvas\253na giden kap\253n\253n tekrar[ENTER]a\231\253lmas\253na kalan s\252re: "
gameforge.spider_dungeon_3floor_boss._350_say = "%s dakika "
