gameforge.spider_dungeon_3floor_boss._390_say = "Arachnida anahtar\253n\253 ancak grup lideri[ENTER]kullanabilir. "
gameforge.spider_dungeon_3floor_boss._400_say = "\214r\252mcek Barones yok edildi! T\252m sava\254\231\253lar \252\231[ENTER]dakika i\231inde yuvadan d\253\254ar\253 \253\254\253nlanacak. "
gameforge.spider_dungeon_3floor_boss._40_say = "Anahtar \252retiminden \246nce "
