gameforge.spider_dungeon_3floor_boss._60_say = "Ay iyiki buradas\253n. Sana \246nemli haberlerim var:[ENTER]\214r\252mcek Zindan\253'nda, G\246zc\252 Birli\240i taraf\253ndan[ENTER]\252\231\252nc\252 bir kat ke\254fedildi. Bu yeni yuva[ENTER]bildi\240imiz yuvalardan daha k\252\231\252k ama olduk\231a cani[ENTER]ve sinsi \246r\252mcekler bar\253nd\253r\253yormu\254. Ayr\253ca[ENTER]adamlar\253m orada eski bir mezar ta\254\253 buldu ama[ENTER]\252zerine kaz\253lm\253\254 yaz\253lar\253 de\254ifre edemedi. Bu[ENTER]ta\254\253 bulmak i\231in yola koyul ve bana o yaz\253n\253n bir[ENTER]kopyas\253n\253 getir. "
gameforge.spider_dungeon_3floor_boss._70_sendLetter = "Yaz\253 "
