gameforge.spider_dungeon_3floor_boss._90_say = "Ya\254as\253n, eski mezar ta\254\253n\253 buldun ve \252zerindeki[ENTER]yaz\253n\253n kopyas\253n\253 ald\253n! Y\252zba\254\253ya g\246stermek i\231in[ENTER]geri d\246n. "
