gameforge.subquest_02._150_say = "Sat\253c\253:[ENTER]\222a\254\253rmad\253m, hep s\253rad\253\254\253 istekleri vard\253r.[ENTER]L\252tfen tekrar sorabilir misin? "
gameforge.subquest_02._160_say = "Sat\253c\253:[ENTER]Ger\231ekten \246yle mi dedi? \199ok garip! O bu yeme\240i[ENTER]hi\231 sevmezdi. Ona tekrar sorabilir misin l\252tfen?[ENTER]Bunu istedi\240ini sanm\253yorum. "
gameforge.subquest_02._20_say = "Eminim z\253rh sat\253c\253s\253n\253 biliyorsundur. O benim[ENTER]babam. Ona bir ak\254am yeme\240i haz\253rlamay\253[ENTER]d\252\254\252n\252yorum, ancak ne yemek istedi\240ini[ENTER]bilmiyorum. Ona l\252tfen ak\254am ne yemek istedi\240ini[ENTER]sorar m\253s\253n? Vaktini ald\253\240\253mdan dolay\253 seni[ENTER]\246d\252llendirece\240im. "
