gameforge.subquest_02._40_sayReward = "Z\253rh sat\253c\253s\253na git ve sor. "
gameforge.subquest_02._50_say = "Ho\254geldin![ENTER]Ben; seni b\253\231ak ve k\253l\253\231 darbelerinden koruyacak[ENTER]z\253rhlar \252retirim. "
