gameforge.subquest_03._20_say = "Bana yard\253mc\253 olabilir misin? Metin ta\254lar\253[ENTER]g\246kten ya\240maya ba\254lad\253\240\253ndan beri, bilinmeyen[ENTER]salg\253n hastal\253klar da ba\254lad\253. Bir\231ok doktor[ENTER]bunlar\253n \252zerinde b\252y\252k gayretlerle \231al\253\254\253yorlar[ENTER]ancak \252retmeye \231al\253\254t\253klar\253 ilac\253n yap\253m\253 i\231in[ENTER]eksik malzemeler var. K\246y\252n d\253\254\253nda, vah\254i[ENTER]hayvanlar var bu sebeple de biz gerekti\240i gibi[ENTER]\231\253k\253p arayam\253yoruz. "
gameforge.subquest_03._30_say = "Sen bana ila\231 i\231in gereken malzemeleri[ENTER]getirebilir misin? Senden yard\253m istiyorum \231\252nk\252[ENTER]sen bir macerac\253s\253n. Mavi Kurdun karaci\240erine[ENTER]ihtiyac\253m var. "
gameforge.subquest_03._40_say = "Bana mavi kurt karaci\240eri getir. Buldu\240un zaman[ENTER]bana tekrar d\246n l\252tfen. "
gameforge.subquest_03._50_sayReward = "Metin ta\254lar\253 d\252\254meye ba\254lad\253\240\253ndan beri,[ENTER]bilinmeyen bir salg\253n\253 da beraberinde getirdi.[ENTER]Baek-Go bir ila\231 \252zerinde \231al\253\254\253yor fakat[ENTER]tamamlamas\253 i\231in mavi kurt karaci\240erine ihtiyac\253[ENTER]var. Kendisine kurt karaci\240eri g\246t\252r. "
gameforge.subquest_03._60_npcChat = "Karaci\240eri nas\253l bulabilirim? "
gameforge.subquest_03._70_say = "Kurt karaci\240eri bulabilmenin tek yolu var, o da[ENTER]Mavi Kurt bulup \246ld\252rmen. "
gameforge.subquest_03._80_say = "Mavi kurtlar i\231in \252zg\252n\252m, ancak bu ilac\253n[ENTER]\252retilmesi i\231in onlar\253n karaci\240eri gerekli.[ENTER]Te\254ekk\252r ederim. "
gameforge.subquest_03._90_sendLetter = "Baek-Go'ya geri d\246n. "
