gameforge.subquest_04._150_sayTitle = "Oduncu Deokbae: "
gameforge.subquest_04._160_say = "Ho\254geldin. Baltalar\253m var. Bir tane almak ister[ENTER]misin? Baltaya ihtiyac\253n yok mu? O zaman neden[ENTER]geldin? Ah, Demirci'nin mektubu. Te\254ekk\252r ederim.[ENTER]Ben bir oduncuyum, ama ayn\253 zamanda kazmalar ve[ENTER]di\240er gere\231leri de sat\253yorum. Bazen Demirci'ye[ENTER]baz\253 gere\231ler sipari\254 ediyorum. Bu \254ekilde[ENTER]arkada\254 olduk. "
gameforge.subquest_04._170_say = "Mektubu getirdi\240in i\231in te\254ekk\252r ederim. Onunla[ENTER]ger\231ekten Seo-Pyung-bar'da bulu\254mal\253y\253m...[ENTER]Kendisine sayg\253lar\253m\253 ilet. "
gameforge.subquest_04._180_say = "Demirciden mektup mu? Ah, uzun zaman olmu\254tu.[ENTER]Peki mektup nerede? Onu yolda kaybetmedi\240ini[ENTER]umuyorum, ettin mi yoksa? "
gameforge.subquest_04._190_select = "\221\254te, burada. "
gameforge.subquest_04._200_select = "Ah, bende de\240il. "
gameforge.subquest_04._20_say = "Hey, selam macerac\253! Senden bir iyilik[ENTER]isteyece\240im. Deokbae ad\253nda biri var. Kendisi[ENTER]oduncudur ve benim yak\253n arkada\254lar\253mdan biridir.[ENTER]Belki biraz can s\253k\253c\253 bir tarz\253 vard\253r ama[ENTER]kendisi mesle\240inde e\254siz say\253l\253r. "
gameforge.subquest_04._210_say = "G\246revi b\253rak\253yor musun? "
gameforge.subquest_04._220_say = "G\252zel, \231abuk gel. "
gameforge.subquest_04._230_say = "Onu kay\253p m\253 ettin? Kaybol g\246z\252m\252n \246n\252nden! "
gameforge.subquest_04._240_say = "Demirciye git ve mektubu tekrar al. Onu tekrar[ENTER]kaybetme. "
gameforge.subquest_04._250_sayReward = "Demirciye d\246n ve \246d\252l\252n\252 al. "
gameforge.subquest_04._260_targetVid = "Demirci'ye d\246n "
gameforge.subquest_04._270_npcChat = "Mektubu teslim ettim. "
gameforge.subquest_04._280_say = "Eh, Deokbae nas\253l iyi mi? Hala ayn\253 de\240il mi?[ENTER]Te\254ekk\252r ederim. \214d\252l\252n burada. \199ok de\240il[ENTER]biliyorum ama bir g\252n mutlaka ihtiyac\253n olacak.[ENTER]Te\254ekk\252rler tekrar.  "
gameforge.subquest_04._290_sayReward = "4.000 tecr\252be puan\253 kazand\253n.[ENTER]3.000 Yang kazand\253n. "
gameforge.subquest_04._30_say = "Bir s\252redir g\246rm\252yorum onu. Kendisine halini[ENTER]hatr\253n\253 soran bir mektup yazd\253m. Bu mektubu ona[ENTER]iletmeni istiyorum fakat yollar \231ok tehlikeli. Bu[ENTER]y\252zden dikkatli ol. Ayr\253ca mektubu sak\253n[ENTER]kaybetme! "
gameforge.subquest_04._40_say = "Ah, di\240er k\246ye nas\253l gidece\240ini bilmiyor musun?[ENTER]K\252\231\252k haritay\253 g\246r\252nt\252lemek i\231in M tu\254una bas.[ENTER]Haritada mavi bir nokta belirecek. Bu nokta, seni[ENTER]yandaki alana g\246t\252recek olan kap\253y\253 simgeler.[ENTER]\221kinci k\246y, bu alandad\253r. "
