gameforge.subquest_07._120_sayReward = "Octavio i\231in gri kurt ba\240\253rsa\240\253 bul. Gri[ENTER]Kurtlardan bulabilirsin. "
gameforge.subquest_07._130_npcChat = "Kurt Ba\240\253rsa\240\253n\253 ald\253m. "
gameforge.subquest_07._140_say = "Te\254ekk\252r ederim, art\253k bu nadide yeme\240i[ENTER]pi\254irebilirim. Bir ziyafet olacak! Yard\253m\253n i\231in[ENTER]sana minnettar\253m. Bu m\252tevaz\253 \246d\252l\252 kabul et. "
