gameforge.subquest_07._160_say = "Gri kurt ba\240\253rsaklar\253na ihtiyac\253m var. L\252tfen[ENTER]bana onlardan getir. "
gameforge.subquest_07._20_npcChat = "En iyi yemek kitab\253 "
gameforge.subquest_07._30_say = "Hm, Soon'u tan\253yor musun? Kendisi kitap kurdudur[ENTER]ve b\252t\252n zaman\253n\253 kitap okuyarak ge\231irir.[ENTER]Duydu\240uma g\246re Soon'da harika bir yemek kitab\253[ENTER]varm\253\254. L\252tfen bunun do\240rulu\240unu \246\240ren. Nadir[ENTER]bulunan ve egzotik yemek tarifleri olan bir kitap[ENTER]oldu\240unu biliyorum. Bu tarifleri \246\240renmeliyim. "
gameforge.subquest_07._40_targetVid = "Soon'a sor. "
gameforge.subquest_07._50_sayReward = "Soon'a elinde yabanc\253 bir yemek kitab\253 olup[ENTER]olmad\253\240\253n\253 sor. "
gameforge.subquest_07._60_npcChat = "\214zel bir yemek kitab\253n var m\253? "
gameforge.subquest_07._70_say = "Bla, bla.. Ah! Yine ne laz\253m? Evet, egzotik[ENTER]yemekler i\231eren bir yemek kitab\253 bende var. Ona[ENTER]ihtiyac\253m da yok, sana verebilirim istersen.[ENTER]Ancak l\252tfen okurken beni tekrar rahats\253z etme. "
