gameforge.subquest_08._240_sayTitle = "Yu-Rang: "
gameforge.subquest_08._250_say = "Nas\253l yard\253mc\253 olabilirim? Ah! Pirin\231 pastalar\253![ENTER]Tabii, sana verebilirim! Ama... Taurean isminde[ENTER]bir \231ocuk var, buraya s\252rekli gelip benimle[ENTER]tart\253\254\253yor. Bunu neden yapt\253\240\253n\253 bilmiyorum. E\240er[ENTER]benim i\231in Taurean'la konu\254ursan, sana pirin\231[ENTER]hamuru veririm.  "
