gameforge.subquest_10._150_say = "Ne? Benim \231ald\253\240\253m\253 m\253 d\252\254\252n\252yorsun? Hay\253r, asla,[ENTER]ben \246yle bir\254ey yapmad\253m ve yapmam da! Ger\231ekten,[ENTER]ben su\231lu de\240ilim![ENTER][ENTER]Pekala... Ben oraya sat\253c\253y\253 g\246rmeye gitmi\254tim,[ENTER]ama kendisi orada de\240ildi! Onun haricinde orada[ENTER]bir Beyaz Yeminli ok\231u da g\246rm\252\254t\252m. O an kendisi[ENTER]de beni farketti ve ka\231t\253. Belki de o \231alm\253\254t\253r. "
