gameforge.subquest_10._180_targetVid = "Sat\253c\253ya git. "
gameforge.subquest_10._190_npcChat = "Tokan\253 getirdim. "
gameforge.subquest_10._200_say = "Ah, \231ok te\254ekk\252r ederim. \222imdi \231ok mutlu oldum;[ENTER]sonunda s\252sl\252 sa\231 tokam\253 geri ald\253m! Bana \231ok[ENTER]yard\253mc\253 oldun! Minnettarl\253\240\253m\253 nas\253l[ENTER]g\246sterebilirim? Bende binicilik bileti var. \214zel[ENTER]bir\254ey say\253lmaz ama ona art\253k ihtiyac\253m yok,[ENTER]markette \231al\253\254maya ba\254lad\253\240\253mdan beri buradan[ENTER]ayr\253lam\253yorum. Bu bileti te\254ekk\252r\252m\252n kar\254\253l\253\240\253[ENTER]olarak kabul et l\252tfen. Tekrar \231ok te\254ekk\252r[ENTER]ederim. "
