gameforge.subquest_11._40_say = "Karde\254im di\240er k\246ydeki Yu-Hwan'\253 g\246rmeye gitmek[ENTER]istiyordu. Yu-Hwan'a gidip karde\254imi sorabilir[ENTER]misin? Zaman\253n varsa onu arar m\253s\253n? "
