gameforge.subquest_12._20_say = "Bir saniye gelir misin? Sen iyi bir d\246v\252\254\231\252s\252n.[ENTER]Y\252zba\254\253'dan seninle ilgili \231ok \246vg\252 dinledim. "
gameforge.subquest_12._30_say = "Beyaz Yeminli Mi-Jung'u takip eder misin? K\246y\252[ENTER]kendisinin ve \231etesinin sald\253r\253lar\253ndan korumak[ENTER]zor. E\240er liderlerden biri olan Mi-Jung'u[ENTER]\246ld\252r\252rsek, bu durum biraz daha de\240i\254ecek. K\246y\252n[ENTER]g\252venli\240i senin ellerinde. Ba\254araca\240\253ndan \254\252phem[ENTER]yok. "
gameforge.subquest_12._40_select = "Evet, bu i\254i bitirece\240im. "
gameforge.subquest_12._50_select = "Hay\253r, bu durumla ba\254a \231\253kamam. "
gameforge.subquest_12._60_say = "Ger\231ekten bize yard\253m etmek istemiyor musun? "
gameforge.subquest_12._70_say = "San\253r\253m \254u an do\240ru zaman de\240il. Daha sonra[ENTER]tekrar gel. "
gameforge.subquest_12._80_say = "E\240er yard\253m etmek istemiyorsan, yap\253labilecek[ENTER]bir\254ey yok gibi g\246r\252n\252yor. Gidebilirsin... "
gameforge.subquest_12._90_say = "Ger\231ekten yard\253m etmeyecek misin? "
