gameforge.subquest_13._120_sayReward = "Silah Sat\253c\253s\253'n\253n sana ihtiyac\253 var. Onun i\231in[ENTER]Uriel'den Demir ve Ariyoung'dan Keten al. "
gameforge.subquest_13._130_npcChat = "Ich brauche Eisenerz "
gameforge.subquest_13._140_say = "Demir madeni mi laz\253m? E\240er bana bir iyilik[ENTER]yaparsan, sana verebilirim. "
gameforge.subquest_13._150_say = "Kaplanlar paketimi \231ald\253lar. Ben hayat\253m\253[ENTER]kurtarmak i\231in ka\231t\253m ve o pakette \231ok \246nemli[ENTER]kitaplar kald\253. E\240er o kitaplara ula\254amazsam,[ENTER]Metin ta\254lar\253 hakk\253ndaki ara\254t\253rmalar\253m sonra[ENTER]erer. O paketi benim i\231in getir, sana demir[ENTER]madeni vereyim. "
gameforge.subquest_13._160_npcChat = "Paketini ald\253m. "
gameforge.subquest_13._170_say = "Te\254ekk\252rler! Biliyorum, senden \231ok s\253k yard\253m[ENTER]istiyorum. Al, demir madeni burada. Umar\253m sana[ENTER]yard\253mc\253 olur. "
gameforge.subquest_13._180_say = "Ne? Daha m\253 \231ok demir madeni laz\253m? Bunlar a\240a\231ta[ENTER]yeti\254miyor, biliyorsun! Sana daha \231ok veririm,[ENTER]tabii e\240er benim i\231in bir iyilik yaparsan.[ENTER]Kaplanlar paketimi \231ald\253lar. Onun i\231inde \231ok[ENTER]\246nemli kitaplar\253m vard\253. E\240er o kitaplara tekrar[ENTER]ula\254amazsam Metin ta\254lar\253 hakk\253ndaki b\252t\252n[ENTER]ara\254t\253rmalar\253m son erer. L\252tfen o paketi bana[ENTER]geri getir. "
gameforge.subquest_13._190_say = "Sana zaten verdim. Unuttun mu? "
gameforge.subquest_13._200_sayTitle = "Uriel'in paketini buldun. "
gameforge.subquest_13._20_npcChat = "Silahlar i\231in Malzeme "
gameforge.subquest_13._210_say = "Uriel'in paketini buldun, ona geri d\246n. "
gameforge.subquest_13._220_npcChat = "Ketene ihtiyac\253m var. "
gameforge.subquest_13._230_say = "Ketene mi ihtiyac\253n var? Onu Ah-Yu'ya verdim.[ENTER]Bekle![ENTER]Ona gideceksen bu mektubu da g\246t\252r\252r m\252s\252n? Biz[ENTER]asl\253nda iyi arkada\254\253z ama \231ocu\240u y\252z\252nden uzun[ENTER]s\252redir g\246r\252\254emedik. Ayn\253 zamanda sana biraz[ENTER]keten vermesini de s\246yleyece\240im... Evet, bu[ENTER]herkesin yarar\253na olacak! Ve ona selam\253m\253 ilet. "
gameforge.subquest_13._240_say = "Ariyoung:[ENTER]Ah-Yu'dan keten ald\253\240\253na eminim, alamad\253n m\253? "
gameforge.subquest_13._250_npcChat = "Ariyoung'un mektubu "
gameforge.subquest_13._260_say = "Ariyoung'dan mektup mu? Uzun s\252reden sonra ondan[ENTER]haber olmak sevindirici. Eskiden s\253k\231a sohbet[ENTER]ederdik. Ama son zamanlarda bir \254ekilde zorla\254t\253.[ENTER]Ama bekle biraz. Burada biraz Ketene ihtiyac\253n[ENTER]oldu\240u yaz\253yor? Ariyoung bana vermi\254ti. Biraz\253n\253[ENTER]sana verebilirim. Bana mektubu getirdi\240in i\231in[ENTER]te\254ekk\252r ederim. Ona cevap verece\240im... "
gameforge.subquest_13._270_qSetTitle = "Silah Sat\253c\253s\253na gidelim "
gameforge.subquest_13._280_targetVid = "Silah sat\253c\253s\253na git. "
gameforge.subquest_13._290_sayTitle = "Malzemeleri ver. "
gameforge.subquest_13._300_sayReward = "T\252m malzemeleri toplad\253m.[ENTER]Silah sat\253c\253s\253na malzemeleri b\253rak. "
gameforge.subquest_13._30_say = "Hey, sen! Benim i\231in bir iyilik yapar m\253s\253n? Yeni[ENTER]bir t\252r silah yapmaya \231al\253\254\253yorum. Ancak gereken[ENTER]malzemeleri bulmak \246yle kolay de\240il. Ba\254\253mdan[ENTER]a\254k\253n i\254im var ve bu malzemeleri aramaya[ENTER]\231\253kam\253yorum. Onlar\253 benim i\231in toplar m\253s\253n? "
gameforge.subquest_13._310_say = "\221yi i\254 \231\253kard\253n. Ger\231ekten \231ok iyi ve h\253zl\253s\253n.[ENTER]\221zin ver silah \252zerinde \231al\253\254ay\253m![ENTER]*\231ank, \231ank* (\231eki\231 sesi)[ENTER]\221\254te yeni nesil silahlar. En iyisini yapt\253m.[ENTER]Umar\253m bu silah\253 seversin. "
gameforge.subquest_13._320_sayTitle = "\214d\252l: "
gameforge.subquest_13._330_sayReward = "122.000 tecr\252be puan\253 kazand\253n.[ENTER]20.000 Yang kazand\253n. "
gameforge.subquest_13._340_sayReward = "Geni\254 K\253l\253\231+3 kazand\253n. "
