gameforge.subquest_13._360_sayReward = "Tavusku\254u Yelpaze+3 kazand\253n. "
gameforge.subquest_13._40_say = "Tabii ki, seni \246d\252llendirece\240im. \199ok yak\253nda[ENTER]silahlar bitecek ve sana onlardan birini[ENTER]verece\240im. \221htiyac\253m olan malzemeler: demir[ENTER]madeni ve keten. Demir madenini Uriel'den ve[ENTER]keteni de Ariyoung'tn alabilirsin. Hepsini[ENTER]toplad\253\240\253nda haber ver. "
gameforge.subquest_13._50_say = "Ger\231ekten bunu yapmak istemiyor musun? "
gameforge.subquest_13._60_say = "San\253r\253m bu sana fazla geldi.[ENTER]Zaman\253n oldu\240unda geri gel! "
gameforge.subquest_13._70_say = "E\240er yapmak istemiyorsan, san\253r\253m yard\253mc\253[ENTER]olamayacaks\253n. Ho\254\231akal. "
gameforge.subquest_13._80_say = "\199ok iyi![ENTER]Silahlar haz\253r olur olmaz benden bir tane[ENTER]alacaks\253n. \221yi \254anslar. "
gameforge.subquest_13._90_sendLetter = "Malzemeleri ara "
