gameforge.subquest_15._110_sayReward = "Beyaz Yeminlilerden Eun-Jung'u \246ld\252rd\252n. K\246y[ENTER]Gardiyan\253na geri d\246n ve rapor ver. "
gameforge.subquest_15._120_say = "Harikas\253n! Bekledi\240imden daha iyisin. Beyaz[ENTER]Yeminlilerin bu iki lideri hakk\253nda elimizden[ENTER]bir\254ey gelmiyordu ve sen ikisini de yeniverdin. "
gameforge.subquest_15._130_say = "Bu inan\253lmaz. Uygun bir \246d\252l almal\253s\253n. Bunu al[ENTER]ve k\246y\252n huzuru i\231in \231al\253\254maya devam et! "
gameforge.subquest_15._140_sayReward = "150.000 tecr\252be puan\253 kazand\253n.[ENTER]25.000 Yang kazand\253n.[ENTER]Alt\253n Kolye+4 kazand\253n. "
gameforge.subquest_15._20_say = "Bir dakika buraya gel.[ENTER]Kaptan senden \231ok bahsetti. Korkusuz[ENTER]g\246r\252n\252yorsun. Bu nedenle yard\253m\253na ihtiyac\253m var:[ENTER]Beyaz Yeminliler eskisinden de k\246t\252 davranmaya[ENTER]ba\254lad\253. "
gameforge.subquest_15._30_say = "Beyaz Yeminlilerin lideri Mi-Jung'u yendin. Ama[ENTER]hala tehlikedeyiz! Beyaz Yeminlilerin tehlikesi[ENTER]azalaca\240\253na artt\253! "
gameforge.subquest_15._40_say = "Son olarak, Y\252zba\254\253 Eun-Jung'\253 \246ld\252rmeliyiz ki[ENTER]art\253k \252st\252n oldu\240umuzu anlay\253p geri \231ekilsinler.[ENTER]Eun-Jung'\253 \246ld\252r! Kaderimiz senin ellerinde. "
gameforge.subquest_15._50_sayTitle = "Gardiyan: "
gameforge.subquest_15._60_say = "Daha sonra yine gelir misin? Bu i\254 i\231in do\240ru[ENTER]insan sensin. "
gameforge.subquest_15._70_say = "Bunu yapamaz m\253s\253n? Ger\231ekten hayal k\253r\253kl\253\240\253na[ENTER]u\240rad\253m. "
gameforge.subquest_15._80_say = "Biliyorum bize yard\253m edebilirsin! Eun-Jung'u sen[ENTER]\246ld\252r biz de geri kalan\253yla ilgilenelim. \221yi[ENTER]\254anslar! "
