gameforge.subquest_16._100_qSetTitle = "Yu-Hwan'a sor "
gameforge.subquest_16._10_targetVid = "Z\253rhl\253 s\252varleri aramak "
gameforge.subquest_16._110_targetVid = "Yu-Hwan'a git "
gameforge.subquest_16._120_say = "Hayat ne harika - a\254k ne harika...[ENTER]Ah,yine sen! \222imdi ne istiyorsun? Z\253rhl\253[ENTER]s\252variler hakk\253nda bilgi mi? Bana onlar\253 m\253[ENTER]soruyorsun? Y\252zba\254\253n\253n b\252y\252k planlar\253 olmal\253? "
gameforge.subquest_16._130_sayTitle = "Yu-Hwan: "
gameforge.subquest_16._140_say = "Bu zamana kadar pek orijinal yaz\253 kurtulmad\253 ama[ENTER]z\253rhl\253 s\252variler hakk\253nda baz\253 \254ark\253lar[ENTER]biliyorum. Bir dakika, \254u enstr\252man\253m\253 akort[ENTER]edeyim... Ah, acelen mi var? Bu g\252nlerde kimsenin[ENTER]dinlemeye zaman\253 yok...[ENTER]Ah peki. Kabaca s\246ylersek, Isup'un s\252varileri[ENTER]neredeyse yenilmez. Hem iyi e\240itimliler hem de[ENTER]a\240\253r z\253rhlara ra\240men h\253zl\253 hareket edebiliyorlar. "
gameforge.subquest_16._150_say = "O, bu k\253tan\253n g\246rd\252\240\252 en iyi orduydu. S\252varileri[ENTER]kimse durduramad\253\240\253 i\231in \231ok \252lke ma\240lup oldu.[ENTER]Bug\252n de \246yle olabilirdi. Ancak sert e\240itim[ENTER]y\246ntemlerine ve bu tip z\253rhlar yapmak i\231in \231ok[ENTER]fazla iyi kalite demire ihtiyac\253n\253z var. Bu[ENTER]konuyu Seyyar Sat\253c\253ya ve bilge Uriel'e sor.[ENTER]Muhtemelen onlar daha fazla ayr\253nt\253 biliyordur. "
gameforge.subquest_16._160_makequestbutton = "Seyyar Sat\253c\253ya git "
gameforge.subquest_16._170_qSetTitle = "Z\253rhl\253 s\252variler. "
gameforge.subquest_16._180_targetVid = "Sat\253c\253: "
gameforge.subquest_16._190_sayReward = "M\252zisyen Yu-Hwan Seyyar Sat\253c\253 ve Uriel'in Z\253rhl\253[ENTER]S\252variler hakk\253nda daha fazla bilgisi[ENTER]olabilece\240ini s\246yl\252yor. \214nce Seyyar Sat\253c\253ya git. "
gameforge.subquest_16._200_sayTitle = "Sat\253c\253: "
gameforge.subquest_16._20_npcChat = "Z\253rhl\253 s\252variler. "
gameforge.subquest_16._210_say = "Benim gibi basit bir Seyyar Sat\253c\253dan ne[ENTER]istiyorsun? Z\253rhl\253 s\252variler i\231in demir z\253rh m\253?[ENTER]Bunlar eski hikayeler. Bunlarla kim ilgilenir ki?[ENTER]Para kazanmam gerek ve t\252m g\252n burada \231ene[ENTER]\231alamam. "
gameforge.subquest_16._220_say = "\221\254leri yoluna koymak her g\252n daha da zorla\254\253yor.[ENTER]G\246kten metin ta\254lar\253 ya\240maya ba\254lad\253\240\253ndan beri[ENTER]ben... Ne diyordun? Ha evet s\252variler.[ENTER]Bildi\240im kadar\253yla, \246zel z\253rhlar\253 vard\253 ve o[ENTER]z\253rhlar\253 \252retmek i\231in \246zel bilgiler gerekiyordu.[ENTER]Onlar yap\253lm\253\254 en iyi z\253rhlard\253! Standart[ENTER]b\253\231aklar veya oklar bu m\252kemmel z\253hlar\253[ENTER]delemiyordu. "
gameforge.subquest_16._230_say = "B\246yle s\252varilere z\253rh yapmak i\231in ne kadar para[ENTER]gerekti\240ini hayal edebilirsin. S\246ylentiye g\246re[ENTER]zaman\253nda t\252m krall\253klar\253n hazinelerini[ENTER]kullanm\253\254lar! E\240er \246yle z\253rhlar satabilseydim[ENTER]hayat\253m kurtulurdu! "
gameforge.subquest_16._240_say = "Bug\252nlerde Metin ta\254lar\253 y\252z\252nden z\253rh bile[ENTER]yap\253lam\253yor. Bu yeni \231e\254it z\253rhla eskisi gibi[ENTER]z\253rhl\253 s\252varilere sahip olmak hayal de\240il. \199ok[ENTER]konu\254tum. Gitmeliyim. G\246r\252\254\252r\252z! "
gameforge.subquest_16._250_sayTitle = "Z\253rhl\253 s\252variler. "
gameforge.subquest_16._260_say = "Seyyar Sat\253c\253 z\253rhl\253 s\252varilerin demir z\253hlar\253yla[ENTER]ilgili bir\254eyler biliyordu. \222imdi yan k\246ye git ve[ENTER]bilge Uriel ile e\240itimleri hakk\253nda konu\254. "
gameforge.subquest_16._270_sayTitle = "Uriel: "
gameforge.subquest_16._280_say = "Seni buraya getiren nedir? Z\253rhl\253 s\252variler mi?[ENTER]Tabii ki onlar hakk\253nda bilgim var. Herkes bilir.[ENTER]O ordu t\252m zamanlar\253n en iyisi olarak tarihe[ENTER]ge\231ti! Haklar\253ndaki \231o\240u \254ey abart\253lm\253\254 olabilir[ENTER]ama herkes onlardan \231ok korkard\253. Hakl\253lard\253 da. "
gameforge.subquest_16._290_say = "Yo\240un e\240itimleri sayesinde onlar herkesten daha[ENTER]\252st\252nd\252. Sadece en iyileri e\240itimi bitirebilirdi,[ENTER]\231o\240u e\240itim s\253ras\253nda \246l\252rd\252. D\252\254\252n\252yorum da[ENTER]\254imdi o e\240itim verilse hi\231 bir sava\254\231\253 hayatta[ENTER]kalamazd\253. "
gameforge.subquest_16._300_say = "Sana e\240itim hakk\253nda biraz detayl\253 bilgi[ENTER]verece\240im. Biliyorum \254u anda baz\253 korkun\231[ENTER]sava\254lar oluyor, ancak z\253rhl\253 s\252variler gibi[ENTER]korkusuz bir ordunun tekrar kurulmas\253n\253n pek de[ENTER]iyi bir fikir oldu\240unu sanm\253yorum. "
gameforge.subquest_16._30_say = "Senin i\231in yeni bir g\246revim var. Z\253rhl\253 s\252variler[ENTER]hakk\253nda bilgi toplaman emredildi. Bu Kral[ENTER]Isup'\253n ordusunun en \246nemli par\231as\253. Z\253rhl\253[ENTER]s\252variler di\240er \252lkelerin en \231ok korktuklar\253[ENTER]birliktir. \199\252nk\252 \231ok \252st\252n sald\253r\253 g\252c\252ne ve h\253za[ENTER]sahiptirler. "
gameforge.subquest_16._310_say = "Y\252zba\254\253ya git ve \246\240rendi\240in her\254eyi anlat. "
gameforge.subquest_16._320_makequestbutton = "Y\252zba\254\253ya git. "
gameforge.subquest_16._330_npcChat = "Z\253rhl\253 s\252variler hakk\253nda rapor ver. "
gameforge.subquest_16._340_sayTitle = "Y\252zba\254\253 "
gameforge.subquest_16._350_say = "Bir\254eyler bulabildin mi? Anlat!...[ENTER]Hmm, \231ok ilgin\231. Yani a\240\253r z\253rh ve zor e\240itimden[ENTER]ba\254ka bir\254ey yok? O zaman bu m\252mk\252n! B\246yle bir[ENTER]ordu \252\231 krall\253\240\253 tekrar birle\254tirebilir! "
gameforge.subquest_16._360_say = "Ancak \231ok paraya ihtiyac\253m olacak. Ve \231ok iyi[ENTER]demircilere. Ve iyinin en iyisi olmak i\231in[ENTER]cehenneme gitmeye g\246n\252ll\252 askerlere! Hay\253r,[ENTER]hay\253r! Bana \246yle bakma. Merak etme \254imdiye kadar[ENTER]yeteri kadar i\254 yapt\253n. "
gameforge.subquest_16._370_say = "\214d\252l\252n\252 al ve biraz dinlen.[ENTER]Sonra g\246r\252\254\252r\252z. "
gameforge.subquest_16._380_sayReward = "150.000 tecr\252be puan\253 kazand\253n.[ENTER]30.000 Yang kazand\253n.[ENTER]Alt\253n K\252pe kazand\253n. "
gameforge.subquest_16._40_say = "Toplanan bilgiyle askeri g\252c\252m\252z\252 artt\253rabiliriz.[ENTER]\214nce Yu-Hwan'\253 ziyaret et. Eminim Isup'un[ENTER]s\252varileri hakk\253nda bilgisi vard\253r. "
gameforge.subquest_16._50_say = "H\253m, nas\253l istersen. Sonra g\246r\252\254\252r\252z! "
gameforge.subquest_16._60_say = "B\246yle bir z\253rhl\253 birli\240i idare etmek isterdim...[ENTER]Dikkatli ol... "
gameforge.subquest_16._70_say = "Te\254ekk\252rler, ho\254\231akal. "
gameforge.subquest_16._80_sayTitle = "Z\253rhl\253 s\252variler. "
gameforge.subquest_16._90_sayReward = "Y\252zba\254\253 Kral Isup'\253n efsanevi s\252varileriyle[ENTER]ilgili bilgi ar\253yor. M\252zisyen Yu-Hwan muhtemelen[ENTER]bir\254eyler biliyordur. Git ve ona sor. "
