gameforge.subquest_17._140_say = "Bunu ona iletti\240inde \231ok \231aresiz hissedecek[ENTER]kendisini. Onlar birbirlerini \231ok seviyorlard\253...[ENTER]Ama ona mutlaka anlatmak zorundas\253n. \222\252phe i\231inde[ENTER]ya\254amaya dayanamaz. "
