gameforge.subquest_17._160_sayTitle = "Ariyoung: "
gameforge.subquest_17._170_say = "Market\231inin k\246t\252 haberleri var. Ariyoung'a git ve[ENTER]kocas\253n\253n \246l\252m\252nden bahset. "
gameforge.subquest_17._180_npcChat = "Kocan \246ld\252... "
gameforge.subquest_17._190_say = "Ne... Sen ne diyorsun?! O... O \246ld\252r\252ld\252 m\252?![ENTER]Siyah r\252zgar \231etesi mi? Tanr\253m... hay\253r... \246lm\252\254[ENTER]olamaz, bir yanl\253\254l\253k olmal\253... Onsuz ben \254imdi[ENTER]ne yapaca\240\253m *a\240lamaya ba\254lar* "
gameforge.subquest_17._200_say = "Bana kocam\253n cesedini getirebilir misin? L\252tfen,[ENTER]ona en az\253ndan ho\254\231akal demek istiyorum. E\240er[ENTER]cesedini getiremezsen en az\253ndan ondan bana bir[ENTER]hat\253ra getir. Ne bulursan! Siyah R\252zgar[ENTER]\231etesinden Goo-Pae kesin onun e\254yalar\253n\253[ENTER]alm\253\254t\253r. L\252tfen ona bak. "
