gameforge.subquest_23._220_say = "Aramay\253 b\253rak\253yor musun? "
gameforge.subquest_23._230_say = "Mirine ger\231ekten \231ok \252zg\252n.[ENTER]Daha sonra d\246nece\240im. "
gameforge.subquest_23._240_say = "Mirine'nin a\240abeyi Ejder Vadisine gitti\240inden[ENTER]beridir haber al\253nam\253yor. Bu mutlaka ba\254\253na[ENTER]bir\254ey geldi\240i anlam\253na gelmiyor tabii ki. Sadece[ENTER]bir k\253z senden oraya gitmeni istedi diye, gitmene[ENTER]gerek yok bence. "
