gameforge.subquest_34._120_select = "Tekrar dene "
gameforge.subquest_34._130_say = "Bu g\246revi tamamen b\253rakmak istiyor musun? "
gameforge.subquest_34._140_say = "Bir d\246v\252\254\252 kazanmak kolay de\240ildir, \246zellikle[ENTER]generallere kar\254\253. Tekrar dene. "
gameforge.subquest_34._150_say = "Dedi\240im gibi, o \231etenin generalleri \231ok g\252\231l\252.[ENTER]Ho\254\231a kal. "
gameforge.subquest_34._160_say = "Ger\231ekten \231ok cesursun. Eminim Siyah R\252zgar[ENTER]\199etesini yenebilirsin! "
gameforge.subquest_34._170_targetVid = "Y\252zba\254\253'na rapor ver "
gameforge.subquest_34._180_say = "Y\252zba\254\253'ya git ve Siyah R\252zgar \199etesi[ENTER]generallerini \246ld\252rd\252\240\252n\252 bildir. "
gameforge.subquest_34._185_npcChat = "Generalleri \246ld\252rd\252m! "
gameforge.subquest_34._190_say = "Generalleri \246ld\252rd\252n. Siyah R\252zgar \231etesini[ENTER]generalleri yokken yok etmek \231ok daha kolay; biz[ENTER]gerisini hallederiz.[ENTER]Siyah R\252zgar \199etesi y\252z\252nden \231ok ba\254\253m\253z a\240r\253d\253.[ENTER]Sana \231ok te\254ekk\252r bor\231luyuz. \221\254te \246d\252l\252n, umar\253m[ENTER]tekrar g\246r\252\254\252r\252z! "
gameforge.subquest_34._200_sayReward = "1.000.000 tecr\252be puan\253 kazand\253n. "
gameforge.subquest_34._20_sayTitle = "Y\252zba\254\253 "
gameforge.subquest_34._210_sayReward = "Bir Lisan Y\252z\252\240\252 kazand\253n. "
gameforge.subquest_34._30_say = "Daha \246nce yok edildikten sonra dahi Siyah R\252zgar[ENTER]\231etesi pes etmedi. Daha g\252\231s\252z olarak devam[ENTER]ediyorlar, pes etmiyorlar. Olduk\231a vah\254i bir[ENTER]yap\253lar\253 var. E\240er onlar\253 yenmeyi d\252\254\252n\252yorsak,[ENTER]\246ncelikle generallerini \246ld\252rmeliyiz. "
gameforge.subquest_34._40_say = "Bir defa generallerini \246ld\252rd\252\240\252m\252zde, di\240er[ENTER]\252yeleri ba\254ar\253s\253zl\253\240a u\240rayacak. Bu zor bir[ENTER]g\246rev, ancak kazanacaksak onlardan Siyah R\252zgar[ENTER]Jak-To, Siyah R\252zgar To-Su ve Siyah R\252zgar[ENTER]Gu-Ryung'u \246ld\252rmemiz gerekiyor.[ENTER]Bu g\246revi ba\254ar\253rsan, art\253k onlar hakk\253nda[ENTER]endi\254elenmemiz gerekmeyecek. \221yi \254anslar,[ENTER]kazanman i\231in dua ediyorum. "
gameforge.subquest_34._50_say = "Bu g\246revi tamamen b\253rakmak istiyor musun? "
gameforge.subquest_34._60_say = "Pekala, haz\253r oldu\240unda tekrar gel. Burada senin[ENTER]gibi \231ok ki\254i yok, sana ihtiyac\253m\253z var. "
gameforge.subquest_34._70_say = "Bunu yapamazs\253n...[ENTER]Peki \254imdi onlar\253 nas\253l yenece\240iz? "
gameforge.subquest_34._80_say = "Sana g\252venebilece\240imi biliyordum! Generaller[ENTER]\246ld\252kten sonra Siyah R\252zgar Sava\254\231\253lar\253'n\253n i\254i[ENTER]kolay. Bol \254anslar! "
gameforge.subquest_34._90_sendLetter = "Siyah R\252zgar \199etesinin generallerini \246ld\252r. "
