gameforge.subquest_36._100_sayTitle = "Do\240ru Seyis'in yan\253na "
gameforge.subquest_36._10_targetVid = "Yonah: "
gameforge.subquest_36._110_say = "10 balya saman toplad\253n. Atlara yem verebilmesi[ENTER]i\231in onlar\253 Seyir'e g\246t\252r. "
gameforge.subquest_36._120_sayTitle = "Ah\253rlar i\231in saman "
gameforge.subquest_36._130_say = "Ah\253rlarda yem k\253tl\253\240\253 var.[ENTER]10 balya saman temin et ve atlar a\231l\253ktan \246lmeden[ENTER]onlar\253 Seyir'e g\246t\252r![ENTER]Saman\253, av yaparak kazanabilirsin. "
gameforge.subquest_36._140_npcChat = "Saman m\253 laz\253m sana? "
gameforge.subquest_36._150_say = "Buraya seni Yonah g\246nderdi\240i i\231in mi geldin?[ENTER]Seni \231ok anlatt\253lar.[ENTER]Ah ah, atlar\253m\253z yeterince beslenemiyor. Onlar\253[ENTER]kurtarmaya \231al\253\254mal\253y\253z. Bana yard\253m et ve atlara[ENTER]saman bul! "
gameforge.subquest_36._160_say = "\221nsan s\246z\252nde durmal\253. Ayr\253ca ilerde belki bende[ENTER]ata binmek istiyorum. Mutlaka saman bulmal\253y\253m. "
gameforge.subquest_36._170_say = "\214z\252r dilerim. Ben de ar\253yorum ama bir t\252rl\252 saman[ENTER]bulunmuyor. "
gameforge.subquest_36._180_say = "Bekliyorum, umar\253m bunu yapabilirsin.[ENTER]Anl\253yorum, kendi i\254imi senin \252zerine y\253kmak iyi[ENTER]bir\254ey olmasa gerek. Ama yeniden deneyebilirsin.[ENTER]Di\240er krall\253ktan bir arkada\254\253m var; kendisi \231ok[ENTER]g\252\231l\252. E\240er bana yard\253m edersen, kendisinden sana[ENTER]yard\253m etmesini isteyebilirim. "
gameforge.subquest_36._190_select = "Aramaya devam et "
gameforge.subquest_36._200_say = "Tabii ki, sana yard\253mc\253 olaca\240\253m. Benim o kadar[ENTER]g\252c\252m yok. "
gameforge.subquest_36._20_npcChat = "Ah\253rlarda sorun var "
gameforge.subquest_36._210_say = "Yeterince enerjim yok. Sana yard\253m etmek isterim[ENTER]ama yapamam. Ben yeterince g\252\231l\252 de\240ilim. "
gameforge.subquest_36._220_npcChat = "Atlar i\231in saman temin ettim. "
gameforge.subquest_36._230_say = "Saman m\253 temin ettin? Ah sa\240ol.[ENTER]Yonah'a at yeminin azald\253\240\253n\253 anlatt\253m. O \231ok iyi[ENTER]bir dostum oluyor. Yard\253m edecek birini[ENTER]arayaca\240\253n\253 tahmin ettim ama bu kadar \231abuk[ENTER]olaca\240\253n\253 d\252\254\252nmedim. Atlara baksana, ne[ENTER]heyecanla yemlerini yiyorlar. "
gameforge.subquest_36._240_sayReward = "1.800.000 tecr\252be puan\253 kazand\253n. "
gameforge.subquest_36._250_sendLetter = "Yonah'a d\246n "
gameforge.subquest_36._260_sayTitle = "Yonah'a d\246n "
gameforge.subquest_36._270_say = "Atlara vermesi i\231in Seyis'e 10 balya saman[ENTER]g\246t\252rd\252n. Yonah'\253n yan\253na git ve ona ba\254ar\253n\253[ENTER]anlat. "
gameforge.subquest_36._280_npcChat = "Atlar beslenmi\254! "
gameforge.subquest_36._290_say = "Merhaba, d\246nm\252\254s\252n![ENTER]Bu kadar saman toplamak ku\254kusuz kolay de\240ildi.[ENTER]Pes etmedi\240in i\231in sa\240ol! Al sana k\252\231\252k bir[ENTER]hediye. "
gameforge.subquest_36._300_sayReward = "G\246rev Kitab\253 kazand\253n. "
gameforge.subquest_36._30_say = "Hey, bir soru soraca\240\253m! Ah\253rlardan sorumlu ba\254ka[ENTER]birini daha tan\253yorum, ancak son d\246nemde \231ok[ENTER]sorun ya\254ad\253k. Sava\254 s\253ras\253nda atlara \231ok ihtiya\231[ENTER]duyuluyor ama atlar\253n da s\253n\253rlar\253 var... "
gameforge.subquest_36._40_say = "Fazla at, az yiyecek var. Pek \231o\240u \246ld\252. Atlar\253[ENTER]kurtarmak i\231in yiyecek getirir misin? Bunu sadece[ENTER]sen yapabilirsin. 10 tane saman topla ve buraya[ENTER]getir. Seyis, e\240er benim g\246nderdi\240imi s\246ylersen[ENTER]anlayacakt\253r. "
gameforge.subquest_36._50_select = "Hemen yola \231\253k\253yorum! "
gameforge.subquest_36._60_select = "Hay\253r, bu ilkel bir i\254. "
gameforge.subquest_36._70_say = "\222u g\252nlerde, pek \231ok ki\254i at istemeye ba\254lad\253.[ENTER]Ancak herkese yetecek kadar at ve yem yok. Atlar[ENTER]a\231l\253ktan \246lecek. Fikrini de\240i\254tirirsen geri d\246n. "
gameforge.subquest_36._80_say = "Aah, atlar\253n yeterince yiyecekleri yok...[ENTER]San\253r\253m bununla ba\254a \231\253kmam gerekecek... "
gameforge.subquest_36._90_say = "Biliyorum \231ok me\254gulsun, ama bana biraz \246ncelik[ENTER]veremez misin? Bu g\252nlerde atlar ger\231ekten \231ok[ENTER]\246nemli. Samana ihtiyac\253m\253z var. "
gameforge.subquest_37 = {}
gameforge.subquest_37._100_say = "Yonah, yeni porselen imal etmek i\231in elinden[ENTER]geleni yap\253yor ama deneyleri bir i\254e yaram\253yor.[ENTER]Alim Uriel'\253n yan\253na git ve ona Celadon porseleni[ENTER]hakk\253nda bilgisi var m\253 diye sor. "
gameforge.subquest_37._10_targetVid = "Celadon porseleninin s\253rr\253. "
gameforge.subquest_37._110_npcChat = "Celadon porselenini bilir misin? "
gameforge.subquest_37._120_sayTitle = "Uriel: "
gameforge.subquest_37._130_say = "Celadon porseleni mi? Pekala, ge\231mi\254i ve bilimi[ENTER]hakk\253nda bilgim var fakat d\252r\252st olmak gerekirse[ENTER]hi\231 ilgimi \231eken bir sanat dal\253 olmad\253. Ama belki[ENTER]Soon bir\254eyler biliyordur. \221nsanlar onu pek[ENTER]sevmezler fakat kendisi pek \231ok farkl\253 t\252rde[ENTER]kitap okur. Bu konuda da bir\254eyler bilmesi \231ok[ENTER]muhtemel. "
gameforge.subquest_37._140_makequestbutton = "Soon'a git "
gameforge.subquest_37._150_targetVid = "Soon'un yan\253na git "
gameforge.subquest_37._160_say = "Ne yaz\253kki Uriel, Celadon porseleni ile ilgili[ENTER]bir\254ey bilmiyor. Ama kitap kurdu Soon, de\240i\254ik[ENTER]konulu kitaplar okuyor. Onun yan\253na git ve[ENTER]Celadon porseleninin nas\253l yap\253ld\253\240\253n\253 sor. "
gameforge.subquest_37._170_sayTitle = "Soon: "
gameforge.subquest_37._180_say = "Ne istiyorsun? Kitap okurken rahats\253z etme beni![ENTER]Ne? Celadon porseleni mi? Tabiki biliyorum. Ne de[ENTER]olsa onunla ilgili neredeyse bir y\253\240\253n kitap[ENTER]okudum. Neden mi? Bo\254una bana 'kitap kurdu'[ENTER]dememi\254ler! T\252m kitaplarda yaz\253l\253 olan her\254eyi[ENTER]anlar\253m! "
gameforge.subquest_37._190_say = "Celadon porseleninin nas\253l yap\253ld\253\240\253n\253 sana[ENTER]ezbere yazabilirim ama niye yapay\253mki?[ENTER]Hmm bekle, bir fikrim var. Kom\254u k\246ydeki Seyyar[ENTER]sat\253c\253ya hal\226 alamad\253\240\253m bir kitab\253n sipari\254ini[ENTER]verdim ama uzun yola \231\253kmaya zaman\253m yok. Kitab\253[ENTER]almaya gidersen porselen yap\253m\253nda sana yard\253mc\253[ENTER]olurum. Haydi bakal\253m! "
gameforge.subquest_37._200_makequestbutton = "Seyyar sat\253c\253ya git "
gameforge.subquest_37._20_sayTitle = "Yonah: "
gameforge.subquest_37._210_targetVid = "Seyyar sat\253c\253ya git "
gameforge.subquest_37._220_say = "Kitap kurdu Soon, Celadon porseleninden iyi[ENTER]anl\253yor ama bilgisini kar\254\253l\253k almadan payla\254mak[ENTER]istemiyor. Soon i\231in kom\254u k\246ydeki sipari\254[ENTER]verdi\240in Seyyar sat\253c\253ya git ve kitab\253 al. "
gameforge.subquest_37._230_npcChat = "Beni Soon g\246nderdi... "
gameforge.subquest_37._240_say = "Merhaba! Bana bir daha yard\253m etmek i\231in mi[ENTER]geldin? Hmm, Soon'un kitab\253n\253 istiyorsun. Zaten[ENTER]\254ehire inecektim ama o \231ok aceleci. Kitab\253 almak[ENTER]i\231in ba\254kalar\253n\253 yolluyor. Hmm.[ENTER]\221\254te kitap. Soon'un, bu ka\240\253t y\253\240\253nlar\253nda ne[ENTER]buldu\240unu anlam\253yorum. Asl\253nda h\253zl\253 Yang[ENTER]kazanmak daha \246nemli. "
gameforge.subquest_37._250_qSetTitle = "Soon'a d\246n "
gameforge.subquest_37._260_targetVid = "Soon'a d\246n "
gameforge.subquest_37._270_say = "Seyyar sat\253c\253dan Soon'un kitab\253n\253 ald\253n.[ENTER]Soon'un yan\253na d\246n ve sana Celadon porselenini[ENTER]nas\253l imal etti\240ine dair ipucu vermesi i\231in[ENTER]kitab\253 ona ver. "
gameforge.subquest_37._280_npcChat = "Kitab\253 ald\253m "
gameforge.subquest_37._290_say = "Ya\254as\253n! Hele \254\252k\252r okunacak yeni konular geldi![ENTER]Te\254ekk\252r ederim sana! Tan\253mad\253\240\253m pek fazla kitap[ENTER]yoktur...[ENTER]Al, Celadon porseleni yap\253m\253 i\231in neyin \246nemli[ENTER]oldu\240unu yazd\253m sana. Tarife uyarsan muhte\254em[ENTER]porselenler imal edeceksin.[ENTER]\222imdi yeni kitab\253 okuman\253n zaman\253 geldi.[ENTER]Ho\254\231akal. "
gameforge.subquest_37._300_makequestbutton = "Yonah'a d\246n "
gameforge.subquest_37._30_say = "Hmm...Bu bir i\254e yaram\253yor. Bu da yaram\253yor...[ENTER]Ah merhaba! Buraya bak\253n. Hi\231 durmadan porselen[ENTER]imal ediyorum ama \231o\240u hemen k\253r\253l\253yor.[ENTER]Zannedersem yeni ve sa\240lam porselene ihtiyac\253m[ENTER]var... "
gameforge.subquest_37._310_targetVid = "Notlar\253 Yonah'a g\246t\252r "
gameforge.subquest_37._320_say = "Soon, s\246z\252nde durup Celadon porseleni pi\254irmek[ENTER]i\231in gerekli olan bir k\253lavuz yazd\253. Onu Yonah'a[ENTER]g\246t\252r. "
gameforge.subquest_37._330_say = "Aah! Burda Celadon porseleni yap\253m\253 hakk\253nda[ENTER]her\254ey yaz\253yor. Bu notlar sayesinde usta olarak[ENTER]tarih yazaca\240\253m. Yard\253m\253n i\231in sa\240ol. \199ok yak\253nda[ENTER]sana serami\240in hass\253n\253 g\246sterebilece\240im! Bana[ENTER]g\252ven. Benim porselenim as\253rlarca dayan\253kl\253[ENTER]olacak. "
gameforge.subquest_37._340_sayReward = "2.500.000 tecr\252be puan\253 kazand\253n. "
gameforge.subquest_37._350_sayReward = "35.000 Yang kazand\253n. "
gameforge.subquest_37._360_sayReward = "Ye\254imTa\254\253 Ayakkab\253+3 ald\253n. "
gameforge.subquest_37._40_say = "Yeni bir y\246ntem deneyece\240im. Celadon porseleni[ENTER]\252retmek kolay de\240il. \221\254te bu sebeple herkes bunu[ENTER]\252retemiyor. Sanat\253m\253 ya\254atabilmem i\231in bilmem[ENTER]gerekiyor. Bu durumda, evet Uriel bir\254eyler[ENTER]biliyor olmal\253. Uriel'e git ve kendisine celadon[ENTER]porselenin nas\253l \252retildi\240ini sor l\252tfen. Eminim[ENTER]ki sana yard\253mc\253 olacakt\253r. "
gameforge.subquest_37._50_say = "Bu g\246revi tamamen b\253rakmak istiyor musun? "
gameforge.subquest_37._60_say = "Hm, san\253r\253m \231ok me\254guls\252n?[ENTER]Vaktin olunca bana u\240ramay\253 unutma. "
gameforge.subquest_37._70_say = "En iyi porseleni \252retmek istiyorum..[ENTER]Anl\253yorum, kendine iyi bak... "
gameforge.subquest_37._80_say = "\199ok te\254ekk\252r ederim. Belki Soon bilir. Az sonra[ENTER]g\246r\252\254mek \252zere! "
gameforge.subquest_37._90_targetVid = "Do\240ru Uriel'in yan\253na "
