gameforge.subquest_38._130_npcChat = "\221\254te yay\253n... "
gameforge.subquest_38._140_say = "Ne? \221nan\253lmaz!!! A\254\253r\253 S\252sl\252 Yay! Atalar\253m\253z\253n[ENTER]onuru geri d\246nd\252. Bunu kaybetti\240im i\231in uzun[ENTER]s\252reler ac\253 \231ektim... Sana nas\253l te\254ekk\252r[ENTER]edece\240imi inan bilemiyorum. Sana bunu vermek[ENTER]benim i\231in bir onur. Yapt\253\240\253na kar\254\253l\253k \231ok k\252\231\252k[ENTER]ama kalpten veriyorum...[ENTER]L\252tfen al. Te\254ekk\252rler tekrar, art\253k huzur i\231inde[ENTER]ya\254ayabilirim. "
gameforge.subquest_38._150_sayReward = "1.500.000 tecr\252be puan\253 kazand\253n. "
gameforge.subquest_38._160_sayReward = "35.000 Yang kazand\253n. "
gameforge.subquest_38._170_sayReward = "Bir tane cesaret pelerini kazand\253n. "
gameforge.subquest_38._180_say = "Yay\253m\253 m\253 buldun? Hani nerdeki? Yine kay\253p m\253[ENTER]ettin yoksa? "
gameforge.subquest_38._190_select = "Aramaya devam ediyorum. "
gameforge.subquest_38._200_say = "Peki \246yle olsun.[ENTER]Kendine dikkat et. "
gameforge.subquest_38._20_say = "Hey, bir saniye beni dinler misin? G\246rd\252\240\252n gibi,[ENTER]ben avc\253y\253m; ailem nesillerdir avc\253l\253k yapar.[ENTER]Fakat benim yapt\253\240\253m bir hata, beni b\252t\252n ailem[ENTER]kar\254\253s\253nda onursuz k\253ld\253... "
gameforge.subquest_38._210_say = "Bir daha m\253 deniyorsun? Te\254ekk\252r ederim sana.[ENTER]Sende bu beceri varken ba\254araca\240\253ndan eminim. "
gameforge.subquest_38._30_say = "Bu mevzu uzun zaman \246nce maymunlar taraf\253ndan[ENTER]\231al\253nan A\254\253r\253 S\252sl\252 Yay hakk\253nda, bir anl\253k[ENTER]dikkatsizli\240im y\252z\252nden oldu. Maymunlar zindan\253na[ENTER]avlanmaya gitti\240im bir defas\253nda bana ger\231ek,[ENTER]k\246t\252 y\252zlerini g\246sterdiler ve yay\253 \231ald\253lar. "
gameforge.subquest_38._40_say = "Hi\231 o zindan\253n derinlerine inmedim, bu y\252zden ne[ENTER]kadar derin oldu\240unu bilmiyorum a\231\253k\231as\253. Senin[ENTER]yard\253m\253na ihtiyac\253m var...[ENTER]Bir\231ok ki\254iden senin ne kadar yetenekli oldu\240unu[ENTER]duydum. Bu sebeple iyilik istemeye sana geldim.[ENTER]Bu yay olmadan atalar\253mla y\252zle\254emem... "
gameforge.subquest_38._50_sayTitle = "Yang-Shin: "
gameforge.subquest_38._60_say = "Ah, hemen geri almam gerekiyor...[ENTER]Biraz zaman\253n oldu\240unda l\252tfen geri gel. "
gameforge.subquest_38._70_say = "Pek ala...[ENTER]Seyyat ederken dikkatli ol. "
gameforge.subquest_38._80_say = "A\254\253r\253 s\252sl\252 bir yay oldu\240u i\231in bulunmas\253 kolay.[ENTER]Bu i\254 i\231in seni bolca \246d\252llendirece\240im. "
gameforge.subquest_38._90_sayTitle = "S\252sl\252 yay\253 ara "
