gameforge.subquest_39._120_makequestbutton = "Baek-Go'nun yan\253na git "
gameforge.subquest_39._130_qSetTitle = "Baek-Go'nun yan\253na git "
gameforge.subquest_39._140_targetVid = "Hadi Baek-Go'ya git. "
gameforge.subquest_39._150_npcChat = "Hastam var... "
gameforge.subquest_39._160_sayTitle = "Baek-Go: "
gameforge.subquest_39._170_say = "Ah, sen misin? Nas\253ls\253n?[ENTER]Hastaya m\253 bak\253yorsun? Anlatsana neyi[ENTER]var...Hmm... \222u ana kadar hangi ilac\253 kulland\253?[ENTER]Ne dedin?! Tabiki daha \231ok hasta olur! Bu ila\231[ENTER]kesinlikle yaramaz! "
gameforge.subquest_39._180_say = "Hayatta oldu\240una \254\252kretsin! Bir hastay\253 yanl\253\254[ENTER]tedavi etmek \231ok tehlikeli! Ama onu iyile\254tirecek[ENTER]bir\254ey biliyorum. V\252cudunu toksinlerden ar\253nd\253r\253p[ENTER]sa\240l\253\240\253na tekrar kavu\254turan bir bitki var. Ancak[ENTER]bu bitkiyi aramak \231ok tehlikeli. "
gameforge.subquest_39._190_say = "Bildi\240im kadar\253yla bu bitki Sangsun Dong'da[ENTER]yeti\254iyor. Maymun lort o bitkiyi yemesini \231ok[ENTER]sevdi\240inden sadece onun i\231in toplan\253yor. O[ENTER]bitkiyi alabilmek i\231in onu \246ld\252rmelisin.[ENTER]Bana o bitkiyi getirirsen sana do\240ru ilac\253[ENTER]yapar\253m. "
