gameforge.subquest_49._140_npcChat = "Bingsu nedir? "
gameforge.subquest_49._150_say = "Bu Taurean varya, her\254eyi \231ok iyi biliyormu\254 gibi[ENTER]yap\253yor ama daha Bingsu'nun ne oldu\240unu bile[ENTER]bilmiyor! Nas\253l olurda b\246yle lezzetli bir\254eyi[ENTER]bilmez? Sen de mi bilmiyorsun?? Kom\254u k\246ydeki[ENTER]Octavio'nun yan\253na gitmeni tavsiye ederim.[ENTER]Kendisi \231ok \252nl\252 bir a\254\231\253d\253r ve en iyi re\231eteleri[ENTER]bilir. Bir defas\253nda benim i\231in Bingsu yapm\253\254t\253,[ENTER]hmm... Hakl\253 oldu\240umu sana \253spat edecek! "
gameforge.subquest_49._160_makequestbutton = "Haydi Octavio'nun yan\253na "
gameforge.subquest_49._170_say = "Taurean, Bingsu'nun ne oldu\240unu illa \246\240renmek[ENTER]istiyor. Lokanta sahibi Octavio'nun yan\253na git.[ENTER]O sana muhakkak yard\253mc\253 olacakt\253r. "
gameforge.subquest_49._180_npcChat = "Bingsu'nun ne oldu\240unu biliyor musun? "
gameforge.subquest_49._190_say = "Bingsu mu? Tabii ki biliyorum. B\252t\252n iyi a\254\231\253lar[ENTER]Bingsu yapmay\253 bilir! \214nce buzu g\252zelce k\253r.[ENTER]Sonra \252zerine \254eker ve ince kesilmi\254 pirin\231[ENTER]pastas\253 koy. En son da s\252sleme i\231in biraz taze[ENTER]meyve ekle. "
gameforge.subquest_49._200_say = "Neden sordun? Taurean ve Harang kavga m\253 ediyor?[ENTER]Bu yeni bir haber de\240il. Ama Harang hakl\253. Bingsu[ENTER]\246zellikle s\253cak yaz g\252nlerinin sevilen bir[ENTER]yiyece\240idir. Taurean iyi bir \231ocuk ama zaman[ENTER]zaman b\246yle dar kafal\253 olabiliyor. E\240er[ENTER]malzemeleri al\253rsan onun i\231in Bingsu yapabilirim. "
gameforge.subquest_49._20_npcChat = "Bingsu mu? "
gameforge.subquest_49._210_say = "Taurean'a \246d\252l olarak Bingsu vermek istiyorum.[ENTER]Ne d\252\254\252n\252yorsun? Sohan da\240\253ndan buz alabilir[ENTER]misin? "
gameforge.subquest_49._220_say = "Bu g\246revi tamamen b\253rakmak istiyor musun? "
gameforge.subquest_49._230_say = "Dondurma sevmez misin? Yoksa \231ok mu fazla yedin?[ENTER]Bu Taurean i\231in, l\252tfen bir kez daha d\252\254\252n. "
