gameforge.training_mount = {}
gameforge.training_mount._01_say = "Ne yaz\253k ki bine\240ini geli\254tirecek kadar binicilik[ENTER]tecr\252ben yok. En az\253ndan sava\254 at\253 ruhsat\253na[ENTER]sahip olman gerekir. "
gameforge.training_mount._02_say = "Kusura bakma ama do\240ru belgeler olmadan sana[ENTER]yard\253mc\253 olamam. Yine beni i\254letmeye kalk\253\254ma[ENTER]yoksa fena yapar\253m. "
gameforge.training_mount._03_say = "Binek hayvan\253 m\252hr\252n nerede? O m\252h\252r olmadan[ENTER]binek geli\254tiremem. Sol a\254a\240\253da d\246nen paran\253n[ENTER]arkas\253na bak. Orada bulunan sertifikay\253 bana[ENTER]getirirsen, binek hayvan\253 m\252hr\252 ile[ENTER]de\240i\254tirebilirsin. "
gameforge.training_mount._04_say = "Yeni bir bine\240e binmek istiyorum! "
gameforge.training_mount._05_say = "\222ii\254t! Hal\226 at s\253rt\253nda m\253 gidiyorsun?[ENTER]\221nanam\253yorum?! Art\253k yaban hayvan\253 ehlile\254tirme[ENTER]diye bir\254ey var, hi\231 duymad\253n m\253? "
gameforge.training_mount._06_say = "Ehlile\254tirilmi\254 yaban hayvanlar\253n\253 sava\254 i\231in[ENTER]e\240itebilmen i\231in derin binicilik bilgisine sahip[ENTER]olmal\253s\253n. Ayr\253ca \254u e\254yalar da sana l\226z\253m[ENTER]olacak: bine\240ini yabani binek hayvan\253 yapmak i\231in[ENTER]evrim par\254\246meni; bine\240ini cesur binek hayvan\253[ENTER]yapmak i\231in de mutasyon par\254\246meni gerekir. "
gameforge.training_mount._07_say = "Daha fazla sorular\253n olursa diledi\240in zaman[ENTER]yan\253ma gelebilirsin. Sana elimden geldi\240i kadar[ENTER]yard\253mc\253 olaca\240\253m. "
gameforge.training_mount._08_say = "Bine\240imi geli\254tirmek istiyorum! "
gameforge.training_mount._09_say = "Demek bine\240ini geli\254tirmek istiyorsun, \246yle mi?[ENTER]Nas\253l yap\253ld\253\240\253n\253 biliyor musun? Hadi gel[ENTER]anlatay\253m. "
gameforge.training_mount._10_say = "Bine\240ini geli\254tirip yabani binek hayvan\253[ENTER]yapabilmen i\231in evrim par\254\246meni aray\253\254\253na[ENTER]\231\253kmal\253s\253n. Sonra yaban hayvan\253n\253 e\240itip cesur[ENTER]binek hayvan\253 yapabilmek i\231in de mutasyon[ENTER]par\254\246menini bulmal\253s\253n. Tehlikeli devlerin[ENTER]ya\254ad\253\240\253 \231ok uzak bir diyarda sakl\253 olduklar\253[ENTER]s\246yleniyor! "
gameforge.training_mount._11_say = "Bana o par\254\246menlerden birini getirirsen bine\240ini[ENTER]geli\254tirece\240im. Getirdin mi yoksa? "
gameforge.training_mount._12_say = "Evet, bine\240imi geli\254tirmek istiyorum! "
gameforge.training_mount._13_say = "Hay\253r, \254imdi de\240il. "
gameforge.training_mount._14_say = "Ah, par\254\246menlerin birini getirmi\254sin. Hangisini[ENTER]getirdin? Evrim par\254\246meniyle tecr\252besiz yavru[ENTER]hayvan\253n\253 sava\254 i\231in e\240itiyorsun. Sonra da[ENTER]mutasyon par\254\246meniyle geli\254tirip cesur binek[ENTER]hayvan\253 yapabiliyorsun. "
gameforge.training_mount._15_2_say = "Mutasyon par\254\246meni bende. "
gameforge.training_mount._15_say = "Evrim par\254\246meni bende. "
gameforge.training_mount._16_say = "Par\254\246men getirmedim. "
gameforge.training_mount._17_say = "Ah i\254te evrim par\254\246meni! Binek hayvan\253 m\252hr\252ne[ENTER]bir g\246z atay\253m. Sahtesiyle beni kand\253rmaya[ENTER]\231al\253\254an nicelerini g\246rd\252m! \221lk \246nce ger\231ek olup[ENTER]olmad\253\240\253na bakaca\240\253m. Ver bakal\253m. (M\252hr\252 seyisin[ENTER]\252zerine \231ek.) "
gameforge.training_mount._18_say = "Mutasyon par\254\246meni! \220n\252n\252 \231ok duydum ama daha[ENTER]\246nce hi\231 elimde tutmam\253\254t\253m. \222imdi bana binek[ENTER]hayvan\253 m\252hr\252n\252 g\246ster. Ger\231ek olup olmad\253\240\253na[ENTER]bak\253p onaylad\253ktan sonra daha g\252\231l\252s\252yle de\240i\254[ENTER]toku\254 edece\240im. (M\252hr\252 seyisin \252zerine \231ek.) "
gameforge.training_mount._19_say = "Par\254\246menlerin birini bulur bulmaz yan\253ma d\246n ki[ENTER]eski binek hayvan\253 m\252hr\252n\252 daha g\252\231l\252s\252yle de\240i\254[ENTER]toku\254 edebileyim. "
gameforge.training_mount._20_say = "Binek hayvan\253 m\252hr\252n\252n ah\253 gitmi\254 vah\253 kalm\253\254.[ENTER]Bekle yenisiyle de\240i\254tireyim.[ENTER]Buyur alabilirsin. \222imdi yabani binek hayvan\253n\253[ENTER]\231a\240\253rabilirsin. Mutasyon par\254\246menini ke\254feder[ENTER]ke\254fetmez de yan\253ma d\246n. Sana daha g\252\231l\252 bir[ENTER]binek hayvan\253 m\252hr\252 haz\253rlayaca\240\253m. "
gameforge.training_mount._21_say = "\221\254te sana bir m\252ddet \246nce verdi\240im binek hayvan\253[ENTER]m\252hr\252. Ama baya\240\253 kullan\253lm\253\254. Onu bana geri ver,[ENTER]sana daha g\252\231l\252 bir binek hayvan\253 m\252hr\252[ENTER]haz\253rlayaca\240\253m! "
gameforge.training_mount._22_say = "Bu m\252h\252r, d\246n\252\254m\252\254 bine\240ini \231a\240\253rman\253 sa\240lar. Ona[ENTER]g\246z\252n gibi bak, de\240eri paha bi\231ilmez! "
gameforge.training_mount._23_say = "At becerileri kullanabilir miyim? "
gameforge.training_mount._24_say = "At becerileri kullanmak istiyorsun, \246yle mi?[ENTER]Senin de isteklerin bitmiyor! Ger\231i onu ben bile[ENTER]isterim....Neyse, onu \246\240renebilmek i\231in bir tak\253m[ENTER]kurallara uymal\253s\253n. "
gameforge.training_mount._25_say = "\221lk olarak at binmeyi \246\240renmelisin, aksi taktirde[ENTER]senin i\231in \231ok tehlikeli olabilir. Bunun d\253\254\253nda,[ENTER]sava\254ta kullanmaya elveri\254li bir bine\240in olmas\253[ENTER]gerekir. Ancak o zaman at becerilerini kullanacak[ENTER]durumunda olur. "
gameforge.training_mount._26_say = "Bine\240in, at becerilerini kullanabilecek durumda[ENTER]m\253? De\240ilse, e\240itime izin veremeyece\240im. Ne[ENTER]yapmay\253 d\252\254\252n\252yorsun? "
gameforge.training_mount._27_say = "Anl\253yorum. \222imdi de g\252c\252n\252 ve binicilik bilgini[ENTER]tahmin edece\240im. Bekle bir saniye. "
gameforge.training_mount._28_say = "H\253mm...g\252\231l\252 bir omurga, derin binicilik bilgisi[ENTER]ve sava\254maya merakl\253 bir bine\240in var. At[ENTER]berecilerini kullanabilirsin. "
gameforge.training_mount._29_say = "Bine\240in art\253k at becerileri kullanabilir. Yeni[ENTER]bir binek hayvan\253 alacak olursan, becerileri[ENTER]yeniden \246\240renmesi gerekecektir. B\246yle bir durumda[ENTER]yan\253ma d\246nebilirsin. "
gameforge.training_mount._30_say = "Yapma ya, at binmesini bilmiyorsan senin i\231in[ENTER]tehlikeli olabilece\240ini s\246ylemi\254tim sana.[ENTER]\214\240rendi\240in zaman yan\253ma d\246n. "
gameforge.training_mount._31_say = "Korkar\253m bine\240in hen\252z haz\253r de\240il. Sava\254maya[ENTER]daha hevesli oldu\240unda tekrar gel. "
gameforge.training_mount._32_say = "Konu\254urken bine\240inden iner misin l\252tfen? Boynum[ENTER]tutuldu. Durmadan yukar\253 bakarak konu\254mak zor[ENTER]oluyor. "
gameforge.training_mount._33_say = "Bine\240ini geli\254tirmek i\231in gerekli olan binicilik[ENTER]iznine sahip de\240ilsin. Yabani binek hayvan\253[ENTER]e\240itimi i\231in en az\253ndan sava\254 at\253 iznin olmal\253.[ENTER]Cesur binek hayvan\253 ehlile\254tirmek i\231in ise asker[ENTER]at\253 iznin olmal\253. "
gameforge.training_mount._34_say = "G\246r\252yorum ki g\252\231l\252 bir at\253\254t\253rmal\253\240\253n var. Bu[ENTER]de\240erli \254ifal\253 bitki bine\240ine enerji verir - bu[ENTER]\246mr\252n\252 birka\231 g\252n uzat\253r. Senin i\231in ne yapmam\253[ENTER]istersin? Bine\240inin \246mr\252n\252 m\252 uzatmam\253 m\253 yoksa[ENTER]bine\240ini geli\254tirmemi mi? "
gameforge.training_mount._35_select_1 = "Uzat "
gameforge.training_mount._35_select_2 = "Geli\254tir "
gameforge.training_mount._36_select_1 = "7 G\252n "
gameforge.training_mount._36_select_2 = "15 G\252n "
gameforge.training_mount._36_select_3 = "30 G\252n "
gameforge.training_mount._36_select_4 = "Mutasyon Par\254\246meni + 200k Yang "
gameforge.training_mount._37_say = "Se\231ti\240in s\252reye uygun g\252\231l\252 at\253\254t\253rmal\253\240\253n ne[ENTER]yaz\253k ki yok. Ama bunu d\246nen paraya t\253klayarak[ENTER]alabilirsin! "
gameforge.training_mount._38_say = "Mutasyon Par\254\246meni b\252y\252k bir g\252ce sahiptir. Cesur[ENTER]bine\240inin \246mr\252n\252 d\246rt g\252ne kadar uzatabilir. Bir[ENTER]deneme sana 200.000 Yang'a mal olur. Ancak bunun[ENTER]i\231in bine\240in \231ok yorulmu\254 olmal\253 ve \246mr\252 bir[ENTER]g\252nden daha az olmal\253. Ayr\253ca tabii biraz da[ENTER]\254ans\253n olmal\253! E\240er uzatma ba\254ar\253s\253z olursa ona[ENTER]g\252\231l\252 bir at\253\254t\253rmal\253k yedir. Bunu d\246nen paran\253n[ENTER]arkas\253nda bulabilirsin. "
gameforge.training_mount._39_say = "G\252\231l\252 bine\240in hen\252z \231ok g\252\231l\252. Mutasyon par\254\246meni[ENTER]burada hi\231bir etki sa\240lamaz. Bir g\252nden az \246mr\252[ENTER]kald\253\240\253nda yine gel. "
gameforge.training_mount._40_say = "Sana ne yaz\253k ki yard\253m edemeyece\240im. Ya mutasyon[ENTER]par\254\246meni yan\253nda de\240il ya da 200.000 Yang'\253n[ENTER]yok. "
