gameforge.upgrade_refine_scroll._170_say = "Ejderha par\254\246meni \252rettin! E\240er b\252y\252l\252 metal[ENTER]kullan\253rsan bu ka\240\253tlardan \252retmek kolay[ENTER]olacakt\253r. Bunu sevdim! Ha ha ha! "
gameforge.upgrade_refine_scroll._180_say = "Ejderha Tanr\253s\253 ka\240\253d\253 \252retme i\254lemin ba\254ar\253s\253z[ENTER]oldu, \231\252nk\252 gereken t\252m e\254yalara sahip de\240ilsin. "
gameforge.upgrade_refine_scroll._190_npcChat = "Demircinin El Kitab\253 \252ret "
gameforge.upgrade_refine_scroll._200_say = "Hi\231 Demirci Ta\254\253 diye bir\254ey duymu\254 muydun? Bu[ENTER]ta\254 Demirci'nin kan\253 ve al\253nterinden yap\253l\253r.[ENTER]E\240er bana demircinin ta\254\253n\253 ve kutsama ka\240\253d\253[ENTER]getirirsen sana ailemin ge\231mi\254inden bug\252ne gelmi\254[ENTER]olan bir el kitab\253 yapar\253m. Bu el kitab\253, ejderha[ENTER]par\254\246meni ile ayn\253 i\254e yarar fakat ba\254ar\253 y\252zdesi[ENTER]daha y\252ksektir.  "
gameforge.upgrade_refine_scroll._20_say = "Sava\254 tanr\253lar\253 taraf\253ndan kutsanm\253\254 gizemli bir[ENTER]ka\240\253t var, bu ka\240\253t e\254yalar\253n +0 'dan +3 'e kadar[ENTER]y\252kseltilmesinin ba\254ar\253 oran\253n\253 %100'e \231\253kar\253yor.[ENTER]Ancak bu ka\240\253t +4 ve \252st\252 i\231in \231al\253\254m\253yor. "
gameforge.upgrade_refine_scroll._210_say = "Bundan \252retebilmek i\231in, Demircinin ta\254\253na[ENTER]ihtiyac\253n var. "
gameforge.upgrade_refine_scroll._220_sayItem = "Demircinin Ta\254\253 "
gameforge.upgrade_refine_scroll._230_say = "Bunu \252retebilmek i\231in, kutsama ka\240\253d\253na ihtiyac\253n[ENTER]var.  "
gameforge.upgrade_refine_scroll._240_say = "Gereken t\252m e\254yalara sahip misin? Peki,[ENTER]demircinin el kitab\253n\253 yapmak istiyor musun? "
gameforge.upgrade_refine_scroll._250_say = "Senin i\231in demircinin el kitab\253n\253 yapt\253m! Art\253k[ENTER]hanedan\253m\253n y\253llar i\231inde biriktirdi\240i bilgilere[ENTER]sahipsin. Onu ak\253ll\253ca kullan! Ha, ha, ha! "
gameforge.upgrade_refine_scroll._260_sayItem = "Demircinin el kitab\253 "
gameforge.upgrade_refine_scroll._270_say = "Demircinin el kitab\253n\253 \252retemiyorum \231\252nk\252 gereken[ENTER]malzemelere sahip de\240ilsin. "
gameforge.upgrade_refine_scroll._30_say = "Bunu \252retebilmek i\231in, b\252y\252l\252 metale ihtiyac\253n[ENTER]var. "
gameforge.upgrade_refine_scroll._40_sayItem = "B\252y\252l\252 metal "
gameforge.upgrade_refine_scroll._50_say = "Ayr\253ca kutsama ka\240\253d\253na da ihtiyac\253n var. "
gameforge.upgrade_refine_scroll._60_sayItem = "Kutsama ka\240\253d\253 "
gameforge.upgrade_refine_scroll._70_say = "T\252m gereken e\254yalara sahip misin?[ENTER]Bir tane \252retmek istiyor musun?[ENTER]Yan\253s\253ra 200.000 Yang'a ihtiyac\253n olacak.[ENTER]E\240er b\252y\252l\252 metal ve kutsama ka\240\253d\253n varsa, sava\254[ENTER]ka\240\253d\253 \252retebilirsin. Bu ka\240\253d\253 \252retmek istiyor[ENTER]musun? "
gameforge.upgrade_refine_scroll._80_say = "Ka\240\253d\253 \252rettin! E\240er b\252y\252l\252 metalin varsa, sava\254[ENTER]ka\240\253d\253 \252retmek ger\231ekten kolay oluyor! Sevdim bu[ENTER]i\254i! "
