gameforge.warehouse = {}
gameforge.warehouse._100_say = "Ho\254geldin! Alt\253n k\252l\231elerin ne i\231in oldu\240unu[ENTER]biliyor musun? E\240er \231ok Yang ta\254\253rsan, bu, \254\246yle[ENTER]ba\240\253rmaya benzer: L\252tfen beni \246ld\252r\252n! Bu nedenle[ENTER]ben Yang'\253 alt\253na \231eviriyorum ve dilersen senin[ENTER]i\231in sakl\253yorum. "
gameforge.warehouse._10_npcChat = "Depoyu kullanmak istiyorum. "
gameforge.warehouse._110_say = "Tamam, Alt\253n k\252l\231enin de\240erinden fazlas\253n\253 talep[ENTER]ediyorum. Ama yine de adil bir hizmet veriyorum[ENTER]\246yle de\240il mi? Kendini soyulmu\254 gibi g\246rmene hi\231[ENTER]gerek yok. Biliyorsun d\253\254ar\253s\253 olduk\231a tehlikeli. "
gameforge.warehouse._120_npcChat = "Nesne market deposunu a\231 "
gameforge.warehouse._130_say = "Hmm..[ENTER]T\252m madenler t\252ketildi.[ENTER]Art\253k alt\253n ve g\252m\252\254 bulmak zor.[ENTER]Yeni bir kaynak bulununcaya kadar, yeni alt\253n ve[ENTER]g\252m\252\254 olmayacak. "
gameforge.warehouse._140_say = "Ho\254geldin! Nesne market depo'na m\253 bakmak[ENTER]istiyorsun? Niye bana geliyorsunki? Envanterine[ENTER]bak, oraya do\240rudan giri\254 var art\253k. "
gameforge.warehouse._150_say = "Bu sembolun \252zerine t\253klayarak her yere ve[ENTER]istedi\240in zaman Nesne Market Depo'na[ENTER]girebilirsin. Bu arada, de\240i\254tirmediysen \254ifren[ENTER]000000'd\253r. "
gameforge.warehouse._20_sayTitle = "Depocu: "
gameforge.warehouse._30_say = "Depoyu kullanmak istiyor musun? E\240er istiyorsan[ENTER]bunun i\231in Yang \246demen gerekiyor. Bug\252n moralim[ENTER]iyi, bu y\252zden sana 500 Yang'a kulland\253raca\240\253m.[ENTER]Hadi gel.. Ucuz de\240il mi? "
gameforge.warehouse._40_say = "Ne? Yeterince Yang yok mu?[ENTER]Yeterince paran olunca tekrar gel. "
gameforge.warehouse._50_say = "Senin i\231in ayr\253lan depo a\231\253ld\253. Onu kullanmak[ENTER]istedi\240in zaman benimle konu\254man yeterli.[ENTER]Deponun \254ifresi: "
gameforge.warehouse._60_sayReward = "000000 "
gameforge.warehouse._70_say = "G\252venlik sebebiyle bunu de\240i\254tirmelisin.[ENTER][ENTER]Belki 45 kutunun yetmeyece\240ini d\252\254\252nebilirsin.[ENTER]Ama kimbilir, e\240er benimle uzun s\252re \231al\253\254\253rsan[ENTER]sana daha \231ok kutu ay\253rabilirim.[ENTER]Hehe!  "
gameforge.warehouse._80_say = "Pekala, kimseyi zorlam\253yorum. Fikrini[ENTER]de\240i\254tirirsen sonra tekrar u\240ra. "
gameforge.warehouse._90_npcChat = "Depoyu a\231 "
